  const [invites, setInvites] = useState<Invite[]>([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  
  // Form state
  const [email, setEmail] = useState("");
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [phone, setPhone] = useState("");
  const [companyName, setCompanyName] = useState("");
  const [serviceType, setServiceType] = useState("");

  useEffect(() => {
    // Fetch invites when tab changes
    if (activeTab === "vendor") {
      fetchVendorInvites();
    }
  }, [activeTab]);

  const fetchVendorInvites = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await fetch('/api/auth/invites/vendor');
      if (!res.ok) throw new Error('Failed to fetch invites');
      const data = await res.json();
      setInvites(data.invites || []);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load invites');
      setInvites([]);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    setError(null);
    setSuccess(null);

    try {
      const endpoint = '/api/auth/invites/vendor';
      const body: Record<string, string> = {
        email,
        firstName,
        lastName,
        phone,
        companyName,
        serviceType
      };

      const res = await fetch(endpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || 'Failed to send invite');
      }

      setSuccess(`Invite sent to ${email} successfully!`);
      // Reset form
      setEmail("");
      setFirstName("");
      setLastName("");
      setPhone("");
      setCompanyName("");
      setServiceType("");
      
      // Refresh invites list
      fetchVendorInvites();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to send invite');
    } finally {
      setSubmitting(false);
    }
  };

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric'
    });
  };

  const getStatusBadge = (invite: Invite) => {
    // Check if expired
    if (new Date(invite.expiresAt) < new Date()) {
      return <Badge className="bg-gray-100 text-gray-700">Expired</Badge>;
    }
    // Check status from invite
    if (invite.status === 'ACCEPTED') {
      return <Badge className="bg-green-100 text-green-700">Accepted</Badge>;
    }
    return <Badge className="bg-blue-100 text-blue-700">Pending</Badge>;
  };

  return (
    <div className="container mx-auto py-10 max-w-6xl">
      <div className="mb-6">
        <h1 className="text-3xl font-bold">Send Invites</h1>
        <p className="text-gray-500 mt-1">
          Invite new users to join the platform. Select a role type below.
        </p>
      </div>

      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="grid w-full grid-cols-3 mb-6">
          <TabsTrigger value="tenant" className="flex items-center gap-2">
            <Users className="h-4 w-4" />
            Tenant
          </TabsTrigger>
          <TabsTrigger value="vendor" className="flex items-center gap-2">
            <Truck className="h-4 w-4" />
            Vendor
          </TabsTrigger>
          <TabsTrigger value="agent" className="flex items-center gap-2">
            <UserCircle className="h-4 w-4" />
            Agent
          </TabsTrigger>
        </TabsList>

        {/* Tenant Tab */}
        <TabsContent value="tenant">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Users className="h-5 w-5" />
                Invite Tenant
              </CardTitle>
              <CardDescription>
                Tenants are linked to leases. This requires selecting a property and lease.
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 mb-4">
                <div className="flex items-start gap-3">
                  <AlertCircle className="h-5 w-5 text-amber-600 mt-0.5" />
                  <div>
                    <p className="font-medium text-amber-800">Tenant invites require property context</p>
                    <p className="text-sm text-amber-700 mt-1">
                      To invite tenants, navigate to a specific property manager dashboard and use the tenant management section. 
                      Tenant invites are tied to leases and properties.
                    </p>
                  </div>
                </div>
              </div>
              <p className="text-sm text-gray-500">
                Go to <span className="font-medium">Property Manager → Tenants → Invite Tenant</span> to send tenant invites.
              </p>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Vendor Tab */}
        <TabsContent value="vendor">
          <div className="grid gap-6 md:grid-cols-2">
            {/* Send Invite Form */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Send className="h-5 w-5" />
                  Send Vendor Invite
                </CardTitle>
                <CardDescription>
                  Invite a vendor to join your organization.
                </CardDescription>
              </CardHeader>
              <CardContent>
                {success && (
                  <div className="bg-green-50 border border-green-200 rounded-lg p-3 mb-4">
                    <div className="flex items-center gap-2 text-green-700">
                      <CheckCircle className="h-4 w-4" />
                      <span className="text-sm">{success}</span>
                    </div>
                  </div>
                )}
                
                {error && (
                  <div className="bg-red-50 border border-red-200 rounded-lg p-3 mb-4">
                    <div className="flex items-center gap-2 text-red-700">
                      <AlertCircle className="h-4 w-4" />
                      <span className="text-sm">{error}</span>
                    </div>
                  </div>
                )}

                <form onSubmit={handleSubmit} className="space-y-4">
                  <div>
                    <label className="text-sm font-medium">Email *</label>
                    <Input
                      type="email"
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      placeholder="vendor@company.com"
                      required
                    />
                  </div>
                  
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-sm font-medium">First Name *</label>
                      <Input
                        value={firstName}
                        onChange={(e) => setFirstName(e.target.value)}
                        placeholder="John"
                        required
                      />
                    </div>
                    <div>
                      <label className="text-sm font-medium">Last Name</label>
                      <Input
                        value={lastName}
                        onChange={(e) => setLastName(e.target.value)}
                        placeholder="Doe"
                      />
                    </div>
                  </div>

                  <div>
                    <label className="text-sm font-medium">Phone</label>
                    <Input
                      type="tel"
                      value={phone}
                      onChange={(e) => setPhone(e.target.value)}
                      placeholder="+1 (555) 000-0000"
                    />
                  </div>

                  <div>
                    <label className="text-sm font-medium">Company Name</label>
                    <Input
                      value={companyName}
                      onChange={(e) => setCompanyName(e.target.value)}
                      placeholder="ABC Services LLC"
                    />
                  </div>

                  <div>
                    <label className="text-sm font-medium">Service Type</label>
                    <Input
                      value={serviceType}
                      onChange={(e) => setServiceType(e.target.value)}
                      placeholder="Plumbing, Electrical, HVAC, etc."
                    />
                  </div>

                  <Button type="submit" className="w-full" disabled={submitting}>
                    {submitting ? (
                      <>
                        <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                        Sending...
                      </>
                    ) : (
                      <>
                        <Send className="h-4 w-4 mr-2" />
                        Send Invite
                      </>
                    )}
                  </Button>
                </form>
              </CardContent>
            </Card>

            {/* Pending Invites List */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Mail className="h-5 w-5" />
                  Pending Invites
                </CardTitle>
                <CardDescription>
                  View and manage pending vendor invitations.
                </CardDescription>
              </CardHeader>
              <CardContent>
                {loading ? (
                  <div className="flex items-center justify-center py-8">
                    <Loader2 className="h-6 w-6 animate-spin text-gray-400" />
                  </div>
                ) : invites.length === 0 ? (
                  <div className="text-center py-8 text-gray-500">
                    <Mail className="h-8 w-8 mx-auto mb-2 text-gray-400" />
                    <p>No pending vendor invites</p>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {invites.map((invite) => (
                      <div
                        key={invite.id}
                        className="flex items-center justify-between p-3 border rounded-lg hover:bg-gray-50"
                      >
                        <div className="flex items-center gap-3">
                          <div className="h-10 w-10 rounded-full bg-orange-100 flex items-center justify-center">
                            <Truck className="h-5 w-5 text-orange-600" />
                          </div>
                          <div>
                            <p className="font-medium">{invite.email}</p>
                            <p className="text-sm text-gray-500">
                              Sent {formatDate(invite.createdAt)} • Expires {formatDate(invite.expiresAt)}
                            </p>
                          </div>
                        </div>
                        {getStatusBadge(invite)}
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        {/* Agent Tab */}
        <TabsContent value="agent">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <UserCircle className="h-5 w-5" />
                Invite Agent
              </CardTitle>
              <CardDescription>
                Agents are typically invited by tenants to help manage their properties.
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 mb-4">
                <div className="flex items-start gap-3">
                  <AlertCircle className="h-5 w-5 text-amber-600 mt-0.5" />
                  <div>
                    <p className="font-medium text-amber-800">Agent invites require tenant context</p>
                    <p className="text-sm text-amber-700 mt-1">
                      Agents are invited by tenants who own properties. This workflow is initiated from the tenant side.
                    </p>
                  </div>
                </div>
              </div>
              <p className="text-sm text-gray-500">
                To invite agents, tenants can use the agent invitation feature from their dashboard.
              </p>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { 
  Users, 
  Shield, 
  UserCircle, 
  MoreHorizontal,
  Search,
  Settings,
  Building2,
  Mail,
  Phone,
  LinkIcon
} from "lucide-react";
import Link from "next/link";

interface Role {
  id: string;
  name: string;
  description: string;
  userCount: number;
  permissions: string[];
}

interface User {
  id: string;
  name: string;
  email: string;
  phone: string;
  role: string;
  organization: string;
  status: "active" | "invited" | "inactive";
}

export default function AdminUsersPage() {
  const [searchTerm, setSearchTerm] = useState("");
  const [roles, setRoles] = useState<Role[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);
        
        // Fetch users from API - returns org-wide for SYSTEM_ADMIN
        const usersRes = await fetch('/api/auth/users');
        if (!usersRes.ok) throw new Error('Failed to fetch users');
        const usersData = await usersRes.json();
        
        // Transform API data for admin view
        const transformedUsers: User[] = Array.isArray(usersData) ? usersData.map((u: any) => ({
          id: u.id,
          name: u.firstName && u.lastName ? `${u.firstName} ${u.lastName}` : u.name || 'Unknown',
          email: u.email || '',
          phone: u.phone || '',
          role: u.role || 'TENANT',
          organization: u.organization?.name || 'N/A',
          status: u.emailVerified ? 'active' : 'invited'
        })) : [];
        
        setUsers(transformedUsers);
        
        // Generate roles from user data - admin view shows all roles
        const roleCounts = transformedUsers.reduce((acc, user) => {
          acc[user.role] = (acc[user.role] || 0) + 1;
          return acc;
        }, {} as Record<string, number>);
        
        const roleData: Role[] = [
          {
            id: "system_admin",
            name: "System Admin",
            description: "Full platform access and settings",
            userCount: roleCounts['SYSTEM_ADMIN'] || 0,
            permissions: ["all"]
          },
          {
            id: "property_manager",
            name: "Property Manager",
            description: "Manage properties, tenants, and finance",
            userCount: roleCounts['PROPERTY_MANAGER'] || 0,
            permissions: ["properties", "tenants", "leases", "finance"]
          },
          {
            id: "agent",
            name: "Agent",
            description: "Can manage properties and tenants",
            userCount: roleCounts['AGENT'] || 0,
            permissions: ["properties", "tenants", "leases"]
          },
          {
            id: "vendor",
            name: "Vendor",
            description: "Can view and respond to maintenance requests",
            userCount: roleCounts['VENDOR'] || 0,
            permissions: ["maintenance", "reports"]
          },
          {
            id: "tenant",
            name: "Tenant",
            description: "Can view lease and make payments",
            userCount: roleCounts['TENANT'] || 0,
            permissions: ["lease", "payments", "maintenance"]
          }
        ];
        
        setRoles(roleData);
        
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load data');
      } finally {
        setLoading(false);
      }
    };
    
    fetchData();
  }, []);

  const filteredUsers = users.filter(user =>
    user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.role.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.organization.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "active":
        return <Badge className="bg-green-100 text-green-700">Active</Badge>;
      case "invited":
        return <Badge className="bg-blue-100 text-blue-700">Pending Invite</Badge>;
      case "inactive":
        return <Badge className="bg-gray-100 text-gray-700">Inactive</Badge>;
      default:
        return <Badge>{status}</Badge>;
    }
  };

  const getRoleBadge = (role: string) => {
    switch (role) {
      case "SYSTEM_ADMIN":
        return <Badge className="bg-red-100 text-red-700">System Admin</Badge>;
      case "PROPERTY_MANAGER":
        return <Badge className="bg-purple-100 text-purple-700">Property Manager</Badge>;
      case "AGENT":
        return <Badge className="bg-blue-100 text-blue-700">Agent</Badge>;
      case "VENDOR":
        return <Badge className="bg-orange-100 text-orange-700">Vendor</Badge>;
      case "TENANT":
        return <Badge className="bg-green-100 text-green-700">Tenant</Badge>;
      default:
        return <Badge>{role}</Badge>;
    }
  };

  if (loading) {
    return (
      <div className="container mx-auto py-10 max-w-6xl">
        <div className="flex items-center justify-center h-64">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto mb-4"></div>
            <p className="text-gray-500">Loading users...</p>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto py-10 max-w-6xl">
        <div className="flex items-center justify-center h-64">
          <div className="text-center">
            <p className="text-red-500 mb-2">Error: {error}</p>
            <Button onClick={() => window.location.reload()}>Retry</Button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto py-10 max-w-6xl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold">User Management</h1>
          <p className="text-gray-500 mt-1">
            Manage all users across organizations. View and manage user roles and permissions.
          </p>
        </div>
        <Link href="/admin/invites">
          <Button>
            <Mail className="h-4 w-4 mr-2" />
            Send Invites
          </Button>
        </Link>
      </div>

      <div className="grid gap-6">
        {/* Roles Overview */}
        <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
          {roles.map(role => (
            <Card key={role.id}>
              <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                  <CardTitle className="text-lg">{role.name}</CardTitle>
                  <Shield className="h-5 w-5 text-gray-400" />
                </div>
              </CardHeader>
              <CardContent>
                <p className="text-sm text-gray-500 mb-3">{role.description}</p>
                <div className="flex items-center justify-between">
                  <span className="text-2xl font-bold">{role.userCount}</span>
                  <span className="text-sm text-gray-500">users</span>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Users List */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Users className="h-5 w-5" />
              All Users
            </CardTitle>
            <CardDescription>
              View and manage users across all organizations.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {/* Search */}
            <div className="relative mb-4">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Search users by name, email, role, or organization..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>

            {/* Users Table */}
            <div className="rounded-md border">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">User</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Role</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Organization</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Status</th>
                    <th className="px-4 py-3 text-right text-sm font-medium text-gray-500">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {filteredUsers.length === 0 ? (
                    <tr>
                      <td colSpan={5} className="px-4 py-8 text-center text-gray-500">
                        No users found. Try adjusting your search or send invites.
                      </td>
                    </tr>
                  ) : (
                    filteredUsers.map(user => (
                      <tr key={user.id} className="hover:bg-gray-50">
                        <td className="px-4 py-3">
                          <div className="flex items-center gap-3">
                            <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center">
                              <UserCircle className="h-6 w-6 text-blue-600" />
                            </div>
                            <div>
                              <p className="font-medium">{user.name}</p>
                              <p className="text-sm text-gray-500">{user.email}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-4 py-3">
                          {getRoleBadge(user.role)}
                        </td>
                        <td className="px-4 py-3">
                          {user.organization ? (
                            <div className="flex items-center gap-2 text-sm">
                              <Building2 className="h-4 w-4 text-gray-400" />
                              {user.organization}
                            </div>
                          ) : (
                            <span className="text-gray-400">—</span>
                          )}
                        </td>
                        <td className="px-4 py-3">
                          {getStatusBadge(user.status)}
                        </td>
                        <td className="px-4 py-3 text-right">
                          <Button variant="ghost" size="sm">
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { DashboardSidebar } from "@/components/Dashboard/DashboardSidebar";
import { DashboardNavbar } from "@/components/Dashboard/DashboardNavbar";
import { useAuth } from "@/context/AuthContext";
import ProtectedRoute from "@/components/ProtectedRoute";
import { Loader2 } from "lucide-react";
import { redirect } from "next/navigation";
import { DashboardProvider, useDashboard } from "@/context/DashboardContext";

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <ProtectedRoute>
      <DashboardProvider>
        <DashboardLayoutContent>{children}</DashboardLayoutContent>
      </DashboardProvider>
    </ProtectedRoute>
  );
}

import { usePathname, useRouter } from "next/navigation";
import { useState, useEffect } from "react";

function DashboardLayoutContent({ children }: { children: React.ReactNode }) {
  const { user, isLoading } = useAuth();
  const { isSidebarCollapsed, toggleSidebar, setMobileDrawerOpen } =
    useDashboard();
  const pathname = usePathname();
  const router = useRouter();
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  const allowedPaths = {
    SYSTEM_ADMIN: "/admin",
    PROPERTY_MANAGER: "/property-manager",
    TENANT: "/tenant",
    VENDOR: "/vendor",
    AGENT: "/agent",
  } as const;

  useEffect(() => {
    if (!isLoading && user && isMounted) {
      const expectedPath = allowedPaths[user.role as keyof typeof allowedPaths];
      if (expectedPath && !pathname.startsWith(expectedPath) && !pathname.startsWith('/account')) {
        router.push(expectedPath);
      }
    }
  }, [user, isLoading, isMounted, pathname, router]);

  // Prevent Hydration Mismatch
  if (!isMounted) {
    return null;
  }

  if (isLoading || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
          <p className="text-gray-600">Loading...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">

      {/* Sidebar with dark background */}
      <div className="bg-[#003b73] text-white">
        <DashboardSidebar
          user={user}
          isCollapsed={isSidebarCollapsed}
          toggleSidebar={toggleSidebar}
        />
      </div>

      {/* Main Content */}
      <div className="flex flex-col flex-1 overflow-hidden">
        {/* Navbar with dark background */}
        <header className="flex-shrink-0 z-10 bg-[#003b73] border-b border-[#002b5b] text-white">
          <DashboardNavbar
            toggleSidebar={() => setMobileDrawerOpen(true)}
          />
        </header>

        {/* Main area - fills the whole content, no margins */}
        <motion.main
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, ease: "easeOut" }}
          className="flex-1 overflow-y-auto bg-gray-50 m-0 p-0"
        >
          {children}
        </motion.main>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { FileText, Upload, Trash2 } from "lucide-react";
import { LeaseDocumentType } from "@prisma/client";
import { useParams } from "next/navigation";

interface LeaseDocument {
  id: string;
  leaseId: string;
  documentType: LeaseDocumentType;
  fileName: string;
  fileUrl: string;
  fileSize: number;
  mimeType: string;
  uploadedBy: string;
  description?: string;
  createdAt: string;
}

export default function DocumentsManager() {
  const { id: leaseId } = useParams(); // get leaseId from route
  const [documents, setDocuments] = useState<LeaseDocument[]>([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [documentType, setDocumentType] = useState<LeaseDocumentType>("OTHER");
  const [description, setDescription] = useState("");

  useEffect(() => {
    if (leaseId) fetchDocuments();
  }, [leaseId]);

  async function fetchDocuments() {
    try {
      setLoading(true);
      const res = await fetch(`/api/lease/${leaseId}/document`);
      if (!res.ok) throw new Error("Failed to fetch documents");
      const data: LeaseDocument[] = await res.json();
      setDocuments(data);
    } catch (err) {
      console.error("Fetch documents error:", err);
      setDocuments([]);
    } finally {
      setLoading(false);
    }
  }

  async function uploadDocument() {
    if (!file || !leaseId) return;
    try {
      setUploading(true);
      const formData = new FormData();
      formData.append("file", file);
      formData.append("documentType", documentType);
      formData.append("description", description);

      const res = await fetch(`/api/lease/${leaseId}/document`, {
        method: "POST",
        body: formData,
      });

      if (!res.ok) {
        const errorData = await res.json().catch(() => ({ error: "Upload failed" }));
        throw new Error(errorData.error);
      }

      const newDoc: LeaseDocument = await res.json();
      setDocuments([newDoc, ...documents]);
      setFile(null);
      setDescription("");
      setDocumentType("OTHER");
    } catch (err: any) {
      console.error("Document upload error:", err);
      alert(err.message || "Upload failed");
    } finally {
      setUploading(false);
    }
  }

  async function deleteDocument(docId: string) {
    if (!leaseId || !confirm("Are you sure you want to delete this document?")) return;
    try {
      const res = await fetch(`/api/lease/${leaseId}/document/${docId}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete document");
      setDocuments(documents.filter((d) => d.id !== docId));
    } catch (err) {
      console.error("Delete document error:", err);
      alert("Failed to delete document");
    }
  }

  if (loading) {
    return (
      <div className="flex justify-center items-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="bg-white p-6 rounded-xl shadow space-y-6">
      <h2 className="text-xl font-semibold flex items-center gap-2">
        <FileText className="w-6 h-6 text-blue-600" />
        Lease Documents
      </h2>

      {/* Upload Form */}
      <div className="p-4 border border-gray-200 rounded-lg bg-gray-50 space-y-3">
        <input type="file" onChange={(e) => setFile(e.target.files?.[0] || null)} className="block w-full" />
        <select
          className="w-full border border-gray-300 rounded px-3 py-2"
          value={documentType}
          onChange={(e) => setDocumentType(e.target.value as LeaseDocumentType)}
        >
          {Object.keys(LeaseDocumentType).map((type) => (
            <option key={type} value={type}>
              {type.replace(/_/g, " ")}
            </option>
          ))}
        </select>
        <textarea
          placeholder="Description (optional)"
          className="w-full border border-gray-300 rounded px-3 py-2"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
        />
        <button
          onClick={uploadDocument}
          disabled={!file || uploading}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center gap-2"
        >
          <Upload className="w-4 h-4" />
          {uploading ? "Uploading..." : "Upload Document"}
        </button>
      </div>

      {/* Documents List */}
      {documents.length === 0 ? (
        <div className="text-center py-12 text-gray-500">No documents uploaded yet</div>
      ) : (
        <div className="space-y-3">
          {documents.map((doc) => (
            <div key={doc.id} className="border border-gray-200 rounded p-4 flex justify-between items-center">
              <div>
                <p className="font-medium">{doc.fileName}</p>
                <p className="text-xs text-gray-500">
                  {doc.documentType.replace(/_/g, " ")} &middot; {(doc.fileSize / 1024).toFixed(2)} KB &middot; Uploaded on{" "}
                  {new Date(doc.createdAt).toLocaleDateString()}
                </p>
              </div>
              <div className="flex gap-2">
                <a href={doc.fileUrl} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline text-sm">
                  View
                </a>
                <button
                  onClick={() => deleteDocument(doc.id)}
                  className="text-red-600 hover:bg-red-50 p-1 rounded"
                  title="Delete"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

