                      }`}
                  >
                    <span className={`flex items-center gap-2 ${utility.key ? "text-slate-900 font-medium" : "text-slate-400"}`}>
                      <span>{utility.icon}</span>
                      {utility.label}
                    </span>
                    <span className={utility.key ? "text-emerald-600 font-bold" : "text-slate-300"}>
                      {utility.key ? "✓" : "○"}
                    </span>
                  </div>
                ))}
              </div>
            </div>

            {/* Late Fees */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <h3 className="text-lg font-bold text-slate-900 mb-4 flex items-center gap-2">
                <span className="text-2xl">⚠️</span>
                Late Fees
              </h3>
              <div className="space-y-3">
                {lease.lateFeeFlat !== null && (
                  <div className="p-3 bg-amber-50 rounded-lg border border-amber-200">
                    <p className="text-xs text-amber-600 mb-1">Flat Fee</p>
                    <p className="font-bold text-amber-900">${lease.lateFeeFlat.toLocaleString()}</p>
                  </div>
                )}
                {lease.lateFeeDaily !== null && (
                  <div className="p-3 bg-red-50 rounded-lg border border-red-200">
                    <p className="text-xs text-red-600 mb-1">Daily Fee</p>
                    <p className="font-bold text-red-900">${lease.lateFeeDaily.toLocaleString()}/day</p>
                  </div>
                )}
              </div>
            </div>

            {/* Termination */}
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <h3 className="text-lg font-bold text-slate-900 mb-4 flex items-center gap-2">
                <span className="text-2xl">🚫</span>
                Termination
              </h3>
              <div className="space-y-3">
                {lease.earlyTerminationFee !== null && (
                  <div className="p-3 bg-slate-50 rounded-lg">
                    <p className="text-xs text-slate-500 mb-1">Early Termination Fee</p>
                    <p className="font-bold text-slate-900">${lease.earlyTerminationFee.toLocaleString()}</p>
                  </div>
                )}
                {lease.terminationNoticeDays !== null && (
                  <div className="p-3 bg-slate-50 rounded-lg">
                    <p className="text-xs text-slate-500 mb-1">Notice Period</p>
                    <p className="font-bold text-slate-900">{lease.terminationNoticeDays} days</p>
                  </div>
                )}
                {lease.usageType && (
                  <div className="p-3 bg-slate-50 rounded-lg">
                    <p className="text-xs text-slate-500 mb-1">Usage Type</p>
                    <p className="font-bold text-slate-900">{lease.usageType}</p>
                  </div>
                )}
              </div>
            </div>

            {/* Metadata */}
            <div className="bg-slate-800 text-white rounded-2xl shadow-sm p-6">
              <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                <span className="text-2xl">📊</span>
                Metadata
              </h3>
              <div className="space-y-3 text-sm">
                <div className="pb-3 border-b border-slate-700">
                  <p className="text-slate-400 text-xs mb-1">Created</p>
                  <p className="font-mono">{new Date(lease.createdAt).toLocaleString()}</p>
                </div>
                <div className="pb-3 border-b border-slate-700">
                  <p className="text-slate-400 text-xs mb-1">Last Updated</p>
                  <p className="font-mono">{new Date(lease.updatedAt).toLocaleString()}</p>
                </div>
                <div>
                  <p className="text-slate-400 text-xs mb-1">Lease ID</p>
                  <p className="font-mono text-xs break-all">{lease.id}</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// app/property-manager/content/lease/[id]/renew/page.tsx
"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { Calendar, DollarSign, FileText, RefreshCw, Send } from "lucide-react";

interface Lease {
  id: string;
  startDate: string;
  endDate: string;
  rentAmount: number;
  leaseTerm: string;
  tenant?: { fullName: string; email: string };
  application?: { fullName: string; email: string };
  property: { name: string };
  unit: { unitNumber: string };
  renewalHistory: Array<{
    id: string;
    oldEndDate: string;
    newEndDate: string;
    oldRentAmount: number;
    newRentAmount: number;
    status: string;
    createdAt: string;
  }>;
}

export default function LeaseRenewalPage() {
  const { id } = useParams();
  const router = useRouter();
  const [lease, setLease] = useState<Lease | null>(null);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);

  const [renewalForm, setRenewalForm] = useState({
    renewalType: "MANUAL",
    newTermMonths: 12,
    newEndDate: "",
    rentIncrease: 0,
    rentIncreaseType: "PERCENTAGE", // PERCENTAGE or FIXED
    newRentAmount: 0,
    negotiationNotes: "",
  });

  useEffect(() => {
    fetchLease();
  }, [id]);

  async function fetchLease() {
    try {
      const res = await fetch(`/api/lease/${id}`);
      const data = await res.json();
      if (res.ok) {
        setLease(data);
        
        // Calculate default new end date
        const currentEnd = new Date(data.endDate);
        const newEnd = new Date(currentEnd);
        newEnd.setMonth(newEnd.getMonth() + 12);
        
        setRenewalForm({
          ...renewalForm,
          newEndDate: newEnd.toISOString().split("T")[0],
          newRentAmount: data.rentAmount,
        });
      }
    } catch (error) {
      console.error("Failed to fetch lease:", error);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (lease) {
      let newRent = lease.rentAmount;
      
      if (renewalForm.rentIncreaseType === "PERCENTAGE") {
        newRent = lease.rentAmount * (1 + renewalForm.rentIncrease / 100);
      } else {
        newRent = lease.rentAmount + renewalForm.rentIncrease;
      }
      
      setRenewalForm((prev) => ({ ...prev, newRentAmount: newRent }));
    }
  }, [renewalForm.rentIncrease, renewalForm.rentIncreaseType]);

  async function handleSubmitRenewal() {
    if (!lease) return;

    setSubmitting(true);
    try {
      const res = await fetch(`/api/lease/${lease.id}/renew`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(renewalForm),
      });

      const data = await res.json();

      if (res.ok) {
        alert("Renewal offer sent to tenant!");
        router.push(`/property-manager/content/lease/${lease.id}`);
      } else {
        alert(data.error || "Failed to initiate renewal");
      }
    } catch (error) {
      console.error("Renewal error:", error);
      alert("An error occurred");
    } finally {
      setSubmitting(false);
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading lease...</p>
        </div>
      </div>
    );
  }

  if (!lease) {
    return (
      <div className="max-w-4xl mx-auto p-6">
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <p className="text-red-800">Lease not found</p>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto p-6">
      {/* Header */}
      <div className="mb-6">
        <h1 className="text-3xl font-bold flex items-center gap-3">
          <RefreshCw className="w-8 h-8 text-blue-600" />
          Lease Renewal
        </h1>
        <p className="text-gray-600 mt-2">
          Create a renewal offer for {lease.tenant?.fullName || lease.application?.fullName}
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Current Lease Info */}
        <div className="bg-white rounded-xl shadow p-6">
          <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
            <FileText className="w-5 h-5 text-gray-600" />
            Current Lease Details
          </h2>

          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-500">Property</p>
              <p className="font-semibold">{lease.property.name}</p>
            </div>

            <div>
              <p className="text-sm text-gray-500">Unit</p>
              <p className="font-semibold">{lease.unit.unitNumber}</p>
            </div>

            <div>
              <p className="text-sm text-gray-500">Current Term</p>
              <p className="font-semibold">
                {new Date(lease.startDate).toLocaleDateString()} -{" "}
                {new Date(lease.endDate).toLocaleDateString()}
              </p>
            </div>

            <div>
              <p className="text-sm text-gray-500">Current Rent</p>
              <p className="text-2xl font-bold text-blue-600">
                ${lease.rentAmount.toLocaleString()}
              </p>
            </div>

            <div>
              <p className="text-sm text-gray-500">Tenant</p>
              <p className="font-semibold">
                {lease.tenant?.fullName || lease.application?.fullName}
              </p>
              <p className="text-sm text-gray-500">
                {lease.tenant?.email || lease.application?.email}
              </p>
            </div>
          </div>
        </div>

        {/* Renewal Form */}
        <div className="bg-white rounded-xl shadow p-6">
          <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
            <Calendar className="w-5 h-5 text-blue-600" />
            Renewal Terms
          </h2>

          <div className="space-y-4">
            {/* Renewal Type */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Renewal Type
              </label>
              <select
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={renewalForm.renewalType}
                onChange={(e) =>
                  setRenewalForm({ ...renewalForm, renewalType: e.target.value })
                }
              >
                <option value="MANUAL">Manual</option>
                <option value="AUTO">Automatic</option>
                <option value="RENEGOTIATED">Renegotiated</option>
              </select>
            </div>

            {/* New Term Length */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                New Term (months)
              </label>
              <input
                type="number"
                min="1"
                max="60"
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={renewalForm.newTermMonths}
                onChange={(e) => {
                  const months = parseInt(e.target.value);
                  const currentEnd = new Date(lease.endDate);
                  const newEnd = new Date(currentEnd);
                  newEnd.setMonth(newEnd.getMonth() + months);
                  
                  setRenewalForm({
                    ...renewalForm,
                    newTermMonths: months,
                    newEndDate: newEnd.toISOString().split("T")[0],
                  });
                }}
              />
            </div>

            {/* New End Date */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                New End Date
              </label>
              <input
                type="date"
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={renewalForm.newEndDate}
                onChange={(e) =>
                  setRenewalForm({ ...renewalForm, newEndDate: e.target.value })
                }
              />
            </div>

            {/* Rent Increase Type */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Rent Adjustment Type
              </label>
              <select
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={renewalForm.rentIncreaseType}
                onChange={(e) =>
                  setRenewalForm({
                    ...renewalForm,
                    rentIncreaseType: e.target.value,
                  })
                }
              >
                <option value="PERCENTAGE">Percentage Increase</option>
                <option value="FIXED">Fixed Amount Increase</option>
              </select>
            </div>

            {/* Rent Increase Amount */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Rent Increase{" "}
                {renewalForm.rentIncreaseType === "PERCENTAGE" ? "(%)" : "($)"}
              </label>
              <input
                type="number"
                step="0.01"
                min="0"
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={renewalForm.rentIncrease}
                onChange={(e) =>
                  setRenewalForm({
                    ...renewalForm,
                    rentIncrease: parseFloat(e.target.value),
                  })
                }
              />
            </div>

            {/* New Rent Amount (Calculated) */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
              <p className="text-sm text-gray-700 mb-1">New Monthly Rent</p>
              <p className="text-3xl font-bold text-blue-600">
                ${renewalForm.newRentAmount.toLocaleString()}
              </p>
              <p className="text-sm text-gray-500 mt-1">
                Increase of $
                {(renewalForm.newRentAmount - lease.rentAmount).toLocaleString()}
              </p>
            </div>

            {/* Notes */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Notes (optional)
              </label>
              <textarea
                rows={3}
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                placeholder="Additional terms or notes for this renewal..."
                value={renewalForm.negotiationNotes}
                onChange={(e) =>
                  setRenewalForm({
                    ...renewalForm,
                    negotiationNotes: e.target.value,
                  })
                }
              />
            </div>

            {/* Submit Button */}
            <button
              onClick={handleSubmitRenewal}
              disabled={submitting}
              className={`w-full py-3 rounded-lg font-semibold flex items-center justify-center gap-2 ${
                submitting
                  ? "bg-gray-400 cursor-not-allowed"
                  : "bg-blue-600 hover:bg-blue-700 text-white"
              }`}
            >
              <Send className="w-5 h-5" />
              {submitting ? "Sending..." : "Send Renewal Offer"}
            </button>
          </div>
        </div>
      </div>

      {/* Renewal History */}
      {lease.renewalHistory && lease.renewalHistory.length > 0 && (
        <div className="mt-6 bg-white rounded-xl shadow p-6">
          <h2 className="text-xl font-semibold mb-4">Renewal History</h2>
          <div className="space-y-3">
            {lease.renewalHistory.map((renewal) => (
              <div
                key={renewal.id}
                className="border border-gray-200 rounded-lg p-4"
              >
                <div className="flex justify-between items-start">
                  <div>
                    <p className="font-semibold text-gray-900">
                      {new Date(renewal.oldEndDate).toLocaleDateString()} →{" "}
                      {new Date(renewal.newEndDate).toLocaleDateString()}
                    </p>
                    <p className="text-sm text-gray-600 mt-1">
                      Rent: ${renewal.oldRentAmount} → ${renewal.newRentAmount}
                    </p>
                  </div>
                  <span
                    className={`px-3 py-1 rounded-full text-xs font-semibold ${
                      renewal.status === "EXECUTED"
                        ? "bg-navy-100 text-green-800"
                        : renewal.status === "PENDING"
                        ? "bg-yellow-100 text-yellow-800"
                        : "bg-gray-100 text-gray-800"
                    }`}
                  >
                    {renewal.status}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Back Button */}
      <div className="mt-6">
        <button
          onClick={() => router.back()}
          className="px-6 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300"
        >
          Back to Lease
        </button>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from "@/components/ui/select";
import { Toaster, toast } from "sonner";
import {
  ArrowLeft,
  Loader2,
  Calculator,
  AlertCircle,
  Zap,
  Building2,
  User,
  DollarSign,
  CheckCircle,
  TrendingUp,
} from "lucide-react";
import Link from "next/link";

interface LeaseUtility {
  id: string;
  Lease: {
    id: string;
    tenant?: { firstName?: string; lastName?: string; email?: string } | null;
    unit?: { number?: string; unitNumber?: string } | null;
    property?: { name?: string; address?: string } | null;
  };
  utility: { id: string; name: string; unitPrice: number | null; type: "FIXED" | "METERED" };
}

export default function NewMeterReadingPage() {
  const router = useRouter();
  const [leaseUtilities, setLeaseUtilities] = useState<LeaseUtility[]>([]);
  const [selectedLU, setSelectedLU] = useState<string>("");
  const [readingValue, setReadingValue] = useState<string>("");
  const [amount, setAmount] = useState<number | null>(null);
  const [isLoadingUtilities, setIsLoadingUtilities] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [readingsMap, setReadingsMap] = useState<{
    [leaseUtilityId: string]: { initial: number | null; previous: number | null };
  }>({});

  const [consumption, setConsumption] = useState<number | null>(null);

  useEffect(() => {
    loadLeaseUtilities();
  }, []);

  const loadLeaseUtilities = async () => {
    try {
      setIsLoadingUtilities(true);
      setError(null);
      const res = await fetch("/api/lease-utility");
      const data = await res.json();

      if (data.success) {
        const metered = (data.data || []).filter((lu: LeaseUtility) => lu.utility.type === "METERED");
        setLeaseUtilities(metered);
        if (metered.length === 0) {
          setError("No metered utilities found. Please assign metered utilities to leases first.");
        }
      } else {
        setError(data.error || "Failed to load utilities");
        toast.error("Failed to load utilities");
      }
    } catch (err) {
      setError("An error occurred while loading utilities");
      toast.error("Failed to load utilities");
    } finally {
      setIsLoadingUtilities(false);
    }
  };

  const selectedUtility = leaseUtilities.find((lu) => lu.id === selectedLU);
  const selectedReadings = readingsMap[selectedLU] || { initial: null, previous: null };
  const { initial: initialReading, previous: previousReading } = selectedReadings;

  // Fetch readings per lease utility
  useEffect(() => {
    const fetchReadings = async () => {
      if (!selectedLU) return;
      try {
        const res = await fetch(`/api/utility-readings?leaseUtilityId=${selectedLU}`);
        const data = await res.json();
        if (data.success) {
          const readings = (data.data || []).sort(
            (a: any, b: any) => new Date(a.readingDate).getTime() - new Date(b.readingDate).getTime()
          );

          const initial = readings.length ? readings[0].readingValue : null;
          const previous =
            readings.length > 1 ? readings[readings.length - 1].readingValue : readings[0]?.readingValue || 0;

          setReadingsMap((prev) => ({
            ...prev,
            [selectedLU]: { initial, previous },
          }));
        }
      } catch (err) {
        console.error(err);
      }
    };
    fetchReadings();
  }, [selectedLU]);

  // Calculate consumption
  useEffect(() => {
    const current = parseFloat(readingValue);
    if (!isNaN(current) && previousReading !== null) {
      const cons = current - previousReading;
      setConsumption(cons >= 0 ? cons : null);
    } else setConsumption(null);
  }, [readingValue, previousReading]);

  // Calculate amount
  useEffect(() => {
    if (selectedUtility && selectedUtility.utility.unitPrice && consumption !== null) {
      setAmount(consumption * selectedUtility.utility.unitPrice);
    } else {
      setAmount(null);
    }
  }, [selectedUtility, consumption]);

  const handleSubmit = async () => {
    if (!selectedLU) return toast.error("Please select a lease utility");
    const value = parseFloat(readingValue);
    if (!readingValue || isNaN(value) || value <= 0)
      return toast.error("Please enter a valid reading value greater than 0");
    if (previousReading !== null && value < previousReading)
      return toast.error("Current reading cannot be less than the previous reading");
    if (amount === null) return toast.error("Unable to calculate amount");

    setIsSubmitting(true);
    try {
      const res = await fetch("/api/utility-readings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          leaseUtilityId: selectedLU,
          readingValue: value,
          amount,
          readingDate: new Date().toISOString(),
        }),
      });
      const data = await res.json();
      if (data.success) {
        toast.success("Meter reading added successfully!");
        setTimeout(() => router.push("/property-manager/content/meter-readings"), 1000);
      } else {
        toast.error(data.error || "Failed to add reading");
        setIsSubmitting(false);
      }
    } catch (err) {
      toast.error("An error occurred while submitting the reading");
      setIsSubmitting(false);
    }
  };

  const formatCurrency = (value: number) =>
    new Intl.NumberFormat("en-US", { style: "currency", currency: "USD", minimumFractionDigits: 2 }).format(value);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-cyan-50">
      <Toaster position="top-right" richColors />

      {/* Header */}
      <div className="bg-gradient-to-r from-[#0b1f3a] via-[#15386a] to-[#0b1f3a] text-white shadow-2xl">
        <div className="max-w-6xl mx-auto px-6 py-8">
          <Link href="/property-manager/content/meter-readings">
            <Button variant="ghost" size="sm" className="text-white hover:bg-white/10 mb-6 transition-all">
              <ArrowLeft className="w-4 h-4 mr-2" /> Back to Readings
            </Button>
          </Link>
          <div className="flex items-center gap-6">
            <div className="bg-gradient-to-br from-[#30D5C8] to-[#28bfb3] p-4 rounded-2xl shadow-lg">
              <Zap className="w-10 h-10 text-[#0b1f3a]" />
            </div>
            <div>
              <h1 className="text-4xl font-bold mb-2">Add Meter Reading</h1>
              <p className="text-blue-200 text-lg">Record a new utility meter reading for accurate billing</p>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-6xl mx-auto px-6 py-10">
        {isLoadingUtilities ? (
          <Card className="border-none shadow-2xl">
            <CardContent className="flex items-center justify-center py-20">
              <div className="text-center">
                <Loader2 className="w-16 h-16 animate-spin text-[#30D5C8] mx-auto mb-6" />
                <span className="text-gray-600 text-xl font-medium">Loading utilities...</span>
              </div>
            </CardContent>
          </Card>
        ) : error ? (
          <Card className="border-none shadow-2xl overflow-hidden">
            <div className="bg-gradient-to-r from-red-50 to-orange-50 p-8">
              <CardContent className="flex flex-col items-center justify-center space-y-6">
                <div className="bg-white p-5 rounded-full shadow-lg">
                  <AlertCircle className="w-16 h-16 text-red-600" />
                </div>
                <div className="text-center max-w-lg">
                  <h3 className="text-2xl font-bold text-gray-900 mb-3">Unable to Load Utilities</h3>
                  <p className="text-gray-700 text-lg leading-relaxed">{error}</p>
                </div>
                <div className="flex gap-4 pt-4">
                  <Button onClick={loadLeaseUtilities} variant="outline" className="border-2 border-red-200 hover:bg-red-50 h-12 px-6">
                    <TrendingUp className="w-4 h-4 mr-2" /> Try Again
                  </Button>
                  <Link href="/property-manager/content/utilities">
                    <Button className="bg-[#0b1f3a] hover:bg-[#15386a] h-12 px-6">
                      <Zap className="w-4 h-4 mr-2" /> Go to Utilities
                    </Button>
                  </Link>
                </div>
              </CardContent>
            </div>
          </Card>
        ) : (
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
            {/* Main Form */}
            <div className="lg:col-span-3">
              <Card className="border-none shadow-2xl overflow-hidden">
                <CardHeader className="bg-gradient-to-r from-[#0b1f3a] to-[#15386a] text-white pb-8">
                  <CardTitle className="flex items-center gap-3 text-2xl">
                    <div className="bg-white/10 p-2 rounded-lg">
                      <Calculator className="w-7 h-7" />
                    </div>
                    New Meter Reading
                  </CardTitle>
                  <p className="text-blue-200 mt-2 text-sm">Complete the form to record usage</p>
                </CardHeader>
                <CardContent className="p-8 space-y-8">
                  {/* Lease Utility Selector */}
                  <div className="space-y-4">
                    <Label htmlFor="lease-utility" className="text-[#0b1f3a] font-bold text-lg flex items-center gap-2">
                      <div className="bg-[#30D5C8]/10 p-1.5 rounded">
                        <Zap className="w-5 h-5 text-[#30D5C8]" />
                      </div>
                      Select Lease Utility <span className="text-red-500">*</span>
                    </Label>
                    <Select value={selectedLU} onValueChange={(val) => { setSelectedLU(val); setReadingValue(""); }}>
                      <SelectTrigger
                        id="lease-utility"
                        className="h-14 border-2 border-gray-300 hover:border-[#30D5C8] focus:border-[#30D5C8] transition-colors text-base bg-white shadow-sm"
                      >
                        <SelectValue placeholder="Choose a metered utility assignment..." />
                      </SelectTrigger>
                      <SelectContent className="bg-white max-h-[400px] overflow-y-auto border-2 border-gray-200 shadow-xl">
                        {leaseUtilities.map((lu) => {
                          const tenant = lu.Lease?.tenant;
                          const property = lu.Lease?.property;
                          const unit = lu.Lease?.unit;
                          const tenantName =
                            tenant?.firstName || tenant?.lastName
                              ? `${tenant?.firstName ?? ""} ${tenant?.lastName ?? ""}`.trim()
                              : "Unknown Tenant";
                          return (
                            <SelectItem key={lu.id} value={lu.id} className="cursor-pointer hover:bg-blue-50 focus:bg-blue-50 border-b border-gray-100 last:border-0">
                              <div className="py-3 px-2">
                                <div className="font-bold text-[#0b1f3a] text-base mb-2 flex items-center gap-2">
                                  <Zap className="w-4 h-4 text-[#30D5C8]" />
                                  {lu.utility.name}
                                </div>
                                <div className="space-y-1.5 ml-6">
                                  <div className="flex items-center gap-2 text-sm text-gray-700">
                                    <User className="w-4 h-4 text-[#30D5C8]" />
                                    <span className="font-medium">{tenantName}</span>
                                  </div>
                                  <div className="flex items-center gap-2 text-sm text-gray-700">
                                    <Building2 className="w-4 h-4 text-[#30D5C8]" />
                                    <span>Unit: {unit?.unitNumber || unit?.number || "N/A"} • {property?.name || "N/A"}</span>
                                  </div>
                                  <div className="flex items-center gap-2 text-sm text-gray-700">
                                    <DollarSign className="w-4 h-4 text-emerald-500" />
                                    <span className="font-semibold text-emerald-600">
                                      {formatCurrency(lu.utility.unitPrice || 0)}/unit
                                    </span>
                                  </div>
                                </div>
                              </div>
                            </SelectItem>
                          );
                        })}
                      </SelectContent>
                    </Select>
                  </div>

                  {/* Initial, Previous & Consumption */}
                  {selectedLU && (
                    <div className="bg-blue-50 border-2 border-blue-200 rounded-xl p-4 shadow-sm space-y-2">
                      <p className="text-sm text-gray-600">Initial Reading: <span className="font-bold">{initialReading ?? "—"}</span> units</p>
                      <p className="text-sm text-gray-600">Previous Reading: <span className="font-bold">{previousReading ?? "—"}</span> units</p>
                      <p className="text-sm text-gray-600">Consumption: <span className="font-bold">{consumption ?? "—"}</span> units</p>
                    </div>
                  )}

                  {/* Reading Input */}
                  <div className="space-y-4">
                    <Label htmlFor="reading-value" className="text-[#0b1f3a] font-bold text-lg flex items-center gap-2">
                      <div className="bg-[#30D5C8]/10 p-1.5 rounded">
                        <TrendingUp className="w-5 h-5 text-[#30D5C8]" />
                      </div>
                      Reading Value (units) <span className="text-red-500">*</span>
                    </Label>
                    <Input
                      id="reading-value"
                      type="number"
                      step="0.01"
                      min={previousReading || 0}
                      value={readingValue}
                      onChange={(e) => setReadingValue(e.target.value)}
                      placeholder="Enter meter reading (e.g., 45.6)"
                      disabled={isSubmitting}
                      className="h-14 border-2 border-gray-300 hover:border-[#30D5C8] focus:border-[#30D5C8] transition-colors text-lg bg-white shadow-sm"
                      required
                    />
                  </div>

                  {/* Actions */}
                  <div className="flex gap-4 pt-6 border-t-2 border-gray-100">
                    <Button
                      onClick={handleSubmit}
                      disabled={isSubmitting || !selectedLU || !readingValue}
                      className="flex-1 h-14 bg-gradient-to-r from-[#30D5C8] to-[#28bfb3] hover:from-[#28bfb3] hover:to-[#30D5C8] text-[#0b1f3a] font-bold text-lg shadow-lg hover:shadow-xl transition-all"
                    >
                      {isSubmitting ? (
                        <>
                          <Loader2 className="w-5 h-5 mr-2 animate-spin" />
                          Submitting...
                        </>
                      ) : (
                        <>
                          <CheckCircle className="w-5 h-5 mr-2" />
                          Submit Reading
                        </>
                      )}
                    </Button>
                    <Link href="/property-manager/content/meter-readings" className="flex-1">
                      <Button
                        type="button"
                        variant="outline"
                        className="w-full h-14 border-2 hover:bg-gray-50 font-semibold text-base"
                        disabled={isSubmitting}
                      >
                        Cancel
                      </Button>
                    </Link>
                  </div>
                </CardContent>
              </Card>
            </div>

            {/* Sidebar with live calculation */}
            <div className="lg:col-span-2">
              <div className="sticky top-6">
                <Card className="border-none shadow-2xl overflow-hidden">
                  <div className="bg-gradient-to-br from-[#30D5C8] via-[#28bfb3] to-[#30D5C8] text-white">
                    <CardHeader className="pb-6">
                      <CardTitle className="flex items-center gap-3 text-white text-xl">
                        <Calculator className="w-6 h-6" />
                        Live Calculation
                      </CardTitle>
                      <p className="text-white/80 text-sm">Your reading breakdown</p>
                    </CardHeader>
                    <CardContent className="pb-8">
                      {selectedLU && readingValue ? (
                        <div className="space-y-4">
                          <div className="bg-white/95 backdrop-blur-sm rounded-xl p-5 shadow-lg">
                            <p className="text-sm text-gray-600 font-medium mb-2">Current Reading</p>
                            <p className="text-3xl font-bold text-[#0b1f3a] flex items-baseline gap-2">
                              {readingValue} <span className="text-base font-normal text-gray-600">units</span>
                            </p>
                          </div>

                          {selectedUtility && (
                            <div className="bg-white/95 backdrop-blur-sm rounded-xl p-5 shadow-lg">
                              <p className="text-sm text-gray-600 font-medium mb-2">Unit Price</p>
                              <p className="text-2xl font-bold text-[#0b1f3a]">
                                {formatCurrency(selectedUtility.utility.unitPrice || 0)}
                              </p>
                              <p className="text-xs text-gray-500 mt-1">per unit</p>
                            </div>
                          )}

                          <div className="bg-white/95 backdrop-blur-sm rounded-xl p-5 shadow-lg">
                            <p className="text-sm text-gray-600 font-medium mb-2">Consumption</p>
                            <p className="text-3xl font-bold text-[#0b1f3a]">{consumption !== null ? consumption : "—"} units</p>
                          </div>

                          <div className="relative">
                            <div className="absolute inset-0 bg-gradient-to-r from-emerald-400 to-green-400 rounded-xl blur-xl opacity-50"></div>
                            <div className="relative bg-white rounded-xl p-6 shadow-2xl border-2 border-emerald-200">
                              <div className="flex items-center gap-2 mb-3">
                                <DollarSign className="w-5 h-5 text-emerald-600" />
                                <p className="text-sm font-bold text-emerald-900 uppercase tracking-wide">Total Amount</p>
                              </div>
                              <p className="text-4xl font-bold text-emerald-600 mb-2">
                                {amount ? formatCurrency(amount) : "—"}
                              </p>
                              {amount && selectedUtility && (
                                <div className="bg-emerald-50 rounded-lg p-3 mt-3">
                                  <p className="text-xs text-emerald-800 font-medium">
                                    {consumption} units × {formatCurrency(selectedUtility.utility.unitPrice || 0)}
                                  </p>
                                </div>
                              )}
                            </div>
                          </div>
                        </div>
                      ) : (
                        <div className="text-center py-12">
                          <div className="bg-white/20 backdrop-blur-sm rounded-full w-20 h-20 flex items-center justify-center mx-auto mb-6 shadow-lg">
                            <Calculator className="w-10 h-10" />
                          </div>
                          <p className="text-white/90 leading-relaxed px-4">
                            Select a utility and enter a reading value to see the calculated amount
                          </p>
                        </div>
                      )}
                    </CardContent>
                  </div>
                </Card>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { toast } from "react-hot-toast";
import { Button } from "@/components/ui/button";
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "@/components/ui/dropdown-menu";
import { Input } from "@mui/material";

interface Property {
  id: string;
  city: string;
  address: string;
}

interface Unit {
  id: string;
  unitNumber: string;
  unitName: string | null;
}

interface Tenant {
  id: string;
  firstName?: string;
  lastName?: string;
  email?: string;
}

interface Lease {
  id: string;
  property: Property;
  unit: Unit;
  tenant: Tenant;
}

interface Invoice {
  id: string;
  Lease: Lease;
  amount: number;
  dueDate: string;
  status: "PENDING" | "PAID" | "OVERDUE";
  type: string;
  payment?: Payment[];
}

interface Payment {
  id: string;
  amount: number;
  method: string;
  paidOn: string;
  reference?: string;
  invoice: Invoice;
  isReversed?: boolean;
  postingStatus: "PENDING" | "POSTED" | "FAILED";
}

interface FullReceipt {
  id: string;
  receiptNo: string;
  issuedOn: string;
  paymentId: string;
  invoiceId: string;
  payment: {
    id: string;
    amount: number;
    method: string;
    paidOn: string;
    reference?: string;
    invoice: Invoice;
  };
}

export default function PaymentsPage() {
  const [payments, setPayments] = useState<Payment[]>([]);
  const [loading, setLoading] = useState(false);
  const [properties, setProperties] = useState<Property[]>([]);
  const [units, setUnits] = useState<Unit[]>([]);
  const [selectedProperty, setSelectedProperty] = useState<string>("");
  const [selectedUnit, setSelectedUnit] = useState<string>("");
  const [generatingReceipt, setGeneratingReceipt] = useState<string | null>(null);
  const [viewingReceipt, setViewingReceipt] = useState<FullReceipt | null>(null);

  // Helper function to safely get tenant name from invoice
  const getTenantName = (invoice: Invoice): string => {
    if (!invoice?.Lease?.tenant) return 'Unknown Tenant';
    const firstName = invoice.Lease.tenant.firstName ?? '';
    const lastName = invoice.Lease.tenant.lastName ?? '';
    const name = `${firstName} ${lastName}`.trim();
    return name || invoice.Lease.tenant.email || 'Unknown Tenant';
  };

  // Helper function to safely get tenant info from payment
  const getTenantInfo = (payment: Payment) => {
    const tenant = payment?.invoice?.Lease?.tenant;
    if (!tenant) return { firstName: '', lastName: '', email: '', fullName: 'Unknown Tenant' };
    const firstName = tenant.firstName ?? '';
    const lastName = tenant.lastName ?? '';
    const fullName = `${firstName} ${lastName}`.trim() || tenant.email || 'Unknown Tenant';
    return { firstName, lastName, email: tenant.email || '', fullName };
  };

  // Recording payment modal
  const [showRecordPaymentModal, setShowRecordPaymentModal] = useState(false);
  const [pendingInvoices, setPendingInvoices] = useState<Invoice[]>([]);
  const [filteredInvoices, setFilteredInvoices] = useState<Invoice[]>([]);
  const [selectedInvoice, setSelectedInvoice] = useState<string>("");
  const [paymentAmount, setPaymentAmount] = useState<string>("");
  const [paymentMethod, setPaymentMethod] = useState<"CASH" | "CREDIT_CARD">("CASH");
  const [paymentReference, setPaymentReference] = useState("");

  // Modal filters
  const [modalPropertyFilter, setModalPropertyFilter] = useState<string>("");
  const [modalUnitFilter, setModalUnitFilter] = useState<string>("");
  const [modalUnits, setModalUnits] = useState<Unit[]>([]);

  // Payment reversal state
  const [showReverseModal, setShowReverseModal] = useState(false);
  const [paymentToReverse, setPaymentToReverse] = useState<Payment | null>(null);
  const [reversalReason, setReversalReason] = useState("");

  // Memoized fetch functions to prevent infinite loops
  const fetchPayments = useCallback(async () => {
    setLoading(true);
    try {
      const queryParams = new URLSearchParams();
      if (selectedProperty) queryParams.append("propertyId", selectedProperty);
      if (selectedUnit) queryParams.append("unitNumber", selectedUnit);

      const res = await fetch(`/api/payments?${queryParams.toString()}`);
      if (!res.ok) throw new Error("Failed to fetch payments");

      const data: Payment[] = await res.json();
      setPayments(data);
    } catch (error) {
      console.error(error);
      toast.error("Failed to fetch payments");
    } finally {
      setLoading(false);
    }
  }, [selectedProperty, selectedUnit]);

  const fetchProperties = useCallback(async () => {
    try {
      const res = await fetch("/api/propertymanager");
      if (!res.ok) throw new Error("Failed to fetch properties");
      const data: Property[] = await res.json();
      setProperties(data);
    } catch (error) {
      console.error(error);
      toast.error("Failed to load properties");
    }
  }, []);

  const fetchUnits = useCallback(async (propertyId: string) => {
    try {
      const res = await fetch(`/api/units?propertyId=${propertyId}`);
      if (!res.ok) throw new Error("Failed to fetch units");
      const data: Unit[] = await res.json();
      setUnits(data);
    } catch (error) {
      console.error(error);
      toast.error("Failed to load units");
    }
  }, []);

  const fetchPendingInvoices = useCallback(async () => {
    try {
      const res = await fetch("/api/invoices?status=PENDING,OVERDUE");
      if (!res.ok) throw new Error("Failed to fetch invoices");
      const data = await res.json();
      
      // Handle both grouped and flat response formats
      let invoiceList: Invoice[] = [];
      if (data.invoices && Array.isArray(data.invoices)) {
        // New format with separate invoices array
        invoiceList = data.invoices;
      } else if (Array.isArray(data)) {
        // Old flat format
        invoiceList = data;
      }
      
      setPendingInvoices(invoiceList);
      setFilteredInvoices(invoiceList);
    } catch (error) {
      console.error(error);
      toast.error("Failed to load pending invoices");
    }
  }, []);

  const fetchUnitsForModal = useCallback(async (propertyId: string) => {
    try {
      const res = await fetch(`/api/units?propertyId=${propertyId}`);
      if (!res.ok) throw new Error("Failed to fetch units");
      const data: Unit[] = await res.json();
      setModalUnits(data);
    } catch (error) {
      console.error(error);
      toast.error("Failed to load units");
    }
  }, []);

  // Initial data fetch
  useEffect(() => {
    fetchPayments();
    fetchProperties();
  }, [fetchPayments, fetchProperties]);

  // Handle property/unit filter changes
  useEffect(() => {
    if (selectedProperty) {
      fetchUnits(selectedProperty);
    } else {
      setUnits([]);
    }
  }, [selectedProperty, fetchUnits]);

  // Fetch payments when filters change
  useEffect(() => {
    fetchPayments();
  }, [fetchPayments]);

  // Filter invoices when modal filters change
  useEffect(() => {
    let filtered = pendingInvoices;

    if (modalPropertyFilter) {
      filtered = filtered.filter(inv => inv.Lease.property.id === modalPropertyFilter);
    }

    if (modalUnitFilter) {
      filtered = filtered.filter(inv => inv.Lease.unit.unitNumber === modalUnitFilter);
    }

    setFilteredInvoices(filtered);
  }, [modalPropertyFilter, modalUnitFilter, pendingInvoices]);

  // Fetch units for modal property filter
  useEffect(() => {
    if (modalPropertyFilter) {
      fetchUnitsForModal(modalPropertyFilter);
    } else {
      setModalUnits([]);
      setModalUnitFilter("");
    }
  }, [modalPropertyFilter, fetchUnitsForModal]);

  function openRecordPaymentModal() {
    setShowRecordPaymentModal(true);
    fetchPendingInvoices();
  }

  function closeRecordPaymentModal() {
    setShowRecordPaymentModal(false);
    setSelectedInvoice("");
    setPaymentAmount("");
    setPaymentMethod("CASH");
    setPaymentReference("");
    setModalPropertyFilter("");
    setModalUnitFilter("");
    setModalUnits([]);
  }

  async function recordPayment() {
    if (!selectedInvoice) return toast.error("Please select an invoice");

    const amount = parseFloat(paymentAmount);
    if (isNaN(amount) || amount <= 0) return toast.error("Please enter a valid amount");

    const invoice = filteredInvoices.find(inv => inv.id === selectedInvoice) ||
      pendingInvoices.find(inv => inv.id === selectedInvoice);
    if (!invoice) return toast.error("Invoice not found");

    const validPayments = invoice.payment?.filter(p => !p.isReversed) || [];
    const paidAmount = validPayments.reduce((sum, p) => sum + p.amount, 0);
    const remaining = invoice.amount - paidAmount;

    if (paymentMethod === "CREDIT_CARD" && Math.abs(amount - remaining) > 0.01) {
      return toast.error(`Credit card payments must be for the full remaining balance of USD ${remaining.toFixed(2)}`);
    }

    if (paymentMethod === "CASH" && amount > remaining) {
      return toast.error(`Payment amount cannot exceed remaining balance of USD ${remaining.toFixed(2)}`);
    }

    try {
      const res = await fetch(`/api/invoices/${selectedInvoice}/payments`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          amount,
          method: paymentMethod,
          reference: paymentReference || undefined,
        }),
      });

      const data = await res.json();
      if (res.ok) {
        const isPaidInFull = data.status === "PAID";
        if (isPaidInFull) {
          toast.success(`Payment recorded successfully! Invoice is now fully paid.`);
        } else {
          toast.success(`Partial payment of USD ${amount.toFixed(2)} recorded. Remaining: USD ${data.remaining.toFixed(2)}`);
        }
        closeRecordPaymentModal();
        await fetchPayments();
        await fetchPendingInvoices();
      } else {
        toast.error(data.error || "Failed to record payment");
      }
    } catch (err) {
      console.error(err);
      toast.error("Failed to record payment");
    }
  }

  function openReverseModal(payment: Payment) {
    setPaymentToReverse(payment);
    setShowReverseModal(true);
  }

  function closeReverseModal() {
    setPaymentToReverse(null);
    setShowReverseModal(false);
    setReversalReason("");
  }

  async function reversePayment() {
    if (!paymentToReverse) return;

    if (!reversalReason) {
      toast.error("Please provide a reason for reversal");
      return;
    }

    try {
      const res = await fetch(`/api/payments/${paymentToReverse.id}/reversal`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ reason: reversalReason }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Failed to reverse payment");

      toast.success("Payment reversed successfully!");

      // Close modal and refresh data
      closeReverseModal();
      await fetchPayments(); // This will refresh the payments list

    } catch (err) {
      console.error(err);
      const errorMessage = err instanceof Error ? err.message : "Failed to reverse payment";
      toast.error(errorMessage);
    }
  }

  async function generateReceipt(paymentId: string) {
    setGeneratingReceipt(paymentId);
    try {
      const res = await fetch(`/api/receipt/generate`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ paymentId }),
      });

      if (!res.ok) throw new Error("Failed to generate receipt");

      const receipt = await res.json();
      toast.success(`Receipt ${receipt.receiptNo} generated successfully!`);

      viewReceipt(receipt.id);
    } catch (error) {
      console.error(error);
      toast.error("Failed to generate receipt");
    } finally {
      setGeneratingReceipt(null);
    }
  }

  async function viewReceipt(receiptId: string) {
    try {
      const res = await fetch(`/api/receipt/${receiptId}`);
      if (!res.ok) throw new Error("Receipt not found");

      const receipt: FullReceipt = await res.json();
      setViewingReceipt(receipt);
    } catch (error) {
      console.error(error);
      toast.error("Failed to fetch receipt");
    }
  }

  function printReceipt() {
    window.print();
  }

  async function downloadReceipt() {
    if (!viewingReceipt) return;

    try {
      const html2canvas = (await import('html2canvas')).default;
      const { jsPDF } = await import('jspdf');

      const element = document.getElementById('receipt-content');
      if (!element) return toast.error('Receipt content not found');

      const container = document.createElement('div');
      container.style.position = 'absolute';
      container.style.top = '-9999px';
      container.style.left = '-9999px';
      container.style.width = '800px';
      container.style.background = 'white';
      document.body.appendChild(container);

      const cloned = element.cloneNode(true) as HTMLElement;
      cloned.style.transform = 'scale(1)';
      cloned.style.opacity = '1';
      container.appendChild(cloned);

      const allElements = cloned.querySelectorAll<HTMLElement>('*');
      allElements.forEach(el => {
        const styles = window.getComputedStyle(el);
        ['backgroundColor', 'color', 'borderColor'].forEach(prop => {
          const value = styles.getPropertyValue(prop);
          if (value.includes('oklch')) {
            el.style.setProperty(prop, '#ffffff', 'important');
          }
        });
      });

      toast.loading('Generating PDF...');

      const canvas = await html2canvas(cloned, {
        scale: 2,
        useCORS: true,
        backgroundColor: '#ffffff',
      });

      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pageWidth = pdf.internal.pageSize.getWidth();
      const imgProps = pdf.getImageProperties(imgData);
      const pdfHeight = (imgProps.height * pageWidth) / imgProps.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pageWidth, pdfHeight);
      pdf.save(`Receipt_${viewingReceipt.receiptNo}.pdf`);

      toast.dismiss();
      toast.success('Receipt downloaded successfully!');

      document.body.removeChild(container);
    } catch (error) {
      console.error('PDF generation error:', error);
      toast.dismiss();
      toast.error('Failed to download receipt');
    }
  }

  // Filter out reversed payments for calculations
  const validPay = payments.filter(p => !p.isReversed);
  const totalAmount = validPay.reduce((sum, p) => sum + p.amount, 0);
  const paymentMethods = {
    CASH: validPay.filter(p => p.method === "CASH").length,
    CREDIT_CARD: validPay.filter(p => p.method === "CREDIT_CARD").length,
  };

  const selectedInvoiceData = filteredInvoices.find(inv => inv.id === selectedInvoice);
  const validPayments = selectedInvoiceData?.payment?.filter(p => !p.isReversed) || [];
  const paidSoFar = validPayments.reduce((sum, p) => sum + p.amount, 0);
  const remainingBalance = selectedInvoiceData ? selectedInvoiceData.amount - paidSoFar : 0;

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-8 flex items-center justify-between">
          <div>
            <h1 className="text-4xl font-bold text-slate-800 mb-2">Payment Records</h1>
            <p className="text-slate-600">Track and manage all rental payments</p>
          </div>
          <Button
            onClick={openRecordPaymentModal}
            className="bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white font-semibold px-6 py-3 shadow-lg"
          >
            <svg className="w-5 h-5 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            Record Payment
          </Button>
        </div>

        {/* Record Payment Modal */}
        {showRecordPaymentModal && (
          <div className="fixed inset-0  bg-opacity-50 flex items-start justify-center z-50 p-4 overflow-auto">
            <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full transform transition-all my-8">
              <div className="bg-gradient-to-r from-blue-600 to-blue-700 px-6 py-5 rounded-t-2xl">
                <div className="flex items-center justify-between">
                  <h2 className="text-xl font-bold text-white">Record Payment</h2>
                  <button
                    onClick={closeRecordPaymentModal}
                    className="text-white hover:bg-white hover:bg-opacity-20 rounded-full p-1 transition-colors"
                  >
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              </div>

              <div className="px-6 py-6">
                <div className="space-y-5">
                  {/* Filter Section */}
                  <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                    <h4 className="text-sm font-semibold text-blue-900 mb-3 flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
                      </svg>
                      Filter Invoices
                    </h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                      <div>
                        <label className="block text-xs font-medium text-blue-900 mb-1.5">Property</label>
                        <select
                          value={modalPropertyFilter}
                          onChange={(e) => setModalPropertyFilter(e.target.value)}
                          className="w-full border border-blue-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white"
                        >
                          <option value="">All Properties</option>
                          {properties.map((p) => (
                            <option key={p.id} value={p.id}>{p.city} - {p.address}</option>
                          ))}
                        </select>
                      </div>
                      <div>
                        <label className="block text-xs font-medium text-blue-900 mb-1.5">Unit</label>
                        <select
                          value={modalUnitFilter}
                          onChange={(e) => setModalUnitFilter(e.target.value)}
                          disabled={!modalPropertyFilter}
                          className="w-full border border-blue-300 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white disabled:bg-blue-100 disabled:cursor-not-allowed"
                        >
                          <option value="">All Units</option>
                          {modalUnits.map((u) => (
                            <option key={u.id} value={u.unitNumber}>
                              {u.unitNumber} {u.unitName ? `- ${u.unitName}` : ""}
                            </option>
                          ))}
                        </select>
                      </div>
                    </div>
                    {(modalPropertyFilter || modalUnitFilter) && (
                      <div className="mt-3 flex items-center justify-between text-xs">
                        <span className="text-blue-700">
                          Showing {filteredInvoices.length} of {pendingInvoices.length} invoices
                        </span>
                        <button
                          onClick={() => {
                            setModalPropertyFilter("");
                            setModalUnitFilter("");
                          }}
                          className="text-blue-600 hover:text-blue-800 font-medium"
                        >
                          Clear filters
                        </button>
                      </div>
                    )}
                  </div>

                  {/* Select Invoice */}
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Select Invoice *</label>
                    <select
                      value={selectedInvoice}
                      onChange={(e) => {
                        setSelectedInvoice(e.target.value);
                        setPaymentAmount("");
                      }}
                      className="w-full border border-slate-300 rounded-lg px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white"
                    >
                      <option value="">Choose an invoice...</option>
                      {filteredInvoices.map((inv) => {
                        const validPayments = inv.payment?.filter(p => !p.isReversed) || [];
                        const paid = validPayments.reduce((sum, p) => sum + p.amount, 0);
                        const remaining = inv.amount - paid;
                        const tenantFirstName = inv.Lease.tenant?.firstName ?? '';
                        const tenantLastName = inv.Lease.tenant?.lastName ?? '';
                        const tenantName = tenantFirstName || tenantLastName ? `${tenantFirstName} ${tenantLastName}`.trim() : 'Unknown';
                        return (
                          <option key={inv.id} value={inv.id}>
                            #{inv.id.slice(0, 8)} - {inv.type} - {inv.Lease.property.city} Unit {inv.Lease.unit.unitNumber} - Tenant: {tenantName} - USD {remaining.toFixed(2)} remaining
                          </option>
                        );
                      })}
                    </select>
                    {filteredInvoices.length === 0 && (
                      <p className="text-xs text-amber-600 mt-1">
                        No pending invoices found with current filters. Try adjusting your filters.
                      </p>
                    )}
                  </div>

                  {/* Show invoice details when selected */}
                  {selectedInvoiceData && (
                    <div className="bg-slate-50 rounded-lg p-4 space-y-2">
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-600">Invoice Amount:</span>
                        <span className="font-semibold">USD {selectedInvoiceData.amount.toFixed(2)}</span>
                      </div>
                      <div className="flex justify-between text-sm">
                        <span className="text-slate-600">Already Paid:</span>
                        <span className="font-semibold text-emerald-600">USD {paidSoFar.toFixed(2)}</span>
                      </div>
                      <div className="flex justify-between text-sm pt-2 border-t border-slate-200">
                        <span className="text-slate-700 font-medium">Remaining Balance:</span>
                        <span className="font-bold text-blue-600 text-lg">USD {remainingBalance.toFixed(2)}</span>
                      </div>
                    </div>
                  )}

                  {/* Payment Method */}
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">Payment Method *</label>
                    <select
                      value={paymentMethod}
                      onChange={(e) => {
                        setPaymentMethod(e.target.value as "CASH" | "CREDIT_CARD");
                        if (e.target.value === "CREDIT_CARD" && selectedInvoiceData) {
                          setPaymentAmount(remainingBalance.toString());
                        }
                      }}
                      className="w-full border border-slate-300 rounded-lg px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-white"
                    >
                      <option value="CASH">💵 Cash</option>
                      <option value="CREDIT_CARD">💳 Credit Card</option>
                    </select>
                  </div>

                  {/* Payment Amount */}
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">
                      Payment Amount *
                      {paymentMethod === "CREDIT_CARD" && (
                        <span className="text-xs font-normal text-slate-500 ml-2">(Must be full balance)</span>
                      )}
                      {paymentMethod === "CASH" && (
                        <span className="text-xs font-normal text-slate-500 ml-2">(Partial payments allowed)</span>
                      )}
                    </label>
                    <div className="relative">
                      <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600 font-medium">USD</span>
                      <input
                        type="number"
                        step="0.01"
                        min="0"
                        max={remainingBalance}
                        value={paymentAmount}
                        onChange={(e) => setPaymentAmount(e.target.value)}
                        readOnly={paymentMethod === "CREDIT_CARD"}
                        placeholder="0.00"
                        className="w-full border border-slate-300 rounded-lg pl-16 pr-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 disabled:bg-slate-100"
                      />
                    </div>
                    {paymentMethod === "CASH" && remainingBalance > 0 && (
                      <button
                        type="button"
                        onClick={() => setPaymentAmount(remainingBalance.toString())}
                        className="text-xs text-blue-600 hover:text-blue-700 mt-1 font-medium"
                      >
                        Use full remaining balance (USD {remainingBalance.toFixed(2)})
                      </button>
                    )}
                  </div>

                  {/* Reference */}
                  <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">
                      Reference Number
                      <span className="text-xs font-normal text-slate-500 ml-2">(Optional)</span>
                    </label>
                    <input
                      type="text"
                      value={paymentReference}
                      onChange={(e) => setPaymentReference(e.target.value)}
                      placeholder="e.g., Receipt number, transaction ID"
                      className="w-full border border-slate-300 rounded-lg px-4 py-3 text-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    />
                  </div>

                  {/* Info message */}
                  <div className={`rounded-lg p-4 ${paymentMethod === "CASH"
                    ? "bg-amber-50 border border-amber-200"
                    : "bg-blue-50 border border-blue-200"
                    }`}>
                    <div className="flex gap-3">
                      <svg className={`w-5 h-5 flex-shrink-0 mt-0.5 ${paymentMethod === "CASH" ? "text-amber-600" : "text-blue-600"
                        }`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                      </svg>
                      <div className={`text-sm ${paymentMethod === "CASH" ? "text-amber-800" : "text-blue-800"
                        }`}>
                        {paymentMethod === "CASH" ? (
                          <>
                            <p className="font-semibold mb-1">Cash Payment</p>
                            <p>You can record partial payments. The invoice will remain open until fully paid.</p>
                          </>
                        ) : (
                          <>
                            <p className="font-semibold mb-1">Credit Card Payment</p>
                            <p>Credit card payments must be for the full remaining balance.</p>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div className="px-6 py-4 bg-slate-50 rounded-b-2xl flex gap-3">
                <Button
                  onClick={closeRecordPaymentModal}
                  variant="outline"
                  className="flex-1 py-3 border-2 border-slate-300 hover:bg-slate-100"
                >
                  Cancel
                </Button>
                <Button
                  onClick={recordPayment}
                  className="flex-1 py-3 bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white font-semibold shadow-lg"
                >
                  Record Payment
                </Button>
              </div>
            </div>
          </div>
        )}

        {/* Receipt Modal */}
        {viewingReceipt && (
          <div className="fixed inset-0  bg-opacity-50 flex items-start justify-center z-50 p-4 overflow-auto">
            <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full relative overflow-visible my-8">
              <div className="flex items-center justify-between px-6 py-4 border-b border-slate-200">
                <h2 className="text-xl font-bold text-slate-800">Receipt Details</h2>
                <div className="flex gap-2">
                  <button
                    onClick={downloadReceipt}
                    className="px-4 py-2 bg-emerald-600 text-white rounded-lg hover:bg-emerald-700 transition-colors text-sm font-medium flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Download PDF
                  </button>
                  <button
                    onClick={printReceipt}
                    className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm font-medium flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
                    </svg>
                    Print
                  </button>
                  <button
                    onClick={() => setViewingReceipt(null)}
                    className="px-4 py-2 bg-slate-100 text-slate-700 rounded-lg hover:bg-slate-200 transition-colors text-sm font-medium"
                  >
                    Close
                  </button>
                </div>
              </div>

              <div className="p-8" id="receipt-content">
                {/* Use inline styles for PDF generation - these render properly in PDFs */}
                <div style={{
                  width: '100%',
                  maxWidth: '800px',
                  margin: '0 auto',
                  backgroundColor: 'white',
                  fontFamily: 'Arial, sans-serif',
                  color: '#1a1a1a'
                }}>
                  {/* Header Section */}
                  <div style={{
                    textAlign: 'center',
                    borderBottom: '3px solid #2563eb',
                    paddingBottom: '20px',
                    marginBottom: '30px'
                  }}>
                    <div style={{
                      fontSize: '32px',
                      fontWeight: 'bold',
                      color: '#2563eb',
                      marginBottom: '8px',
                      letterSpacing: '1px'
                    }}>
                      PAYMENT RECEIPT
                    </div>
                    <div style={{
                      fontSize: '14px',
                      color: '#64748b',
                      marginTop: '8px'
                    }}>
                      Official Payment Confirmation
                    </div>
                  </div>

                  {/* Receipt Number & Date */}
                  <div style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    marginBottom: '30px',
                    padding: '15px',
                    backgroundColor: '#f8fafc',
                    borderRadius: '8px'
                  }}>
                    <div>
                      <div style={{ fontSize: '12px', color: '#64748b', marginBottom: '4px' }}>
                        Receipt No.
                      </div>
                      <div style={{ fontSize: '20px', fontWeight: 'bold', color: '#1e293b' }}>
                        {viewingReceipt.receiptNo}
                      </div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      <div style={{ fontSize: '12px', color: '#64748b', marginBottom: '4px' }}>
                        Issue Date
                      </div>
                      <div style={{ fontSize: '16px', fontWeight: '600', color: '#1e293b' }}>
                        {new Date(viewingReceipt.issuedOn).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric'
                        })}
                      </div>
                    </div>
                  </div>

                  {/* Payment Details Grid */}
                  <div style={{
                    display: 'grid',
                    gridTemplateColumns: '1fr 1fr',
                    gap: '20px',
                    marginBottom: '30px'
                  }}>
                    {/* Left Column - Tenant Info */}
                    <div>
                      <div style={{
                        fontSize: '14px',
                        fontWeight: 'bold',
                        color: '#1e293b',
                        marginBottom: '15px',
                        borderBottom: '2px solid #e2e8f0',
                        paddingBottom: '8px'
                      }}>
                        TENANT INFORMATION
                      </div>
                      <div style={{ marginBottom: '12px' }}>
                        <div style={{ fontSize: '11px', color: '#64748b', marginBottom: '3px' }}>
                          Name
                        </div>
                        <div style={{ fontSize: '14px', fontWeight: '600', color: '#1e293b' }}>
                          {viewingReceipt.payment.invoice.Lease.tenant?.firstName ?? ''} {viewingReceipt.payment.invoice.Lease.tenant?.lastName ?? ''}
                        </div>
                      </div>
                      <div style={{ marginBottom: '12px' }}>
                        <div style={{ fontSize: '11px', color: '#64748b', marginBottom: '3px' }}>
                          Email
                        </div>
                        <div style={{ fontSize: '14px', color: '#1e293b' }}>
                          {viewingReceipt.payment.invoice.Lease.tenant?.email || 'N/A'}
                        </div>
                      </div>
                    </div>

                    {/* Right Column - Property Details */}
                    <div>
                      <div style={{
                        fontSize: '14px',
                        fontWeight: 'bold',
                        color: '#1e293b',
                        marginBottom: '15px',
                        borderBottom: '2px solid #e2e8f0',
                        paddingBottom: '8px'
                      }}>
                        PROPERTY DETAILS
                      </div>
                      <div style={{ marginBottom: '12px' }}>
                        <div style={{ fontSize: '11px', color: '#64748b', marginBottom: '3px' }}>
                          Property
                        </div>
                        <div style={{ fontSize: '14px', fontWeight: '600', color: '#1e293b' }}>
                          {viewingReceipt.payment.invoice.Lease.property.city}
                        </div>
                        <div style={{ fontSize: '13px', color: '#64748b' }}>
                          {viewingReceipt.payment.invoice.Lease.property.address}
                        </div>
                      </div>
                      <div style={{ marginBottom: '12px' }}>
                        <div style={{ fontSize: '11px', color: '#64748b', marginBottom: '3px' }}>
                          Unit Number
                        </div>
                        <div style={{ fontSize: '14px', fontWeight: '600', color: '#1e293b' }}>
                          {viewingReceipt.payment.invoice.Lease.unit.unitNumber}
                          {viewingReceipt.payment.invoice.Lease.unit.unitName &&
                            ` - ${viewingReceipt.payment.invoice.Lease.unit.unitName}`
                          }
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Invoice Details */}
                  <div style={{
                    backgroundColor: '#f8fafc',
                    padding: '20px',
                    borderRadius: '8px',
                    marginBottom: '30px'
                  }}>
                    <div style={{
                      fontSize: '14px',
                      fontWeight: 'bold',
                      color: '#1e293b',
                      marginBottom: '15px'
                    }}>
                      INVOICE DETAILS
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#64748b' }}>Invoice Number</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        #{viewingReceipt.payment.invoice.id.slice(0, 8)}
                      </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#64748b' }}>Invoice Type</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        {viewingReceipt.payment.invoice.type}
                      </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#64748b' }}>Due Date</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        {new Date(viewingReceipt.payment.invoice.dueDate).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric'
                        })}
                      </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#64748b' }}>Invoice Amount</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        $ {viewingReceipt.payment.invoice.amount.toFixed(2)}
                      </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                      <div style={{ fontSize: '13px', color: '#64748b' }}>Invoice Status</div>
                      <div style={{
                        fontSize: '13px',
                        fontWeight: 'bold',
                        color: viewingReceipt.payment.invoice.status === 'PAID' ? '#10b981' : '#f59e0b'
                      }}>
                        {viewingReceipt.payment.invoice.status}
                      </div>
                    </div>
                  </div>

                  {/* Payment Information */}
                  <div style={{
                    backgroundColor: '#eff6ff',
                    border: '2px solid #2563eb',
                    padding: '20px',
                    borderRadius: '8px',
                    marginBottom: '30px'
                  }}>
                    <div style={{
                      fontSize: '14px',
                      fontWeight: 'bold',
                      color: '#1e293b',
                      marginBottom: '15px'
                    }}>
                      PAYMENT INFORMATION
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#002b5b' }}>Payment ID</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        #{viewingReceipt.payment.id.slice(0, 12)}
                      </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#002b5b' }}>Payment Date</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        {new Date(viewingReceipt.payment.paidOn).toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric'
                        })}
                      </div>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                      <div style={{ fontSize: '13px', color: '#002b5b' }}>Payment Method</div>
                      <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                        {viewingReceipt.payment.method === 'CASH' ? '💵 Cash' : '💳 Credit Card'}
                      </div>
                    </div>
                    {viewingReceipt.payment.reference && (
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                        <div style={{ fontSize: '13px', color: '#002b5b' }}>Reference Number</div>
                        <div style={{ fontSize: '13px', fontWeight: '600', color: '#1e293b' }}>
                          {viewingReceipt.payment.reference}
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Amount Paid - Prominent */}
                  <div style={{
                    backgroundColor: '#10b981',
                    color: 'white',
                    padding: '25px',
                    borderRadius: '12px',
                    textAlign: 'center',
                    marginBottom: '30px'
                  }}>
                    <div style={{ fontSize: '14px', marginBottom: '8px', opacity: 0.9 }}>
                      AMOUNT PAID
                    </div>
                    <div style={{ fontSize: '48px', fontWeight: 'bold', letterSpacing: '1px' }}>
                      $ {viewingReceipt.payment.amount.toFixed(2)}
                    </div>
                  </div>

                  {/* Footer */}
                  <div style={{
                    borderTop: '2px solid #e2e8f0',
                    paddingTop: '20px',
                    marginTop: '40px'
                  }}>
                    <div style={{
                      textAlign: 'center',
                      fontSize: '11px',
                      color: '#64748b',
                      lineHeight: '1.6'
                    }}>
                      <div style={{ marginBottom: '8px', fontWeight: '600' }}>
                        Thank you for your payment!
                      </div>
                      <div style={{ marginBottom: '4px' }}>
                        This is an official receipt for the payment received.
                      </div>
                      <div style={{ marginBottom: '4px' }}>
                        Please keep this receipt for your records.
                      </div>
                      <div style={{ marginTop: '15px', fontSize: '10px', color: '#94a3b8' }}>
                        Generated on {new Date().toLocaleDateString('en-US', {
                          year: 'numeric',
                          month: 'long',
                          day: 'numeric',
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </div>
                    </div>
                  </div>

                  {/* Verification Code */}
                  <div style={{
                    marginTop: '20px',
                    textAlign: 'center',
                    padding: '15px',
                    backgroundColor: '#f8fafc',
                    borderRadius: '8px'
                  }}>
                    <div style={{ fontSize: '10px', color: '#94a3b8', marginBottom: '8px' }}>
                      RECEIPT VERIFICATION CODE
                    </div>
                    <div style={{
                      fontFamily: 'monospace',
                      fontSize: '12px',
                      fontWeight: 'bold',
                      color: '#1e293b',
                      letterSpacing: '2px'
                    }}>
                      {viewingReceipt.receiptNo}-{viewingReceipt.payment.id.slice(0, 8).toUpperCase()}
                    </div>
                  </div>
                </div>
              </div>            </div>
          </div>
        )}

        {/* Reverse Payment Modal */}
        {showReverseModal && paymentToReverse && (
          <div className="fixed inset-0  bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl p-6 max-w-md w-full shadow-2xl">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-12 h-12 rounded-full bg-red-100 flex items-center justify-center">
                  <svg className="w-6 h-6 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                  </svg>
                </div>
                <div>
                  <h3 className="text-lg font-bold text-slate-800">Reverse Payment</h3>
