                                        <div className="flex justify-between text-sm">
                                          <span className="text-gray-600">Balance:</span>
                                          <span className={`font-semibold ${calculateInvoiceBalance(utilityInvoice) > 0 ? "text-red-600" : "text-navy-700"
                                            }`}>
                                            {formatCurrency(calculateInvoiceBalance(utilityInvoice))}
                                          </span>
                                        </div>
                                        {utilityInvoice.utilities && utilityInvoice.utilities.length > 0 && (
                                          <div className="mt-2">
                                            <div className="text-xs font-medium text-gray-600 mb-1">Utility Details:</div>
                                            {utilityInvoice.utilities.map((u) => (
                                              <div key={u.id} className="flex justify-between text-xs">
                                                <span className="text-gray-500">{u.name} ({u.type})</span>
                                                <span>
                                                  {u.fixedAmount !== undefined ? `Fixed: ${formatCurrency(u.fixedAmount)}` : ''}
                                                  {u.unitPrice !== undefined ? ` • Unit Price: ${formatCurrency(u.unitPrice)}` : ''}
                                                  {u.isTenantResponsible !== undefined ? ` • Tenant Responsible: ${u.isTenantResponsible ? "Yes" : "No"}` : ''}
                                                </span>
                                              </div>
                                            ))}
                                          </div>
                                        )}


                                      </div>
                                    </div>
                                  )}
                                </div>
                              </div>

                              {/* Combined Payment History */}
                              <div>
                                <h4 className="font-semibold text-gray-900 mb-3 flex items-center gap-2">
                                  <CreditCard className="h-4 w-4 text-navy-700" />
                                  Payment History
                                </h4>
                                <div className="bg-white rounded-lg border border-gray-200 p-4">
                                  <div className="space-y-2">
                                    {group.invoices.flatMap((invoice: Invoice) => invoice.payment || []).length > 0 ? (
                                      group.invoices.flatMap((invoice: Invoice) => invoice.payment || []).map((payment: Payment) => (
                                        <div key={payment.id} className="flex justify-between items-center p-3 bg-navy-50 rounded border border-navy-200">
                                          <div>
                                            <div className="font-medium text-gray-900 capitalize">
                                              {payment.method} Payment
                                            </div>
                                            <div className="text-sm text-gray-500">
                                              {payment.reference && `Ref: ${payment.reference}`}
                                              {payment.paidOn && ` • ${formatDate(payment.paidOn)}`}
                                            </div>
                                          </div>
                                          <span className="font-semibold text-navy-700">
                                            {formatCurrency(payment.amount)}
                                          </span>
                                        </div>
                                      ))
                                    ) : (
                                      <div className="text-sm text-gray-500 italic p-3 bg-white rounded border border-gray-200">
                                        No payments recorded for this billing period
                                      </div>
                                    )}
                                  </div>
                                </div>
                              </div>
                            </div>
                          </td>
                        </tr>
                      )}
                    </React.Fragment>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}

        {/* Manual Invoice Modal */}
        {showManualModal && (
          <div className="fixed inset-0 z-50 flex items-start justify-center pt-20 bg-black/50">
            <div className="bg-white p-6 rounded-lg border border-gray-200 shadow-lg w-full max-w-md relative">
              <button
                onClick={() => setShowManualModal(false)}
                className="absolute top-3 right-3 text-gray-500 hover:text-gray-700"
              >
                ✕
              </button>

              <h2 className="text-xl text-blue-500 font-semibold mb-4">Create Manual Invoice</h2>

              <label className="block text-sm font-medium mb-1">Type</label>
              <select
                value={manualType}
                onChange={(e) => setManualType(e.target.value as "RENT" | "UTILITY")}
                className="w-full border p-2 rounded mb-3"
              >
                <option value="RENT">Rent</option>
                <option value="UTILITY">Utility</option>
              </select>

              <label className="block text-sm font-medium mb-1">Amount</label>
              <input
                type="number"
                value={manualAmount}
                onChange={(e) => setManualAmount(Number(e.target.value))}
                className="w-full border p-2 rounded mb-3"
              />

              <label className="block text-sm font-medium mb-1">Due Date</label>
              <input
                type="date"
                value={manualDate}
                onChange={(e) => setManualDate(e.target.value)}
                className="w-full border p-2 rounded mb-4"
              />

              <div className="flex justify-between">
                <Button variant="outline" onClick={() => setShowManualModal(false)}>
                  Cancel
                </Button>

                <Button
                  variant="outline"
                  disabled={loadingManual}
                  onClick={handleCreateManualInvoice}
                >
                  {loadingManual ? "Creating..." : "Create"}
                </Button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useSearchParams } from "next/navigation";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { AlertCircle, PieChart, ArrowLeft, Lock, Info } from "lucide-react";
import Link from "next/link";
import { UtilityStatusBadge } from "../../components/UtilityStatusBadge";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";

interface Allocation {
    id: string;
    unitNumber: string;
    tenantName: string;
    amount: number;
    percentage: number;
    basis: string;
}

interface BillWithAllocations {
    id: string;
    providerName: string;
    totalAmount: number;
    status: string;
    splitMethod: string;
    allocations: Allocation[];
}

interface UtilityBill {
    id: string;
    providerName: string;
    billDate: string;
    status: string;
}

export default function AllocationsPage() {
    const { id } = useParams();
    const searchParams = useSearchParams();
    const utilityId = id as string;
    const preselectedBillId = searchParams.get("billId");

    const [bills, setBills] = useState<UtilityBill[]>([]);
    const [selectedBillId, setSelectedBillId] = useState<string>(preselectedBillId || "");
    const [billData, setBillData] = useState<BillWithAllocations | null>(null);
    const [utilityName, setUtilityName] = useState<string>("Utility");
    const [isLoading, setIsLoading] = useState(true);
    const [isLoadingAllocations, setIsLoadingAllocations] = useState(false);

    useEffect(() => {
        loadInitialData();
    }, [utilityId]);

    useEffect(() => {
        if (selectedBillId) {
            loadAllocations(selectedBillId);
        } else {
            setBillData(null);
        }
    }, [selectedBillId]);

    const loadInitialData = async () => {
        try {
            setIsLoading(true);

            const [utilRes, billsRes] = await Promise.all([
                fetch(`/api/utilities/${utilityId}`),
                fetch(`/api/utilities/${utilityId}/bills`),
            ]);

            const utilData = await utilRes.json();
            const billsData = await billsRes.json();

            const utilityData = utilData?.data || utilData;
            if (utilityData) {
                setUtilityName(utilityData.name || "Utility");
            }

            if (billsData.success) {
                const billsWithAllocations = (billsData.data || []).filter(
                    (b: UtilityBill) => b.status !== "DRAFT"
                );
                setBills(billsWithAllocations);

                if (preselectedBillId && billsWithAllocations.some((b: UtilityBill) => b.id === preselectedBillId)) {
                    setSelectedBillId(preselectedBillId);
                } else if (billsWithAllocations.length > 0 && !selectedBillId) {
                    setSelectedBillId(billsWithAllocations[0].id);
                }
            }
        } catch (err) {
            console.error("Load initial data error:", err);
        } finally {
            setIsLoading(false);
        }
    };

    const loadAllocations = async (billId: string) => {
        try {
            setIsLoadingAllocations(true);

            const res = await fetch(`/api/utilities/bills/${billId}/allocations`);
            const data = await res.json();

            if (data.success) {
                setBillData(data.data);
            } else {
                setBillData(null);
            }
        } catch (err) {
            console.error("Load allocations error:", err);
            setBillData(null);
        } finally {
            setIsLoadingAllocations(false);
        }
    };

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat("en-US", {
            style: "currency",
            currency: "USD",
        }).format(amount);
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString("en-US", {
            year: "numeric",
            month: "short",
            day: "numeric",
        });
    };

    const formatAllocationBasis = (method: string) => {
        const labels: Record<string, string> = {
            EQUAL: "Equal Usage",
            OCCUPANCY_BASED: "Occupancy-based",
            SQ_FOOTAGE: "Square Footage",
            SUB_METERED: "Sub-metered",
            CUSTOM_RATIO: "Custom Ratio",
            AI_OPTIMIZED: "AI Optimized",
        };
        return labels[method] ?? method;
    };

    const allocations = billData?.allocations ?? [];

    return (
        <div className="min-h-screen bg-slate-50/50 p-6">
            <div className="max-w-6xl mx-auto space-y-8">
                {/* Header */}
                <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                    <div className="space-y-1">
                        <Link href={`/property-manager/content/utilities/${utilityId}`}>
                            <Button variant="ghost" size="sm" className="text-slate-500 hover:text-slate-900 px-0 -ml-2 mb-1 h-auto py-1">
                                <ArrowLeft className="w-3.5 h-3.5 mr-1" /> Back
                            </Button>
                        </Link>
                        <h2 className="text-2xl font-bold text-[#0b1f3a] tracking-tight">Bill Allocations</h2>
                        <p className="text-slate-500 text-sm">View how costs are distributed for {utilityName}</p>
                    </div>

                    {bills.length > 0 && (
                        <div className="w-full md:w-[300px]">
                            <Select value={selectedBillId} onValueChange={setSelectedBillId}>
                                <SelectTrigger className="bg-white border-slate-200">
                                    <SelectValue placeholder="Select a bill" />
                                </SelectTrigger>
                                <SelectContent>
                                    {bills.map((bill) => (
                                        <SelectItem key={bill.id} value={bill.id}>
                                            {bill.providerName} - {formatDate(bill.billDate)}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    )}
                </div>

                {/* Read-Only Notice */}
                <div className="bg-slate-50 border border-slate-200 rounded-lg p-4 flex items-start gap-3 shadow-sm">
                    <div className="bg-slate-100 p-1.5 rounded-full mt-0.5">
                        <Lock className="w-4 h-4 text-slate-600" />
                    </div>
                    <div>
                        <h4 className="text-sm font-semibold text-slate-800">Read-Only View</h4>
                        <p className="text-sm text-slate-600 mt-0.5">
                            Allocations are calculated by the system and cannot be edited. This view is for transparency and audit purposes.
                        </p>
                    </div>
                </div>

                {/* Content */}
                <Card className="border-slate-200 shadow-sm rounded-xl overflow-hidden bg-white">
                    <CardContent className="p-0">
                        {isLoading ? (
                            <div className="p-6 space-y-4">
                                {[1, 2, 3].map(i => (
                                    <Skeleton key={i} className="h-12 w-full" />
                                ))}
                            </div>
                        ) : bills.length === 0 ? (
                            <div className="text-center py-20 space-y-4">
                                <div className="w-16 h-16 mx-auto bg-slate-50 rounded-full flex items-center justify-center border border-slate-100">
                                    <PieChart className="w-8 h-8 text-slate-300" />
                                </div>
                                <div>
                                    <h3 className="text-lg font-medium text-[#0b1f3a]">No bills with allocations</h3>
                                    <p className="text-slate-500 max-w-sm mx-auto mt-1">
                                        Allocations appear after a bill is processed from DRAFT status.
                                    </p>
                                </div>
                            </div>
                        ) : !selectedBillId ? (
                            <div className="text-center py-20 space-y-4">
                                <div className="w-16 h-16 mx-auto bg-blue-50 rounded-full flex items-center justify-center">
                                    <Info className="w-8 h-8 text-blue-400" />
                                </div>
                                <div>
                                    <h3 className="text-lg font-medium text-[#0b1f3a]">Select a bill</h3>
                                    <p className="text-slate-500">Use the dropdown above to view allocations</p>
                                </div>
                            </div>
                        ) : isLoadingAllocations ? (
                            <div className="p-6 space-y-4">
                                {[1, 2, 3, 4].map(i => (
                                    <Skeleton key={i} className="h-10 w-full" />
                                ))}
                            </div>
                        ) : allocations.length === 0 ? (
                            <div className="text-center py-20 space-y-4">
                                <div className="w-16 h-16 mx-auto bg-amber-50 rounded-full flex items-center justify-center">
                                    <AlertCircle className="w-8 h-8 text-amber-400" />
                                </div>
                                <div>
                                    <h3 className="text-lg font-medium text-[#0b1f3a]">No allocations found</h3>
                                    <p className="text-slate-500">This bill may not have been allocated yet</p>
                                </div>
                            </div>
                        ) : (
                            <>
                                {/* Bill Summary */}
                                {billData && (
                                    <div className="p-6 border-b border-slate-100 bg-slate-50/30">
                                        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                            <div>
                                                <p className="text-xs text-slate-500 uppercase tracking-wider mb-1">Provider</p>
                                                <p className="font-semibold text-[#0b1f3a]">{billData.providerName}</p>
                                            </div>
                                            <div>
                                                <p className="text-xs text-slate-500 uppercase tracking-wider mb-1">Total Amount</p>
                                                <p className="font-semibold text-[#0b1f3a]">{formatCurrency(billData.totalAmount)}</p>
                                            </div>
                                            <div>
                                                <p className="text-xs text-slate-500 uppercase tracking-wider mb-1">Split Method</p>
                                                <Badge variant="outline" className="bg-white border-slate-200">
                                                    {formatAllocationBasis(billData.splitMethod)}
                                                </Badge>
                                            </div>
                                            <div>
                                                <p className="text-xs text-slate-500 uppercase tracking-wider mb-1">Status</p>
                                                <UtilityStatusBadge status={billData.status} />
                                            </div>
                                        </div>
                                    </div>
                                )}

                                {/* Allocations Table */}
                                <Table>
                                    <TableHeader className="bg-slate-50/50">
                                        <TableRow className="border-b border-slate-100 hover:bg-transparent">
                                            <TableHead className="font-semibold text-[#0b1f3a] pl-6">Unit</TableHead>
                                            <TableHead className="font-semibold text-[#0b1f3a]">Tenant</TableHead>
                                            <TableHead className="font-semibold text-[#0b1f3a]">Amount</TableHead>
                                            <TableHead className="font-semibold text-[#0b1f3a]">Percentage</TableHead>
                                            <TableHead className="font-semibold text-[#0b1f3a] pr-6">Basis</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {allocations.map((allocation, index) => (
                                            <TableRow
                                                key={allocation.id}
                                                className={`hover:bg-blue-50/30 border-b border-slate-50 last:border-0 ${index % 2 === 1 ? 'bg-slate-25' : ''}`}
                                            >
                                                <TableCell className="font-medium text-[#0b1f3a] pl-6">
                                                    Unit {allocation.unitNumber}
                                                </TableCell>
                                                <TableCell className="text-slate-600">
                                                    {allocation.tenantName}
                                                </TableCell>
                                                <TableCell className="font-mono text-[#0b1f3a]">
                                                    {formatCurrency(allocation.amount)}
                                                </TableCell>
                                                <TableCell>
                                                    <Badge variant="secondary" className="bg-slate-100 text-slate-700">
                                                        {allocation.percentage.toFixed(1)}%
                                                    </Badge>
                                                </TableCell>
                                                <TableCell className="text-slate-500 text-sm pr-6">
                                                    {allocation.basis}
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>

                                {/* Total Row */}
                                <div className="p-4 bg-slate-50 border-t border-slate-100 flex justify-between items-center">
                                    <span className="font-semibold text-[#0b1f3a]">Total Allocated</span>
                                    <span className="font-bold text-lg text-[#0b1f3a]">
                                        {formatCurrency(allocations.reduce((sum, a) => sum + a.amount, 0))}
                                    </span>
                                </div>
                            </>
                        )}
                    </CardContent>
                </Card>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Loader2, AlertCircle } from "lucide-react";
import { UtilitySplitMethod } from "@/lib/utilities/utility-types";

interface Property {
    id: string;
    name: string;
}

interface CreateBillModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    utilityId: string;
    utilityName: string;
}

/**
 * CreateBillModal - Create a new utility bill
 * 
 * Responsibilities:
 * - Collect bill details: provider, amount, dates, split method
 * - Submit to backend createBill()
 * - Bill starts in DRAFT status
 * - No calculations - all math is backend-only
 */
export function CreateBillModal({
    isOpen,
    onClose,
    onSuccess,
    utilityId,
    utilityName,
}: CreateBillModalProps) {
    const [properties, setProperties] = useState<Property[]>([]);
    const [selectedPropertyId, setSelectedPropertyId] = useState<string>("");
    const [providerName, setProviderName] = useState("");
    const [totalAmount, setTotalAmount] = useState("");
    const [billDate, setBillDate] = useState(new Date().toISOString().split("T")[0]);
    const [dueDate, setDueDate] = useState("");
    const [splitMethod, setSplitMethod] = useState<UtilitySplitMethod>(
        UtilitySplitMethod.EQUAL
    );
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isLoadingProperties, setIsLoadingProperties] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Load properties when modal opens
    useEffect(() => {
        if (isOpen) {
            loadProperties();
        }
    }, [isOpen]);

    const loadProperties = async () => {
        try {
            setIsLoadingProperties(true);
            const res = await fetch("/api/propertymanager");
            const data = await res.json();

            const props = Array.isArray(data)
                ? data
                : Array.isArray(data.data)
                    ? data.data
                    : [];

            setProperties(props);

            // Auto-select first property if only one
            if (props.length === 1) {
                setSelectedPropertyId(props[0].id);
            }
        } catch (err) {
            console.error("Load properties error:", err);
        } finally {
            setIsLoadingProperties(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);

        // Basic validation
        const amount = parseFloat(totalAmount);
        if (isNaN(amount) || amount <= 0) {
            setError("Total amount must be a positive number");
            return;
        }

        if (!providerName.trim()) {
            setError("Provider name is required");
            return;
        }

        if (!selectedPropertyId) {
            setError("Please select a property");
            return;
        }

        if (!dueDate) {
            setError("Due date is required");
            return;
        }

        if (new Date(dueDate) < new Date(billDate)) {
            setError("Due date cannot be before bill date");
            return;
        }

        setIsSubmitting(true);

        try {
            // Use new API endpoint
            const res = await fetch(`/api/utilities/${utilityId}/bills`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    propertyId: selectedPropertyId,
                    providerName: providerName.trim(),
                    totalAmount: amount,
                    billDate: new Date(billDate),
                    dueDate: new Date(dueDate),
                    splitMethod,
                }),
            });

            const data = await res.json();

            if (data.success) {
                onSuccess();
                handleClose();
            } else {
                // Map backend errors
                const errorMessages: Record<string, string> = {
                    INVALID_PROPERTY: "Invalid property selected.",
                    INVALID_DATES: "Bill date must be before due date.",
                    INVALID_AMOUNT: "Total amount must be a positive number.",
                    PROPERTY_NOT_FOUND: "Property not found.",
                };
                setError(errorMessages[data.error] || data.message || "Failed to create bill");
            }
        } catch (err) {
            console.error("Create bill error:", err);
            setError("An error occurred while creating the bill");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleClose = () => {
        setSelectedPropertyId("");
        setProviderName("");
        setTotalAmount("");
        setBillDate(new Date().toISOString().split("T")[0]);
        setDueDate("");
        setSplitMethod(UtilitySplitMethod.EQUAL);
        setError(null);
        onClose();
    };

    const splitMethodLabels: Record<UtilitySplitMethod, string> = {
        [UtilitySplitMethod.EQUAL]: "Equal Usage",
        [UtilitySplitMethod.OCCUPANCY_BASED]: "Occupancy-based",
        [UtilitySplitMethod.SQ_FOOTAGE]: "Square Footage",
        [UtilitySplitMethod.SUB_METERED]: "Sub-metered",
        [UtilitySplitMethod.CUSTOM_RATIO]: "Custom Ratio",
        [UtilitySplitMethod.AI_OPTIMIZED]: "AI Optimized",
    };

    const selectedProperty = properties.find(p => p.id === selectedPropertyId);

    return (
        <Dialog open={isOpen} onOpenChange={handleClose}>
            <DialogContent className="sm:max-w-lg">
                <DialogHeader>
                    <DialogTitle>Create Utility Bill</DialogTitle>
                    <DialogDescription>
                        Create a new utility bill for <strong>{utilityName}</strong>.
                        The bill will start in DRAFT status.
                    </DialogDescription>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {error && (
                        <div className="flex items-center gap-2 p-3 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
                            <AlertCircle className="w-4 h-4 flex-shrink-0" />
                            {error}
                        </div>
                    )}

                    <div className="space-y-2">
                        <Label htmlFor="property">
                            Property <span className="text-red-500">*</span>
                        </Label>
                        <Select
                            value={selectedPropertyId}
                            onValueChange={setSelectedPropertyId}
                            disabled={isSubmitting || isLoadingProperties}
                        >
                            <SelectTrigger className="border-2 border-slate-200 focus:border-[#30D5C8]">
                                <SelectValue placeholder={isLoadingProperties ? "Loading..." : "Select property"} />
                            </SelectTrigger>
                            <SelectContent>
                                {properties.map((property) => (
                                    <SelectItem key={property.id} value={property.id}>
                                        {property.name}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="providerName">
                            Provider Name <span className="text-red-500">*</span>
                        </Label>
                        <Input
                            id="providerName"
                            value={providerName}
                            onChange={(e) => setProviderName(e.target.value)}
                            placeholder="e.g., City Water Department"
                            disabled={isSubmitting}
                            required
                            className="border-2 border-slate-200 focus:border-[#30D5C8]"
                        />
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="totalAmount">
                            Total Amount <span className="text-red-500">*</span>
                        </Label>
                        <div className="relative">
                            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">
                                $
                            </span>
                            <Input
                                id="totalAmount"
                                type="number"
                                step="0.01"
                                min="0.01"
                                value={totalAmount}
                                onChange={(e) => setTotalAmount(e.target.value)}
                                placeholder="0.00"
                                disabled={isSubmitting}
                                required
                                className="pl-7 border-2 border-slate-200 focus:border-[#30D5C8]"
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                            <Label htmlFor="billDate">
                                Bill Date <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="billDate"
                                type="date"
                                value={billDate}
                                onChange={(e) => setBillDate(e.target.value)}
                                disabled={isSubmitting}
                                required
                                className="border-2 border-slate-200 focus:border-[#30D5C8]"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="dueDate">
                                Due Date <span className="text-red-500">*</span>
                            </Label>
                            <Input
                                id="dueDate"
                                type="date"
                                value={dueDate}
                                onChange={(e) => setDueDate(e.target.value)}
                                disabled={isSubmitting}
                                required
                                className="border-2 border-slate-200 focus:border-[#30D5C8]"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <Label htmlFor="splitMethod">
                            Allocation Method <span className="text-red-500">*</span>
                        </Label>
                        <Select
                            value={splitMethod}
                            onValueChange={(value) => setSplitMethod(value as UtilitySplitMethod)}
                            disabled={isSubmitting}
                        >
                            <SelectTrigger className="border-2 border-slate-200 focus:border-[#30D5C8]">
                                <SelectValue placeholder="Select allocation method" />
                            </SelectTrigger>
                            <SelectContent>
                                {Object.entries(splitMethodLabels).map(([value, label]) => (
                                    <SelectItem key={value} value={value}>
                                        {label}
                                    </SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                        <p className="text-xs text-slate-500">
                            Determines how the bill is split across units
                        </p>
                    </div>

                    <DialogFooter className="gap-2 sm:gap-0">
                        <Button
                            type="button"
                            variant="outline"
                            onClick={handleClose}
                            disabled={isSubmitting}
                        >
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            disabled={isSubmitting || !selectedPropertyId}
                            className="bg-[#30D5C8] hover:bg-[#30D5C8]/90 text-white"
                        >
                            {isSubmitting ? (
                                <>
                                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                    Creating...
                                </>
                            ) : (
                                "Create Bill"
                            )}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Plus, FileText, ArrowLeft, Info, Calendar } from "lucide-react";
import Link from "next/link";
import { Toaster } from "sonner";
import { UtilityStatusBadge } from "../../components/UtilityStatusBadge";
import { CreateBillModal } from "./CreateBillModal";
import { BillActions } from "./BillActions";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";

interface Bill {
    id: string;
    providerName: string;
    billDate: string;
    dueDate: string;
    totalAmount: number;
    splitMethod: string;
    status: string;
}

export default function BillsPage() {
    const { id } = useParams();
    const utilityId = id as string;

    const [bills, setBills] = useState<Bill[]>([]);
    const [utilityName, setUtilityName] = useState<string>("Utility");
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    useEffect(() => {
        loadData();
    }, [utilityId]);

    const loadData = async () => {
        try {
            setIsLoading(true);

            const [utilRes, billsRes] = await Promise.all([
                fetch(`/api/utilities/${utilityId}`),
                fetch(`/api/utilities/${utilityId}/bills`),
            ]);

            const utilData = await utilRes.json();
            const billsData = await billsRes.json();

            const utilityData = utilData?.data || utilData;
            if (utilityData) {
                setUtilityName(utilityData.name || "Utility");
            }

            if (billsData.success) {
                setBills(billsData.data || []);
            }
        } catch (err) {
            console.error("Load bills error:", err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleBillCreated = () => {
        loadData();
    };

    const handleActionComplete = () => {
        loadData();
    };

    const formatCurrency = (amount: number) => {
        return new Intl.NumberFormat("en-US", {
            style: "currency",
            currency: "USD",
        }).format(amount);
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString("en-US", {
            year: "numeric",
            month: "short",
            day: "numeric",
        });
    };

    const formatSplitMethod = (method: string) => {
        const labels: Record<string, string> = {
            EQUAL: "Equal Usage",
            OCCUPANCY_BASED: "Occupancy-based",
            SQ_FOOTAGE: "Sq. Footage",
            SUB_METERED: "Sub-metered",
            CUSTOM_RATIO: "Custom Ratio",
            AI_OPTIMIZED: "AI Optimized",
        };
        return labels[method] ?? method;
    };

    return (
        <div className="min-h-screen bg-slate-50/50 p-6">
            <Toaster position="top-right" richColors />
            <div className="max-w-6xl mx-auto space-y-8">
                {/* Header */}
                <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                    <div className="space-y-1">
                        <Link href={`/property-manager/content/utilities/${utilityId}`}>
                            <Button variant="ghost" size="sm" className="text-slate-500 hover:text-slate-900 px-0 -ml-2 mb-1 h-auto py-1">
                                <ArrowLeft className="w-3.5 h-3.5 mr-1" /> Back
                            </Button>
                        </Link>
                        <h2 className="text-2xl font-bold text-[#0b1f3a] tracking-tight">Provider Bills</h2>
                        <p className="text-slate-500 text-sm">Manage bills and payment status for {utilityName}</p>
                    </div>

                    <Button
                        onClick={() => setIsModalOpen(true)}
                        className="bg-[#30D5C8] hover:bg-[#2bcbbe] text-white shadow-sm"
                    >
                        <Plus className="w-4 h-4 mr-2" />
                        Create Bill
                    </Button>
                </div>

                {/* Info Banner */}
                <div className="bg-blue-50/60 border border-blue-100 rounded-lg p-4 flex gap-3 shadow-sm">
                    <Info className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                    <div className="space-y-1">
                        <h4 className="text-sm font-semibold text-blue-900">Workflow</h4>
                        <p className="text-sm text-blue-800/80 leading-relaxed">
                            Bills progress through: <Badge variant="secondary" className="bg-slate-200 text-slate-700 mx-1 border-0">DRAFT</Badge>
                            → <Badge variant="secondary" className="bg-blue-200 text-blue-800 mx-1 border-0">PROCESSING</Badge>
                            → <Badge variant="secondary" className="bg-green-200 text-green-800 mx-1 border-0">APPROVED</Badge>
                            → <Badge variant="secondary" className="bg-purple-200 text-purple-800 mx-1 border-0">POSTED</Badge>.
                            Create a bill to start the process.
                        </p>
                    </div>
                </div>

                <Card className="border-slate-200 shadow-sm rounded-xl overflow-hidden bg-white">
                    <CardContent className="p-0">
                        {isLoading ? (
                            <div className="p-6 space-y-4">
                                {[1, 2, 3].map(i => (
                                    <div key={i} className="flex gap-4">
                                        <Skeleton className="h-12 w-full rounded" />
                                    </div>
                                ))}
                            </div>
                        ) : bills.length === 0 ? (
                            <div className="text-center py-20 space-y-4">
                                <div className="w-16 h-16 mx-auto bg-slate-50 rounded-full flex items-center justify-center border border-slate-100">
                                    <FileText className="w-8 h-8 text-slate-300" />
                                </div>
                                <div>
                                    <h3 className="text-lg font-medium text-[#0b1f3a]">No bills recorded</h3>
                                    <p className="text-slate-500 max-w-sm mx-auto mt-1 mb-4">
                                        Create your first bill to track costs and allocate expenses to tenants.
                                    </p>
                                    <Button
                                        onClick={() => setIsModalOpen(true)}
                                        variant="outline"
                                        className="border-slate-200"
                                    >
                                        <Plus className="w-4 h-4 mr-2" />
                                        Create First Bill
                                    </Button>
                                </div>
                            </div>
                        ) : (
                            <Table>
                                <TableHeader className="bg-slate-50/50">
                                    <TableRow className="border-b border-slate-100 hover:bg-transparent">
                                        <TableHead className="font-semibold text-[#0b1f3a] pl-6">Provider</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Dates</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Amount</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Allocation</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Status</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a] text-right pr-6">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {bills.map((bill) => (
                                        <TableRow key={bill.id} className="hover:bg-blue-50/30 border-b border-slate-50 last:border-0 group">
                                            <TableCell className="font-medium text-[#0b1f3a] pl-6 py-4">
                                                {bill.providerName}
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex flex-col text-sm">
                                                    <span className="text-slate-700 flex items-center gap-1.5">
                                                        <Calendar className="w-3 h-3 text-slate-400" /> {formatDate(bill.billDate)}
                                                    </span>
                                                    <span className="text-slate-400 text-xs mt-0.5">
                                                        Due: {formatDate(bill.dueDate)}
                                                    </span>
                                                </div>
                                            </TableCell>
                                            <TableCell className="font-medium text-[#0b1f3a]">
                                                {formatCurrency(bill.totalAmount)}
                                            </TableCell>
                                            <TableCell className="text-slate-600">
                                                <Badge variant="outline" className="font-normal bg-slate-50 text-slate-600 border-slate-200">
                                                    {formatSplitMethod(bill.splitMethod)}
                                                </Badge>
                                            </TableCell>
                                            <TableCell>
                                                <UtilityStatusBadge status={bill.status} />
                                            </TableCell>
                                            <TableCell className="text-right pr-6">
                                                <BillActions
                                                    billId={bill.id}
                                                    billStatus={bill.status}
                                                    utilityId={utilityId}
                                                    onActionComplete={handleActionComplete}
                                                />
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        )}
                    </CardContent>
                </Card>
            </div>

            <CreateBillModal
                isOpen={isModalOpen}
                onClose={() => setIsModalOpen(false)}
                onSuccess={handleBillCreated}
                utilityId={utilityId}
                utilityName={utilityName}
            />
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { Loader2, ArrowLeft, AlertCircle, Gauge, FileText, PieChart, Info } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import Link from "next/link";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { UtilityAllocationProcessor } from "@/components/utilities/UtilityAllocationProcessor";
import { MeterReadingsTable } from "@/components/utilities/MeterReadingsTable";

// Tab type
type TabId = "overview" | "readings" | "bills" | "allocations";

interface Utility {
  id: string;
  name: string;
  type: "FIXED" | "METERED";
  unitPrice?: number;
  fixedAmount?: number;
  propertyId?: string;
  propertyName?: string;
}

export default function UtilityDetailsPage() {
  // Keep [id] in route, use utilityId in code
  const { id } = useParams();
  const utilityId = id as string;

  const [utility, setUtility] = useState<Utility | null>(null);
  const [activeTab, setActiveTab] = useState<TabId>("overview");
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    loadUtility();
  }, [utilityId]);

  // Handle hash-based navigation
  useEffect(() => {
    const hash = window.location.hash.replace("#", "") as TabId;
    if (hash && ["overview", "readings", "bills", "allocations"].includes(hash)) {
      setActiveTab(hash);
    }
  }, []);

  const loadUtility = async () => {
    try {
      setIsLoading(true);
      setError(null);

      const res = await fetch(`/api/utilities/${utilityId}`);
      const data = await res.json();

      let utilityData = null;
      if (data?.success && data?.data) {
        utilityData = data.data;
      } else if (data?.id) {
        utilityData = data;
      }

      if (utilityData) {
        setUtility(utilityData);
      } else {
        setError("Utility not found");
      }
    } catch (err) {
      console.error("Load utility error:", err);
      setError("Failed to load utility");
    } finally {
      setIsLoading(false);
    }
  };

  const handleTabChange = (tab: TabId) => {
    setActiveTab(tab);
    // Update URL hash without full navigation
    window.history.replaceState(null, "", `#${tab}`);
  };

  const formatCurrency = (amount?: number | null) => {
    if (amount === null || amount === undefined) return "N/A";
    return new Intl.NumberFormat("en-US", {
      style: "currency",
      currency: "USD",
    }).format(amount);
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-slate-50 to-blue-50">
        <Loader2 className="w-8 h-8 animate-spin text-[#30D5C8]" />
        <span className="ml-3 text-[#15386a]">Loading utility...</span>
      </div>
    );
  }

  if (error || !utility) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-6">
        <div className="max-w-2xl mx-auto border border-slate-200 shadow-xl rounded-2xl bg-white">
          <div className="flex flex-col items-center justify-center py-12 space-y-4">
            <div className="w-16 h-16 bg-red-50 rounded-full flex items-center justify-center">
              <AlertCircle className="w-8 h-8 text-red-500" />
            </div>
            <p className="text-[#15386a]/70">{error || "Utility not found"}</p>
            <Link href="/property-manager/content/utilities">
              <Button
                variant="outline"
                className="text-[#30D5C8] border-[#30D5C8]/30 hover:bg-[#30D5C8]/5"
              >
                <ArrowLeft className="w-4 h-4 mr-2" />
                Back to Utilities
              </Button>
            </Link>
          </div>
        </div>
      </div>
    );
  }

  const tabs: { id: TabId; label: string; icon: React.ReactNode }[] = [
    { id: "overview", label: "Overview", icon: <Info className="w-4 h-4" /> },
    { id: "readings", label: "Readings", icon: <Gauge className="w-4 h-4" /> },
    { id: "bills", label: "Bills", icon: <FileText className="w-4 h-4" /> },
    { id: "allocations", label: "Allocations", icon: <PieChart className="w-4 h-4" /> },
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-6">
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Back Button */}
        <div className="flex items-center gap-4">
          <Link href="/property-manager/content/utilities">
            <Button
              variant="ghost"
              className="text-[#15386a] hover:text-[#0b1f3a] hover:bg-[#30D5C8]/5"
            >
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Utilities
            </Button>
          </Link>
        </div>

        {/* Utility Header */}
        <Card className="border-slate-200 shadow-xl rounded-2xl overflow-hidden">
          <CardHeader className="bg-gradient-to-r from-[#0b1f3a] to-[#15386a] text-white">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <CardTitle className="text-2xl">{utility.name}</CardTitle>
                <span
                  className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-semibold ${utility.type === "FIXED"
                    ? "bg-white/20 text-white"
                    : "bg-[#30D5C8] text-[#0b1f3a]"
                    }`}
                >
                  {utility.type === "FIXED" ? "Fixed" : "Metered"}
                </span>
              </div>
            </div>
          </CardHeader>
          <CardContent className="p-6">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
              <div className="bg-gradient-to-br from-[#15386a]/5 to-[#15386a]/10 p-4 rounded-xl border border-[#15386a]/20">
                <p className="text-sm text-[#15386a]/70 mb-1 font-medium">Billing Type</p>
                <p className="text-lg font-bold text-[#0b1f3a]">
                  {utility.type === "FIXED" ? "Fixed Amount" : "Metered"}
                </p>
              </div>
              <div className="bg-gradient-to-br from-[#30D5C8]/5 to-[#30D5C8]/10 p-4 rounded-xl border border-[#30D5C8]/20">
                <p className="text-sm text-[#15386a]/70 mb-1 font-medium">
                  {utility.type === "FIXED" ? "Fixed Amount" : "Unit Price"}
                </p>
                <p className="text-lg font-bold text-[#0b1f3a]">
                  {utility.type === "FIXED"
                    ? formatCurrency(utility.fixedAmount)
                    : formatCurrency(utility.unitPrice)}
                </p>
              </div>
              <div className="bg-gradient-to-br from-slate-50 to-slate-100 p-4 rounded-xl border border-slate-200">
                <p className="text-sm text-[#15386a]/70 mb-1 font-medium">Property</p>
                <p className="text-lg font-bold text-[#0b1f3a]">
                  {utility.propertyName ?? "Not assigned"}
                </p>
              </div>
              <div className="bg-gradient-to-br from-slate-50 to-slate-100 p-4 rounded-xl border border-slate-200">
                <p className="text-sm text-[#15386a]/70 mb-1 font-medium">Utility ID</p>
                <p className="text-sm font-mono text-[#0b1f3a] truncate">
                  {utilityId}
                </p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Tabs value={activeTab} onValueChange={(value) => handleTabChange(value as TabId)}>
          <TabsList className="mb-6 w-full justify-start border-b rounded-none bg-transparent h-auto p-0">
            {tabs.map((tab) => (
              <TabsTrigger
                key={tab.id}
                value={tab.id}
                className="data-[state=active]:border-b-2 data-[state=active]:border-blue-600 rounded-none pb-3"
              >
                <span className="flex items-center gap-2">
                  {tab.icon}
                  {tab.label}
                </span>
              </TabsTrigger>
            ))}
          </TabsList>

          <Card className="border-slate-200 shadow-xl rounded-2xl overflow-hidden">
            <CardContent className="p-6">
              <TabsContent value="overview">
                <OverviewTab utility={utility} />
              </TabsContent>
              <TabsContent value="readings">
                <ReadingsTab
                  utilityId={utilityId}
                  utilityType={utility.type}
                  propertyId={utility.propertyId}
                />
              </TabsContent>
              <TabsContent value="bills">
                <BillsTab utilityId={utilityId} />
              </TabsContent>
              <TabsContent value="allocations">
                <AllocationsTab utilityId={utilityId} propertyId={utility.propertyId} />
              </TabsContent>
            </CardContent>
          </Card>
        </Tabs>
      </div>
    </div>
  );
}

// =============================================================================
// TAB COMPONENTS
// =============================================================================

function OverviewTab({ utility }: { utility: Utility }) {
  return (
    <div className="space-y-6">
      <h3 className="text-xl font-bold text-[#0b1f3a]">Utility Overview</h3>
      <p className="text-[#15386a]/70">
        This is the overview tab for <strong>{utility.name}</strong>.
        Use the tabs above to view readings, bills, and allocations.
      </p>
      <div className="grid md:grid-cols-2 gap-6">
        <div className="p-6 bg-gradient-to-br from-[#15386a]/5 to-transparent rounded-xl border border-[#15386a]/10">
          <h4 className="font-semibold text-[#0b1f3a] mb-2">Quick Actions</h4>
          <ul className="space-y-2 text-[#15386a]/70">
            <li>• View and add meter readings in the <strong>Readings</strong> tab</li>
            <li>• Manage provider bills in the <strong>Bills</strong> tab</li>
            <li>• View cost allocations in the <strong>Allocations</strong> tab</li>
          </ul>
        </div>
        <div className="p-6 bg-gradient-to-br from-[#30D5C8]/5 to-transparent rounded-xl border border-[#30D5C8]/10">
          <h4 className="font-semibold text-[#0b1f3a] mb-2">Utility Details</h4>
          <dl className="space-y-2 text-[#15386a]/70">
            <div className="flex justify-between">
              <dt>Type:</dt>
              <dd className="font-medium text-[#0b1f3a]">{utility.type}</dd>
            </div>
            <div className="flex justify-between">
              <dt>Billing:</dt>
              <dd className="font-medium text-[#0b1f3a]">
                {utility.type === "FIXED" ? "Fixed Monthly" : "Usage-based"}
              </dd>
            </div>
          </dl>
        </div>
      </div>
    </div>
  );
}

function ReadingsTab({
  utilityId,
  utilityType,
  propertyId,
}: {
  utilityId: string;
  utilityType: "FIXED" | "METERED";
  propertyId?: string;
}) {
  if (utilityType === "FIXED") {
    return (
      <div className="text-center py-12 space-y-4">
        <div className="w-16 h-16 mx-auto bg-slate-100 rounded-full flex items-center justify-center">
          <Gauge className="w-8 h-8 text-slate-400" />
        </div>
        <p className="text-[#15386a]/70">
          Meter readings are not available for fixed-rate utilities.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <MeterReadingsTable propertyId={propertyId ?? "property-unknown"} />
      <p className="text-xs text-slate-500">Utility ID: {utilityId}</p>
    </div>
  );
}

function BillsTab({ utilityId }: { utilityId: string }) {
  // TODO: Implement BillsTab content
  // This will be replaced with the full bills module
  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h3 className="text-xl font-bold text-[#0b1f3a]">Provider Bills</h3>
        <Button className="bg-[#30D5C8] hover:bg-[#30D5C8]/90 text-white">
          Create Bill
        </Button>
      </div>
