import { useState } from "react";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogFooter,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Loader2, AlertCircle, Calendar, Hash } from "lucide-react";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";

interface AddReadingModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: (reading: any) => void; // Accepts reading data from form submission
    leaseUtilityId: string;
    utilityId: string;
    utilityName: string;
    mockMode?: boolean;
    // New props for global use
    isGlobalAdd?: boolean;
    properties?: string[];
    units?: string[];
}

/**
 * AddReadingModal - Enhanced meter reading form
 */
export function AddReadingModal({
    isOpen,
    onClose,
    onSuccess,
    leaseUtilityId,
    utilityId,
    utilityName,
    mockMode = false,
    isGlobalAdd = false,
    properties = [],
    units = [],
}: AddReadingModalProps) {
    const [readingValue, setReadingValue] = useState("");
    const [readingDate, setReadingDate] = useState(
        new Date().toISOString().split("T")[0]
    );
    const [selectedProperty, setSelectedProperty] = useState("");
    const [selectedUnit, setSelectedUnit] = useState("");
    const [selectedUtilityType, setSelectedUtilityType] = useState("");
    const [notes, setNotes] = useState("");

    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);

        // Realistic Validation
        if (isGlobalAdd && (!selectedProperty || !selectedUnit || !selectedUtilityType)) {
            setError("Please select Property, Unit, and Utility Type");
            return;
        }

        const value = parseFloat(readingValue);
        if (isNaN(value) || value < 0) {
            setError("Reading value must be a non-negative number");
            return;
        }

        setIsSubmitting(true);

        try {
            if (mockMode || true) { // Defaulting to true for now as we don't have the API ready
                await new Promise(resolve => setTimeout(resolve, 800));

                if (value > 999999) {
                    throw new Error("Reading value unreasonably high");
                }

                // Pass the reading data to the parent
                onSuccess({
                    property: selectedProperty,
                    unit: selectedUnit,
                    tenant: `${selectedProperty} - ${selectedUnit} Tenant`, // Placeholder tenant name
                    utilityType: selectedUtilityType as "Water" | "Electricity" | "Gas",
                    readingValue: value,
                    readingDate: readingDate,
                });
                handleClose();
                return;
            }
        } catch (err: any) {
            console.error("Add reading error:", err);
            setError(err.message || "An error occurred while adding the reading");
        } finally {
            setIsSubmitting(false);
        }
    };

    const handleClose = () => {
        setReadingValue("");
        setReadingDate(new Date().toISOString().split("T")[0]);
        setSelectedProperty("");
        setSelectedUnit("");
        setSelectedUtilityType("");
        setNotes("");
        setError(null);
        onClose();
    };

    return (
        <Dialog open={isOpen} onOpenChange={(open: boolean) => !isSubmitting && !open && handleClose()}>
            <DialogContent className="sm:max-w-[480px] bg-white border-slate-200 shadow-xl overflow-y-auto max-h-[90vh]">
                <DialogHeader className="border-b border-slate-50 pb-4">
                    <div className="flex items-center gap-3">
                        <div className="bg-[#003b73] p-2.5 rounded-xl shadow-inner">
                            <Hash className="w-5 h-5 text-white" />
                        </div>
                        <div>
                            <DialogTitle className="text-xl font-bold text-slate-900">Add Meter Reading</DialogTitle>
                            <DialogDescription className="text-xs font-medium text-slate-500">
                                Record a new consumption entry for the audit log.
                            </DialogDescription>
                        </div>
                    </div>
                </DialogHeader>

                <form onSubmit={handleSubmit} className="space-y-6 pt-4">
                    {error && (
                        <div className="flex items-center gap-3 p-3 bg-red-50 border border-red-100 rounded-xl text-red-600 text-xs font-semibold animate-in fade-in slide-in-from-top-1">
                            <AlertCircle className="w-4 h-4 flex-shrink-0" />
                            {error}
                        </div>
                    )}

                    <div className="grid grid-cols-1 gap-4">
                        {isGlobalAdd && (
                            <>
                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Property</Label>
                                        <Select value={selectedProperty} onValueChange={setSelectedProperty}>
                                            <SelectTrigger className="bg-slate-50 border-slate-200">
                                                <SelectValue placeholder="Select Property" />
                                            </SelectTrigger>
                                            <SelectContent className="bg-white">
                                                {properties.map(p => (
                                                    <SelectItem key={p} value={p}>{p}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Unit</Label>
                                        <Select value={selectedUnit} onValueChange={setSelectedUnit}>
                                            <SelectTrigger className="bg-slate-50 border-slate-200">
                                                <SelectValue placeholder="Select Unit" />
                                            </SelectTrigger>
                                            <SelectContent className="bg-white">
                                                {units.map(u => (
                                                    <SelectItem key={u} value={u}>{u}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Utility Type</Label>
                                    <div className="flex gap-2">
                                        {["Water", "Electricity", "Gas"].map((type) => (
                                            <button
                                                key={type}
                                                type="button"
                                                onClick={() => setSelectedUtilityType(type)}
                                                className={`flex-1 py-2 px-3 rounded-lg border text-xs font-bold transition-all ${selectedUtilityType === type
                                                    ? 'bg-[#003b73] text-white border-[#003b73] shadow-md'
                                                    : 'bg-white text-slate-600 border-slate-200 hover:border-slate-300'
                                                    }`}
                                            >
                                                {type}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            </>
                        )}

                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label htmlFor="readingValue" className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">
                                    Reading Value <span className="text-red-500">*</span>
                                </Label>
                                <div className="relative">
                                    <Hash className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                                    <Input
                                        id="readingValue"
                                        type="number"
                                        step="0.01"
                                        min="0"
                                        value={readingValue}
                                        onChange={(e: React.ChangeEvent<HTMLInputElement>) => setReadingValue(e.target.value)}
                                        placeholder="0.00"
                                        disabled={isSubmitting}
                                        required
                                        className="pl-9 bg-slate-50 border-slate-200"
                                    />
                                </div>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="readingDate" className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">
                                    Reading Date <span className="text-red-500">*</span>
                                </Label>
                                <div className="relative">
                                    <Calendar className="absolute left-3 top-2.5 h-4 w-4 text-slate-400" />
                                    <Input
                                        id="readingDate"
                                        type="date"
                                        value={readingDate}
                                        onChange={(e: React.ChangeEvent<HTMLInputElement>) => setReadingDate(e.target.value)}
                                        disabled={isSubmitting}
                                        required
                                        className="pl-9 bg-slate-50 border-slate-200"
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="space-y-2">
                            <Label htmlFor="notes" className="text-[11px] font-bold text-slate-500 uppercase tracking-wider">Notes / Remarks</Label>
                            <Textarea
                                id="notes"
                                placeholder="Any observations about the meter or reading..."
                                value={notes}
                                onChange={(e) => setNotes(e.target.value)}
                                className="bg-slate-50 border-slate-200 min-h-[80px]"
                            />
                        </div>
                    </div>

                    <div className="bg-amber-50/50 border border-amber-100 rounded-xl p-3 flex items-start gap-3">
                        <AlertCircle className="w-4 h-4 text-amber-600 mt-0.5" />
                        <p className="text-[10px] text-amber-800 font-medium leading-relaxed">
                            <span className="font-bold">Important:</span> Readings are immutable once saved. Please verify the value matches the physical meter before proceeding.
                        </p>
                    </div>

                    <DialogFooter className="border-t border-slate-50 pt-6">
                        <Button
                            type="button"
                            variant="ghost"
                            onClick={handleClose}
                            disabled={isSubmitting}
                            className="text-slate-500 font-bold hover:bg-slate-100"
                        >
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            disabled={isSubmitting || !readingValue}
                            className="bg-[#003b73] hover:bg-[#002b5b] text-white px-8 h-11 font-bold rounded-xl shadow-lg shadow-blue-100 transition-all active:scale-95"
                        >
                            {isSubmitting ? (
                                <>
                                    <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                                    Submitting...
                                </>
                            ) : (
                                "Commit Reading"
                            )}
                        </Button>
                    </DialogFooter>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Plus, Gauge, ArrowLeft, Lock, Calendar } from "lucide-react";
import Link from "next/link";
import { AddReadingModal } from "./AddReadingModal";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Skeleton } from "@/components/ui/skeleton";

interface Reading {
    id: string;
    readingDate: string;
    readingValue: number;
    createdAt: string;
    unit?: { unitNumber: string };
    tenant?: { name: string };
}

interface LeaseUtility {
    id: string;
    unitNumber: string;
    tenantName: string;
}

export default function ReadingsPage() {
    const { id } = useParams();
    const utilityId = id as string;

    const [readings, setReadings] = useState<Reading[]>([]);
    const [leaseUtilities, setLeaseUtilities] = useState<LeaseUtility[]>([]);
    const [selectedLeaseUtility, setSelectedLeaseUtility] = useState<string>("");
    const [utilityName, setUtilityName] = useState<string>("Utility");
    const [utilityType, setUtilityType] = useState<"FIXED" | "METERED">("METERED");
    const [isLoading, setIsLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    useEffect(() => {
        loadData();
    }, [utilityId]);

    const loadData = async () => {
        try {
            setIsLoading(true);

            const [utilRes, readingsRes, leaseUtilRes] = await Promise.all([
                fetch(`/api/utilities/${utilityId}`),
                fetch(`/api/utilities/${utilityId}/readings`),
                fetch("/api/lease-utility"),
            ]);

            const utilData = await utilRes.json();
            const readingsData = await readingsRes.json();
            const leaseUtilData = await leaseUtilRes.json();

            const utility = utilData?.data || utilData;
            if (utility) {
                setUtilityName(utility.name || "Utility");
                setUtilityType(utility.type || "METERED");
            }

            if (readingsData.success) {
                setReadings(readingsData.data || []);
            }

            const allLeaseUtilities = leaseUtilData?.data || leaseUtilData || [];
            const filteredLeaseUtilities = allLeaseUtilities.filter(
                (lu: { utilityId: string }) => lu.utilityId === utilityId
            );
            setLeaseUtilities(filteredLeaseUtilities);
        } catch (err) {
            console.error("Load readings error:", err);
        } finally {
            setIsLoading(false);
        }
    };

    const handleReadingAdded = () => {
        loadData();
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleDateString("en-US", {
            year: "numeric",
            month: "short",
            day: "numeric",
        });
    };

    const formatDateTime = (dateString: string) => {
        return new Date(dateString).toLocaleString("en-US", {
            year: "numeric",
            month: "short",
            day: "numeric",
            hour: "2-digit",
            minute: "2-digit",
        });
    };

    // Fixed utilities don't have readings view
    if (!isLoading && utilityType === "FIXED") {
        return (
            <div className="min-h-screen bg-slate-50/50 p-6">
                <div className="max-w-4xl mx-auto space-y-6">
                    <Link href={`/property-manager/content/utilities/${utilityId}`}>
                        <Button variant="ghost" className="text-slate-600 hover:text-slate-900 hover:bg-slate-100 pl-0">
                            <ArrowLeft className="w-4 h-4 mr-2" />
                            Back to Utility
                        </Button>
                    </Link>

                    <Card className="border-slate-200 shadow-sm rounded-xl">
                        <CardContent className="p-16 text-center">
                            <div className="w-16 h-16 mx-auto bg-slate-100 rounded-full flex items-center justify-center mb-4">
                                <Gauge className="w-8 h-8 text-slate-400" />
                            </div>
                            <h3 className="text-xl font-bold text-[#0b1f3a] mb-2">
                                No Meter Readings needed
                            </h3>
                            <p className="text-slate-500 max-w-md mx-auto">
                                This utilizes a <strong>Fixed Rate</strong> billing method, which does not require meter readings.
                            </p>
                        </CardContent>
                    </Card>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-50/50 p-6">
            <div className="max-w-6xl mx-auto space-y-8">
                {/* Header */}
                <div className="flex flex-col md:flex-row items-start md:items-center justify-between gap-4">
                    <div className="space-y-1">
                        <Link href={`/property-manager/content/utilities/${utilityId}`}>
                            <Button variant="ghost" size="sm" className="text-slate-500 hover:text-slate-900 px-0 -ml-2 mb-1 h-auto py-1">
                                <ArrowLeft className="w-3.5 h-3.5 mr-1" /> Back
                            </Button>
                        </Link>
                        <h2 className="text-2xl font-bold text-[#0b1f3a] tracking-tight">Meter Readings</h2>
                        <p className="text-slate-500 text-sm">Historical readings for {utilityName}</p>
                    </div>

                    <div className="flex flex-col sm:flex-row w-full sm:w-auto gap-3">
                        <div className="w-full sm:w-[280px]">
                            <Select value={selectedLeaseUtility} onValueChange={setSelectedLeaseUtility}>
                                <SelectTrigger className="bg-white border-slate-200">
                                    <SelectValue placeholder="Select Unit to Add Reading" />
                                </SelectTrigger>
                                <SelectContent>
                                    {leaseUtilities.length === 0 ? (
                                        <div className="p-2 text-sm text-slate-500 text-center">No units assigned</div>
                                    ) : (
                                        leaseUtilities.map((lu) => (
                                            <SelectItem key={lu.id} value={lu.id}>
                                                Unit {lu.unitNumber} - {lu.tenantName}
                                            </SelectItem>
                                        ))
                                    )}
                                </SelectContent>
                            </Select>
                        </div>
                        <Button
                            onClick={() => setIsModalOpen(true)}
                            disabled={!selectedLeaseUtility}
                            className="bg-[#30D5C8] hover:bg-[#2bcbbe] text-white shadow-sm"
                        >
                            <Plus className="w-4 h-4 mr-2" />
                            Add Reading
                        </Button>
                    </div>
                </div>

                {/* Audit Notice */}
                <div className="bg-amber-50 border border-amber-200/60 rounded-lg p-4 flex items-start gap-3 shadow-sm">
                    <div className="bg-amber-100 p-1.5 rounded-full mt-0.5">
                        <Lock className="w-4 h-4 text-amber-700" />
                    </div>
                    <div>
                        <h4 className="text-sm font-semibold text-amber-900">Immutable Audit Log</h4>
                        <p className="text-sm text-amber-800/80 mt-0.5">
                            To ensure billing accuracy and audit integrity, meter readings cannot be modified or deleted once recorded.
                        </p>
                    </div>
                </div>

                {/* Readings Table */}
                <Card className="border-slate-200 shadow-sm rounded-xl overflow-hidden bg-white">
                    <CardContent className="p-0">
                        {isLoading ? (
                            <div className="p-6 space-y-4">
                                {[1, 2, 3].map(i => (
                                    <div key={i} className="flex gap-4">
                                        <Skeleton className="h-4 w-1/4" />
                                        <Skeleton className="h-4 w-1/4" />
                                        <Skeleton className="h-4 w-1/4" />
                                        <Skeleton className="h-4 w-1/4" />
                                    </div>
                                ))}
                            </div>
                        ) : readings.length === 0 ? (
                            <div className="text-center py-20 space-y-4">
                                <div className="w-16 h-16 mx-auto bg-slate-50 rounded-full flex items-center justify-center border border-slate-100">
                                    <Gauge className="w-8 h-8 text-slate-300" />
                                </div>
                                <div>
                                    <h3 className="text-lg font-medium text-[#0b1f3a]">No readings found</h3>
                                    <p className="text-slate-500 max-w-sm mx-auto mt-1">
                                        Select a unit from the dropdown above to add the first meter reading.
                                    </p>
                                </div>
                            </div>
                        ) : (
                            <Table>
                                <TableHeader className="bg-slate-50/50">
                                    <TableRow className="border-b border-slate-100 hover:bg-transparent">
                                        <TableHead className="font-semibold text-[#0b1f3a]">Reading Date</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Value</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Unit</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a]">Tenant</TableHead>
                                        <TableHead className="font-semibold text-[#0b1f3a] text-right">Recorded At</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {readings.map((reading) => (
                                        <TableRow key={reading.id} className="hover:bg-blue-50/30 border-b border-slate-50 last:border-0">
                                            <TableCell className="font-medium text-[#0b1f3a]">
                                                <div className="flex items-center gap-2">
                                                    <Calendar className="w-3.5 h-3.5 text-slate-400" />
                                                    {formatDate(reading.readingDate)}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <Badge variant="secondary" className="font-mono bg-slate-100 text-slate-700 hover:bg-slate-200">
                                                    {reading.readingValue.toLocaleString()}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-slate-600">
                                                {reading.unit?.unitNumber ?? "—"}
                                            </TableCell>
                                            <TableCell className="text-slate-600">
                                                {reading.tenant?.name ?? "—"}
                                            </TableCell>
                                            <TableCell className="text-slate-400 text-xs text-right">
                                                {formatDateTime(reading.createdAt)}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        )}
                    </CardContent>
                </Card>

                <AddReadingModal
                    isOpen={isModalOpen}
                    onClose={() => setIsModalOpen(false)}
                    onSuccess={handleReadingAdded}
                    leaseUtilityId={selectedLeaseUtility}
                    utilityId={utilityId}
                    utilityName={utilityName}
                />
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, useMemo } from "react";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Search, Download, FileText, Droplets, Zap, Flame } from "lucide-react";
import { Skeleton } from "@/components/ui/skeleton";

// ----------------------------------------------------------------------
// TYPES
// ----------------------------------------------------------------------

interface AllocationRow {
    id: string;
    unit: string;
    tenant: string;
    utility: string;
    provider: string;
    period: string; // Formatted DD/MM/YY – DD/MM/YY
    periodRaw: Date; // For sorting/filtering
    amount: number;
    basis: string;
    property: string;
    propertyId: string;
}

// ----------------------------------------------------------------------
// HELPER FUNCTIONS
// ----------------------------------------------------------------------

const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(amount);
};

// ----------------------------------------------------------------------
// MAIN COMPONENT
// ----------------------------------------------------------------------

export default function AllocationsPage() {
    const [isLoading, setIsLoading] = useState(true);
    const [allAllocations, setAllAllocations] = useState<AllocationRow[]>([]);
    const [error, setError] = useState<string | null>(null);

    // Filters
    const [filterProperty, setFilterProperty] = useState("all");
    const [filterProvider, setFilterProvider] = useState("all");
    const [filterUtility, setFilterUtility] = useState("all");
    const [filterPeriod, setFilterPeriod] = useState("all");
    const [searchQuery, setSearchQuery] = useState("");

    // Load data from API
    useEffect(() => {
        const loadData = async () => {
            setIsLoading(true);
            setError(null);

            try {
                const response = await fetch("/api/utilities/allocations");

                if (!response.ok) {
                    throw new Error("Failed to fetch allocations");
                }

                const data = await response.json();

                // Transform API response to AllocationRow format
                const rows: AllocationRow[] = data.allocations.map((alloc: {
                    id: string;
                    unit: string;
                    tenant: string;
                    utility: string;
                    provider: string;
                    period: string;
                    periodRaw: string;
                    amount: number;
                    basis: string;
                    property: string;
                    propertyId: string;
                }) => ({
                    ...alloc,
                    periodRaw: new Date(alloc.periodRaw),
                }));

                // Sort by date (newest first) then unit
                rows.sort((a, b) => {
                    return b.periodRaw.getTime() - a.periodRaw.getTime() || a.unit.localeCompare(b.unit);
                });

                setAllAllocations(rows);
            } catch (err) {
                console.error("Error loading allocations:", err);
                setError(err instanceof Error ? err.message : "An error occurred");
            } finally {
                setIsLoading(false);
            }
        };

        loadData();
    }, []);

    // Derived State: Filtered Allocations
    const filteredAllocations = useMemo(() => {
        return allAllocations.filter(row => {
            const matchesProperty = filterProperty === "all" || row.propertyId === filterProperty;
            const matchesProvider = filterProvider === "all" || row.provider === filterProvider;
            const matchesUtility = filterUtility === "all" || row.utility === filterUtility;

            // Period filter logic (grouping by Month Year)
            const rowPeriodLabel = row.periodRaw.toLocaleString('en-US', { month: 'long', year: 'numeric' });
            const matchesPeriod = filterPeriod === "all" || rowPeriodLabel === filterPeriod;

            const matchesSearch = searchQuery === "" ||
                row.tenant.toLowerCase().includes(searchQuery.toLowerCase()) ||
                row.unit.toLowerCase().includes(searchQuery.toLowerCase());

            return matchesProperty && matchesProvider && matchesUtility && matchesPeriod && matchesSearch;
        });
    }, [allAllocations, filterProperty, filterProvider, filterUtility, filterPeriod, searchQuery]);

    // Derived State: Summary Metrics
    const summary = useMemo(() => {
        const totalAmount = filteredAllocations.reduce((sum, row) => sum + row.amount, 0);
        const uniqueTenants = new Set(filteredAllocations.map(r => r.tenant)).size;

        // Determine display strings for summary
        const displayedUtility = filterUtility !== "all" ? filterUtility : "All Utilities";
        const displayedPeriod = filterPeriod !== "all" ? filterPeriod : "All Periods";

        return {
            totalAmount,
            tenantCount: uniqueTenants,
            utilityType: displayedUtility,
            period: displayedPeriod
        };
    }, [filteredAllocations, filterUtility, filterPeriod]);

    // Extract unique options for dropdowns
    const uniqueProperties = useMemo(() => {
        const props = new Map();
        allAllocations.forEach(r => props.set(r.propertyId, r.property));
        return Array.from(props.entries()).map(([id, name]) => ({ id, name }));
    }, [allAllocations]);

    const uniquePeriods = useMemo(() => {
        const periods = new Set<string>();
        allAllocations.forEach(r => {
            periods.add(r.periodRaw.toLocaleString('en-US', { month: 'long', year: 'numeric' }));
        });
        return Array.from(periods);
    }, [allAllocations]);

    const uniqueProviders = useMemo(() => {
        const providers = new Set<string>();
        allAllocations.forEach(r => providers.add(r.provider));
        return Array.from(providers).sort();
    }, [allAllocations]);


    const handleExportCSV = () => {
        const headers = ["Unit", "Tenant", "Utility", "Period", "Amount", "Basis", "Property"];
        const rows = filteredAllocations.map(r => [
            r.unit,
            r.tenant,
            r.utility,
            r.period,
            r.amount.toFixed(2),
            r.basis,
            r.property
        ]);

        const csvContent = [
            headers.join(","),
            ...rows.map(r => r.map(c => `"${c}"`).join(",")) // Quote fields to handle commas
        ].join("\n");

        const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `allocations_export_${new Date().toISOString().slice(0, 10)}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <div className="space-y-8 pb-12 max-w-[1400px] mx-auto">

            {/* 1. PAGE HEADER */}
            <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 border-b border-slate-200 pb-6">
                <div>
                    <h1 className="text-3xl font-bold text-[#003b73] tracking-tight">Cost Allocations</h1>
                    <p className="text-slate-500 mt-2 text-base">
                        Finalized utility bill distributions per tenant
                    </p>
                </div>
                <Button
                    variant="outline"
                    className="border-slate-300 text-slate-700 hover:bg-slate-50 hover:text-[#003b73]"
                    onClick={handleExportCSV}
                    disabled={filteredAllocations.length === 0}
                >
                    <Download className="w-4 h-4 mr-2" />
                    Export CSV
                </Button>
            </div>

            {/* 2. FILTER BAR */}
            <div className="flex flex-wrap items-center gap-4 bg-white p-1 rounded-lg">
                <Select value={filterProperty} onValueChange={setFilterProperty}>
                    <SelectTrigger className="w-[180px] bg-white border-slate-200">
                        <SelectValue placeholder="Property" />
                    </SelectTrigger>
                    <SelectContent className="bg-white border-slate-200 shadow-lg z-50">
                        <SelectItem value="all">All Properties</SelectItem>
                        {uniqueProperties.map(p => (
                            <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>

                <Select value={filterProvider} onValueChange={setFilterProvider}>
                    <SelectTrigger className="w-[200px] bg-white border-slate-200">
                        <SelectValue placeholder="Provider" />
                    </SelectTrigger>
                    <SelectContent className="bg-white border-slate-200 shadow-lg z-50">
                        <SelectItem value="all">All Providers</SelectItem>
                        {uniqueProviders.map(p => (
                            <SelectItem key={p} value={p}>{p}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>

                <Select value={filterUtility} onValueChange={setFilterUtility}>
                    <SelectTrigger className="w-[140px] bg-white border-slate-200">
                        <SelectValue placeholder="Utility Type" />
                    </SelectTrigger>
                    <SelectContent className="bg-white border-slate-200 shadow-lg z-50">
                        <SelectItem value="all">All Utilities</SelectItem>
                        <SelectItem value="Electricity">Electricity</SelectItem>
                        <SelectItem value="Water">Water</SelectItem>
                        <SelectItem value="Gas">Gas</SelectItem>
                    </SelectContent>
                </Select>

                <Select value={filterPeriod} onValueChange={setFilterPeriod}>
                    <SelectTrigger className="w-[160px] bg-white border-slate-200">
                        <SelectValue placeholder="Billing Period" />
                    </SelectTrigger>
                    <SelectContent className="bg-white border-slate-200 shadow-lg z-50">
                        <SelectItem value="all">All Periods</SelectItem>
                        {uniquePeriods.map(p => (
                            <SelectItem key={p} value={p}>{p}</SelectItem>
                        ))}
                    </SelectContent>
                </Select>

                <div className="relative flex-1 min-w-[200px]">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
                    <Input
                        placeholder="Search unit or tenant..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="pl-9 bg-white border-slate-200"
                    />
                </div>
            </div>

            {/* 3. SUMMARY SECTION */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="bg-white border border-slate-200 rounded-lg p-5 shadow-sm">
                    <div className="text-slate-500 text-xs font-semibold uppercase tracking-wider mb-1">Total Allocated</div>
                    <div className="text-2xl font-bold text-[#003b73]">{formatCurrency(summary.totalAmount)}</div>
                </div>
                <div className="bg-white border border-slate-200 rounded-lg p-5 shadow-sm">
                    <div className="text-slate-500 text-xs font-semibold uppercase tracking-wider mb-1">Tenants Billed</div>
                    <div className="text-2xl font-bold text-slate-900">{summary.tenantCount}</div>
                </div>
                <div className="bg-white border border-slate-200 rounded-lg p-5 shadow-sm flex items-center justify-between">
                    <div>
                        <div className="text-slate-500 text-xs font-semibold uppercase tracking-wider mb-1">Utility Type</div>
                        <div className="text-lg font-semibold text-slate-700">{summary.utilityType}</div>
                    </div>
                    {summary.utilityType === 'Electricity' && <Zap className="w-6 h-6 text-amber-500 opacity-20" />}
                    {summary.utilityType === 'Water' && <Droplets className="w-6 h-6 text-blue-500 opacity-20" />}
                    {summary.utilityType === 'Gas' && <Flame className="w-6 h-6 text-orange-500 opacity-20" />}
                </div>
                <div className="bg-white border border-slate-200 rounded-lg p-5 shadow-sm">
                    <div className="text-slate-500 text-xs font-semibold uppercase tracking-wider mb-1">Billing Period</div>
                    <div className="text-lg font-semibold text-slate-700">{summary.period}</div>
                </div>
            </div>

            {/* 4. ALLOCATION TABLE */}
            <div className="bg-white border border-slate-200 rounded-xl shadow-sm overflow-hidden">
                <Table>
                    <TableHeader className="bg-slate-50">
                        <TableRow className="border-b border-slate-200">
                            <TableHead className="w-[80px] font-bold text-slate-600 pl-6 py-4">Unit</TableHead>
                            <TableHead className="w-[160px] font-bold text-slate-600 py-4">Tenant</TableHead>
                            <TableHead className="w-[160px] font-bold text-slate-600 py-4">Property</TableHead>
                            <TableHead className="w-[180px] font-bold text-slate-600 py-4">Provider</TableHead>
                            <TableHead className="w-[100px] font-bold text-slate-600 py-4">Utility</TableHead>
                            <TableHead className="w-[160px] font-bold text-slate-600 py-4">Period</TableHead>
                            <TableHead className="w-[120px] font-bold text-slate-600 py-4">Amount</TableHead>
                            <TableHead className="font-bold text-slate-600 py-4">
                                <div className="flex items-center gap-1">
                                    Basis
                                    <span title="The calculation method used (e.g. Metered usage from submeter readings)." className="text-slate-400 hover:text-slate-600 cursor-help">
                                        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10" /><path d="M9.09 9a3 3 0 0 1 5.83 1c0 2-3 3-3 3" /><path d="M12 17h.01" /></svg>
                                    </span>
                                </div>
                            </TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {isLoading ? (
                            [...Array(5)].map((_, i) => (
                                <TableRow key={i} className="border-b border-slate-100">
                                    <TableCell className="pl-6"><Skeleton className="h-5 w-10" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-28" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-28" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-32" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-16" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-24" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-16" /></TableCell>
                                    <TableCell><Skeleton className="h-5 w-24" /></TableCell>
                                </TableRow>
                            ))
                        ) : filteredAllocations.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={8} className="h-32 text-center text-slate-400">
                                    <div className="flex flex-col items-center justify-center gap-2">
                                        <FileText className="w-8 h-8 opacity-20" />
                                        <p>No allocations found matching filters</p>
                                    </div>
                                </TableCell>
                            </TableRow>
                        ) : (
                            filteredAllocations.map((row) => (
                                <TableRow key={row.id} className="border-b border-slate-100 hover:bg-slate-50/60 transition-colors h-[64px]">
                                    <TableCell className="font-semibold text-slate-900 pl-6">
                                        {row.unit}
                                    </TableCell>
                                    <TableCell className="text-slate-700 font-medium">
                                        {row.tenant}
                                    </TableCell>
                                    <TableCell className="text-slate-600 text-sm">
                                        {row.property}
                                    </TableCell>
                                    <TableCell className="text-slate-600 text-sm">
                                        {row.provider}
                                    </TableCell>
                                    <TableCell>
                                        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border
                                            ${row.utility === 'Electricity' ? 'bg-amber-50 text-amber-700 border-amber-200' :
                                                row.utility === 'Water' ? 'bg-blue-50 text-blue-700 border-blue-200' :
                                                    row.utility === 'Gas' ? 'bg-orange-50 text-orange-700 border-orange-200' :
                                                        'bg-slate-100 text-slate-700 border-slate-200'}`}>
                                            {row.utility}
                                        </span>
                                    </TableCell>
                                    <TableCell className="text-slate-600 text-sm font-mono tracking-tight">
                                        {row.period}
                                    </TableCell>
                                    <TableCell className="font-bold text-[#003b73] text-base">
                                        {formatCurrency(row.amount)}
                                    </TableCell>
                                    <TableCell className="text-slate-500 text-sm">
                                        {row.basis}
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </div>
        </div>
    );
}

//app/(dashboard)/property-manager/content/utilities/new/page.tsx
"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Select, SelectItem, SelectTrigger, SelectValue, SelectContent } from "@/components/ui/select";
import { useRouter } from "next/navigation";
import { Toaster, toast } from "sonner";
import { ArrowLeft, Loader2 } from "lucide-react";
import Link from "next/link";

export default function NewUtilityPage() {
  const router = useRouter();
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [form, setForm] = useState({
    name: "",
    type: "FIXED",
    unitPrice: "",
    fixedAmount: "",
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!form.name.trim()) {
      toast.error("Please enter a utility name");
      return;
    }

    if (form.type === "METERED" && (!form.unitPrice || parseFloat(form.unitPrice) <= 0)) {
      toast.error("Please enter a valid unit price for metered utilities");
      return;
    }

    if (form.type === "FIXED" && (!form.fixedAmount || parseFloat(form.fixedAmount) <= 0)) {
      toast.error("Please enter a valid fixed amount");
      return;
    }

    setIsSubmitting(true);

    try {
      const res = await fetch("/api/utilities", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: form.name.trim(),
          type: form.type,
          unitPrice: form.type === "METERED" ? parseFloat(form.unitPrice) : null,
          fixedAmount: form.type === "FIXED" ? parseFloat(form.fixedAmount) : null,
        }),
      });

      const data = await res.json();

      if (data.success) {
        toast.success("Utility created successfully!");
        setTimeout(() => {
          router.push("/property-manager/content/utilities");
        }, 1000);
      } else {
        toast.error(data.error || "Failed to create utility");
        setIsSubmitting(false);
      }
    } catch (error) {
      toast.error("An error occurred while creating the utility");
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 p-6">
      <Toaster position="top-right" richColors />

      <div className="max-w-3xl mx-auto space-y-6">
        <div className="flex items-center gap-4">
          <Link href="/property-manager/content/utilities">
            <Button variant="ghost" size="sm" className="text-[#15386a] hover:text-[#0b1f3a] hover:bg-[#30D5C8]/5">
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Utilities
            </Button>
          </Link>
        </div>

        <Card className="border-slate-200 shadow-xl rounded-2xl overflow-hidden">
          <CardHeader className="bg-gradient-to-r from-[#0b1f3a] to-[#15386a] text-white">
            <CardTitle className="text-2xl">Add New Utility</CardTitle>
          </CardHeader>
          <CardContent className="p-8">
            <div className="space-y-6">
              <div className="space-y-2">
                <Label htmlFor="name" className="text-[#0b1f3a] font-semibold">
                  Utility Name <span className="text-red-500">*</span>
                </Label>
                <Input
                  id="name"
                  name="name"
                  placeholder="e.g., Electricity, Water, Gas"
                  value={form.name}
                  onChange={handleChange}
                  disabled={isSubmitting}
                  required
                  className="border-2 border-slate-200 focus:border-[#30D5C8] text-[#0b1f3a]"
                />
              </div>

              <div className="space-y-2 bg-white">
                <Label htmlFor="type" className="text-[#0b1f3a] font-semibold">
                  Billing Type <span className="text-red-500">*</span>
                </Label>
                <Select
                  value={form.type}
                  onValueChange={(v) => setForm({ ...form, type: v, unitPrice: "", fixedAmount: "" })}
                  disabled={isSubmitting}
                >
                  <SelectTrigger id="type" className="border-2 border-slate-200 focus:border-[#30D5C8] text-[#0b1f3a] bg-white">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent className="text-[#0b1f3a] bg-white">
                    <SelectItem value="FIXED">Fixed Amount (Same charge each period)</SelectItem>
                    <SelectItem value="METERED">Metered (Based on usage)</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {form.type === "METERED" && (
                <div className="space-y-2 bg-gradient-to-br from-[#30D5C8]/5 to-[#30D5C8]/10 p-5 rounded-xl border-2 border-[#30D5C8]/20">
                  <Label htmlFor="unitPrice" className="text-[#0b1f3a] font-semibold">
                    Unit Price (per unit) <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="unitPrice"
                    type="number"
                    name="unitPrice"
                    placeholder="e.g., 12.50"
                    step="0.01"
                    min="0"
                    value={form.unitPrice}
                    onChange={handleChange}
                    disabled={isSubmitting}
                    required
                    className="border-2 border-slate-200 focus:border-[#30D5C8] text-[#0b1f3a]"
                  />
                  <p className="text-sm text-[#15386a]/70">
                    Price charged per unit of consumption (e.g., per kWh, gallon, etc.)
                  </p>
                </div>
              )}

              {form.type === "FIXED" && (
                <div className="space-y-2 bg-gradient-to-br from-[#15386a]/5 to-[#15386a]/10 p-5 rounded-xl border-2 border-[#15386a]/20">
                  <Label htmlFor="fixedAmount" className="text-[#0b1f3a] font-semibold">
                    Fixed Amount <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="fixedAmount"
                    type="number"
                    name="fixedAmount"
                    placeholder="e.g., 50.00"
                    step="0.01"
                    min="0"
                    value={form.fixedAmount}
                    onChange={handleChange}
                    disabled={isSubmitting}
                    required
                    className="border-2 border-slate-200 focus:border-[#30D5C8] text-[#0b1f3a]"
                  />
                  <p className="text-sm text-[#15386a]/70">
                    Fixed amount charged each billing period
                  </p>
                </div>
              )}

              <div className="flex gap-3 pt-4">
                <Button 
                  type="button" 
                  disabled={isSubmitting} 
                  className="flex-1 bg-[#30D5C8] hover:bg-[#30D5C8]/90 text-white shadow-lg shadow-[#30D5C8]/20 hover:shadow-xl hover:shadow-[#30D5C8]/30 transition-all"
                  onClick={handleSubmit}
                >
                  {isSubmitting ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Creating...
                    </>
                  ) : (
                    "Create Utility"
                  )}
                </Button>
                <Link href="/property-manager/content/utilities" className="flex-1">
                  <Button type="button" variant="outline" className="w-full border-2 border-slate-300 text-[#0b1f3a] hover:bg-slate-50" disabled={isSubmitting}>
                    Cancel
                  </Button>
                </Link>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { 
  Users, 
  Search, 
  Phone, 
  Mail, 
  Home, 
  Building2,
  UserCircle,
  MoreHorizontal,
  MessageSquare,
  FileText,
  Filter,
  AlertCircle
} from "lucide-react";

interface Tenant {
  id: string;
  name: string;
  email: string;
  phone: string;
  property: string;
  unit: string;
  leaseStatus: "active" | "expiring" | "expired";
  moveInDate: string;
  rentAmount: number;
  balance: number;
}

export default function DirectoryPage() {
  const [searchTerm, setSearchTerm] = useState("");
  const [propertyFilter, setPropertyFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [tenants, setTenants] = useState<Tenant[]>([]);
  const [properties, setProperties] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);
        
        // Fetch tenants
        const tenantsRes = await fetch('/api/tenants');
        if (!tenantsRes.ok) throw new Error('Failed to fetch tenants');
        const tenantsData = await tenantsRes.json();
        
        // Transform API data to match interface
        const transformedTenants: Tenant[] = Array.isArray(tenantsData) ? tenantsData.map((t: any) => ({
          id: t.id,
          name: t.firstName && t.lastName ? `${t.firstName} ${t.lastName}` : t.name || 'Unknown',
          email: t.email || '',
          phone: t.phone || '',
          property: t.property?.name || t.propertyName || '',
          unit: t.unit?.unitNumber || t.unitNumber || '',
          leaseStatus: t.leaseStatus || 'active',
          moveInDate: t.moveInDate || t.createdAt?.split('T')[0] || '',
          rentAmount: t.rentAmount || t.rent || 0,
          balance: t.balance || 0
        })) : [];
        
        setTenants(transformedTenants);
        
        // Extract unique properties
        const uniqueProperties = [...new Set(transformedTenants.map(t => t.property).filter(Boolean))];
        setProperties(['all', ...uniqueProperties]);
        
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load data');
      } finally {
        setLoading(false);
      }
    };
    
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="container mx-auto py-10 max-w-6xl">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-3xl font-bold">Tenant Directory</h1>
            <p className="text-gray-500 mt-1">
              View and manage all your tenant contacts in one place.
            </p>
          </div>
        </div>
        <Card>
          <CardContent className="p-12 text-center">
            <Users className="h-12 w-12 text-gray-300 mx-auto mb-4 animate-pulse" />
            <p className="text-gray-500">Loading tenants...</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto py-10 max-w-6xl">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h1 className="text-3xl font-bold">Tenant Directory</h1>
            <p className="text-gray-500 mt-1">
              View and manage all your tenant contacts in one place.
            </p>
          </div>
        </div>
        <Card>
          <CardContent className="p-12 text-center">
            <AlertCircle className="h-12 w-12 text-red-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium mb-2">Failed to load tenants</h3>
            <p className="text-gray-500 mb-4">{error}</p>
            <Button onClick={() => window.location.reload()}>
              Retry
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }
  const filteredTenants = tenants.filter(tenant => {
    const matchesSearch = 
      tenant.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      tenant.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      tenant.phone.includes(searchTerm) ||
      tenant.unit.toLowerCase().includes(searchTerm.toLowerCase());
    
    const matchesProperty = propertyFilter === "all" || tenant.property === propertyFilter;
    const matchesStatus = statusFilter === "all" || tenant.leaseStatus === statusFilter;
    
    return matchesSearch && matchesProperty && matchesStatus;
  });

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "active":
        return <Badge className="bg-green-100 text-green-700">Active</Badge>;
      case "expiring":
        return <Badge className="bg-yellow-100 text-yellow-700">Expiring Soon</Badge>;
      case "expired":
        return <Badge className="bg-red-100 text-red-700">Expired</Badge>;
      default:
        return <Badge>{status}</Badge>;
    }
  };

  const getBalanceColor = (balance: number) => {
    if (balance === 0) return "text-green-600";
    if (balance > 10000) return "text-red-600";
    return "text-yellow-600";
  };

  return (
    <div className="container mx-auto py-10 max-w-6xl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold">Tenant Directory</h1>
          <p className="text-gray-500 mt-1">
            View and manage all your tenant contacts in one place.
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant="outline" className="text-sm">
            {tenants.length} Total Tenants
          </Badge>
        </div>
      </div>

      <Card className="mb-6">
        <CardContent className="p-4">
          <div className="flex flex-col md:flex-row items-start md:items-center gap-4">
            <div className="relative flex-1 w-full">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Search by name, email, phone, or unit..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>
            <div className="flex items-center gap-2 w-full md:w-auto">
              <select
                value={propertyFilter}
                onChange={(e) => setPropertyFilter(e.target.value)}
                className="flex h-10 w-full md:w-48 rounded-md border border-input bg-background px-3 py-2 text-sm"
              >
                <option value="all">All Properties</option>
                {properties.filter(p => p !== "all").map(prop => (
                  <option key={prop} value={prop}>{prop}</option>
                ))}
              </select>
              <select
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
                className="flex h-10 w-full md:w-40 rounded-md border border-input bg-background px-3 py-2 text-sm"
              >
                <option value="all">All Status</option>
                <option value="active">Active</option>
                <option value="expiring">Expiring</option>
                <option value="expired">Expired</option>
              </select>
              <Button variant="outline">
                <Filter className="h-4 w-4 mr-2" />
                More
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-500">Total Tenants</p>
                <p className="text-2xl font-bold">{tenants.length}</p>
              </div>
              <Users className="h-8 w-8 text-blue-500" />
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-500">Active Leases</p>
                <p className="text-2xl font-bold">{tenants.filter(t => t.leaseStatus === "active").length}</p>
              </div>
              <Badge className="bg-green-100 text-green-700">Active</Badge>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-500">Expiring Soon</p>
                <p className="text-2xl font-bold">{tenants.filter(t => t.leaseStatus === "expiring").length}</p>
              </div>
              <Badge className="bg-yellow-100 text-yellow-700">Warning</Badge>
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-500">Outstanding Balance</p>
                <p className="text-2xl font-bold">
                  KES {tenants.reduce((sum, t) => sum + t.balance, 0).toLocaleString()}
                </p>
              </div>
              <Badge className="bg-red-100 text-red-700">Due</Badge>
            </div>
          </CardContent>
        </Card>
      </div>

      <Card>
        <CardContent className="p-0">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Tenant</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Property / Unit</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Contact</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Lease Status</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Rent</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Balance</th>
                <th className="px-4 py-3 text-right text-sm font-medium text-gray-500">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {filteredTenants.map(tenant => (
                <tr key={tenant.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-3">
                      <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center">
                        <UserCircle className="h-6 w-6 text-blue-600" />
                      </div>
                      <div>
                        <p className="font-medium">{tenant.name}</p>
                        <p className="text-xs text-gray-500">Since {tenant.moveInDate}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex items-center gap-2 text-sm">
                      <Building2 className="h-4 w-4 text-gray-400" />
                      <div>
                        <p>{tenant.property}</p>
                        <p className="text-gray-500">{tenant.unit}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    <div className="space-y-1">
                      <div className="flex items-center gap-2 text-sm">
                        <Phone className="h-3 w-3 text-gray-400" />
                        {tenant.phone}
                      </div>
                      <div className="flex items-center gap-2 text-sm text-gray-500">
                        <Mail className="h-3 w-3" />
                        {tenant.email}
                      </div>
                    </div>
                  </td>
                  <td className="px-4 py-3">
                    {getStatusBadge(tenant.leaseStatus)}
                  </td>
                  <td className="px-4 py-3">
                    <span className="text-sm font-medium">
                      KES {tenant.rentAmount.toLocaleString()}
                    </span>
                  </td>
                  <td className="px-4 py-3">
                    <span className={`text-sm font-medium ${getBalanceColor(tenant.balance)}`}>
                      {tenant.balance === 0 ? "— " : `KES ${tenant.balance.toLocaleString()}`}
                    </span>
                  </td>
                  <td className="px-4 py-3 text-right">
                    <div className="flex items-center justify-end gap-1">
                      <Button variant="ghost" size="icon" title="Send Message">
                        <MessageSquare className="h-4 w-4" />
                      </Button>
                      <Button variant="ghost" size="icon" title="View Lease">
                        <FileText className="h-4 w-4" />
                      </Button>
                      <Button variant="ghost" size="icon">
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </CardContent>
      </Card>

      {filteredTenants.length === 0 && (
        <Card>
          <CardContent className="p-12 text-center">
            <Users className="h-12 w-12 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium mb-2">No tenants found</h3>
            <p className="text-gray-500">
              {searchTerm ? "Try adjusting your search or filters" : "Add tenants to your properties to see them here"}
            </p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { 
  FolderOpen, 
  FileText, 
  File, 
  Search, 
  Upload,
  MoreHorizontal,
  Download,
  Eye,
  Trash2,
  Filter,
  Grid,
  List,
  Home,
  Building2
} from "lucide-react";

interface Document {
  id: string;
  name: string;
  type: string;
  category: string;
  size: string;
  uploadedAt: string;
  property?: string;
  unit?: string;
  status: "active" | "archived";
}

interface Folder {
  id: string;
  name: string;
  count: number;
  icon: string;
}

export default function DocumentsPage() {
  const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [folders, setFolders] = useState<Folder[]>([]);
  const [documents, setDocuments] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);
        
        // Fetch documents from API
        const res = await fetch('/api/dss/documents');
        if (!res.ok) throw new Error('Failed to fetch documents');
        const data = await res.json();
        
        const docs: Document[] = Array.isArray(data) ? data.map((d: any) => ({
          id: d.id,
          name: d.name || d.fileName || 'Untitled',
          type: d.type || 'PDF',
          category: d.category || 'Other',
          size: d.size || '0 KB',
          uploadedAt: d.createdAt?.split('T')[0] || new Date().toISOString().split('T')[0],
          property: d.property?.name || '',
          unit: d.unit?.unitNumber || '',
          status: d.status || 'active'
        })) : [];
        
        setDocuments(docs);
        
        // Generate folders from document categories
        const categories = [...new Set(docs.map(d => d.category))];
        const folderData: Folder[] = categories.map(cat => ({
          id: cat.toLowerCase(),
          name: cat,
          count: docs.filter(d => d.category === cat).length,
          icon: 'FileText'
        }));
        setFolders(folderData);
        
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load documents');
      } finally {
        setLoading(false);
      }
    };
    
    fetchData();
  }, []);

  const filteredDocuments = documents.filter(doc => {
    const matchesSearch = doc.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === "all" || doc.category.toLowerCase() === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const getCategoryColor = (category: string) => {
    switch (category) {
      case "Leases": return "bg-blue-100 text-blue-700";
      case "Invoices": return "bg-green-100 text-green-700";
      case "Maintenance": return "bg-orange-100 text-orange-700";
      case "Applications": return "bg-purple-100 text-purple-700";
      case "ID Documents": return "bg-teal-100 text-teal-700";
      case "Insurance": return "bg-red-100 text-red-700";
      default: return "bg-gray-100 text-gray-700";
    }
  };

  return (
    <div className="container mx-auto py-10 max-w-6xl">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold">Documents</h1>
          <p className="text-gray-500 mt-1">
            Manage all your property documents in one place.
          </p>
        </div>
        <div className="flex items-center gap-2">
          <Button variant="outline">
            <Filter className="h-4 w-4 mr-2" />
            Filter
          </Button>
          <Button>
            <Upload className="h-4 w-4 mr-2" />
            Upload Document
          </Button>
        </div>
      </div>

      {/* Folders Grid */}
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-8">
        {folders.map(folder => (
          <Card 
            key={folder.id} 
            className="cursor-pointer hover:shadow-md transition-shadow"
            onClick={() => setSelectedCategory(folder.name.toLowerCase())}
          >
            <CardContent className="p-4">
              <div className="flex flex-col items-center text-center">
                <div className="p-3 bg-blue-100 rounded-lg mb-3">
                  <FolderOpen className="h-6 w-6 text-blue-600" />
                </div>
                <h3 className="font-medium text-sm">{folder.name}</h3>
                <p className="text-xs text-gray-500">{folder.count} files</p>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Search and View Toggle */}
      <Card className="mb-6">
        <CardContent className="p-4">
          <div className="flex items-center justify-between gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Search documents..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>
            <div className="flex items-center gap-2">
              <Button
                variant={viewMode === "grid" ? "default" : "ghost"}
                size="icon"
                onClick={() => setViewMode("grid")}
              >
                <Grid className="h-4 w-4" />
              </Button>
              <Button
                variant={viewMode === "list" ? "default" : "ghost"}
                size="icon"
                onClick={() => setViewMode("list")}
              >
                <List className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Documents Display */}
      {viewMode === "grid" ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {filteredDocuments.map(doc => (
            <Card key={doc.id} className="hover:shadow-md transition-shadow">
              <CardContent className="p-4">
                <div className="flex items-start justify-between mb-3">
                  <div className="p-2 bg-gray-100 rounded-lg">
                    <FileText className="h-6 w-6 text-gray-600" />
                  </div>
                  <Badge className={getCategoryColor(doc.category)}>
                    {doc.category}
                  </Badge>
                </div>
                <h4 className="font-medium text-sm mb-1 truncate">{doc.name}</h4>
                <p className="text-xs text-gray-500 mb-3">{doc.size} • {doc.uploadedAt}</p>
                <div className="flex items-center gap-1 text-xs text-gray-500">
                  <Home className="h-3 w-3" />
                  {doc.property}
                  {doc.unit && ` / ${doc.unit}`}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      ) : (
        <Card>
          <CardContent className="p-0">
            <table className="w-full">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Name</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Category</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Property</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Size</th>
                  <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Date</th>
                  <th className="px-4 py-3 text-right text-sm font-medium text-gray-500">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredDocuments.map(doc => (
                  <tr key={doc.id} className="hover:bg-gray-50">
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-3">
                        <FileText className="h-5 w-5 text-gray-400" />
                        <span className="font-medium">{doc.name}</span>
                      </div>
                    </td>
                    <td className="px-4 py-3">
                      <Badge className={getCategoryColor(doc.category)}>
                        {doc.category}
                      </Badge>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2 text-sm">
                        <Building2 className="h-4 w-4 text-gray-400" />
                        {doc.property}
                        {doc.unit && <span className="text-gray-400">/ {doc.unit}</span>}
                      </div>
                    </td>
                    <td className="px-4 py-3 text-sm text-gray-500">{doc.size}</td>
                    <td className="px-4 py-3 text-sm text-gray-500">{doc.uploadedAt}</td>
                    <td className="px-4 py-3 text-right">
                      <div className="flex items-center justify-end gap-1">
                        <Button variant="ghost" size="icon">
                          <Eye className="h-4 w-4" />
                        </Button>
                        <Button variant="ghost" size="icon">
                          <Download className="h-4 w-4" />
                        </Button>
                        <Button variant="ghost" size="icon">
                          <Trash2 className="h-4 w-4 text-red-500" />
                        </Button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </CardContent>
        </Card>
      )}

      {/* Empty State */}
      {filteredDocuments.length === 0 && (
        <Card>
          <CardContent className="p-12 text-center">
            <File className="h-12 w-12 text-gray-300 mx-auto mb-4" />
            <h3 className="text-lg font-medium mb-2">No documents found</h3>
            <p className="text-gray-500 mb-4">
              {searchTerm ? "Try adjusting your search terms" : "Upload your first document to get started"}
            </p>
            <Button>
              <Upload className="h-4 w-4 mr-2" />
              Upload Document
            </Button>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { toast } from "sonner";
import { fetchInvoiceById } from "@/lib/Invoice";
import { UtilityItem } from "@/app/data/FinanceData";

interface Invoice {
  id: string;
  lease_id: string;
  type: "RENT" | "UTILITY";
  amount: number;
  dueDate: string;
  status: "PENDING" | "PAID" | "OVERDUE";
  postingStatus: "PENDING" | "POSTED" | "FAILED";
  createdAt: string;
  updatedAt: string;
  Lease?: {
    tenant?: {
      firstName?: string;
      lastName?: string;
    };
    property?: {
      buildingName?: string | null;
    };
  };
}

interface InvoiceWithUtilities extends Invoice {
  utilities?: UtilityItem[];
}

export default function InvoiceDetailsPage() {
  const { id } = useParams();
  const [invoice, setInvoice] = useState<InvoiceWithUtilities>();
  const [loading, setLoading] = useState(true);
  const router = useRouter();

  useEffect(() => {
    if (!id) return;

    const invoiceId = Array.isArray(id) ? id[0] : id;

    const loadInvoice = async () => {
      try {
        const data = await fetchInvoiceById(invoiceId);
        setInvoice(data);
      } catch (err: any) {
        toast.error(err.message || "Unable to load invoice details");
      } finally {
        setLoading(false);
      }
    };

    loadInvoice();
  }, [id]);

  if (loading) return <p className="text-center py-20 text-gray-500">Loading...</p>;
  if (!invoice) return <p className="text-center py-20 text-gray-500">Invoice not found</p>;

  // Only calculate utility total if invoice type is UTILITY
  const utilityTotal =
    invoice.type === "UTILITY" && invoice.utilities
      ? invoice.utilities.reduce((sum, u) => {
        const total = u.type === "METERED" ? (u.units ?? 0) * (u.unitPrice ?? 0) : u.fixedAmount ?? u.amount ?? 0;
        return sum + total;
      }, 0)
      : 0;


  const buildingName =
    invoice.Lease?.property?.buildingName ||
    "—";
  return (
    <div className="min-h-screen bg-gray-50 p-6 md:p-12 space-y-6">
      <div className="flex items-center mb-8">
        <h1 className="text-3xl font-bold ml-6 text-gray-800">Invoice Details</h1>
      </div>

      {/* General Info */}
      <div className="bg-white rounded-2xl shadow p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Invoice ID</p>
          <p className="font-mono text-gray-800">{invoice.id}</p>
        </div>
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Lease ID</p>
          <p className="text-gray-800">{invoice.lease_id}</p>
        </div>
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Type</p>
          <p className="text-gray-800">{invoice.type}</p>
        </div>
        {invoice.type === "RENT" && (
          <div>
            <p className="text-sm font-semibold text-gray-500 uppercase">Amount</p>
            <p className="font-semibold text-gray-900">$ {invoice.amount.toLocaleString()}</p>
          </div>
        )}
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Due Date</p>
          <p className="text-gray-800">{new Date(invoice.dueDate).toLocaleDateString()}</p>
        </div>
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Status</p>
          <span
            className={`inline-block px-3 py-1 rounded-full text-sm font-semibold ${invoice.status === "PAID"
              ? "bg-navy-100 text-navy-900"
              : invoice.status === "OVERDUE"
                ? "bg-red-100 text-red-700"
                : "bg-yellow-100 text-yellow-700"
              }`}
          >
            {invoice.status}
          </span>
        </div>
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">GL Posting Status</p>
          <span
            className={`inline-block px-3 py-1 rounded-full text-sm font-semibold ${invoice.postingStatus === "POSTED"
              ? "bg-green-100 text-green-700"
              : "bg-gray-100 text-gray-600"
              }`}
          >
            {invoice.postingStatus || "PENDING"}
          </span>
        </div>
      </div>

      {/* Tenant & Property */}
      <div className="bg-white rounded-2xl shadow p-6 grid grid-cols-1 md:grid-cols-2 gap-6">
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Tenant</p>
          <p className="text-gray-800">
            {invoice.Lease?.tenant
              ? `${invoice.Lease.tenant?.firstName ?? ''} ${invoice.Lease.tenant?.lastName ?? ''}`.trim() || "—"
              : "—"}
          </p>
        </div>
        <div>
          <p className="text-sm font-semibold text-gray-500 uppercase">Property</p>
          <p className="text-gray-800">{buildingName}</p>
        </div>
      </div>

      {/* Utility Breakdown — only for UTILITY invoices */}
      {invoice.type === "UTILITY" && invoice.utilities && invoice.utilities.length > 0 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">💧 Utility Breakdown</h3>

          <div className="overflow-x-auto">
            <table className="min-w-full border border-gray-200 rounded-lg">
              <thead className="bg-gray-100">
                <tr>
                  <th className="text-left py-3 px-4 text-sm font-semibold text-gray-600">Utility</th>
                  <th className="text-left py-3 px-4 text-sm font-semibold text-gray-600">Type</th>
                  <th className="text-left py-3 px-4 text-sm font-semibold text-gray-600">Units</th>
                  <th className="text-left py-3 px-4 text-sm font-semibold text-gray-600">Price / Unit</th>
                  <th className="text-left py-3 px-4 text-sm font-semibold text-gray-600">Total</th>
                </tr>
              </thead>
              <tbody>
                {invoice.utilities.map((u) => {
                  const total =
                    u.type === "METERED" ? (u.units ?? 0) * (u.unitPrice ?? 0) : u.fixedAmount ?? u.amount ?? 0;
                  return (
                    <tr key={u.id} className="border-t border-gray-100">
                      <td className="py-3 px-4 text-gray-800">{u.name}</td>
                      <td className="py-3 px-4 text-gray-800">{u.type}</td>
                      <td className="py-3 px-4 text-gray-800">{u.type === "METERED" ? u.units ?? 0 : "—"}</td>
                      <td className="py-3 px-4 text-gray-800">
                        {u.type === "METERED"
                          ? `$ ${(u.unitPrice ?? 0).toLocaleString()}`
                          : u.fixedAmount
                            ? `$ ${u.fixedAmount.toLocaleString()}`
                            : "—"}
                      </td>
                      <td className="py-3 px-4 text-gray-800 font-semibold">$ {total.toLocaleString()}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          <div className="flex justify-end mt-4 border-t pt-4">
            <p className="font-bold text-gray-900">Total: $ {utilityTotal.toLocaleString()}</p>
          </div>
        </div>
      )}

      {/* Metadata */}
      <div className="bg-white rounded-2xl shadow p-6 flex flex-col md:flex-row justify-between items-start md:items-center">
        <div className="text-sm text-gray-500">
          <p>Created: {new Date(invoice.createdAt).toLocaleString()}</p>
          <p>Last Updated: {new Date(invoice.updatedAt).toLocaleString()}</p>
        </div>

        <button
          onClick={() => console.log("Payments button clicked")}
          className="mt-4 md:mt-0 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition"
        >
          Check Payments
        </button>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState, useMemo } from "react";
import { useParams, useRouter } from "next/navigation";
import { toast } from "sonner";
import { fetchInvoices } from "@/lib/Invoice";
import { GroupedInvoice, Invoice, Payment } from "@/app/data/FinanceData";
import Link from "next/link";

interface LeaseInfo {
  tenant?: {
    id?: string;
    firstName?: string;
    lastName?: string;
    email?: string;
  };
  property?: {
    name?: string;
    address?: string;
    buildingName?: string;
  };
  unit?: {
    id?: string;
    unitNumber?: string;
    unitName?: string;
  };
}

export default function LeaseInvoiceGroupPage() {
  const { id } = useParams();
  const [groupedInvoices, setGroupedInvoices] = useState<GroupedInvoice[]>([]);
  const [loading, setLoading] = useState(true);
  const [leaseInfo, setLeaseInfo] = useState<LeaseInfo | null>(null);
  const router = useRouter();

  useEffect(() => {
    if (!id) return;

    const leaseId = Array.isArray(id) ? id[0] : id;

    const loadInvoices = async () => {
      try {
        setLoading(true);
        const data = await fetchInvoices({ lease_id: leaseId });
        
        // data is GroupedInvoice[]
        setGroupedInvoices(data);
        
        // Extract lease info from first invoice if available
        if (data.length > 0 && data[0].invoices.length > 0) {
          const firstInvoice = data[0].invoices[0];
          setLeaseInfo({
            tenant: firstInvoice.Lease?.tenant,
            property: firstInvoice.Lease?.property,
            unit: firstInvoice.Lease?.unit,
          });
        }
      } catch (err: unknown) {
        const errorMessage = err instanceof Error ? err.message : "Unable to load lease invoices";
        toast.error(errorMessage);
        setGroupedInvoices([]);
      } finally {
        setLoading(false);
      }
    };

    loadInvoices();
  }, [id]);

  // Calculate totals across all invoices
  const financialSummary = useMemo(() => {
    let totalAmount = 0;
    let totalPaid = 0;
    let totalBalance = 0;
    
    groupedInvoices.forEach(group => {
      totalAmount += group.totalAmount || 0;
      
      group.invoices.forEach(invoice => {
        const invoicePaid = invoice.payment?.reduce((sum: number, p: Payment) => 
          sum + (p.amount || 0), 0) || 0;
        totalPaid += invoicePaid;
      });
    });
    
    totalBalance = totalAmount - totalPaid;
    
    return {
      totalAmount,
      totalPaid,
      totalBalance,
      invoiceCount: groupedInvoices.reduce((count, group) => count + group.invoices.length, 0),
      groupCount: groupedInvoices.length,
    };
  }, [groupedInvoices]);

  // Download PDF function
  const downloadPDF = async () => {
    if (groupedInvoices.length === 0) {
      toast.error("No invoices to download");
      return;
    }

    const { default: jsPDF } = await import("jspdf");
    const { default: autoTable } = await import("jspdf-autotable");

    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text(`Lease Invoices - ${id}`, 14, 22);
    
    // Add lease info if available
    if (leaseInfo) {
      doc.setFontSize(11);
      const tenantName = `${leaseInfo.tenant?.firstName || ''} ${leaseInfo.tenant?.lastName || ''}`.trim();
      if (tenantName) {
        doc.text(`Tenant: ${tenantName}`, 14, 35);
      }
      if (leaseInfo.property?.buildingName) {
        doc.text(`Property: ${leaseInfo.property.buildingName}`, 14, 42);
      }
      if (leaseInfo.unit?.unitNumber) {
        doc.text(`Unit: ${leaseInfo.unit.unitNumber}`, 14, 49);
      }
    }

    // Grouped invoice table
    const tableColumn = ["Due Date", "Invoice Count", "Total Amount", "Status"];
    const tableRows: string[][] = [];

    groupedInvoices.forEach((group) => {
      const dateStr = new Date(group.date).toLocaleDateString();
      const status = group.invoices.some(inv => inv.status === "OVERDUE") 
        ? "OVERDUE" 
        : group.invoices.every(inv => inv.status === "PAID") 
          ? "PAID" 
          : "PENDING";
      
      tableRows.push([
        dateStr,
        group.invoices.length.toString(),
        `$${group.totalAmount.toLocaleString()}`,
        status,
      ]);
    });

    autoTable(doc, {
      startY: leaseInfo ? 60 : 30,
      head: [tableColumn],
      body: tableRows,
      styles: { fontSize: 10 },
    });

    // Financial summary
    const summaryY = (doc as jsPDF & { lastAutoTable?: { finalY: number } }).lastAutoTable?.finalY || 0 + 10;
    doc.setFontSize(12);
    doc.text("Financial Summary", 14, summaryY);
    doc.setFontSize(10);
    doc.text(`Total Amount: $${financialSummary.totalAmount.toLocaleString()}`, 14, summaryY + 8);
    doc.text(`Total Paid: $${financialSummary.totalPaid.toLocaleString()}`, 14, summaryY + 16);
    doc.text(`Balance Due: $${financialSummary.totalBalance.toLocaleString()}`, 14, summaryY + 24);

    doc.save(`Lease-${id}-Invoices-${new Date().toISOString().split('T')[0]}.pdf`);
  };

  // Navigate to individual invoice
  const viewInvoiceDetails = (invoiceId: string) => {
    router.push(`/property-manager/finance/invoices/${invoiceId}`);
  };

  if (loading) return <p className="text-center py-20 text-gray-500">Loading lease invoices...</p>;
  
  const leaseId = Array.isArray(id) ? id[0] : id;

  return (
    <div className="min-h-screen bg-gray-50 p-6 md:p-12 space-y-6">
      {/* Header with back button */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center">
          <button
            onClick={() => router.push("/property-manager/finance/invoices")}
            className="mr-4 p-2 rounded-lg hover:bg-gray-100 transition"
          >
            ← Back to Invoices
          </button>
          <div>
            <h1 className="text-3xl font-bold text-gray-800">Lease Invoice Group</h1>
            <p className="text-gray-600 font-mono mt-1">Lease ID: {leaseId}</p>
          </div>
        </div>
        
        <div className="flex gap-3">
          <button
            onClick={downloadPDF}
            className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow-md hover:shadow-lg transition-all duration-200 flex items-center gap-2 font-medium"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
            Download PDF
          </button>
          
          <Link
            href={`/property-manager/finance/invoices/create?leaseId=${leaseId}`}
            className="bg-green-600 hover:bg-green-700 text-white px-5 py-2 rounded-lg shadow-md hover:shadow-lg transition-all duration-200 flex items-center gap-2 font-medium"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            Create Invoice
          </Link>
        </div>
      </div>

      {/* Lease Information Card */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h2 className="text-xl font-semibold mb-4 flex items-center gap-2">
          <span className="text-blue-600">📋</span> Lease Information
        </h2>
        
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div>
            <p className="text-sm font-semibold text-gray-500 uppercase">Tenant</p>
            <p className="text-gray-800 text-lg font-medium">
              {leaseInfo?.tenant 
                ? `${leaseInfo.tenant.firstName || ''} ${leaseInfo.tenant.lastName || ''}`.trim() || "—"
                : "—"}
            </p>
            {leaseInfo?.tenant?.email && (
              <p className="text-gray-600 text-sm mt-1">{leaseInfo.tenant.email}</p>
            )}
          </div>
          
          <div>
            <p className="text-sm font-semibold text-gray-500 uppercase">Property</p>
            <p className="text-gray-800 text-lg font-medium">
              {leaseInfo?.property?.buildingName || leaseInfo?.property?.name || "—"}
            </p>
            {leaseInfo?.property?.address && (
              <p className="text-gray-600 text-sm mt-1">{leaseInfo.property.address}</p>
            )}
          </div>
          
          <div>
            <p className="text-sm font-semibold text-gray-500 uppercase">Unit</p>
            <p className="text-gray-800 text-lg font-medium">
              {leaseInfo?.unit?.unitName || leaseInfo?.unit?.unitNumber || "—"}
            </p>
            <div className="flex gap-4 mt-4">
              <button
                onClick={() => router.push(`/property-manager/finance/tenants/${leaseInfo?.tenant?.id}`)}
                className="text-blue-600 hover:text-blue-800 text-sm font-medium"
              >
                View Tenant →
              </button>
              <button
                onClick={() => router.push(`/property-manager/content/payments?leaseId=${leaseId}`)}
                className="text-green-600 hover:text-green-800 text-sm font-medium"
              >
                Check Payments →
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Financial Summary Card */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h2 className="text-xl font-semibold mb-6 flex items-center gap-2">
          <span className="text-green-600">💰</span> Financial Summary
        </h2>
        
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <div className="bg-blue-50 p-4 rounded-xl">
            <p className="text-sm font-semibold text-blue-600 uppercase">Total Invoices</p>
            <p className="text-3xl font-bold text-blue-800">{financialSummary.invoiceCount}</p>
            <p className="text-sm text-blue-600 mt-1">{financialSummary.groupCount} due date groups</p>
          </div>
          
          <div className="bg-green-50 p-4 rounded-xl">
            <p className="text-sm font-semibold text-green-600 uppercase">Total Amount</p>
            <p className="text-3xl font-bold text-green-800">$ {financialSummary.totalAmount.toLocaleString()}</p>
            <p className="text-sm text-green-600 mt-1">All invoices combined</p>
          </div>
          
          <div className="bg-navy-50 p-4 rounded-xl">
            <p className="text-sm font-semibold text-navy-600 uppercase">Total Paid</p>
            <p className="text-3xl font-bold text-navy-800">$ {financialSummary.totalPaid.toLocaleString()}</p>
            <p className="text-sm text-navy-600 mt-1">Received payments</p>
          </div>
          
          <div className={`p-4 rounded-xl ${financialSummary.totalBalance > 0 ? 'bg-red-50' : 'bg-gray-50'}`}>
            <p className="text-sm font-semibold uppercase">Balance Due</p>
            <p className={`text-3xl font-bold ${financialSummary.totalBalance > 0 ? 'text-red-700' : 'text-gray-700'}`}>
              $ {financialSummary.totalBalance.toLocaleString()}
            </p>
            <p className={`text-sm mt-1 ${financialSummary.totalBalance > 0 ? 'text-red-600' : 'text-gray-600'}`}>
              {financialSummary.totalBalance > 0 ? 'Outstanding balance' : 'Fully paid'}
            </p>
          </div>
        </div>
      </div>

      {/* Grouped Invoices Table */}
      <div className="bg-white rounded-2xl shadow overflow-hidden">
        <div className="p-6 border-b border-gray-200">
          <h2 className="text-xl font-semibold flex items-center gap-2">
            <span className="text-purple-600">📄</span> Grouped Invoices by Due Date
          </h2>
          <p className="text-gray-600 mt-1">Invoices grouped by their due date for this lease</p>
        </div>
        
        {groupedInvoices.length === 0 ? (
          <div className="p-12 text-center">
            <div className="text-gray-400 text-6xl mb-4">📭</div>
            <h3 className="text-xl font-medium text-gray-700">No invoices found</h3>
            <p className="text-gray-500 mt-2">This lease doesn't have any invoices yet.</p>
            <Link
              href={`/property-manager/finance/invoices/create?leaseId=${leaseId}`}
              className="inline-block mt-4 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition"
            >
              Create First Invoice
            </Link>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                    Due Date
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                    Invoice Count
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                    Total Amount
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                    Status
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-700 uppercase tracking-wider">
                    Actions
                  </th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {groupedInvoices.map((group, index) => {
                  const dateStr = new Date(group.date).toLocaleDateString();
                  const isOverdue = group.invoices.some(inv => inv.status === "OVERDUE");
                  const isPaid = group.invoices.every(inv => inv.status === "PAID");
                  const isPartiallyPaid = group.invoices.some(inv => inv.status === "PAID") && !isPaid;
                  
                  let statusColor = "bg-yellow-100 text-yellow-800";
                  let statusText = "PENDING";
                  
                  if (isOverdue) {
                    statusColor = "bg-red-100 text-red-800";
                    statusText = "OVERDUE";
                  } else if (isPaid) {
                    statusColor = "bg-green-100 text-green-800";
                    statusText = "PAID";
                  } else if (isPartiallyPaid) {
                    statusColor = "bg-blue-100 text-blue-800";
                    statusText = "PARTIAL";
                  }
                  
                  return (
                    <tr key={`${group.date}-${index}`} className="hover:bg-gray-50 transition">
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-gray-900 font-medium">{dateStr}</div>
                        <div className="text-gray-500 text-sm">
                          {new Date(group.date).toLocaleDateString('en-US', { weekday: 'long' })}
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-medium bg-gray-100 text-gray-800">
                          {group.invoices.length} invoice{group.invoices.length !== 1 ? 's' : ''}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <div className="text-gray-900 font-bold">$ {group.totalAmount.toLocaleString()}</div>
                        {group.totalPaid !== undefined && group.totalPaid > 0 && (
                          <div className="text-gray-600 text-sm">
                            Paid: $ {group.totalPaid.toLocaleString()}
                          </div>
                        )}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-medium ${statusColor}`}>
                          {statusText}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                        <div className="flex gap-2">
                          <button
                            onClick={() => {
                              // Show invoice details for this group
                              const invoiceIds = group.invoices.map(inv => inv.id);
                              if (invoiceIds.length === 1) {
                                viewInvoiceDetails(invoiceIds[0]);
                              } else {
                                // For multiple invoices, we could show a modal or expand the row
                                toast.info(`${group.invoices.length} invoices in this group. Click individual invoices below.`);
                              }
                            }}
                            className="text-blue-600 hover:text-blue-900"
                          >
                            View Details
                          </button>
                          <button
                            onClick={() => {
                              // Generate PDF for just this group
                              toast.success("PDF generation for this group would be implemented");
                            }}
                            className="text-purple-600 hover:text-purple-900"
                          >
                            Download
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
        
        {/* Individual Invoice Details (collapsible if needed) */}
        {groupedInvoices.length > 0 && (
          <div className="border-t border-gray-200 p-6">
            <h3 className="text-lg font-semibold mb-4">All Individual Invoices</h3>
            <div className="space-y-4">
              {groupedInvoices.flatMap((group, groupIndex) => 
                group.invoices.map((invoice, invoiceIndex) => {
                  const paidAmount = invoice.payment?.reduce((sum: number, p: Payment) => 
                    sum + (p.amount || 0), 0) || 0;
                  const balance = invoice.amount - paidAmount;
                  
                  return (
                    <div 
                      key={`${groupIndex}-${invoiceIndex}`} 
                      className="border border-gray-200 rounded-lg p-4 hover:border-blue-300 transition cursor-pointer"
                      onClick={() => viewInvoiceDetails(invoice.id)}
                    >
                      <div className="flex justify-between items-center">
                        <div>
                          <div className="flex items-center gap-3">
                            <span className={`inline-block px-3 py-1 rounded-full text-xs font-semibold ${
                              invoice.status === "PAID" 
                                ? "bg-green-100 text-green-800" 
                                : invoice.status === "OVERDUE" 
                                  ? "bg-red-100 text-red-800" 
                                  : "bg-yellow-100 text-yellow-800"
                            }`}>
                              {invoice.status}
                            </span>
                            <span className="font-mono text-sm text-gray-600">{invoice.id.slice(0, 8)}...</span>
                            <span className="text-gray-700 font-medium">{invoice.type}</span>
                          </div>
                          <p className="text-gray-600 text-sm mt-1">
                            Due: {new Date(invoice.dueDate).toLocaleDateString()}
                          </p>
                        </div>
                        
                        <div className="text-right">
                          <p className="text-lg font-bold text-gray-900">$ {invoice.amount.toLocaleString()}</p>
                          <div className="flex gap-4 text-sm text-gray-600">
                            <span>Paid: $ {paidAmount.toLocaleString()}</span>
                            <span>Balance: $ {balance.toLocaleString()}</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        )}
      </div>

      {/* Action Buttons Footer */}
      <div className="bg-white rounded-2xl shadow p-6 flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div className="text-sm text-gray-500">
          <p>Showing invoices for lease: <span className="font-mono">{leaseId}</span></p>
          <p>Last updated: {new Date().toLocaleDateString()}</p>
        </div>
        
        <div className="flex flex-wrap gap-3">
          <Link
            href={`/property-manager/finance/invoices/create?leaseId=${leaseId}&type=RENT`}
            className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg transition flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
            Create Rent Invoice
          </Link>
          
          <Link
            href={`/property-manager/finance/invoices/create?leaseId=${leaseId}&type=UTILITY`}
            className="bg-green-600 hover:bg-green-700 text-white px-5 py-2 rounded-lg transition flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
            Create Utility Invoice
          </Link>
          
          <button
            onClick={() => router.push(`/property-manager/content/payments?leaseId=${leaseId}`)}
            className="bg-purple-600 hover:bg-purple-700 text-white px-5 py-2 rounded-lg transition flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            Manage Payments
          </button>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { fetchInvoices } from "@/lib/Invoice";
import { GroupedInvoice } from "@/app/data/FinanceData";
import { toast } from "sonner";
import CreateInvoiceModal from "@/components/Dashboard/propertymanagerdash/CreateInvoiceModal";

export default function InvoicesPage() {
  const [invoiceGroups, setInvoiceGroups] = useState<GroupedInvoice[]>([]);
  const [status, setStatus] = useState<string>("");
  const [type, setType] = useState<string>("");
  const router = useRouter();

  const loadInvoices = async () => {
    try {
      const filters: any = {};
      if (status) filters.status = status;
      if (type) filters.type = type;

      const data = await fetchInvoices(filters);

      // data is now GroupedInvoice[]
      setInvoiceGroups(data);
    } catch (error) {
      toast.error("Failed to load invoices");
    }
  };

  useEffect(() => {
    loadInvoices();
  }, [status, type]);

  // --- PDF Download function ---
  const downloadPDF = async () => {
    if (invoiceGroups.length === 0) {
      toast.error("No invoices to download");
      return;
    }

    const { default: jsPDF } = await import("jspdf");
    const { default: autoTable } = await import("jspdf-autotable");

    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Grouped Invoice List", 14, 22);

    const tableColumn = ["Lease ID", "Invoice Count", "Total Amount"];
    const tableRows: any[] = [];

    invoiceGroups.forEach((group) => {
      tableRows.push([
        group.leaseId,
        group.invoices.length,
        group.totalAmount.toLocaleString(),
      ]);
    });

    autoTable(doc, {
      startY: 30,
      head: [tableColumn],
      body: tableRows,
      styles: { fontSize: 10 },
    });

    doc.save(`Invoices_${new Date().toISOString()}.pdf`);
  };

  return (
    <div className="p-8 bg-gray-50 min-h-screen">
      <div className="max-w-6xl mx-auto">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-3xl font-bold text-gray-800">📄 Invoices (Grouped)</h1>
          <CreateInvoiceModal />
        </div>

        {/* Filters + Download Button */}
        <div className="flex flex-wrap gap-4 mb-6 items-center">
          <select
            value={status}
            onChange={(e) => setStatus(e.target.value)}
            className="border border-gray-300 rounded-lg px-4 py-2"
          >
            <option value="">All Statuses</option>
            <option value="PENDING">Pending</option>
            <option value="PAID">Paid</option>
            <option value="OVERDUE">Overdue</option>
          </select>

          <select
            value={type}
            onChange={(e) => setType(e.target.value)}
            className="border border-gray-300 rounded-lg px-4 py-2"
          >
            <option value="">All Types</option>
            <option value="RENT">Rent</option>
            <option value="UTILITY">Utility</option>
          </select>

          <button
            onClick={loadInvoices}
            className="bg-blue-600 text-white px-5 py-2 rounded-lg shadow hover:bg-blue-700"
          >
            Refresh
          </button>

          <button
            onClick={downloadPDF}
            className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg shadow-md hover:shadow-lg transition-all duration-200 flex items-center gap-2 font-medium border border-blue-700"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
            Download PDF
          </button>
        </div>

        {/* Table */}
        <div className="overflow-hidden rounded-xl shadow-md border border-gray-200 bg-white">
          <table className="min-w-full">
            <thead className="bg-blue-100 text-gray-700 uppercase text-xs font-semibold">
              <tr>
                <th className="px-6 py-3 text-left">Lease ID</th>
                <th className="px-6 py-3 text-left">Invoices Count</th>
                <th className="px-6 py-3 text-left">Total Amount</th>
              </tr>
            </thead>

            <tbody className="divide-y divide-gray-200">
              {invoiceGroups.length === 0 ? (
                <tr>
                  <td colSpan={3} className="text-center py-10 text-gray-500 italic">
                    No grouped invoices found.
                  </td>
                </tr>
              ) : (
                invoiceGroups.map((group) => (
                  <tr
                    key={group.leaseId}
                    onClick={() =>
                      router.push(`/property-manager/finance/invoices/group/${group.leaseId}`)
                    }
                    className="cursor-pointer hover:bg-blue-50 transition"
                  >
                    <td className="px-6 py-4 font-mono text-blue-600">{group.leaseId}</td>
                    <td className="px-6 py-4">{group.invoices.length}</td>
                    <td className="px-6 py-4 font-semibold">
                      {group.totalAmount.toLocaleString()}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

