"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { 
  Plug, 
  CreditCard, 
  Mail, 
  MessageSquare, 
  Zap, 
  CheckCircle, 
  XCircle,
  ExternalLink,
  Settings
} from "lucide-react";

interface Integration {
  id: string;
  name: string;
  description: string;
  icon: string;
  status: "connected" | "disconnected";
  category: string;
}

export default function IntegrationsPage() {
  const [integrations, setIntegrations] = useState<Integration[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Fetch integrations from API
    const fetchIntegrations = async () => {
      try {
        setLoading(true);
        setError(null);
        
        // In a real implementation, you'd have an API endpoint for integrations
        // For now, we'll use the existing API endpoints to check status
        const [stripeRes, plaidRes] = await Promise.all([
          fetch('/api/payments').catch(() => ({ ok: false })),
          fetch('/api/plaid/create-link-token').catch(() => ({ ok: false }))
        ]);
        
        const integrationData: Integration[] = [
          {
            id: "stripe",
            name: "Stripe",
            description: "Payment processing for rent collection and invoices",
            icon: "CreditCard",
            status: stripeRes.ok ? "connected" : "disconnected",
            category: "Payments"
          },
          {
            id: "plaid",
            name: "Plaid",
            description: "Bank account verification and ACH payments",
            icon: "Zap",
            status: plaidRes.ok ? "connected" : "disconnected",
            category: "Payments"
          },
          {
            id: "email",
            name: "Email Service",
            description: "Send automated emails to tenants",
            icon: "Mail",
            status: "disconnected",
            category: "Communication"
          },
          {
            id: "sms",
            name: "SMS Notifications",
            description: "Send SMS alerts for payments and maintenance",
            icon: "MessageSquare",
            status: "disconnected",
            category: "Communication"
          },
          {
            id: "dss",
            name: "Digital Signature (DSS)",
            description: "Electronic document signing for leases",
            icon: "Plug",
            status: "disconnected",
            category: "Documents"
          }
        ];
        
        setIntegrations(integrationData);
        
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load integrations');
      } finally {
        setLoading(false);
      }
    };
    
    fetchIntegrations();
  }, []);

  const handleConnect = (integrationId: string) => {
    // In a real implementation, this would initiate OAuth flow or API key entry
    setIntegrations(prev => 
      prev.map(i => 
        i.id === integrationId 
          ? { ...i, status: "connected" as const }
          : i
      )
    );
  };

  const handleDisconnect = (integrationId: string) => {
    setIntegrations(prev => 
      prev.map(i => 
        i.id === integrationId 
          ? { ...i, status: "disconnected" as const }
          : i
      )
    );
  };

  const getIcon = (iconName: string) => {
    switch (iconName) {
      case "CreditCard": return <CreditCard className="h-6 w-6" />;
      case "Zap": return <Zap className="h-6 w-6" />;
      case "Mail": return <Mail className="h-6 w-6" />;
      case "MessageSquare": return <MessageSquare className="h-6 w-6" />;
      default: return <Plug className="h-6 w-6" />;
    }
  };

  const connectedCount = integrations.filter(i => i.status === "connected").length;

  return (
    <div className="container mx-auto py-10 max-w-6xl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold">Integrations</h1>
          <p className="text-gray-500 mt-1">
            Connect third-party services to enhance your property management workflow.
          </p>
        </div>
        <Badge variant="outline" className="text-sm">
          {connectedCount} of {integrations.length} connected
        </Badge>
      </div>

      <div className="grid gap-6">
        {/* Payment Integrations */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <CreditCard className="h-5 w-5" />
              Payment Processing
            </CardTitle>
            <CardDescription>
              Manage payment gateways and financial integrations
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y4">
            {integrations
              .filter(i => i.category === "Payments")
              .map(integration => (
                <div 
                  key={integration.id}
                  className="flex items-center justify-between p-4 border rounded-lg"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-blue-100 rounded-lg text-blue-600">
                      {getIcon(integration.icon)}
                    </div>
                    <div>
                      <h4 className="font-medium">{integration.name}</h4>
                      <p className="text-sm text-gray-500">{integration.description}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {integration.status === "connected" ? (
                      <>
                        <Badge className="bg-green-100 text-green-700">
                          <CheckCircle className="h-3 w-3 mr-1" />
                          Connected
                        </Badge>
                        <Button variant="outline" size="sm" onClick={() => handleDisconnect(integration.id)}>
                          Disconnect
                        </Button>
                      </>
                    ) : (
                      <>
                        <Badge variant="outline">
                          <XCircle className="h-3 w-3 mr-1" />
                          Not Connected
                        </Badge>
                        <Button size="sm" onClick={() => handleConnect(integration.id)}>
                          Connect
                        </Button>
                      </>
                    )}
                  </div>
                </div>
              ))}
          </CardContent>
        </Card>

        {/* Communication Integrations */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <MessageSquare className="h-5 w-5" />
              Communication
            </CardTitle>
            <CardDescription>
              Email, SMS, and notification services
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y4">
            {integrations
              .filter(i => i.category === "Communication")
              .map(integration => (
                <div 
                  key={integration.id}
                  className="flex items-center justify-between p-4 border rounded-lg"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-purple-100 rounded-lg text-purple-600">
                      {getIcon(integration.icon)}
                    </div>
                    <div>
                      <h4 className="font-medium">{integration.name}</h4>
                      <p className="text-sm text-gray-500">{integration.description}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {integration.status === "connected" ? (
                      <>
                        <Badge className="bg-green-100 text-green-700">
                          <CheckCircle className="h-3 w-3 mr-1" />
                          Connected
                        </Badge>
                        <Button variant="outline" size="sm" onClick={() => handleDisconnect(integration.id)}>
                          Disconnect
                        </Button>
                      </>
                    ) : (
                      <>
                        <Badge variant="outline">
                          <XCircle className="h-3 w-3 mr-1" />
                          Not Connected
                        </Badge>
                        <Button size="sm" onClick={() => handleConnect(integration.id)}>
                          Connect
                        </Button>
                      </>
                    )}
                  </div>
                </div>
              ))}
          </CardContent>
        </Card>

        {/* Document Integrations */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Plug className="h-5 w-5" />
              Document Services
            </CardTitle>
            <CardDescription>
              E-signature and document management tools
            </CardDescription>
          </CardHeader>
          <CardContent className="space-y4">
            {integrations
              .filter(i => i.category === "Documents")
              .map(integration => (
                <div 
                  key={integration.id}
                  className="flex items-center justify-between p-4 border rounded-lg"
                >
                  <div className="flex items-center gap-4">
                    <div className="p-3 bg-orange-100 rounded-lg text-orange-600">
                      {getIcon(integration.icon)}
                    </div>
                    <div>
                      <h4 className="font-medium">{integration.name}</h4>
                      <p className="text-sm text-gray-500">{integration.description}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {integration.status === "connected" ? (
                      <>
                        <Badge className="bg-green-100 text-green-700">
                          <CheckCircle className="h-3 w-3 mr-1" />
                          Connected
                        </Badge>
                        <Button variant="outline" size="sm" onClick={() => handleDisconnect(integration.id)}>
                          Disconnect
                        </Button>
                      </>
                    ) : (
                      <>
                        <Badge variant="outline">
                          <XCircle className="h-3 w-3 mr-1" />
                          Not Connected
                        </Badge>
                        <Button size="sm" onClick={() => handleConnect(integration.id)}>
                          Connect
                        </Button>
                      </>
                    )}
                  </div>
                </div>
              ))}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { showCustomToast, ToastContainer } from "@/components/ui/custom-toast";
import { useAuth } from "@/context/AuthContext";
import { Loader2, Shield, ShieldCheck, Phone, Lock } from "lucide-react";

export default function SettingsPage() {
  const { user, refreshUser } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [isSendingOtp, setIsSendingOtp] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);

  // 2FA State
  const [is2FAEnabled, setIs2FAEnabled] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState("");
  const [isPhoneVerified, setIsPhoneVerified] = useState(false);

  // OTP Verification State
  const [showVerificationUI, setShowVerificationUI] = useState(false);
  const [otpDigits, setOtpDigits] = useState(["", "", "", "", "", ""]);

  useEffect(() => {
    if (user) {
      setPhoneNumber(user.phone || "");
      setIs2FAEnabled(user.twoFactorEnabled || false);
      setIsPhoneVerified(!!user.phoneVerified);
    }
  }, [user]);

  // Handle OTP digit change
  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) value = value.slice(-1);
    if (!/^\d*$/.test(value)) return;

    const newDigits = [...otpDigits];
    newDigits[index] = value;
    setOtpDigits(newDigits);

    // Auto-focus next input
    if (value && index < 5) {
      const nextInput = document.getElementById(`otp-${index + 1}`);
      nextInput?.focus();
    }
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Backspace" && !otpDigits[index] && index > 0) {
      const prevInput = document.getElementById(`otp-${index - 1}`);
      prevInput?.focus();
    }
  };

  // Handle sending OTP for phone verification
  const handleSendVerificationOtp = async () => {
    if (!phoneNumber) {
      showCustomToast("Please enter a phone number first", "error");
      return;
    }

    // Validate phone format
    if (!phoneNumber.startsWith("+")) {
      showCustomToast("Phone number must be in E.164 format (e.g., +254712345678)", "error");
      return;
    }

    setIsSendingOtp(true);
    try {
      // First update the phone number
      const updateResponse = await fetch('/api/auth/phone/update', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phone: phoneNumber })
      });

      if (!updateResponse.ok) {
        const error = await updateResponse.json();
        showCustomToast(error.error || "Failed to update phone number", "error");
        setIsSendingOtp(false);
        return;
      }

      // Then send OTP for verification
      const sendResponse = await fetch('/api/auth/phone/send-verification', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phone: phoneNumber })
      });

      if (sendResponse.ok) {
        showCustomToast("Verification code sent to your phone", "success");
        setShowVerificationUI(true);
      } else {
        const error = await sendResponse.json();
        showCustomToast(error.error || "Failed to send verification code", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred", "error");
    } finally {
      setIsSendingOtp(false);
    }
  };

  // Handle OTP verification
  const handleVerifyOtp = async () => {
    const fullCode = otpDigits.join("");
    if (fullCode.length !== 6) {
      showCustomToast("Please enter a valid 6-digit code", "error");
      return;
    }

    setIsVerifying(true);
    try {
      const response = await fetch('/api/auth/phone/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phone: phoneNumber, code: fullCode })
      });

      if (response.ok) {
        showCustomToast("Phone Number Verified Successfully", "success");
        setIsPhoneVerified(true);
        setShowVerificationUI(false);
        setOtpDigits(["", "", "", "", "", ""]);
        await refreshUser();
      } else {
        const error = await response.json();
        showCustomToast(error.error || "Invalid or expired code", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred during verification", "error");
    } finally {
      setIsVerifying(false);
    }
  };

  // Handle enabling 2FA
  const handleEnable2FA = async () => {
    if (!phoneNumber) {
      showCustomToast("Please add a phone number first", "error");
      return;
    }

    if (!isPhoneVerified) {
      showCustomToast("Please verify your phone number first", "error");
      return;
    }

    setIsLoading(true);
    try {
      const response = await fetch('/api/auth/2fa/toggle', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ enable: true })
      });

      if (response.ok) {
        showCustomToast("2FA enabled successfully!", "success");
        setIs2FAEnabled(true);
        await refreshUser();
      } else {
        const error = await response.json();
        showCustomToast(error.error || "Failed to enable 2FA", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred", "error");
    } finally {
      setIsLoading(false);
    }
  };

  // Handle disabling 2FA
  const handleDisable2FA = async () => {
    setIsLoading(true);
    try {
      const response = await fetch('/api/auth/2fa/toggle', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ enable: false })
      });

      if (response.ok) {
        showCustomToast("2FA disabled successfully!", "success");
        setIs2FAEnabled(false);
        await refreshUser();
      } else {
        const error = await response.json();
        showCustomToast(error.error || "Failed to disable 2FA", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred", "error");
    } finally {
      setIsLoading(false);
    }
  };

  // Handle toggle change
  const handleToggle2FA = async (checked: boolean) => {
    if (checked) {
      // Check if phone is verified before enabling
      if (!phoneNumber || !isPhoneVerified) {
        showCustomToast("Please add and verify a phone number first", "error");
        return;
      }
      await handleEnable2FA();
    } else {
      await handleDisable2FA();
    }
  };

  return (
    <div className="container mx-auto py-10 max-w-4xl">
      <h1 className="text-3xl font-bold mb-6">Account Settings</h1>

      <Tabs defaultValue="profile" className="w-full">
        <TabsList className="mb-4">
          <TabsTrigger value="profile" className="flex items-center gap-2">
            <Shield className="h-4 w-4" />
            Profile
          </TabsTrigger>
          <TabsTrigger value="security" className="flex items-center gap-2">
            <Lock className="h-4 w-4" />
            Security & 2FA
          </TabsTrigger>
        </TabsList>

        {/* --- TAB 1: PROFILE --- */}
        <TabsContent value="profile">
          <Card>
            <CardHeader>
              <CardTitle>Personal Information</CardTitle>
              <CardDescription>Update your contact details.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>First Name</Label>
                  <Input defaultValue={user?.firstName} disabled />
                </div>
                <div className="space-y-2">
                  <Label>Last Name</Label>
                  <Input defaultValue={user?.lastName} disabled />
                </div>
              </div>
              <div className="space-y-2">
                <Label>Email</Label>
                <Input defaultValue={user?.email} disabled />
              </div>
              <div className="flex justify-end">
                <Button disabled>Save Changes</Button>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* --- TAB 2: SECURITY (2FA) --- */}
        <TabsContent value="security">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <ShieldCheck className="h-5 w-5" />
                Two-Factor Authentication
              </CardTitle>
              <CardDescription>
                Secure your account with SMS verification. We will send a code to your phone every time you log in.
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">

              {!showVerificationUI ? (
                <>
                  {/* Phone Number Section */}
                  <div className="space-y-2">
                    <Label className="flex items-center gap-2">
                      <Phone className="h-4 w-4" />
                      Phone Number (for OTP)
                    </Label>
                    <div className="flex gap-2">
                      <Input
                        value={phoneNumber}
                        onChange={(e) => setPhoneNumber(e.target.value)}
                        placeholder="+254712345678"
                        disabled={is2FAEnabled}
                      />
                      {!is2FAEnabled && (
                        <Button
                          variant="outline"
                          onClick={handleSendVerificationOtp}
                          disabled={isSendingOtp}
                        >
                          {isSendingOtp ? <Loader2 className="h-4 w-4 animate-spin" /> : "Verify"}
                        </Button>
                      )}
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                      {isPhoneVerified ? (
                        <span className="text-green-600 flex items-center gap-1">
                          ✓ Verified
                        </span>
                      ) : (
                        <span className="text-yellow-600 flex items-center gap-1">
                          ⚠ Not verified
                        </span>
                      )}
                      <span className="text-gray-500 text-xs">Format: +254712345678</span>
                    </div>
                  </div>

                  <div className="border-t my-4" />

                  {/* The 2FA Toggle */}
                  <div className="flex items-center justify-between">
                    <div className="space-y-0.5">
                      <Label className="text-base">Enable 2FA</Label>
                      <p className="text-sm text-gray-500">
                        {is2FAEnabled
                          ? "Your account is protected with 2FA"
                          : "We will send a code to your phone every time you log in"}
                        {isPhoneVerified && !is2FAEnabled && " - Click to enable"}
                      </p>
                    </div>
                    <Switch
                      checked={is2FAEnabled}
                      onCheckedChange={handleToggle2FA}
                      disabled={isLoading || (!isPhoneVerified && !is2FAEnabled)}
                    />
                  </div>
                </>
              ) : (
                <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="space-y-2">
                    <h3 className="text-xl font-bold">Verify Phone Number</h3>
                    <p className="text-sm text-gray-500 leading-relaxed">
                      We've sent a 6-digit verification code to <span className="font-semibold text-gray-700">{phoneNumber}</span>. Enter it below to secure your account.
                    </p>
                  </div>

                  <div className="flex justify-between gap-3 max-w-sm mx-auto">
                    {otpDigits.map((digit, index) => (
                      <Input
                        key={index}
                        id={`otp-${index}`}
                        type="text"
                        inputMode="numeric"
                        maxLength={1}
                        value={digit}
                        onChange={(e) => handleOtpChange(index, e.target.value)}
                        onKeyDown={(e) => handleKeyDown(index, e)}
                        className="w-12 h-14 text-center text-2xl font-bold border-2 focus:border-primary focus:ring-0 rounded-xl"
                      />
                    ))}
                  </div>

                  <div className="text-center">
                    <p className="text-sm text-gray-500">
                      Didn't receive the code?{" "}
                      <button
                        onClick={handleSendVerificationOtp}
                        className="text-primary font-semibold hover:underline decoration-2 underline-offset-4"
                        disabled={isSendingOtp}
                      >
                        {isSendingOtp ? "Sending..." : "Resend Code"}
                      </button>
                    </p>
                  </div>

                  <div className="space-y-3">
                    <Button
                      className="w-full bg-primary hover:bg-blue-600 text-white font-semibold py-6 rounded-2xl shadow-lg shadow-blue-500/20 transition-all active:scale-[0.98]"
                      onClick={handleVerifyOtp}
                      disabled={isVerifying || otpDigits.some(d => !d)}
                    >
                      {isVerifying ? <Loader2 className="h-5 w-5 animate-spin mr-2" /> : "Verify & Continue"}
                    </Button>
                    <Button
                      variant="ghost"
                      className="w-full text-gray-500"
                      onClick={() => setShowVerificationUI(false)}
                      disabled={isVerifying}
                    >
                      Cancel
                    </Button>
                  </div>

                  <div className="pt-4 text-center">
                    <span className="text-[10px] text-gray-400 uppercase tracking-widest font-medium">
                      Standard Carrier Rates Apply
                    </span>
                  </div>
                </div>
              )}

              {isLoading && (
                <div className="flex justify-center">
                  <Loader2 className="h-5 w-5 animate-spin" />
                </div>
              )}

            </CardContent>
          </Card>
        </TabsContent>

      </Tabs>

      {/* Custom Toast Notification */}
      <ToastContainer />
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { 
  Users, 
  Shield, 
  UserCircle, 
  Plus, 
  MoreHorizontal,
  Search,
  Settings,
  Mail,
  Phone,
  Building2
} from "lucide-react";

interface Role {
  id: string;
  name: string;
  description: string;
  userCount: number;
  permissions: string[];
}

interface User {
  id: string;
  name: string;
  email: string;
  phone: string;
  role: string;
  property?: string;
  status: "active" | "invited" | "inactive";
}

export default function RolesPage() {
  const [searchTerm, setSearchTerm] = useState("");
  const [roles, setRoles] = useState<Role[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(null);
        
        // Fetch users from API
        const usersRes = await fetch('/api/auth/users');
        if (!usersRes.ok) throw new Error('Failed to fetch users');
        const usersData = await usersRes.json();
        
        // Transform API data
        const transformedUsers: User[] = Array.isArray(usersData) ? usersData.map((u: any) => ({
          id: u.id,
          name: u.firstName && u.lastName ? `${u.firstName} ${u.lastName}` : u.name || 'Unknown',
          email: u.email || '',
          phone: u.phone || '',
          role: u.role || 'Tenant',
          property: u.organization?.name || '',
          status: u.emailVerified ? 'active' : 'invited'
        })) : [];
        
        setUsers(transformedUsers);
        
        // Generate roles from user data
        const roleCounts = transformedUsers.reduce((acc, user) => {
          acc[user.role] = (acc[user.role] || 0) + 1;
          return acc;
        }, {} as Record<string, number>);
        
        const roleData: Role[] = [
          {
            id: "admin",
            name: "Property Manager",
            description: "Full access to all features and settings",
            userCount: roleCounts['PROPERTY_MANAGER'] || roleCounts['SYSTEM_ADMIN'] || 0,
            permissions: ["all"]
          },
          {
            id: "agent",
            name: "Agent",
            description: "Can manage properties and tenants",
            userCount: roleCounts['AGENT'] || 0,
            permissions: ["properties", "tenants", "leases"]
          },
          {
            id: "vendor",
            name: "Vendor",
            description: "Can view and respond to maintenance requests",
            userCount: roleCounts['VENDOR'] || 0,
            permissions: ["maintenance", "reports"]
          },
          {
            id: "tenant",
            name: "Tenant",
            description: "Can view lease and make payments",
            userCount: roleCounts['TENANT'] || 0,
            permissions: ["lease", "payments", "maintenance"]
          }
        ];
        
        setRoles(roleData);
        
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load data');
      } finally {
        setLoading(false);
      }
    };
    
    fetchData();
  }, []);

  const filteredUsers = users.filter(user =>
    user.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.role.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "active":
        return <Badge className="bg-green-100 text-green-700">Active</Badge>;
      case "invited":
        return <Badge className="bg-blue-100 text-blue-700">Pending Invite</Badge>;
      case "inactive":
        return <Badge className="bg-gray-100 text-gray-700">Inactive</Badge>;
      default:
        return <Badge>{status}</Badge>;
    }
  };

  const getRoleBadge = (role: string) => {
    switch (role) {
      case "Property Manager":
        return <Badge className="bg-purple-100 text-purple-700">Admin</Badge>;
      case "Agent":
        return <Badge className="bg-blue-100 text-blue-700">Agent</Badge>;
      case "Vendor":
        return <Badge className="bg-orange-100 text-orange-700">Vendor</Badge>;
      case "Tenant":
        return <Badge className="bg-green-100 text-green-700">Tenant</Badge>;
      default:
        return <Badge>{role}</Badge>;
    }
  };

  return (
    <div className="container mx-auto py-10 max-w-6xl">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-3xl font-bold">Role Management</h1>
          <p className="text-gray-500 mt-1">
            Manage user roles and permissions for your organization.
          </p>
        </div>
        <Button>
          <Plus className="h-4 w-4 mr-2" />
          Invite User
        </Button>
      </div>

      <div className="grid gap-6">
        {/* Roles Overview */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {roles.map(role => (
            <Card key={role.id}>
              <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                  <CardTitle className="text-lg">{role.name}</CardTitle>
                  <Shield className="h-5 w-5 text-gray-400" />
                </div>
              </CardHeader>
              <CardContent>
                <p className="text-sm text-gray-500 mb-3">{role.description}</p>
                <div className="flex items-center justify-between">
                  <span className="text-2xl font-bold">{role.userCount}</span>
                  <span className="text-sm text-gray-500">users</span>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Users List */}
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Users className="h-5 w-5" />
              Team Members
            </CardTitle>
            <CardDescription>
              View and manage users in your organization.
            </CardDescription>
          </CardHeader>
          <CardContent>
            {/* Search */}
            <div className="relative mb-4">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <Input
                placeholder="Search users..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10"
              />
            </div>

            {/* Users Table */}
            <div className="rounded-md border">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">User</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Role</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Property</th>
                    <th className="px-4 py-3 text-left text-sm font-medium text-gray-500">Status</th>
                    <th className="px-4 py-3 text-right text-sm font-medium text-gray-500">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y">
                  {filteredUsers.map(user => (
                    <tr key={user.id} className="hover:bg-gray-50">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-3">
                          <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center">
                            <UserCircle className="h-6 w-6 text-blue-600" />
                          </div>
                          <div>
                            <p className="font-medium">{user.name}</p>
                            <p className="text-sm text-gray-500">{user.email}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        {getRoleBadge(user.role)}
                      </td>
                      <td className="px-4 py-3">
                        {user.property ? (
                          <div className="flex items-center gap-2 text-sm">
                            <Building2 className="h-4 w-4 text-gray-400" />
                            {user.property}
                          </div>
                        ) : (
                          <span className="text-gray-400">—</span>
                        )}
                      </td>
                      <td className="px-4 py-3">
                        {getStatusBadge(user.status)}
                      </td>
                      <td className="px-4 py-3 text-right">
                        <Button variant="ghost" size="sm">
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import Link from "next/link";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Eye, EyeOff, Plus, Settings } from "lucide-react";
import { toast } from "sonner";
import { ListingDecisionModal } from "@/components/Dashboard/listing/ListingDecisionModal";
import { ListingStatus, UnitWithListingStatus } from "@/lib/listing-types";

interface Unit {
  id: string | null; // null if placeholder
  unitNumber: string;
  unitName: string | null;
  bedrooms: number | null;
  bathrooms: number | null;
  floorNumber: number | null;
  rentAmount: number | null;
  isOccupied: boolean;
  listing?: {
    id: string;
    status: string | { name?: string } | null;
    title: string;
    price: number;
  };
  leases?: Array<{
    id: string;
    leaseStatus: string;
    startDate: string;
    endDate: string;
  }>;
}

export default function ManageUnitsPage() {
  const { id, type } = useParams(); // id = apartmentComplexDetailId or houseDetailId, type = "apartment" | "house"
  const [units, setUnits] = useState<Unit[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [showDecisionModal, setShowDecisionModal] = useState(false);
  const [selectedUnit, setSelectedUnit] = useState<Unit | null>(null);
  const normalizeStatus = (status?: string, hasListing?: boolean): ListingStatus => {
    if (!status) return hasListing ? ListingStatus.ACTIVE : ListingStatus.PRIVATE;
    return Object.values(ListingStatus).includes(status as ListingStatus)
      ? (status as ListingStatus)
      : ListingStatus.PRIVATE;
  };

  const toListingUnit = (unit: Unit): UnitWithListingStatus => {
    const listingStatusName = unit.listing
      ? typeof unit.listing.status === "string"
        ? unit.listing.status
        : unit.listing.status?.name
      : undefined;

    return {
      id: unit.id || "",
      unitNumber: unit.unitNumber,
      propertyId: String(id || ""),
      rentAmount: unit.rentAmount ?? undefined,
      bedrooms: unit.bedrooms ?? undefined,
      bathrooms: unit.bathrooms ?? undefined,
      listing: unit.listing
        ? {
            id: unit.listing.id,
            status: normalizeStatus(listingStatusName, true),
            createdAt: new Date(),
            updatedAt: new Date(),
            title: unit.listing.title || `Unit ${unit.unitNumber}`,
            description: unit.listing.title || `Unit ${unit.unitNumber}`,
            price: unit.listing.price || 0
          }
        : undefined
    };
  };

  useEffect(() => {
    if (!id || !type) return;

    const queryParam =
      type === "apartment"
        ? `apartmentComplexDetailId=${id}`
        : `houseDetailId=${id}`;

    fetch(`/api/units?${queryParam}&include=listing,lease`)
      .then((res) => {
        if (!res.ok) throw new Error("Failed to fetch units");
        return res.json();
      })
      .then((data: Unit[]) => setUnits(data))
      .catch((err) => {
        console.error(err);
        setError("Failed to load units");
      })
      .finally(() => setLoading(false));
  }, [id, type]);

  const handleListingDecision = async (unitId: string, decision: "list" | "private") => {
    try {
      if (!unitId) {
        toast.error("Unit ID is missing. Please try again.");
        return;
      }
      const response = await fetch("/api/listings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          unitId,
          action: decision === "list" ? "CREATE" : "REMOVE",
          listingData: {}
        })
      });

      if (!response.ok) throw new Error("Failed to update listing");
      
      toast.success(`Unit ${decision === "list" ? "listed" : "made private"} successfully`);
      
      // Refresh units data
      const queryParam =
        type === "apartment"
          ? `apartmentComplexDetailId=${id}`
          : `houseDetailId=${id}`;

      const refreshResponse = await fetch(`/api/units?${queryParam}&include=listing,lease`);
      if (refreshResponse.ok) {
        const refreshedData = await refreshResponse.json();
        setUnits(refreshedData);
      }
      
      setShowDecisionModal(false);
      setSelectedUnit(null);
    } catch (error) {
      console.error("Error updating listing:", error);
      toast.error("Failed to update listing");
    }
  };

  const getListingStatusBadge = (unit: Unit) => {
    if (!unit.listing) {
      return <Badge variant="secondary">Private</Badge>;
    }
    
    switch (unit.listing.status) {
      case "ACTIVE":
        return <Badge variant="default" className="bg-green-500">Listed</Badge>;
      case "SUSPENDED":
        return <Badge variant="destructive">Suspended</Badge>;
      case "PENDING":
        return <Badge variant="outline">Pending</Badge>;
      default:
        return <Badge variant="secondary">Private</Badge>;
    }
  };

  const canCreateListing = (unit: Unit) => {
    // Can create listing if unit exists, has no listing, and no active lease
    return unit.id && !unit.listing && (!unit.leases || unit.leases.length === 0);
  };

  if (loading)
    return <p className="text-center mt-10 text-gray-500">Loading units...</p>;

  if (error)
    return <p className="text-center mt-10 text-red-500">{error}</p>;

  if (units.length === 0)
    return <p className="text-center mt-10 text-gray-500">No units found.</p>;

  return (
    <div className="p-6 max-w-5xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900 mb-2">Manage Units</h1>
        <p className="text-gray-600">Configure unit details and marketplace listings</p>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
        {units.map((unit) => (
          <Card
            key={unit.unitNumber}
            className="shadow hover:shadow-lg transition-shadow rounded-xl border border-gray-200"
          >
            <CardContent className="p-6 space-y-4">
              <div className="flex justify-between items-start">
                <h2 className="font-semibold text-lg text-gray-800">
                  Unit {unit.unitNumber}
                </h2>
                {getListingStatusBadge(unit)}
              </div>

              {unit.id ? (
                <div className="text-gray-700 space-y-2">
                  <p>
                    <strong>Bedrooms:</strong> {unit.bedrooms ?? "N/A"}
                  </p>
                  <p>
                    <strong>Bathrooms:</strong> {unit.bathrooms ?? "N/A"}
                  </p>
                  <p>
                    <strong>Rent:</strong> ${unit.rentAmount?.toLocaleString() ?? "N/A"}
                  </p>
                  {unit.listing && (
                    <p>
                      <strong>Listed Price:</strong> ${unit.listing.price?.toLocaleString()}
                    </p>
                  )}
                  {unit.leases && unit.leases.length > 0 && (
                    <p className="text-blue-600">
                      <strong>Lease Status:</strong> {unit.leases[0].leaseStatus}
                    </p>
                  )}
                </div>
              ) : (
                <p className="text-gray-500">No details yet</p>
              )}

              <div className="space-y-2">
                <Link
                  href={`/property-manager/${type}-details/${id}/units/${
                    unit.id ?? unit.unitNumber
                  }/edit`}
                  className="inline-block w-full text-center px-4 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition"
                >
                  {unit.id ? "Edit Unit" : "Add Unit Details"}
                </Link>

                {canCreateListing(unit) && (
                  <Button
                    onClick={() => {
                      setSelectedUnit(unit);
                      setShowDecisionModal(true);
                    }}
                    variant="outline"
                    className="w-full"
                  >
                    <Plus className="w-4 h-4 mr-2" />
                    List on Marketplace
                  </Button>
                )}

                {unit.listing && (
                  <Link
                    href={`/property-manager/listings?unit=${unit.id}`}
                    className="inline-block w-full"
                  >
                    <Button variant="outline" className="w-full">
                      <Settings className="w-4 h-4 mr-2" />
                      Manage Listing
                    </Button>
                  </Link>
                )}
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Listing Decision Modal */}
      {showDecisionModal && selectedUnit && (
        <ListingDecisionModal
          isOpen={showDecisionModal}
          unit={toListingUnit(selectedUnit)}
          onDecision={(unitId, decision) => handleListingDecision(unitId, decision)}
          onClose={() => {
            setShowDecisionModal(false);
            setSelectedUnit(null);
          }}
        />
      )}
    </div>
  );
}

