"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { 
  FileText,
  CheckCircle2,
  AlertCircle,
  Clock,
  Eye,
  PenTool,
  Building2
} from "lucide-react";

interface Tenant {
  id: string;
  fullName: string;
  email: string;
  phone: string;
}

interface Application {
  fullName: string;
  email: string;
  phone: string;
}

interface Lease {
  id: string;
  startDate: string;
  endDate: string;
  rentAmount: number;
  leaseStatus: string;
  landlordSignedAt: string | null;
  tenantSignedAt: string | null;
  tenant?: Tenant | null;
  application?: Application | null;
}

interface Unit {
  id: string;
  unitNumber: string;
  bedrooms?: number;
  bathrooms?: number;
  leases: Lease[];
}

export default function ManageUnitsAndLeasesPage() {
  const { id: propertyId } = useParams();
  const router = useRouter();
  const [units, setUnits] = useState<Unit[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [filter, setFilter] = useState<string>("ALL");

  useEffect(() => {
    async function fetchUnits() {
      try {
        const res = await fetch(`/api/propertymanager/${propertyId}/units-with-leases`);
        const data = await res.json();

        if (!res.ok) throw new Error(data.error || "Failed to fetch units");

        setUnits(data);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    }

    if (propertyId) fetchUnits();
  }, [propertyId]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case "SIGNED":
        return "bg-navy-100 text-green-800";
      case "ACTIVE":
        return "bg-blue-100 text-blue-800";
      case "DRAFT":
        return "bg-yellow-100 text-yellow-800";
      case "EXPIRED":
        return "bg-gray-100 text-gray-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const getSignatureStatus = (lease: Lease) => {
    if (lease.landlordSignedAt && lease.tenantSignedAt) {
      return { 
        icon: <CheckCircle2 className="w-4 h-4" />, 
        text: "Fully Signed", 
        color: "text-navy-700"
      };
    } else if (lease.landlordSignedAt || lease.tenantSignedAt) {
      return { 
        icon: <Clock className="w-4 h-4" />, 
        text: "Partial", 
        color: "text-yellow-600"
      };
    } else {
      return { 
        icon: <AlertCircle className="w-4 h-4" />, 
        text: "Unsigned", 
        color: "text-gray-400"
      };
    }
  };

  const isLeaseActive = (lease: Lease) => {
    const now = new Date();
    const start = new Date(lease.startDate);
    const end = new Date(lease.endDate);
    return now >= start && now <= end;
  };

  const allLeases = units.flatMap(unit => 
    unit.leases.map(lease => ({ ...lease, unit }))
  );

  const filteredLeases = allLeases.filter(lease => {
    if (filter === "ALL") return true;
    return lease.leaseStatus === filter;
  });

  const stats = {
    total: allLeases.length,
    signed: allLeases.filter(l => l.leaseStatus === "SIGNED").length,
    active: allLeases.filter(l => l.leaseStatus === "ACTIVE").length,
    draft: allLeases.filter(l => l.leaseStatus === "DRAFT").length,
    expired: allLeases.filter(l => l.leaseStatus === "EXPIRED").length,
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading leases...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-7xl mx-auto p-6">
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <p className="text-red-800 font-medium">Error loading leases</p>
          <p className="text-red-600 text-sm mt-1">{error}</p>
          <button
            onClick={() => window.location.reload()}
            className="mt-3 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 text-sm"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-2">
            <FileText className="w-8 h-8 text-blue-600" />
            Property Leases
          </h1>
          <p className="text-gray-600 mt-2">Manage all lease agreements for this property</p>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-6">
          <div className="bg-white rounded-lg shadow p-5 border border-gray-200">
            <p className="text-sm text-gray-500 font-medium mb-1">Total Leases</p>
            <p className="text-3xl font-bold text-gray-900">{stats.total}</p>
          </div>
          <div className="bg-navy-50 rounded-lg shadow p-5 border border-green-100">
            <p className="text-sm text-gray-500 font-medium mb-1">Signed</p>
            <p className="text-3xl font-bold text-navy-700">{stats.signed}</p>
          </div>
          <div className="bg-blue-50 rounded-lg shadow p-5 border border-blue-100">
            <p className="text-sm text-gray-500 font-medium mb-1">Active</p>
            <p className="text-3xl font-bold text-blue-600">{stats.active}</p>
          </div>
          <div className="bg-yellow-50 rounded-lg shadow p-5 border border-yellow-100">
            <p className="text-sm text-gray-500 font-medium mb-1">Draft</p>
            <p className="text-3xl font-bold text-yellow-600">{stats.draft}</p>
          </div>
          <div className="bg-gray-50 rounded-lg shadow p-5 border border-gray-100">
            <p className="text-sm text-gray-500 font-medium mb-1">Expired</p>
            <p className="text-3xl font-bold text-gray-600">{stats.expired}</p>
          </div>
        </div>

        {/* Filter Tabs */}
        <div className="bg-white rounded-lg shadow mb-6 p-4 border border-gray-200">
          <div className="flex gap-2 overflow-x-auto">
            {["ALL", "DRAFT", "SIGNED", "ACTIVE", "EXPIRED"].map((status) => (
              <button
                key={status}
                onClick={() => setFilter(status)}
                className={`px-4 py-2 rounded-lg whitespace-nowrap transition-colors font-medium ${
                  filter === status
                    ? "bg-blue-600 text-white"
                    : "bg-gray-100 text-gray-700 hover:bg-gray-200"
                }`}
              >
                {status}
                {status !== "ALL" && (
                  <span className="ml-2 text-xs opacity-75">
                    ({allLeases.filter((l) => l.leaseStatus === status).length})
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Leases Table */}
        {filteredLeases.length === 0 ? (
          <div className="bg-white rounded-lg shadow p-12 text-center border border-gray-200">
            <FileText className="w-16 h-16 text-gray-300 mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-gray-700 mb-2">No Leases Found</h3>
            <p className="text-gray-500 mb-4">
              {filter === "ALL"
                ? "No leases have been created for this property yet."
                : `No leases with status "${filter}".`}
            </p>
          </div>
        ) : (
          <div className="bg-white rounded-lg shadow border border-gray-200 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 border-b border-gray-200">
                  <tr>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Unit
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Tenant
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Contact
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Lease Term
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Rent
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Status
                    </th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Signatures
                    </th>
                    <th className="px-6 py-4 text-right text-xs font-semibold text-gray-600 uppercase tracking-wider">
                      Actions
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200">
                  {filteredLeases.map((lease) => {
                    const signatureStatus = getSignatureStatus(lease);
                    const active = isLeaseActive(lease);
                    
                    return (
                      <tr key={lease.id} className="hover:bg-gray-50 transition-colors">
                        {/* Unit */}
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center text-blue-600 font-bold flex-shrink-0">
                              {lease.unit?.unitNumber || "?"}
                            </div>
                            <div>
                              <div className="text-sm font-semibold text-gray-900">
                                Unit {lease.unit?.unitNumber || "N/A"}
                              </div>
                              {active && (
                                <span className="text-xs text-emerald-600 font-medium">
                                  Active Now
                                </span>
                              )}
                            </div>
                          </div>
                        </td>

                        {/* Tenant */}
                        <td className="px-6 py-4">
                          <div className="text-sm font-medium text-gray-900">
                            {lease.tenant?.fullName || lease.application?.fullName || "—"}
                          </div>
                        </td>

                        {/* Contact */}
                        <td className="px-6 py-4">
                          <div className="text-sm text-gray-600">
                            {lease.tenant?.email || lease.application?.email || "—"}
                          </div>
                          <div className="text-xs text-gray-500">
                            {lease.tenant?.phone || lease.application?.phone || ""}
                          </div>
                        </td>

                        {/* Lease Term */}
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm text-gray-900">
                            {new Date(lease.startDate).toLocaleDateString()}
                          </div>
                          <div className="text-xs text-gray-500">
                            to {new Date(lease.endDate).toLocaleDateString()}
                          </div>
                        </td>

                        {/* Rent */}
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="text-sm font-semibold text-blue-600">
                            ${lease.rentAmount.toLocaleString()}
                          </div>
                          <div className="text-xs text-gray-500">per month</div>
                        </td>

                        {/* Status */}
                        <td className="px-6 py-4 whitespace-nowrap">
                          <span className={`inline-flex px-3 py-1 rounded-full text-xs font-semibold ${getStatusColor(lease.leaseStatus)}`}>
                            {lease.leaseStatus}
                          </span>
                        </td>

                        {/* Signatures */}
                        <td className="px-6 py-4 whitespace-nowrap">
                          <div className="flex items-center gap-2">
                            <span className={signatureStatus.color}>
                              {signatureStatus.icon}
                            </span>
                            <span className={`text-xs font-medium ${signatureStatus.color}`}>
                              {signatureStatus.text}
                            </span>
                          </div>
                          {(lease.landlordSignedAt || lease.tenantSignedAt) && (
                            <div className="mt-1 space-y-0.5">
                              {lease.landlordSignedAt && (
                                <div className="text-xs text-gray-500">
                                  L: {new Date(lease.landlordSignedAt).toLocaleDateString()}
                                </div>
                              )}
                              {lease.tenantSignedAt && (
                                <div className="text-xs text-gray-500">
                                  T: {new Date(lease.tenantSignedAt).toLocaleDateString()}
                                </div>
                              )}
                            </div>
                          )}
                        </td>

                        {/* Actions */}
                        <td className="px-6 py-4 whitespace-nowrap text-right">
                          <div className="flex items-center justify-end gap-2">
                            <button
                              onClick={() => router.push(`/property-manager/content/lease/${lease.id}`)}
                              className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                              title="View Details"
                            >
                              <Eye className="w-4 h-4" />
                            </button>
                            <button
                              onClick={() => router.push(`/property-manager/content/lease/${lease.id}/sign`)}
                              className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                              title="Sign Lease"
                            >
                              <PenTool className="w-4 h-4" />
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { fetchUnitDetails } from "@/lib/units";

export default function ListUnitForm({ propertyId, unitNumber }: { propertyId: string; unitNumber: string }) {
  const router = useRouter();
  const { user } = useAuth();

  const [unit, setUnit] = useState<any>(null);
  const [unitId, setUnitId] = useState<string | null>(null);

  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [price, setPrice] = useState<number | "">("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const load = async () => {
      const data = await fetchUnitDetails(propertyId, unitNumber, false);

      setUnit(data);
      setUnitId(data?.id ?? null);

      if (data) {
        setTitle(`Unit ${unitNumber} for Rent`);
        setDescription(
          `${data.bedrooms ?? ""} Bedroom, ${data.bathrooms ?? ""} Bathroom unit.`
        );
        setPrice(data.rentAmount ?? "");
      }
    };

    load();
  }, [propertyId, unitNumber]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!user) return alert("Not logged in");
    if (!unitId) return alert("Unit ID is missing. Please refresh and try again.");

    setLoading(true);

    const res = await fetch("/api/listings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        unitId,
        action: "CREATE",
        listingData: {
          organizationId: user.organization?.id,
          createdBy: user.id,
          categoryId: "housing",
          propertyId,
          title,
          description,
          price: Number(price),
        },
      }),
    });

    if (res.ok) {
      router.push(`/property-manager/view-own-property/${propertyId}/units`);
    } else {
      alert("Failed to create listing");
    }

    setLoading(false);
  };

  return (
    <div className="max-w-md mx-auto p-8 bg-white rounded-2xl shadow-lg border border-gray-100 mt-8">
      <div className="text-center mb-8">
        <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center mx-auto mb-4">
          <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 8v-4m0 4h4" />
          </svg>
        </div>
        <h2 className="text-3xl font-bold text-gray-900 mb-2">List Unit {unitNumber}</h2>
        <p className="text-gray-600">Create a new listing for this unit</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="space-y-2">
          <label className="block text-sm font-semibold text-gray-700 mb-2">Title</label>
          <input
            className="w-full border border-gray-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-200 outline-none"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
            placeholder="Enter listing title"
          />
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-semibold text-gray-700 mb-2">Description</label>
          <textarea
            className="w-full border border-gray-300 rounded-lg px-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-200 outline-none resize-none min-h-[120px]"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
            placeholder="Describe the unit features and amenities"
          />
        </div>

        <div className="space-y-2">
          <label className="block text-sm font-semibold text-gray-700 mb-2">Monthly Rent</label>
          <div className="relative">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
              <span className="text-gray-500">$</span>
            </div>
            <input
              type="number"
              className="w-full border border-gray-300 rounded-lg pl-8 pr-4 py-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-all duration-200 outline-none"
              value={price}
              onChange={(e) => setPrice(e.target.valueAsNumber || "")}
              required
              placeholder="0.00"
              min="0"
            />
          </div>
        </div>

        <button
          className="w-full bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-700 hover:to-blue-800 text-white py-4 rounded-xl font-semibold shadow-lg hover:shadow-xl transition-all duration-200 transform hover:-translate-y-0.5 disabled:opacity-50 disabled:transform-none disabled:hover:shadow-lg"
          disabled={loading}
        >
          {loading ? (
            <div className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Creating Listing...
            </div>
          ) : (
            "List Unit"
          )}
        </button>
      </form>
    </div>
  );
}

// src/app/(dashboard)/property-manager/view-own-property/[id]/units/page.tsx
import { fetchUnits } from "@/lib/units";
import Link from "next/link";
import { Building, Bed, Bath, DollarSign, Users, Home, Wifi, Utensils, Eye } from "lucide-react";
import { ListingStatus } from "@/lib/listing-types";

export default async function ManageUnitsPage({
  params,
  searchParams,
}: {
  params: Promise<{ id: string }>;
  searchParams: Promise<{ type?: string }>;
}) {
  const { id: propertyId } = await params;
  const { type } = await searchParams;
  const units = await fetchUnits(propertyId);

  if (units.length === 0) {
    return (
      <div className="min-h-[400px] flex items-center justify-center">
        <div className="text-center max-w-md mx-auto p-8">
          <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <Home className="w-8 h-8 text-gray-400" />
          </div>
          <h3 className="text-xl font-semibold text-gray-800 mb-2">No Units Found</h3>
          <p className="text-gray-600 mb-6">
            This property doesn't have any units defined yet. Start by adding units to manage them.
          </p>
        </div>
      </div>
    );
  }

  const occupiedUnits = units.filter(unit => unit.isOccupied).length;
  const totalRooms = units.reduce((total, unit) => total + (unit.bedrooms || 0), 0);
  const totalBathrooms = units.reduce((total, unit) => total + (unit.bathrooms || 0), 0);

  return (
    <div className="p-6 max-w-7xl mx-auto">
      {/* Header */}
      <div className="mb-8">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h1 className="text-3xl font-bold text-gray-900 mb-2">Manage Units</h1>
            <p className="text-gray-600">
              View and manage all units for this property. {units.length} unit{units.length !== 1 ? "s" : ""} found.
            </p>
          </div>
          <div className="flex gap-4">
            <div className="bg-white px-4 py-3 rounded-lg border border-gray-200 shadow-sm">
              <div className="text-sm text-gray-600">Occupied</div>
              <div className="text-2xl font-bold text-navy-700">{occupiedUnits}</div>
            </div>
            <div className="bg-white px-4 py-3 rounded-lg border border-gray-200 shadow-sm">
              <div className="text-sm text-gray-600">Vacant</div>
              <div className="text-2xl font-bold text-blue-600">{units.length - occupiedUnits}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Units Table */}
      <div className="bg-white rounded-2xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr className="border-b border-gray-200">
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900">Unit Details</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900">Specifications</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900">Rent</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900">Appliances</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900">Status</th>
                <th className="px-6 py-4 text-left text-sm font-semibold text-gray-900">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {units.map((unit) => {
                const hasDetails = unit.unitName || unit.bedrooms || unit.bathrooms || unit.floorNumber || unit.rentAmount;
                const listingStatusName = unit.listing?.status?.name as ListingStatus | undefined;
                const isListed = !!unit.listing?.id && (
                  listingStatusName === ListingStatus.ACTIVE ||
                  listingStatusName === ListingStatus.COMING_SOON ||
                  listingStatusName === undefined
                );
                const applianceCount = unit.appliances?.length || 0;

                return (
                  <tr key={unit.unitNumber} className="hover:bg-gray-50 transition-colors">
                    {/* Unit Details */}
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
                          <Home className="w-5 h-5 text-blue-600" />
                        </div>
                        <div>
                          <div className="font-semibold text-gray-900">
                            Unit {unit.unitNumber}
                          </div>
                          {unit.unitName && (
                            <div className="text-sm text-gray-500">{unit.unitName}</div>
                          )}
                          {unit.floorNumber && (
                            <div className="flex items-center gap-1 text-xs text-gray-500 mt-1">
                              <Building className="w-3 h-3" />
                              Floor {unit.floorNumber}
                            </div>
                          )}
                        </div>
                      </div>
                    </td>

                    {/* Specifications */}
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2">
                          <Bed className="w-4 h-4 text-gray-400" />
                          <span className="text-sm font-medium text-gray-900">
                            {unit.bedrooms || 0}
                          </span>
                          <span className="text-xs text-gray-500">Beds</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <Bath className="w-4 h-4 text-gray-400" />
                          <span className="text-sm font-medium text-gray-900">
                            {unit.bathrooms || 0}
                          </span>
                          <span className="text-xs text-gray-500">Baths</span>
                        </div>
                      </div>
                    </td>

                    {/* Rent */}
                    <td className="px-6 py-4">
                      {unit.rentAmount ? (
                        <div className="flex items-center gap-2">
                          <DollarSign className="w-4 h-4 text-navy-700" />
                          <span className="font-semibold text-gray-900">
                            USD {unit.rentAmount.toLocaleString()}
                          </span>
                        </div>
                      ) : (
                        <span className="text-sm text-gray-400 italic">Not set</span>
                      )}
                    </td>

                    {/* Appliances */}
                    <td className="px-6 py-4">
                      {applianceCount > 0 ? (
                        <div className="flex items-center gap-2">
                          <Utensils className="w-4 h-4 text-gray-400" />
                          <span className="text-sm text-gray-900">{applianceCount} appliance{applianceCount !== 1 ? 's' : ''}</span>
                        </div>
                      ) : (
                        <span className="text-sm text-gray-400 italic">None</span>
                      )}
                    </td>

                    {/* Status */}
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <div className={`w-2 h-2 rounded-full ${
                          unit.isOccupied ? 'bg-navy-500 animate-pulse' : 'bg-gray-400'
                        }`} />
                        <span className={`text-sm font-medium ${
                          unit.isOccupied ? 'text-green-800' : 'text-gray-600'
                        }`}>
                          {unit.isOccupied ? 'Occupied' : 'Vacant'}
                        </span>
                      </div>
                    </td>

                    {/* Actions */}
                    <td className="px-6 py-4">
                      <div className="flex flex-col gap-2">
                        <Link
                          href={`/property-manager/view-own-property/${propertyId}/units/${unit.unitNumber}/edit`}
                          className={`px-4 py-2 rounded-lg font-medium text-sm text-center transition-colors ${
                            hasDetails
                              ? 'bg-yellow-500 hover:bg-yellow-600 text-white'
                              : 'bg-blue-600 hover:bg-blue-700 text-white'
                          }`}
                        >
                          {hasDetails ? 'Edit Details' : 'Add Details'}
                        </Link>
                        
                        {isListed && unit.id ? (
                          <Link
                            href={`/property-manager/listings?unit=${unit.id}`}
                            className="px-4 py-2 rounded-lg font-semibold text-sm text-center bg-emerald-700 text-white transition-colors shadow-sm ring-1 ring-emerald-800/40"
                          >
                            <Eye className="w-4 h-4 inline-block mr-2" />
                            Listed
                          </Link>
                        ) : (
                          <Link
                            href={`/property-manager/view-own-property/${propertyId}/units/${unit.unitNumber}/list`}
                            className="px-4 py-2 rounded-lg font-semibold text-sm text-center bg-emerald-600 hover:bg-emerald-700 text-white transition-colors shadow-sm ring-1 ring-emerald-700/30"
                          >
                            List Unit
                          </Link>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Summary Footer */}
      <div className="mt-8 grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-blue-100 rounded-xl flex items-center justify-center">
              <Home className="w-6 h-6 text-blue-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-gray-900">{units.length}</div>
              <div className="text-sm text-gray-600">Total Units</div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-navy-100 rounded-xl flex items-center justify-center">
              <Users className="w-6 h-6 text-navy-700" />
            </div>
            <div>
              <div className="text-2xl font-bold text-navy-700">{occupiedUnits}</div>
              <div className="text-sm text-gray-600">Occupied Units</div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-purple-100 rounded-xl flex items-center justify-center">
              <Bed className="w-6 h-6 text-purple-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-gray-900">{totalRooms}</div>
              <div className="text-sm text-gray-600">Total Rooms</div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-200 shadow-sm">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-orange-100 rounded-xl flex items-center justify-center">
              <Bath className="w-6 h-6 text-orange-600" />
            </div>
            <div>
              <div className="text-2xl font-bold text-gray-900">{totalBathrooms}</div>
              <div className="text-sm text-gray-600">Total Bathrooms</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

import Navbar from "@/components/Dashboard/Navbar/Navbar";
import Footer from "@/components/website/Footer";
import PropertyCards from "@/components/PropertyManagement/ViewProperty";

export default function CategoriesPage() {
  return (
    <div className="min-h-screen bg-background">
      <Navbar />

      <section className="w-full bg-[#18181a] text-white py-18 mb-8 flex flex-col items-center justify-center text-center">
        <div className="max-w-3xl mx-auto px-6">
          <h1 className="text-2xl md:text-4xl text-gradient-primary font-bold mb-6 py-4">
            Your Properties
          </h1>
        </div>
      </section>

      <PropertyCards />

    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { FileText, Upload, Trash2, FileCheck } from "lucide-react";
import { LeaseDocumentType } from "@prisma/client";

interface Lease {
  id: string;
  propertyName: string;
  rentAmount: number;
  paymentDueDay: number;
  startDate: string;
  endDate: string;
  leaseStatus: string;
  documentVersion: number;
}

interface LeaseDocument {
  id: string;
  leaseId: string;
  documentType: LeaseDocumentType;
  fileName: string;
  fileUrl: string;
  fileSize: number;
  mimeType: string;
  uploadedBy: string;
  description?: string;
  createdAt: string;
}

interface LeaseAmendment {
  id: string;
  leaseId: string;
  amendmentType: string;
  description?: string;
  status: "PENDING" | "APPROVED" | "REJECTED" | "EXECUTED";
  createdAt: string;
  effectiveDate: string;
}

export default function TenantLeasePage() {
  const params = useParams();

  // Get leaseId directly from params - it's already resolved in client components
  const leaseId = typeof params.id === 'string' ? params.id : Array.isArray(params.id) ? params.id[0] : null;

  const [lease, setLease] = useState<Lease | null>(null);
  const [documents, setDocuments] = useState<LeaseDocument[]>([]);
  const [amendments, setAmendments] = useState<LeaseAmendment[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [documentType, setDocumentType] = useState<LeaseDocumentType>("OTHER");
  const [description, setDescription] = useState("");

  // Fetch all lease-related data
  useEffect(() => {
    console.log("LeaseId from params:", leaseId);

    if (!leaseId) {
      setError("No lease ID provided");
      setLoading(false);
      return;
    }

    fetchData();
  }, [leaseId]);

  async function fetchData() {
    if (!leaseId) return;

    console.log("Fetching data for lease:", leaseId);
    setLoading(true);
    setError(null);

    try {
      // Fetch lease data
      const leaseRes = await fetch(`/api/lease/${leaseId}`);
      if (!leaseRes.ok) {
        const errorData = await leaseRes.json().catch(() => ({ error: "Failed to fetch lease" }));
        throw new Error(errorData.error || `Failed to fetch lease: ${leaseRes.status}`);
      }
      const leaseDataRaw = await leaseRes.json();

      // Map API response to Lease interface
      const leaseData: Lease = {
        id: leaseDataRaw.id,
        propertyName: leaseDataRaw.property?.name || "Unknown Property",
        rentAmount: leaseDataRaw.rentAmount,
        paymentDueDay: leaseDataRaw.paymentDueDay,
        startDate: leaseDataRaw.startDate,
        endDate: leaseDataRaw.endDate,
        leaseStatus: leaseDataRaw.leaseStatus,
        documentVersion: leaseDataRaw.documentVersion ?? 0,
      };

      setLease(leaseData);

      // Fetch documents - don't fail if this errors
      try {
        const docRes = await fetch(`/api/lease/${leaseId}/document`);
        if (docRes.ok) {
          const docData: LeaseDocument[] = await docRes.json();
          setDocuments(docData);
        } else {
          console.warn("Failed to fetch documents, continuing anyway");
          setDocuments([]);
        }
      } catch (docErr) {
        console.warn("Document fetch error:", docErr);
        setDocuments([]);
      }

      // Fetch amendments - don't fail if this errors
      try {
        const amendRes = await fetch(`/api/lease/${leaseId}/ammendment`);
        if (amendRes.ok) {
          const amendData: LeaseAmendment[] = await amendRes.json();
          setAmendments(amendData);
        } else {
          console.warn("Failed to fetch amendments, continuing anyway");
          setAmendments([]);
        }
      } catch (amendErr) {
        console.warn("Amendment fetch error:", amendErr);
        setAmendments([]);
      }

    } catch (err) {
      console.error("Fetch tenant lease data error:", err);
      setError(err instanceof Error ? err.message : "Failed to fetch lease data");
    } finally {
      setLoading(false);
    }
  }

  // Upload document
  async function uploadDocument() {
    if (!file || !leaseId) return;
    try {
      setUploading(true);
      const formData = new FormData();
      formData.append("file", file);
      formData.append("documentType", documentType);
      formData.append("description", description);

      const res = await fetch(`/api/lease/${leaseId}/document`, {
        method: "POST",
        body: formData,
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({ error: "Upload failed" }));
        throw new Error(errData.error || "Upload failed");
      }

      const newDoc: LeaseDocument = await res.json();
      setDocuments([newDoc, ...documents]);
      setFile(null);
      setDescription("");
      setDocumentType("OTHER");
      alert("Document uploaded successfully!");
    } catch (err) {
      console.error("Document upload error:", err);
      alert(err instanceof Error ? err.message : "Upload failed");
    } finally {
      setUploading(false);
    }
  }

  // Sign amendment
  async function signAmendment(amendmentId: string) {
    if (!leaseId) return;
    try {
      const res = await fetch(`/api/lease/${leaseId}/amendment/${amendmentId}/sign`, {
        method: "POST",
      });
      if (!res.ok) throw new Error("Failed to sign amendment");
      alert("Amendment signed successfully!");
      fetchData(); // Refresh data
    } catch (err) {
      console.error("Sign amendment error:", err);
      alert(err instanceof Error ? err.message : "Failed to sign amendment");
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading lease details...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center bg-white p-8 rounded-xl shadow-lg">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <span className="text-red-600 text-3xl">⚠</span>
          </div>
          <p className="text-xl font-semibold text-red-600 mb-2">Error Loading Lease</p>
          <p className="text-gray-600 mb-4">{error}</p>
          <button
            onClick={() => fetchData()}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  if (!lease) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center bg-white p-8 rounded-xl shadow-lg">
          <p className="text-xl text-red-600">Lease not found</p>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 p-6">
      {/* Lease Details */}
      <div className="bg-white p-6 rounded-xl shadow space-y-2">
        <h2 className="text-xl font-semibold">{lease.propertyName} Lease</h2>
        <p>Rent Amount: ${lease.rentAmount.toLocaleString()}</p>
        <p>Payment Due Day: {lease.paymentDueDay}</p>
        <p>Start Date: {new Date(lease.startDate).toLocaleDateString()}</p>
        <p>End Date: {new Date(lease.endDate).toLocaleDateString()}</p>
        <p>Status: <span className="font-semibold">{lease.leaseStatus}</span></p>
        <p>Document Version: {lease.documentVersion}</p>
      </div>

      {/* Upload Documents */}
      <div className="bg-white p-6 rounded-xl shadow space-y-3">
        <h3 className="text-lg font-medium flex items-center gap-2">
          <FileText className="w-5 h-5 text-blue-600" /> Upload Document
        </h3>
        <input
          type="file"
          onChange={(e) => setFile(e.target.files?.[0] || null)}
          className="block w-full border border-gray-300 rounded px-3 py-2"
        />
        <select
          className="w-full border border-gray-300 rounded px-3 py-2"
          value={documentType}
          onChange={(e) => setDocumentType(e.target.value as LeaseDocumentType)}
        >
          {Object.keys(LeaseDocumentType).map((type) => (
            <option key={type} value={type}>
              {type.replace(/_/g, " ")}
            </option>
          ))}
        </select>
        <textarea
          placeholder="Description (optional)"
          className="w-full border border-gray-300 rounded px-3 py-2"
          value={description}
          onChange={(e) => setDescription(e.target.value)}
          rows={3}
        />
        <button
          onClick={uploadDocument}
          disabled={!file || uploading}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed flex items-center gap-2"
        >
          <Upload className="w-4 h-4" /> {uploading ? "Uploading..." : "Upload Document"}
        </button>
      </div>

      {/* Documents List */}
      <div className="bg-white p-6 rounded-xl shadow space-y-3">
        <h3 className="text-lg font-medium flex items-center gap-2">
          <FileText className="w-5 h-5 text-blue-600" /> Lease Documents ({documents.length})
        </h3>
        {documents.length === 0 ? (
          <p className="text-gray-500">No documents uploaded yet.</p>
        ) : (
          <div className="space-y-2">
            {documents.map((doc) => (
              <div key={doc.id} className="flex justify-between items-center border border-gray-200 rounded p-3 hover:bg-gray-50">
                <div>
                  <p className="font-medium">{doc.fileName}</p>
                  <p className="text-xs text-gray-500">
                    {doc.documentType.replace(/_/g, " ")} &middot; {(doc.fileSize / 1024).toFixed(2)} KB &middot; Uploaded on{" "}
                    {new Date(doc.createdAt).toLocaleDateString()}
                  </p>
                  {doc.description && <p className="text-sm text-gray-600 mt-1">{doc.description}</p>}
                </div>
                <a
                  href={doc.fileUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-600 hover:underline text-sm font-medium"
                >
                  View
                </a>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Amendments */}
      <div className="bg-white p-6 rounded-xl shadow space-y-3">
        <h3 className="text-lg font-medium flex items-center gap-2">
          <FileCheck className="w-5 h-5 text-blue-600" /> Amendments ({amendments.length})
        </h3>
        {amendments.length === 0 ? (
          <p className="text-gray-500">No amendments proposed yet.</p>
        ) : (
          <div className="space-y-2">
            {amendments.map((amend) => (
              <div key={amend.id} className="flex justify-between items-center border border-gray-200 rounded p-3 hover:bg-gray-50">
                <div>
                  <p className="font-medium">{amend.description || amend.amendmentType.replace(/_/g, " ")}</p>
                  <p className="text-xs text-gray-500">
                    Status: <span className="font-semibold">{amend.status}</span> &middot; Effective: {new Date(amend.effectiveDate).toLocaleDateString()}
                  </p>
                </div>
                {amend.status === "PENDING" && (
                  <button
                    onClick={() => signAmendment(amend.id)}
                    className="px-3 py-1 bg-navy-700 text-white rounded hover:bg-navy-800 text-sm font-medium"
                  >
                    Sign Amendment
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import dynamic from "next/dynamic"; // 1. Dynamic Import for PDF to avoid SSR issues
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { Loader2, PenTool, CheckCircle, Clock } from "lucide-react";

// Dynamically import PDF Viewer
const PdfViewer = dynamic(() => import("@/components/dss/PdfViewer"), { ssr: false });

export default function SigningRoomPage() {
  const params = useParams(); // Next.js 15: params might be a Promise in server components, but this is "use client"
  const router = useRouter();
  // Safe cast: In Client Components, params is unwrapped or accessible directly depending on version,
  // but to be safe for Next 15 types, treat as unknown then string.
  const documentId = params?.id as string;

  const [docData, setDocData] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [signing, setSigning] = useState(false);

  // 2. Fetch Data
  useEffect(() => {
    if(!documentId) return;

    async function fetchData() {
      try {
        const res = await fetch(`/api/dss/documents/${documentId}`);
        const data = await res.json();

        if (!res.ok) throw new Error(data.error || "Failed to load");

        setDocData(data);
      } catch (error: any) {
        toast.error(error.message);
      } finally {
        setLoading(false);
      }
    }
    fetchData();
  }, [documentId]);

  // 3. Handle Sign Action
  const handleSign = async () => {
    setSigning(true);
    try {
      const res = await fetch("/api/dss/sign", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          documentId,
          signatureData: "Signed via RentFlow360 Web UI (Timestamped)", // In future, use a canvas signature pad here
        }),
      });

      const result = await res.json();
      if (!res.ok) throw new Error(result.error);

      toast.success("Signed successfully!");

      // Refresh page data to show updated status
      // We manually update local state to avoid full reload
      setDocData((prev: any) => ({
        ...prev,
        canSign: false, // Turn off button
        document: {
             ...prev.document,
             // Optimistically update the current user's status in list
             // (Optional, or just force reload window)
        }
      }));

      // Force reload to be safe
      window.location.reload();

    } catch (error: any) {
      toast.error(error.message);
    } finally {
      setSigning(false);
    }
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin text-blue-600 w-8 h-8" /></div>;
  if (!docData) return <div className="p-10 text-center">Document not found</div>;

  const { document, canSign } = docData;

  return (
    <div className="container mx-auto py-8 max-w-5xl px-4">

      {/* Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4 bg-white p-6 rounded-xl border shadow-sm">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">{document.title}</h1>
          <div className="flex items-center gap-2 mt-1">
             <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                 document.status === 'COMPLETED' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'
             }`}>
                {document.status}
             </span>
             <span className="text-gray-500 text-sm">• Step {document.currentStep}</span>
          </div>
        </div>

        {/* Dynamic Action Button */}
        {canSign ? (
          <Button onClick={handleSign} disabled={signing} size="lg" className="bg-green-600 hover:bg-green-700 w-full md:w-auto">
            {signing ? <Loader2 className="animate-spin mr-2" /> : <PenTool className="mr-2 w-5 h-5" />}
            Sign Now
          </Button>
        ) : (
          <Button disabled variant="outline" size="lg" className="w-full md:w-auto">
            {document.status === 'COMPLETED' ?
               <><CheckCircle className="mr-2 w-5 h-5 text-green-500"/> Document Completed</> :
               <><Clock className="mr-2 w-5 h-5"/> Waiting for others</>
            }
          </Button>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Main Content: PDF */}
        <div className="lg:col-span-2">
           {document.originalFileUrl ? (
             <PdfViewer url={document.originalFileUrl} />
           ) : (
             <div className="h-64 bg-gray-100 rounded-lg flex items-center justify-center text-gray-500">
               No document file available
             </div>
           )}
        </div>

        {/* Sidebar: Participants List */}
        <div className="bg-white p-6 rounded-xl border shadow-sm h-fit">
          <h3 className="font-semibold text-gray-900 mb-4">Signers</h3>
          <div className="space-y-4">
             {document.participants.map((p: any, idx: number) => (
               <div key={idx} className="flex items-center justify-between">
                 <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${
                        p.status === 'SIGNED' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'
                    }`}>
                        {idx + 1}
                    </div>
                    <div>
                        <p className="text-sm font-medium text-gray-900">{p.name || p.email}</p>
                        <p className="text-xs text-gray-500 uppercase">{p.role}</p>
                    </div>
                 </div>
                 {p.status === 'SIGNED' && <CheckCircle className="w-4 h-4 text-green-500" />}
               </div>
             ))}
          </div>
        </div>

      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { useRouter } from "next/navigation";
import {
  Calendar,
  Home,
  Wrench,
  CreditCard,
  AlertCircle,
  CheckCircle,
  Clock,
  DollarSign,
  Plus,
} from "lucide-react";

import { useAuth } from "@/context/AuthContext";
import { useLease } from "@/hooks/useLease";
import { useInvoices } from "@/hooks/useInvoice";
import { useMaintenanceRequests } from "@/hooks/useMaintenanceRequests";
import { PaymentModal } from "@/components/Dashboard/tenantsdash/PaymentModal";

const DashboardPage = () => {
  const [isLoading] = useState(false);
  const { user } = useAuth();
  const router = useRouter();

  const [inviteLink, setInviteLink] = useState<string | null>(null);
  const [inviteError, setInviteError] = useState<string | null>(null);
  const [isGeneratingInvite, setIsGeneratingInvite] = useState(false);
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [showNewRequestModal, setShowNewRequestModal] = useState(false);
  const [newRequestTitle, setNewRequestTitle] = useState("");
  const [newRequestDescription, setNewRequestDescription] = useState("");
  const [newRequestPriority, setNewRequestPriority] = useState<"LOW" | "NORMAL" | "HIGH" | "URGENT">("NORMAL");

  // Leases hook
  const {
    leases,
    activeLease,
    loading: leasesLoading,
    error: leasesError,
    refetch: refetchLeases,
  } = useLease();

  // Invoices hook
  const {
    invoices,
    loading: invoicesLoading,
    error: invoiceError,
    refetch: refetchInvoices,
  } = useInvoices();

  // Maintenance requests hook
  const {
    requests: maintenanceRequests,
    loading: maintenanceLoading,
    error: maintenanceError,
    createRequest,
  } = useMaintenanceRequests();

  const generateInviteLink = async () => {
    setIsGeneratingInvite(true);
    setInviteError(null);

    try {
      const response = await fetch("/api/auth/invites/agent/agent-invite", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
      });

      const data = await response.json();

      if (!response.ok) {
        throw new Error(data.error || "Failed to generate invite link");
      }

      setInviteLink(data.inviteUrl);
    } catch (error) {
      console.error("Error generating invite:", error);
      setInviteError(error instanceof Error ? error.message : "Failed to generate invite link");
    } finally {
      setIsGeneratingInvite(false);
    }
  };

  const copyInviteLink = async () => {
    if (!inviteLink) return;
    
    try {
      await navigator.clipboard.writeText(inviteLink);
      // To replace alert with a toast notification
      alert("Invite link copied to clipboard");
    } catch (error) {
      console.error("Failed to copy:", error);
      alert("Failed to copy link");
    }
  };

  const refetchAll = async () => {
    await Promise.all([refetchLeases(), refetchInvoices()]);
  };

  // Calculate days remaining in lease
  const calculateDaysRemaining = (endDate: string) => {
    const end = new Date(endDate);
    const today = new Date();
    const diffTime = end.getTime() - today.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  };

  // Calculate next rent payment info from invoices
  const getNextPaymentInfo = () => {
    if (invoices.length === 0) {
      return {
        nextPaymentDue: null,
        paymentStatus: "upcoming",
        daysUntilPayment: 0,
        amount: activeLease?.rentAmount || 0,
      };
    }

    // Find unpaid or partially paid rent invoices
    const pendingInvoices = invoices
      .filter((inv) => inv.type === "RENT" && inv.balance > 0)
      .sort(
        (a, b) =>
          new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime()
      );

    if (pendingInvoices.length === 0) {
      return {
        nextPaymentDue: null,
        paymentStatus: "paid",
        daysUntilPayment: 0,
        amount: activeLease?.rentAmount || 0,
      };
    }

    const nextInvoice = pendingInvoices[0];
    const dueDate = new Date(nextInvoice.dueDate);
    const today = new Date();
    const daysUntil = Math.ceil(
      (dueDate.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
    );

    return {
      nextPaymentDue: nextInvoice.dueDate,
      paymentStatus: daysUntil < 0 ? "overdue" : "upcoming",
      daysUntilPayment: daysUntil,
      amount: nextInvoice.balance,
    };
  };

  const paymentInfo = getNextPaymentInfo();

  // Use API data
  const daysRemaining = activeLease
    ? calculateDaysRemaining(activeLease.endDate)
    : 0;

  // Calculate lease duration in days
  const leaseDurationDays = activeLease
    ? Math.ceil(
      (new Date(activeLease.endDate).getTime() -
        new Date(activeLease.startDate).getTime()) /
      (1000 * 60 * 60 * 24)
    )
    : 365;

  const leasePercentComplete =
    leaseDurationDays > 0
      ? ((leaseDurationDays - daysRemaining) / leaseDurationDays) * 100
      : 0;

  const getStatusColor = (status: string) => {
    switch (status) {
      case "completed":
        return "text-green-600 bg-green-50 border-green-200";
      case "in_progress":
        return "text-blue-600 bg-blue-50 border-blue-200";
      case "pending":
        return "text-yellow-600 bg-yellow-50 border-yellow-200";
      default:
        return "text-gray-600 bg-gray-50 border-gray-200";
    }
  };

  const getPaymentStatusColor = (status: string) => {
    switch (status) {
      case "paid":
        return "text-green-600 bg-green-50 border-green-200";
      case "upcoming":
        return "text-blue-600 bg-blue-50 border-blue-200";
      case "overdue":
        return "text-red-600 bg-red-50 border-red-200";
      default:
        return "text-gray-600 bg-gray-50 border-gray-200";
    }
  };

  if (leasesLoading || invoicesLoading || isLoading) {
    return (
      <div className="bg-gray-50 h-full flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900 mx-auto"></div>
          <p className="mt-2 text-gray-600">Loading...</p>
        </div>
      </div>
    );
  }

  // Show error state if API calls failed
  if (leasesError || invoiceError) {
    return (
      <div className="bg-gray-50 h-full flex items-center justify-center">
        <div className="text-center max-w-md p-6">
          <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-4" />
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Failed to Load Data</h2>
          <p className="text-gray-600 mb-4">{leasesError || invoiceError}</p>
          <button 
            onClick={refetchAll}
            className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-lg"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  // Check if user is floating (not linked to any organization)
  const isFloating = !user?.organization;

  if (isFloating) {
    return (
      <div className="bg-gray-50 h-full p-10">
        <div className="max-w-2xl mx-auto text-center">
          <h1 className="text-3xl font-bold mb-4 text-gray-900">Welcome to RentFlow360!</h1>
          <p className="text-lg text-gray-600 mb-8">You are not linked to any property yet.</p>

          <div className="space-y-6">
            <div className="p-6 border rounded-lg bg-blue-50 border-blue-200">
              <h3 className="text-xl font-semibold text-blue-900 mb-2">Have an Invite Code?</h3>
              <p className="text-blue-700 mb-4">Check your email for a link from your landlord or property manager.</p>
              <p className="text-sm text-blue-600">If you have received an invitation, click the link to join your property.</p>
            </div>

            <div className="p-6 border rounded-lg bg-white border-gray-200">
              <h3 className="text-xl font-semibold text-gray-900 mb-2">Looking for a place?</h3>
              <p className="text-gray-600 mb-4">Browse available properties and apply to rent.</p>
              <button className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg font-medium transition-colors">
                Browse Listings (Coming Soon)
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Show message if no active lease found
  if (!activeLease) {
    return (
      <div className="bg-gray-50 h-full p-10">
        <div className="max-w-2xl mx-auto text-center">
          <h1 className="text-3xl font-bold mb-4 text-gray-900">Welcome, {user?.firstName}!</h1>
          <div className="p-6 border rounded-lg bg-yellow-50 border-yellow-200">
            <AlertCircle className="w-12 h-12 text-yellow-600 mx-auto mb-4" />
            <h3 className="text-xl font-semibold text-yellow-900 mb-2">No Active Lease Found</h3>
            <p className="text-yellow-700">You don&apos;t have an active lease at the moment. Please contact your property manager.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-gray-50 h-screen overflow-hidden flex flex-col">
      <div className="flex-1 overflow-y-auto">
        <div className="max-w-7xl mx-auto p-6">

          {/* Invite Agent */}
          <div className="lg:col-span-3 bg-white rounded-lg shadow-sm border border-gray-200 p-6 mb-7">
            <div className="flex items-center justify-between mb-4">
              <div>
                <h2 className="text-xl font-semibold text-gray-900">Invite an Agent</h2>
                <p className="text-sm text-gray-600">
                  Invite a real estate agent to assist you with tenant duties.
                </p>
              </div>
            </div>

            {inviteError && (
              <div className="mb-4 p-3 bg-red-50 border border-red-200 rounded-lg flex items-start gap-2">
                <AlertCircle className="w-5 h-5 text-red-600 flex-shrink-0 mt-0.5" />
                <p className="text-sm text-red-700">{inviteError}</p>
              </div>
            )}

            {!inviteLink ? (
              <button
                onClick={generateInviteLink}
                disabled={isGeneratingInvite}
                className="bg-blue-600 hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed text-white px-6 py-3 rounded-lg font-medium transition-colors"
              >
                {isGeneratingInvite ? "Generating link..." : "Generate Agent Invite Link"}
              </button>
            ) : (
              <div className="space-y-3">
                <div className="flex items-center gap-2">
                  <input
                    type="text"
                    value={inviteLink}
                    readOnly
                    className="flex-1 px-3 py-2 border rounded-lg text-sm bg-gray-50"
                  />
                  <button
                    onClick={copyInviteLink}
                    className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg text-sm font-medium"
                  >
                    Copy
                  </button>
                </div>

                <p className="text-xs text-gray-500">
                  This link will expire in <strong>1 hour</strong> if not used.
                </p>
                
                <button
                  onClick={() => {
                    setInviteLink(null);
                    setInviteError(null);
                  }}
                  className="text-sm text-blue-600 hover:text-blue-700 underline"
                >
                  Generate a new link
                </button>
              </div>
            )}
          </div>

          {/* Main Grid */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 pb-6">
            {/* Lease Duration Card */}
            <div className="lg:col-span-2 bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 bg-blue-50 rounded-lg flex-shrink-0">
                  <Home className="w-6 h-6 text-blue-600" />
                </div>
                <div className="min-w-0">
                  <h2 className="text-xl font-semibold text-gray-900">Lease Information</h2>
                  <p className="text-sm text-gray-500 truncate">
                    {activeLease.property.propertyName !== 'Unnamed Property' && `${activeLease.property.propertyName}, `}
                    {activeLease.property.address}, Unit {activeLease.unit.unitNumber}
                  </p>
                </div>
              </div>

              <div className="space-y-4">
                <div className="flex justify-between items-center gap-4">
                  <span className="text-gray-600 flex-shrink-0">Lease Period</span>
                  <span className="font-medium text-gray-900 text-right text-sm">
                    {new Date(activeLease.startDate).toLocaleDateString()} - {new Date(activeLease.endDate).toLocaleDateString()}
                  </span>
                </div>

                <div>
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-gray-600">Days Remaining</span>
                    <span className="font-bold text-2xl text-blue-600">{daysRemaining}</span>
                  </div>
                  <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
                    <div
                      className="bg-blue-600 h-3 rounded-full transition-all duration-500"
                      style={{ width: `${Math.min(Math.max(leasePercentComplete, 0), 100)}%` }}
                    ></div>
                  </div>
                  <p className="text-xs text-gray-500 mt-1">{leasePercentComplete.toFixed(0)}% of lease period completed</p>
                </div>

                <div className="pt-4 border-t border-gray-200">
                  <div className="flex items-center gap-2 text-sm text-gray-600">
                    <Calendar className="w-4 h-4 flex-shrink-0" />
                    <span className="truncate">Lease ends on {new Date(activeLease.endDate).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</span>
                  </div>
                </div>
              </div>
            </div>

            {/* Payment Reminder Card */}
            <div className={`bg-white rounded-lg shadow-sm border p-6 ${getPaymentStatusColor(paymentInfo.paymentStatus)}`}>
              <div className="flex items-center gap-3 mb-4">
                <div className={`p-2 rounded-lg ${paymentInfo.paymentStatus === 'overdue' ? 'bg-red-100' : paymentInfo.paymentStatus === 'paid' ? 'bg-green-100' : 'bg-blue-100'}`}>
                  <CreditCard className={`w-6 h-6 ${paymentInfo.paymentStatus === 'overdue' ? 'text-red-600' : paymentInfo.paymentStatus === 'paid' ? 'text-green-600' : 'text-blue-600'}`} />
                </div>
                <h2 className="text-xl font-semibold text-gray-900">Rent Payment</h2>
              </div>

              <div className="space-y-3">
                <div>
                  <p className="text-sm text-gray-600 mb-1">Monthly Rent</p>
                  <p className="text-3xl font-bold text-gray-900">${activeLease.rentAmount.toLocaleString()}</p>
                </div>

                {paymentInfo.nextPaymentDue ? (
                  <div className="pt-3 border-t border-gray-200">
                    <p className="text-sm text-gray-600 mb-1">
                      {paymentInfo.paymentStatus === 'overdue' ? 'Overdue Payment' : 'Next Payment Due'}
                    </p>
                    <p className="font-semibold text-gray-900">
                      {new Date(paymentInfo.nextPaymentDue).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}
                    </p>

                    {paymentInfo.paymentStatus === 'upcoming' && paymentInfo.daysUntilPayment > 0 && (
                      <div className="flex items-center gap-2 mt-2 text-sm text-blue-600">
                        <Clock className="w-4 h-4" />
                        <span>{paymentInfo.daysUntilPayment} days remaining</span>
                      </div>
                    )}

                    {paymentInfo.paymentStatus === 'overdue' && (
                      <div className="flex items-center gap-2 mt-2 text-sm text-red-600">
                        <AlertCircle className="w-4 h-4" />
                        <span>{Math.abs(paymentInfo.daysUntilPayment)} days overdue</span>
                      </div>
                    )}

                    {paymentInfo.amount !== activeLease.rentAmount && (
                      <p className="text-sm text-gray-600 mt-2">
                        Amount due: <span className="font-semibold">${paymentInfo.amount.toLocaleString()}</span>
                      </p>
                    )}
                  </div>
                ) : (
                  <div className="pt-3 border-t border-gray-200">
                    <div className="flex items-center gap-2 text-sm text-green-600">
                      <CheckCircle className="w-4 h-4" />
                      <span>All payments current</span>
                    </div>
                  </div>
                )}

                <button 
                  onClick={() => setShowPaymentModal(true)}
                  className="w-full mt-4 bg-blue-600 hover:bg-blue-700 text-white px-4 py-3 rounded-lg font-medium transition-colors flex items-center justify-center gap-2"
                >
                  <DollarSign className="w-5 h-5" />
                  Pay Rent Now
                </button>
              </div>
            </div>

            {/* Maintenance Status Card */}
            <div className="lg:col-span-3 bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <div className="flex items-center justify-between mb-6 gap-4">
                <div className="flex items-center gap-3 min-w-0">
                  <div className="p-2 bg-green-50 rounded-lg flex-shrink-0">
                    <Wrench className="w-6 h-6 text-green-600" />
                  </div>
                  <h2 className="text-xl font-semibold text-gray-900 truncate">Maintenance Requests</h2>
                </div>
                <button 
                  onClick={() => setShowNewRequestModal(true)}
                  className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors whitespace-nowrap flex-shrink-0 flex items-center gap-2"
                >
                  <Plus className="w-4 h-4" />
                  New Request
                </button>
              </div>

              {maintenanceLoading ? (
                <div className="text-center py-8">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-green-600 mx-auto"></div>
                  <p className="mt-2 text-gray-600">Loading maintenance requests...</p>
                </div>
              ) : maintenanceError ? (
                <div className="text-center py-8 text-red-500">
                  <AlertCircle className="w-12 h-12 mx-auto mb-3" />
                  <p>Error loading maintenance requests</p>
                  <p className="text-sm">{maintenanceError}</p>
                </div>
              ) : maintenanceRequests.length === 0 ? (
                <div className="text-center py-8 text-gray-500">
                  <Wrench className="w-12 h-12 mx-auto mb-3 text-gray-300" />
                  <p>No maintenance requests</p>
                  <p className="text-sm mt-2">Submit a request using the "New Request" button</p>
                </div>
              ) : (
                <div className="space-y-3">
                  {maintenanceRequests.map((request) => (
                    <div key={request.id} className={`p-4 rounded-lg border ${getStatusColor(request.status)}`}>
                      <div className="flex items-start justify-between gap-4">
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-3 mb-2 flex-wrap">
                            <h3 className="font-semibold text-gray-900 truncate">{request.title}</h3>
                            <span className={`px-2 py-1 rounded text-xs font-medium whitespace-nowrap flex-shrink-0 ${
                              request.priority === 'high' || request.priority === 'URGENT' ? 'bg-red-100 text-red-700' :
                              request.priority === 'medium' || request.priority === 'NORMAL' ? 'bg-yellow-100 text-yellow-700' :
                              'bg-gray-100 text-gray-700'
                            }`}>
                              {request.priority}
                            </span>
                          </div>
                          <div className="text-sm text-gray-600 mb-2">{request.description}</div>
                          <div className="flex items-center gap-4 text-sm text-gray-600 flex-wrap">
                            <span className="whitespace-nowrap">ID: {request.id.slice(0, 8)}</span>
                            <span className="whitespace-nowrap">Submitted: {new Date(request.createdAt).toLocaleDateString()}</span>
                            {request.completedDate && (
                              <span className="whitespace-nowrap">Completed: {new Date(request.completedDate).toLocaleDateString()}</span>
                            )}
                            {request.property && (
                              <span className="whitespace-nowrap">Property: {request.property.name}</span>
                            )}
                          </div>
                        </div>
                        <div className="flex items-center gap-2 flex-shrink-0">
                          {request.status === 'completed' || request.status === 'COMPLETED' ? (
                            <CheckCircle className="w-5 h-5 text-green-600" />
                          ) : request.status === 'in_progress' || request.status === 'IN_PROGRESS' ? (
                            <Clock className="w-5 h-5 text-blue-600" />
                          ) : (
                            <AlertCircle className="w-5 h-5 text-yellow-600" />
                          )}
                          <span className="text-sm font-medium capitalize whitespace-nowrap">
                            {request.status.toLowerCase().replace('_', ' ')}
                          </span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Quick Actions */}
            <div className="lg:col-span-3 bg-white rounded-lg shadow-sm border border-gray-200 p-6">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">Quick Actions</h2>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <button 
                  onClick={() => router.push('/tenant/content/invoices')}
                  className="p-4 border-2 border-gray-200 hover:border-blue-400 rounded-lg text-left transition-colors group min-w-0"
                >
                  <CreditCard className="w-8 h-8 text-gray-600 group-hover:text-blue-600 mb-2 flex-shrink-0" />
                  <h3 className="font-semibold text-gray-900 truncate">Payment History</h3>
                  <p className="text-sm text-gray-600 truncate">View all transactions</p>
                </button>
                  <button 
                    onClick={() => router.push('/tenant/content/lease')}
                    className="p-4 border-2 border-gray-200 hover:border-blue-400 rounded-lg text-left transition-colors group min-w-0"
                  >
                    <Home className="w-8 h-8 text-gray-600 group-hover:text-blue-600 mb-2 flex-shrink-0" />
                    <h3 className="font-semibold text-gray-900 truncate">Lease Documents</h3>
                    <p className="text-sm text-gray-600 truncate">Access your lease</p>
                  </button>
                <button 
                  onClick={() => setShowNewRequestModal(true)}
                  className="p-4 border-2 border-gray-200 hover:border-blue-400 rounded-lg text-left transition-colors group min-w-0"
                >
                  <Wrench className="w-8 h-8 text-gray-600 group-hover:text-blue-600 mb-2 flex-shrink-0" />
                  <h3 className="font-semibold text-gray-900 truncate">Request Service</h3>
                  <p className="text-sm text-gray-600 truncate">Report an issue</p>
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Payment Modal */}
      {paymentInfo.nextPaymentDue && (
        <PaymentModal
          isOpen={showPaymentModal}
          onClose={() => setShowPaymentModal(false)}
          invoiceId={invoices.find(inv => inv.type === "RENT" && inv.balance > 0)?.id}
          amount={paymentInfo.amount}
          currency="USD"
          onPaymentSuccess={() => {
            refetchInvoices();
            alert("Payment successful! Your invoice will be updated shortly.");
          }}
        />
      )}

      {/* New Maintenance Request Modal */}
      {showNewRequestModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl max-w-md w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-xl font-semibold text-gray-900">New Maintenance Request</h2>
                <button
                  onClick={() => setShowNewRequestModal(false)}
                  className="text-gray-500 hover:text-gray-700"
                >
                  ✕
                </button>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Title *
                  </label>
                  <input
                    type="text"
                    value={newRequestTitle}
                    onChange={(e) => setNewRequestTitle(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg"
                    placeholder="Brief description of the issue"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Description *
                  </label>
                  <textarea
                    value={newRequestDescription}
                    onChange={(e) => setNewRequestDescription(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg h-32"
                    placeholder="Provide detailed information about the issue..."
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Priority
                  </label>
                  <div className="grid grid-cols-4 gap-2">
                    {(["LOW", "NORMAL", "HIGH", "URGENT"] as const).map((priority) => (
                      <button
                        key={priority}
                        type="button"
                        onClick={() => setNewRequestPriority(priority)}
                        className={`px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                          newRequestPriority === priority
                            ? priority === "URGENT"
                              ? "bg-red-600 text-white"
                              : priority === "HIGH"
                              ? "bg-orange-600 text-white"
                              : priority === "NORMAL"
                              ? "bg-blue-600 text-white"
                              : "bg-gray-600 text-white"
                            : "bg-gray-100 text-gray-700 hover:bg-gray-200"
                        }`}
                      >
                        {priority}
                      </button>
                    ))}
                  </div>
                </div>

                <div className="pt-4 border-t border-gray-200">
                  <div className="flex items-center gap-3">
                    <button
                      onClick={() => setShowNewRequestModal(false)}
                      className="px-4 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50"
                    >
                      Cancel
                    </button>
                    <button
                      onClick={async () => {
                        if (!newRequestTitle.trim() || !newRequestDescription.trim()) {
                          alert("Please fill in all required fields");
                          return;
                        }

                        const result = await createRequest({
                          title: newRequestTitle,
                          description: newRequestDescription,
                          priority: newRequestPriority,
                        });

                        if (result.success) {
                          setShowNewRequestModal(false);
                          setNewRequestTitle("");
                          setNewRequestDescription("");
                          setNewRequestPriority("NORMAL");
                          alert("Maintenance request submitted successfully!");
                        } else {
                          alert(`Failed to submit request: ${result.error}`);
                        }
                      }}
                      className="flex-1 bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded-lg font-medium"
                    >
                      Submit Request
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardPage;

"use client";

import { useState, useEffect } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { showCustomToast, ToastContainer } from "@/components/ui/custom-toast";
import { useAuth } from "@/context/AuthContext";
import { Loader2, Shield, ShieldCheck, Phone, Lock } from "lucide-react";

export default function SettingsPage() {
  const { user, refreshUser } = useAuth();
  const [isLoading, setIsLoading] = useState(false);
  const [isSendingOtp, setIsSendingOtp] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);

  // 2FA State
  const [is2FAEnabled, setIs2FAEnabled] = useState(false);
  const [phoneNumber, setPhoneNumber] = useState("");
  const [isPhoneVerified, setIsPhoneVerified] = useState(false);

  // OTP Verification State
  const [showVerificationUI, setShowVerificationUI] = useState(false);
  const [otpDigits, setOtpDigits] = useState(["", "", "", "", "", ""]);

  useEffect(() => {
    if (user) {
      setPhoneNumber(user.phone || "");
      setIs2FAEnabled(user.twoFactorEnabled || false);
      setIsPhoneVerified(!!user.phoneVerified);
    }
  }, [user]);

  // Handle OTP digit change
  const handleOtpChange = (index: number, value: string) => {
    if (value.length > 1) value = value.slice(-1);
    if (!/^\d*$/.test(value)) return;

    const newDigits = [...otpDigits];
    newDigits[index] = value;
    setOtpDigits(newDigits);

    // Auto-focus next input
    if (value && index < 5) {
      const nextInput = document.getElementById(`otp-${index + 1}`);
      nextInput?.focus();
    }
  };

  const handleKeyDown = (index: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === "Backspace" && !otpDigits[index] && index > 0) {
      const prevInput = document.getElementById(`otp-${index - 1}`);
      prevInput?.focus();
    }
  };

  // Handle sending OTP for phone verification
  const handleSendVerificationOtp = async () => {
    if (!phoneNumber) {
      showCustomToast("Please enter a phone number first", "error");
      return;
    }

    if (!phoneNumber.startsWith("+")) {
      showCustomToast("Phone number must be in E.164 format (e.g., +254712345678)", "error");
      return;
    }

    setIsSendingOtp(true);
    try {
      const updateResponse = await fetch('/api/auth/phone/update', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phone: phoneNumber })
      });

      if (!updateResponse.ok) {
        const error = await updateResponse.json();
        showCustomToast(error.error || "Failed to update phone number", "error");
        setIsSendingOtp(false);
        return;
      }

      const sendResponse = await fetch('/api/auth/phone/send-verification', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phone: phoneNumber })
      });

      if (sendResponse.ok) {
        showCustomToast("Verification code sent to your phone", "success");
        setShowVerificationUI(true);
      } else {
        const error = await sendResponse.json();
        showCustomToast(error.error || "Failed to send verification code", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred", "error");
    } finally {
      setIsSendingOtp(false);
    }
  };

  // Handle OTP verification
  const handleVerifyOtp = async () => {
    const fullCode = otpDigits.join("");
    if (fullCode.length !== 6) {
      showCustomToast("Please enter a valid 6-digit code", "error");
      return;
    }

    setIsVerifying(true);
    try {
      const response = await fetch('/api/auth/phone/verify', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ phone: phoneNumber, code: fullCode })
      });

      if (response.ok) {
        showCustomToast("Phone Number Verified Successfully", "success");
        setIsPhoneVerified(true);
        setShowVerificationUI(false);
        setOtpDigits(["", "", "", "", "", ""]);
        await refreshUser();
      } else {
        const error = await response.json();
        showCustomToast(error.error || "Invalid or expired code", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred during verification", "error");
    } finally {
      setIsVerifying(false);
    }
  };

  // Handle enabling 2FA
  const handleEnable2FA = async () => {
    if (!phoneNumber) {
      showCustomToast("Please add a phone number first", "error");
      return;
    }

    if (!isPhoneVerified) {
      showCustomToast("Please verify your phone number first", "error");
      return;
    }

    setIsLoading(true);
    try {
      const response = await fetch('/api/auth/2fa/toggle', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ enable: true })
      });

      if (response.ok) {
        showCustomToast("2FA enabled successfully!", "success");
        setIs2FAEnabled(true);
        await refreshUser();
      } else {
        const error = await response.json();
        showCustomToast(error.error || "Failed to enable 2FA", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred", "error");
    } finally {
      setIsLoading(false);
    }
  };

  // Handle disabling 2FA
  const handleDisable2FA = async () => {
    setIsLoading(true);
    try {
      const response = await fetch('/api/auth/2fa/toggle', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ enable: false })
      });

      if (response.ok) {
        showCustomToast("2FA disabled successfully!", "success");
        setIs2FAEnabled(false);
        await refreshUser();
      } else {
        const error = await response.json();
        showCustomToast(error.error || "Failed to disable 2FA", "error");
      }
    } catch (error) {
      showCustomToast("An error occurred", "error");
    } finally {
      setIsLoading(false);
    }
  };

  // Handle toggle change
  const handleToggle2FA = async (checked: boolean) => {
    if (checked) {
      if (!phoneNumber || !isPhoneVerified) {
        showCustomToast("Please add and verify a phone number first", "error");
        return;
      }
      await handleEnable2FA();
    } else {
      await handleDisable2FA();
    }
  };

  return (
    <div className="container mx-auto py-10 max-w-4xl">
      <h1 className="text-3xl font-bold mb-6">Account Settings</h1>

      <Tabs defaultValue="profile" className="w-full">
        <TabsList className="mb-4">
          <TabsTrigger value="profile" className="flex items-center gap-2">
            <Shield className="h-4 w-4" />
            Profile
          </TabsTrigger>
          <TabsTrigger value="security" className="flex items-center gap-2">
            <Lock className="h-4 w-4" />
            Security & 2FA
          </TabsTrigger>
        </TabsList>

        <TabsContent value="profile">
          <Card>
            <CardHeader>
              <CardTitle>Personal Information</CardTitle>
              <CardDescription>Update your contact details.</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>First Name</Label>
                  <Input defaultValue={user?.firstName} disabled />
                </div>
                <div className="space-y-2">
                  <Label>Last Name</Label>
                  <Input defaultValue={user?.lastName} disabled />
                </div>
              </div>
              <div className="space-y-2">
                <Label>Email</Label>
                <Input defaultValue={user?.email} disabled />
              </div>
              <div className="flex justify-end">
                <Button disabled>Save Changes</Button>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="security">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <ShieldCheck className="h-5 w-5" />
                Two-Factor Authentication
              </CardTitle>
              <CardDescription>
                Secure your account with SMS verification.
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">

              {!showVerificationUI ? (
                <>
                  {/* Phone Number Section */}
                  <div className="space-y-2">
                    <Label className="flex items-center gap-2">
                      <Phone className="h-4 w-4" />
                      Phone Number (for OTP)
                    </Label>
                    <div className="flex gap-2">
                      <Input
                        value={phoneNumber}
                        onChange={(e) => setPhoneNumber(e.target.value)}
                        placeholder="+254712345678"
                        disabled={is2FAEnabled}
                      />
                      {!is2FAEnabled && (
                        <Button
                          variant="outline"
                          onClick={handleSendVerificationOtp}
                          disabled={isSendingOtp}
                        >
                          {isSendingOtp ? <Loader2 className="h-4 w-4 animate-spin" /> : "Verify"}
                        </Button>
                      )}
                    </div>
                    <div className="flex items-center gap-2 text-sm">
                      {isPhoneVerified ? (
                        <span className="text-green-600 flex items-center gap-1">✓ Verified</span>
                      ) : (
                        <span className="text-yellow-600 flex items-center gap-1">⚠ Not verified</span>
                      )}
                      <span className="text-gray-500 text-xs">Format: +254712345678</span>
                    </div>
                  </div>

                  <div className="border-t my-4" />

                  <div className="flex items-center justify-between">
                    <div className="space-y-0.5">
                      <Label className="text-base">Enable 2FA</Label>
                      <p className="text-sm text-gray-500">
                        {is2FAEnabled ? "Your account is protected with 2FA" : "Secure your account with 2FA"}
                      </p>
                    </div>
                    <Switch
                      checked={is2FAEnabled}
                      onCheckedChange={handleToggle2FA}
                      disabled={isLoading || (!isPhoneVerified && !is2FAEnabled)}
                    />
                  </div>
                </>
              ) : (
                <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
                  <div className="space-y-2">
                    <h3 className="text-xl font-bold">Verify Phone Number</h3>
                    <p className="text-sm text-gray-500 leading-relaxed">
                      We've sent a 6-digit verification code to <span className="font-semibold text-gray-700">{phoneNumber}</span>. Enter it below to secure your account.
                    </p>
                  </div>

                  <div className="flex justify-between gap-3 max-w-sm mx-auto">
                    {otpDigits.map((digit, index) => (
                      <Input
                        key={index}
                        id={`otp-${index}`}
                        type="text"
                        inputMode="numeric"
                        maxLength={1}
                        value={digit}
                        onChange={(e) => handleOtpChange(index, e.target.value)}
                        onKeyDown={(e) => handleKeyDown(index, e)}
                        className="w-12 h-14 text-center text-2xl font-bold border-2 focus:border-primary focus:ring-0 rounded-xl"
                      />
                    ))}
                  </div>

                  <div className="text-center">
                    <p className="text-sm text-gray-500">
                      Didn't receive the code?{" "}
                      <button
                        onClick={handleSendVerificationOtp}
                        className="text-primary font-semibold hover:underline decoration-2 underline-offset-4"
                        disabled={isSendingOtp}
                      >
                        {isSendingOtp ? "Sending..." : "Resend Code"}
                      </button>
                    </p>
                  </div>

                  <div className="space-y-3">
                    <Button
                      className="w-full bg-primary hover:bg-blue-600 text-white font-semibold py-6 rounded-2xl shadow-lg shadow-blue-500/20 transition-all active:scale-[0.98]"
                      onClick={handleVerifyOtp}
                      disabled={isVerifying || otpDigits.some(d => !d)}
                    >
                      {isVerifying ? <Loader2 className="h-5 w-5 animate-spin mr-2" /> : "Verify & Continue"}
                    </Button>
                    <Button
                      variant="ghost"
                      className="w-full text-gray-500"
                      onClick={() => setShowVerificationUI(false)}
                      disabled={isVerifying}
                    >
                      Cancel
                    </Button>
                  </div>

                  <div className="pt-4 text-center">
                    <span className="text-[10px] text-gray-400 uppercase tracking-widest font-medium">
                      Standard Carrier Rates Apply
                    </span>
                  </div>
                </div>
              )}

              {isLoading && (
                <div className="flex justify-center">
                  <Loader2 className="h-5 w-5 animate-spin" />
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Custom Toast Notification */}
      <ToastContainer />
    </div>
  );
}

