export async function POST(req: NextRequest) {
  try {
    const data = await req.json();
    const {
      applicationId,
      tenantId,
      propertyId,
      unitId,
      startDate,
      endDate,
      rentAmount,
      securityDeposit,
      leaseTerm,
      paymentDueDay,
      paymentFrequency,
      lateFeeFlat,
      lateFeeDaily,
      gracePeriodDays,
      landlordResponsibilities,
      tenantResponsibilities,
      tenantPaysElectric,
      tenantPaysWater,
      tenantPaysTrash,
      tenantPaysInternet,
      usageType,
      earlyTerminationFee
    } = data;

    if (!applicationId || !propertyId || !unitId) {
      return NextResponse.json(
        { error: "Missing required fields" },
        { status: 400 }
      );
    }

    // Ensure the tenant application exists and is approved
    const app = await prisma.tenantApplication.findUnique({
      where: { id: applicationId },
      include: { property: true, unit: true },
    });

    if (!app) {
      return NextResponse.json({ error: "Application not found" }, { status: 404 });
    }

    if (app.status !== "APPROVED") {
      return NextResponse.json(
        { error: "Application must be approved before creating a lease" },
        { status: 400 }
      );
    }

    // Prevent duplicate lease for the same application
    const existingLease = await prisma.lease.findUnique({
      where: { applicationId },
    });

    if (existingLease) {
      return NextResponse.json(
        { error: "Lease already exists for this application" },
        { status: 409 }
      );
    }

    const lease = await prisma.lease.create({
      data: {
        applicationId,
        tenantId: tenantId ?? null,
        propertyId,
        unitId,
        startDate: new Date(startDate),
        endDate: new Date(endDate),
        rentAmount,
        securityDeposit: securityDeposit ?? null,
        leaseTerm,
        paymentDueDay,
        paymentFrequency,
        lateFeeFlat,
        lateFeeDaily,
        gracePeriodDays,
        landlordResponsibilities,
        tenantResponsibilities,
        tenantPaysElectric,
        tenantPaysWater,
        tenantPaysTrash,
        tenantPaysInternet,
        usageType,
        earlyTerminationFee,
      },
      include: {
        tenant: true,
        property: true,
        unit: true,
        application: true,
      },
    });

    return NextResponse.json(lease, { status: 201 });
  } catch (error: any) {
    console.error("Lease creation error:", error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

