// Utility: Calculate next escalation date
function calculateNextEscalation(startDate: Date, frequency: string): Date {
  const next = new Date(startDate);
  if (frequency === "ANNUAL") {
    next.setFullYear(next.getFullYear() + 1);
  } else if (frequency === "BIANNUAL") {
    next.setMonth(next.getMonth() + 6);
  }
  return next;
}

// POST: Approve lease and transition to APPROVED/ACTIVE/TERMINATED
export async function POST(req: NextRequest) {
  try {
    const user = await getCurrentUser(req);
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { leaseId, action } = await req.json();

    if (!leaseId || !action) {
      return NextResponse.json(
        { error: "Missing leaseId or action" },
        { status: 400 }
      );
    }

    const lease = await prisma.lease.findUnique({
      where: { id: leaseId },
      include: { property: true, tenant: true, application: true },
    });

    if (!lease) {
      return NextResponse.json({ error: "Lease not found" }, { status: 404 });
    }

    // Authorization check
    if (lease.property.managerId !== user.organizationUserId) {
      return NextResponse.json(
        { error: "Not authorized to modify this lease" },
        { status: 403 }
      );
    }

    let updatedLease;
    let auditAction = "";
    const previousStatus = lease.leaseStatus;

    switch (action) {
      case "APPROVE":
        updatedLease = await prisma.lease.update({
          where: { id: leaseId },
          data: { leaseStatus: "APPROVED" },
        });
        auditAction = "APPROVED";
        break;

      case "ACTIVATE":
        if (!lease.landlordSignedAt || !lease.tenantSignedAt) {
          return NextResponse.json(
            { error: "Lease must be signed by both parties before activation" },
            { status: 400 }
          );
        }
        updatedLease = await prisma.lease.update({
          where: { id: leaseId },
          data: { leaseStatus: "ACTIVE" },
        });
        auditAction = "ACTIVATED";
        break;

      case "TERMINATE":
        updatedLease = await prisma.lease.update({
          where: { id: leaseId },
          data: { leaseStatus: "TERMINATED" },
        });
        auditAction = "TERMINATED";
        break;

      default:
        return NextResponse.json({ error: "Invalid action" }, { status: 400 });
    }

    const newStatus = updatedLease.leaseStatus;
    if (!newStatus) {
      return NextResponse.json(
        { error: "Lease status update failed" },
        { status: 500 }
      );
    }

    // Create audit log
    await prisma.leaseAuditLog.create({
      data: {
        id: randomUUID(),
        leaseId,
        action: auditAction,
        performedBy: user.id,
        changes: { 
          previousStatus,
          newStatus
        } as Prisma.InputJsonValue, // cast as InputJsonValue
      } as Prisma.LeaseAuditLogUncheckedCreateInput,
    });

    // Handle listing integration after successful database update
    try {
      await leaseListingIntegration.handleLeaseStatusChange(
        leaseId,
        newStatus,
        previousStatus,
        user.id
      );
    } catch (integrationError) {
      console.error('Lease-listing integration error:', integrationError);
      // Don't fail the request if integration fails, but log it
      // The lease status update was successful, integration can be retried
    }

    return NextResponse.json(updatedLease);
  } catch (error: any) {
    console.error("Workflow error:", error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

/**
 * Security management API endpoint
 * Allows admins to manage bans, security settings, and abuse prevention
 */

import { NextRequest, NextResponse } from 'next/server';
import { withSecurity } from '@/lib/listing-security-middleware';
import { UserRole } from '@/lib/listing-auth.types';
import { AbusePreventionService } from '@/lib/listing-abuse-prevention';
import { ListingSanitizer } from '@/lib/listing-sanitizer';
import { ListingLogger, LogCategory } from '@/lib/listing-logger';

// Secure POST handler for security management actions
const securePostHandler = withSecurity(
  async (request: NextRequest, context, sanitizedData) => {
    const logger = ListingLogger.getInstance();
    const abusePreventionService = AbusePreventionService.getInstance();
    
    try {
      const { action, targetUserId, targetIP, reason, permanent } = sanitizedData;

      // Validate required fields
      if (!action) {
        return NextResponse.json(
          { error: 'Action is required' },
          { status: 400 }
        );
      }

      let result;

      switch (action) {
        case 'ban_user':
          if (!targetUserId || !reason) {
            return NextResponse.json(
              { error: 'Target user ID and reason are required for ban action' },
              { status: 400 }
            );
          }

          abusePreventionService.banUser(
            targetUserId, 
            targetIP || 'unknown', 
            reason, 
            permanent || false
          );

          result = { message: 'User banned successfully' };
          break;

        case 'unban_user':
          if (!targetUserId) {
            return NextResponse.json(
              { error: 'Target user ID is required for unban action' },
              { status: 400 }
            );
          }

          abusePreventionService.unbanUser(
            targetUserId, 
            targetIP || 'unknown', 
            reason || 'Admin unban'
          );

          result = { message: 'User unbanned successfully' };
          break;

        case 'clear_failed_attempts':
          if (!targetUserId) {
            return NextResponse.json(
              { error: 'Target user ID is required for clear action' },
              { status: 400 }
            );
          }

          abusePreventionService.clearFailedAttempts(
            targetUserId, 
            targetIP || 'unknown'
          );

          result = { message: 'Failed attempts cleared successfully' };
          break;

        case 'get_user_status':
          if (!targetUserId) {
            return NextResponse.json(
              { error: 'Target user ID is required for status check' },
              { status: 400 }
            );
          }

          const userStatus = abusePreventionService.getUserSecurityStatus(
            targetUserId, 
            targetIP || 'unknown'
          );

          result = { userStatus };
          break;

        default:
          return NextResponse.json(
            { error: 'Invalid action specified' },
            { status: 400 }
          );
      }

      // Log security management action
      logger.info(
        LogCategory.PERMISSION,
        'Security management action performed',
        {
          adminUserId: context.userId,
          action,
          targetUserId,
          targetIP,
          reason,
          permanent
        }
      );

      return NextResponse.json(result, { status: 200 });

    } catch (error) {
      logger.error(
        LogCategory.ERROR_RECOVERY,
        'Security management action failed',
        error instanceof Error ? error : undefined,
        {
          adminUserId: context.userId,
          action: sanitizedData?.action
        }
      );
      
      return NextResponse.json(
        { error: 'Security management action failed' },
        { status: 500 }
      );
    }
  },
  {
    requireAuth: true,
    requiredRole: UserRole.ADMIN,
    operation: 'manage',
    validateData: true,
    checkRateLimit: true,
    logAccess: true
  }
);

// Custom validation for security management data
function validateSecurityManagementData(data: any) {
  const sanitizedData = {
    action: ListingSanitizer.sanitizeText(data.action, { maxLength: 50 }),
    targetUserId: data.targetUserId ? ListingSanitizer.sanitizeText(data.targetUserId, { maxLength: 100 }) : undefined,
    targetIP: data.targetIP ? ListingSanitizer.sanitizeText(data.targetIP, { maxLength: 45 }) : undefined,
    reason: data.reason ? ListingSanitizer.sanitizeText(data.reason, { maxLength: 500 }) : undefined,
    permanent: ListingSanitizer.sanitizeBoolean(data.permanent)
  };

  // Validate action
  const validActions = ['ban_user', 'unban_user', 'clear_failed_attempts', 'get_user_status'];
  if (!validActions.includes(sanitizedData.action)) {
    throw new Error('Invalid action specified');
  }

  return sanitizedData;
}

export { securePostHandler as POST };

// API endpoint for maintenance-listing integration operations
import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/db";
import { maintenanceListingIntegration } from "@/lib/maintenance-listing-integration";
import { getCurrentUser } from "@/lib/Getcurrentuser";

/**
 * GET /api/maintenance/listing-integration
 * Get maintenance mode status for units
 */
export async function GET(request: NextRequest) {
    try {
        const user = await getCurrentUser(request);
        if (!user?.id) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { searchParams } = new URL(request.url);
        const unitId = searchParams.get('unitId');
        const organizationId = searchParams.get('organizationId');

        if (unitId) {
            // Get status for specific unit
            const status = await maintenanceListingIntegration.getMaintenanceListingStatus(unitId);
            return NextResponse.json(status);
        }

        if (organizationId) {
            // Get all units in maintenance mode for organization
            const units = await maintenanceListingIntegration.getUnitsInMaintenanceMode(organizationId);
            return NextResponse.json({ units });
        }

        return NextResponse.json({ error: "unitId or organizationId required" }, { status: 400 });

    } catch (error) {
        console.error("Error getting maintenance listing status:", error);
        return NextResponse.json(
            { error: "Failed to get maintenance status" },
            { status: 500 }
        );
    }
}

/**
 * POST /api/maintenance/listing-integration
 * Start or end maintenance mode manually
 */
export async function POST(request: NextRequest) {
    try {
        const user = await getCurrentUser(request);
        if (!user?.id) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await request.json();
        const { action, unitId, reason, estimatedEndDate, maintenanceRequestId } = body;

        if (!action || !unitId) {
            return NextResponse.json(
                { error: "action and unitId are required" },
                { status: 400 }
            );
        }

        let result;

        switch (action) {
            case 'start':
                if (!reason) {
                    return NextResponse.json(
                        { error: "reason is required for starting maintenance mode" },
                        { status: 400 }
                    );
                }
                
                result = await maintenanceListingIntegration.startMaintenanceModeManually(
                    unitId,
                    reason,
                    user.id,
                    estimatedEndDate ? new Date(estimatedEndDate) : undefined,
                    maintenanceRequestId
                );
                break;

            case 'end':
                result = await maintenanceListingIntegration.endMaintenanceModeManually(
                    unitId,
                    user.id,
                    reason
                );
                break;

            default:
                return NextResponse.json(
                    { error: "Invalid action. Use 'start' or 'end'" },
                    { status: 400 }
                );
        }

        if (result.success) {
            return NextResponse.json({ success: true, message: result.message });
        } else {
            return NextResponse.json(
                { error: result.message },
                { status: 400 }
            );
        }

    } catch (error) {
        console.error("Error handling maintenance mode operation:", error);
        return NextResponse.json(
            { error: "Failed to process maintenance mode operation" },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/db";
import { getCurrentUser } from "@/lib/Getcurrentuser";
import type { MaintenanceRequest } from "@prisma/client";

// GET /api/maintenance/tenant - Get tenant's maintenance requests
export async function GET(req: NextRequest) {
  try {
    const user = await getCurrentUser(req);
    
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Find tenant's active lease to get property and unit info
    const activeLease = await prisma.lease.findFirst({
      where: {
        tenantId: user.id,
        leaseStatus: "ACTIVE",
      },
      include: {
        property: true,
        unit: true,
      },
    });

    if (!activeLease) {
      return NextResponse.json({ 
        requests: [],
        message: "No active lease found" 
      });
    }

    // Find organization user record for this tenant
    const orgUser = await prisma.organizationUser.findFirst({
      where: {
        userId: user.id,
        organizationId: activeLease.property.organizationId || undefined,
      },
    });

    if (!orgUser) {
      return NextResponse.json({ 
        requests: [],
        message: "User not found in organization" 
      });
    }

    // Fetch maintenance requests for this tenant's unit
    const requests = await prisma.maintenanceRequest.findMany({
      where: {
        organizationId: activeLease.property.organizationId || "",
        propertyId: activeLease.propertyId,
        unitId: activeLease.unitId,
        requestedById: orgUser.id,
      },
      orderBy: { createdAt: "desc" },
      include: {
        property: {
          select: {
            id: true,
            name: true,
            address: true,
            city: true,
          }
        },
        unit: { 
          select: { 
            id: true, 
            unitNumber: true, 
            unitName: true 
          } 
        },
        requestedBy: { 
          include: { 
            user: { 
              select: { 
                firstName: true, 
                lastName: true, 
                email: true 
              } 
            } 
          } 
        },
        vendor: { 
          include: { 
            user: { 
              select: { 
                firstName: true, 
                lastName: true 
              } 
            } 
          } 
        },
      },
    });

    return NextResponse.json({ 
      success: true,
      count: requests.length,
      requests: Array.isArray(requests) ? requests : [] 
    });

  } catch (error) {
    console.error("Tenant maintenance requests error:", error);
    
    // Check if error is due to missing table/column
    if (error instanceof Error && error.message.includes("does not exist")) {
      return NextResponse.json({ 
        success: false,
        error: "Maintenance requests feature not yet available",
        requests: [] 
      }, { status: 503 });
    }
    
    const errorMessage = error instanceof Error ? error.message : "Failed to fetch maintenance requests";
    return NextResponse.json({ 
      success: false,
      error: errorMessage,
      requests: [] 
    }, { status: 500 });
  }
}

// POST /api/maintenance/tenant - Create a new maintenance request
export async function POST(req: NextRequest) {
  try {
    const user = await getCurrentUser(req);
    
    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const body = await req.json();
    const { title, description, priority = "NORMAL", category = "STANDARD" } = body;

    if (!title || !description) {
      return NextResponse.json({ 
        error: "Title and description are required" 
      }, { status: 400 });
    }

    // Find tenant's active lease to get property and unit info
    const activeLease = await prisma.lease.findFirst({
      where: {
        tenantId: user.id,
        leaseStatus: "ACTIVE",
      },
      include: {
        property: true,
        unit: true,
      },
    });

    if (!activeLease) {
      return NextResponse.json({ 
        error: "No active lease found" 
      }, { status: 404 });
    }

    // Find organization user record for this tenant
    const orgUser = await prisma.organizationUser.findFirst({
      where: {
        userId: user.id,
        organizationId: activeLease.property.organizationId || undefined,
      },
    });

    if (!orgUser) {
      return NextResponse.json({ 
        error: "User not found in organization" 
      }, { status: 403 });
    }

    // Validate priority
    const allowedPriorities = ["LOW", "NORMAL", "HIGH", "URGENT"];
    if (priority && !allowedPriorities.includes(priority)) {
      return NextResponse.json({ 
        error: `Invalid priority value: ${priority}` 
      }, { status: 400 });
    }

    // Validate category
    const allowedCategories = ["EMERGENCY", "URGENT", "ROUTINE", "STANDARD"];
    if (category && !allowedCategories.includes(category)) {
      return NextResponse.json({ 
        error: `Invalid category value: ${category}` 
      }, { status: 400 });
    }

    // Create the maintenance request
    const newRequest = await prisma.maintenanceRequest.create({
      data: {
        organizationId: activeLease.property.organizationId || "",
        propertyId: activeLease.propertyId,
        unitId: activeLease.unitId,
        requestedById: orgUser.id,
        title,
        description,
        priority: priority as "LOW" | "NORMAL" | "HIGH" | "URGENT",
        category: category as "EMERGENCY" | "URGENT" | "ROUTINE" | "STANDARD",
        status: "OPEN", // Default status
      },
    });

    return NextResponse.json({ 
      success: true,
      request: newRequest,
      message: "Maintenance request created successfully" 
    }, { status: 201 });

  } catch (error) {
    console.error("Create maintenance request error:", error);
    
    // Check if error is due to missing table
    if (error instanceof Error && error.message.includes("does not exist")) {
      return NextResponse.json({ 
        success: false,
        error: "Maintenance requests feature not yet available" 
      }, { status: 503 });
    }
    
    const errorMessage = error instanceof Error ? error.message : "Failed to create maintenance request";
    return NextResponse.json({ 
      success: false,
      error: errorMessage 
    }, { status: 500 });
  }
}

