              <p className="text-xs text-neutral-400 capitalize">
                {user.role.replace("-", " ")}
              </p>
            </div>
          </div>
        )}
        <button
          onClick={toggleSidebar}
          className="p-2 rounded-lg text-neutral-400 hover:text-white hover:bg-neutral-800"
        >
          <ChevronLeft
            className={cn("w-4 h-4 transition-transform", !open && "rotate-180")}
          />
        </button>
      </div>

      {/* Links */}
      <div className="flex-1 overflow-y-auto">
        <DashboardSidebarLinks user={user} open={open} isCollapsed={!open} />
      </div>
    </div>
  );

  return (
    <>
      <DesktopSidebar />

      {/* Mobile Drawer */}
      {mobileDrawerOpen && (
        <>
          {/* Backdrop */}
          <div
            className="fixed inset-0 bg-black/50 z-40 md:hidden"
            onClick={() => setMobileDrawerOpen(false)}
          />

          {/* Drawer */}
          <div className="fixed left-0 top-0 h-full w-72 z-50 flex flex-col bg-[#003b73] border-r border-[#002b59] md:hidden">
            <div className="flex items-center justify-between p-4 border-b border-[#002b59]">
              <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-white/10 rounded-lg flex items-center justify-center">
                  <Building2 className="w-4 h-4 text-white" />
                </div>
                <div>
                  <h1 className="font-bold text-white text-lg">RentFlow360</h1>
                  <p className="text-xs text-white capitalize">
                    {user.role.replace("-", " ")}
                  </p>
                </div>
              </div>
              <button
                onClick={() => setMobileDrawerOpen(false)}
                className="p-2 rounded-lg text-white hover:text-white hover:bg-[#002b5b]"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar">
              <DashboardSidebarLinks user={user} open={true} isCollapsed={false} />
            </div>

            <div className="border-t border-[#002b59] p-4">
              <div className="flex items-center gap-3 p-3 rounded-lg bg-neutral-800/50">
                <div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center text-white text-sm font-medium">
                  {user.firstName.charAt(0).toUpperCase()}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-white truncate">{user.firstName}</p>
                  <p className="text-xs text-white truncate">{user.email}</p>
                </div>
              </div>
            </div>
          </div>
        </>
      )}
    </>
  );
}

'use client'

import { motion } from 'framer-motion'
import { RouteGroup } from './RouteGroup'
import { systemRoutes, routeConfig } from './SidebarLinks'
import { LogOut } from 'lucide-react'
import { useLogout } from '@/hooks/useLogout';

interface DashboardSidebarLinksProps {
  user: { id: string, firstName: string, role: string, email: string }
  open?: boolean
  isCollapsed?: boolean
  darkMode?: boolean
}

export function DashboardSidebarLinks({ user, open = true, isCollapsed = false, darkMode = true }: DashboardSidebarLinksProps) {
  const userRoutes = routeConfig[user.role as keyof typeof routeConfig] as Record<string, any>;
  const { logout } = useLogout({ redirectTo: '/' });

  const handleLogout = async () => {
    await logout()
  }

  // Get the first/default route group for this role (varies by role)
  const defaultRoutes = userRoutes?.main || userRoutes?.overview || [];

  return (
    <motion.div className="flex flex-1 flex-col justify-between overflow-hidden" layout>
      <div className="flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-2 pb-4">
        {defaultRoutes && defaultRoutes.length > 0 && <RouteGroup routes={defaultRoutes} open={open} isCollapsed={isCollapsed} darkMode={darkMode} />}
        {Object.entries(userRoutes || {}).map(([key, routes]: [string, any]) => {
          const skipKeys = ['main', 'overview'];
          if (skipKeys.includes(key)) return null;
          return (
            <RouteGroup
              key={key}
              routes={routes}
              open={open}
              categoryLabel={key.charAt(0).toUpperCase() + key.slice(1)}
              isCollapsed={isCollapsed}
              darkMode={darkMode}
            />
          );
        })}
      </div>
    </motion.div>
  )
}

'use client'

import { motion } from 'framer-motion'
import { usePathname } from 'next/navigation'
import { RouteItem } from './RouteItem'

interface RouteGroupProps {
  routes: any[]
  open: boolean
  categoryLabel?: string
  isCollapsed?: boolean
  darkMode?: boolean
}

export function RouteGroup({ routes, open, categoryLabel, isCollapsed, darkMode }: RouteGroupProps) {
  const pathname = usePathname()

  return (
    <div className="w-full mb-2">
      {categoryLabel && open && (
        <p
          className={darkMode ? "text-blue-200 text-xs font-semibold uppercase tracking-wider mb-3 px-3" : "text-blue-200 text-xs font-semibold uppercase tracking-wider mb-3 px-3"}
        >
          {categoryLabel}
        </p>
      )}
      <div className="space-y-1 px-2">
        {routes.map((route) => (
          <RouteItem
            key={route.label}
            route={route}
            open={open}
            isActive={pathname === route.path}
            isCollapsed={isCollapsed}
            darkMode={darkMode}
          />
        ))}
      </div>
    </div>
  )
}

