}

interface EditPermissions {
  canEditTitle: boolean
  canEditDescription: boolean
  canEditPrice: boolean
  canEditAvailabilityDate: boolean
  canEditExpirationDate: boolean
}

export default function EditListingModal({
  isOpen,
  onClose,
  listingId,
  unit,
  onSave,
  initialData,
}: EditListingModalProps) {
  const [formData, setFormData] = useState<FormData>({
    title: '',
    description: '',
    price: '',
    availabilityDate: '',
    expirationDate: '',
  })
  
  const [errors, setErrors] = useState<ValidationErrors>({})
  const [isLoading, setIsLoading] = useState(false)
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [permissions, setPermissions] = useState<EditPermissions>({
    canEditTitle: true,
    canEditDescription: true,
    canEditPrice: true,
    canEditAvailabilityDate: true,
    canEditExpirationDate: true,
  })

  // Fetch listing details when modal opens
  useEffect(() => {
    if (isOpen && listingId) {
      fetchListingDetails()
    }
  }, [isOpen, listingId])

  const fetchListingDetails = async () => {
    setIsLoading(true)
    setError(null)
    
    try {
      const response = await fetch(`/api/listings/${listingId}/edit`)
      if (!response.ok) {
        throw new Error('Failed to fetch listing details')
      }
      
      const data = await response.json()
      
      // Set form data from fetched data
      setFormData({
        title: data.listing.title || '',
        description: data.listing.description || '',
        price: data.listing.price?.toString() || '',
        availabilityDate: data.listing.availabilityDate 
          ? new Date(data.listing.availabilityDate).toISOString().split('T')[0]
          : new Date().toISOString().split('T')[0],
        expirationDate: data.listing.expirationDate
          ? new Date(data.listing.expirationDate).toISOString().split('T')[0]
          : '',
      })
      
      // Set permissions from API
      if (data.editPermissions) {
        setPermissions(data.editPermissions)
      }
      
    } catch (err) {
      console.error('Error fetching listing details:', err)
      setError(err instanceof Error ? err.message : 'Failed to load listing details')
      
      // Fallback to initialData if provided
      if (initialData) {
        setFormData({
          title: initialData.title || '',
          description: initialData.description || '',
          price: initialData.price?.toString() || '',
          availabilityDate: initialData.availabilityDate || new Date().toISOString().split('T')[0],
          expirationDate: initialData.expirationDate || '',
        })
      }
    } finally {
      setIsLoading(false)
    }
  }

  const validateForm = (): boolean => {
    const newErrors: ValidationErrors = {}

    // Title validation
    if (!formData.title.trim()) {
      newErrors.title = 'Title is required'
    } else if (formData.title.trim().length < 3) {
      newErrors.title = 'Title must be at least 3 characters long'
    } else if (formData.title.trim().length > 100) {
      newErrors.title = 'Title must be less than 100 characters'
    }

    // Description validation
    if (!formData.description.trim()) {
      newErrors.description = 'Description is required'
    } else if (formData.description.trim().length < 10) {
      newErrors.description = 'Description must be at least 10 characters long'
    } else if (formData.description.trim().length > 1000) {
      newErrors.description = 'Description must be less than 1000 characters'
    }

    // Price validation
    if (!formData.price.trim()) {
      newErrors.price = 'Price is required'
    } else {
      const priceNum = parseFloat(formData.price)
      if (isNaN(priceNum) || priceNum <= 0) {
        newErrors.price = 'Price must be a valid positive number'
      } else if (priceNum > 50000) {
        newErrors.price = 'Price seems unusually high. Please verify.'
      }
    }

    // Availability date validation
    if (!formData.availabilityDate) {
      newErrors.availabilityDate = 'Availability date is required'
    } else {
      const availDate = new Date(formData.availabilityDate)
      const today = new Date()
      today.setHours(0, 0, 0, 0)
      
      if (availDate < today) {
        newErrors.availabilityDate = 'Availability date cannot be in the past'
      }
    }

    // Expiration date validation (optional)
    if (formData.expirationDate) {
      const expDate = new Date(formData.expirationDate)
      const availDate = new Date(formData.availabilityDate)
      
      if (expDate <= availDate) {
        newErrors.expirationDate = 'Expiration date must be after availability date'
      }
    }

    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleInputChange = (field: keyof FormData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }))
    
    // Clear error for this field when user starts typing
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: undefined }))
    }
    
    // Clear general error
    if (error) {
      setError(null)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!validateForm()) {
      return
    }

    setIsSubmitting(true)
    setError(null)
    
    try {
      // Prepare updates object
      const updates: UpdateListingData = {
        title: formData.title.trim(),
        description: formData.description.trim(),
        price: parseFloat(formData.price),
      }
      
      // Only include dates if they're different from current values or if permissions allow
      if (permissions.canEditAvailabilityDate) {
        updates.availabilityDate = new Date(formData.availabilityDate)
      }
      
      if (formData.expirationDate) {
        updates.expirationDate = new Date(formData.expirationDate)
      }

      await onSave(listingId, updates)
      onClose()
    } catch (err) {
      console.error('Error saving listing:', err)
      setError(err instanceof Error ? err.message : 'Failed to save listing changes')
    } finally {
      setIsSubmitting(false)
    }
  }

  const formatCurrency = (amount?: number | string) => {
    if (!amount) return 'Not set'
    const amountNum = typeof amount === 'string' ? parseFloat(amount) : amount
    if (isNaN(amountNum)) return 'Invalid'
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amountNum)
  }

  const formatDate = (dateString?: string) => {
    if (!dateString) return 'Not set'
    const date = new Date(dateString)
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    })
  }

  const getListingStatus = () => {
    return unit.listing?.status || ListingStatus.PRIVATE
  }

  return (
    <Dialog open={isOpen} onOpenChange={(open) => !open ? onClose() : null}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Edit className="h-5 w-5 text-blue-600" />
            Edit Listing Details
          </DialogTitle>
          <DialogDescription>
            Update the listing information for Unit {unit.unitNumber}
          </DialogDescription>
        </DialogHeader>

        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-blue-600 mb-4" />
            <p className="text-gray-600">Loading listing details...</p>
          </div>
        ) : (
          <div className="space-y-6">
            {/* Unit Context Card */}
            <Card className="border-slate-200">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-lg">
                  <Building2 className="h-5 w-5 text-blue-600" />
                  Unit Information
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 text-sm">
                  <div>
                    <span className="font-medium text-slate-600">Unit:</span>
                    <p className="text-slate-900 font-medium">{unit.unitNumber}</p>
                  </div>
                  <div>
                    <span className="font-medium text-slate-600">Current Rent:</span>
                    <p className="text-slate-900 font-medium">{formatCurrency(unit.rentAmount)}</p>
                  </div>
                  {unit.bedrooms && (
                    <div>
                      <span className="font-medium text-slate-600">Bedrooms:</span>
                      <p className="text-slate-900 font-medium">{unit.bedrooms}</p>
                    </div>
                  )}
                  {unit.bathrooms && (
                    <div>
                      <span className="font-medium text-slate-600">Bathrooms:</span>
                      <p className="text-slate-900 font-medium">{unit.bathrooms}</p>
                    </div>
                  )}
                  <div>
                    <span className="font-medium text-slate-600">Status:</span>
                    <div className="mt-1">
                      <Badge 
                        variant={
                          getListingStatus() === ListingStatus.ACTIVE 
                            ? "default" 
                            : getListingStatus() === ListingStatus.SUSPENDED 
                            ? "destructive" 
                            : "secondary"
                        }
                      >
                        {getListingStatus()}
                      </Badge>
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Permission Warnings */}
            {(!permissions.canEditPrice || !permissions.canEditAvailabilityDate) && (
              <Card className="border-yellow-200 bg-yellow-50">
                <CardContent className="p-4">
                  <div className="flex items-start gap-3">
                    <AlertCircle className="h-5 w-5 text-yellow-600 mt-0.5 flex-shrink-0" />
                    <div>
                      <h4 className="font-medium text-yellow-800 mb-1">Editing Restrictions</h4>
                      <ul className="text-sm text-yellow-700 space-y-1">
                        {!permissions.canEditPrice && (
                          <li>• Price cannot be changed because this unit has an active lease</li>
                        )}
                        {!permissions.canEditAvailabilityDate && (
                          <li>• Availability date cannot be changed because this unit has an active lease</li>
                        )}
                      </ul>
                    </div>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Listing Details Form */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <FileText className="h-5 w-5 text-green-600" />
                  Listing Details
                </CardTitle>
              </CardHeader>
              <CardContent>
                <form onSubmit={handleSubmit} className="space-y-6">
                  {/* Title Field */}
                  <div className="space-y-2">
                    <Label htmlFor="title" className="text-sm font-medium">
                      Listing Title *
                    </Label>
                    <Input
                      id="title"
                      value={formData.title}
                      onChange={(e) => handleInputChange('title', e.target.value)}
                      placeholder="e.g., Unit 2A - 2BR/1BA"
                      className={errors.title ? 'border-red-500' : ''}
                      disabled={isSubmitting}
                    />
                    {errors.title && (
                      <div className="flex items-center gap-1 text-sm text-red-600">
                        <AlertCircle className="h-4 w-4" />
                        {errors.title}
                      </div>
                    )}
                    <p className="text-xs text-slate-500">
                      This will be the main headline tenants see when browsing listings
                    </p>
                  </div>

                  {/* Description Field */}
                  <div className="space-y-2">
                    <Label htmlFor="description" className="text-sm font-medium">
                      Description *
                    </Label>
                    <Textarea
                      id="description"
                      value={formData.description}
                      onChange={(e) => handleInputChange('description', e.target.value)}
                      placeholder="Describe the unit's features, amenities, and what makes it special..."
                      rows={4}
                      className={errors.description ? 'border-red-500' : ''}
                      disabled={isSubmitting}
                    />
                    {errors.description && (
                      <div className="flex items-center gap-1 text-sm text-red-600">
                        <AlertCircle className="h-4 w-4" />
                        {errors.description}
                      </div>
                    )}
                    <p className="text-xs text-slate-500">
                      {formData.description.length}/1000 characters
                    </p>
                  </div>

                  {/* Price Field */}
                  <div className="space-y-2">
                    <Label htmlFor="price" className="text-sm font-medium">
                      Monthly Rent *
                    </Label>
                    <div className="relative">
                      <DollarSign className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400" />
                      <Input
                        id="price"
                        type="number"
                        step="0.01"
                        min="0"
                        value={formData.price}
                        onChange={(e) => handleInputChange('price', e.target.value)}
                        placeholder="0.00"
                        className={`pl-10 ${errors.price ? 'border-red-500' : ''}`}
                        disabled={isSubmitting || !permissions.canEditPrice}
                      />
                    </div>
                    {errors.price && (
                      <div className="flex items-center gap-1 text-sm text-red-600">
                        <AlertCircle className="h-4 w-4" />
                        {errors.price}
                      </div>
                    )}
                    {!permissions.canEditPrice && (
                      <p className="text-xs text-yellow-600">
                        Price cannot be changed while unit has an active lease
                      </p>
                    )}
                  </div>

                  {/* Date Fields */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* Availability Date */}
                    <div className="space-y-2">
                      <Label htmlFor="availabilityDate" className="text-sm font-medium">
                        Available From *
                      </Label>
                      <div className="relative">
                        <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <Input
                          id="availabilityDate"
                          type="date"
                          value={formData.availabilityDate}
                          onChange={(e) => handleInputChange('availabilityDate', e.target.value)}
                          className={`pl-10 ${errors.availabilityDate ? 'border-red-500' : ''}`}
                          disabled={isSubmitting || !permissions.canEditAvailabilityDate}
                        />
                      </div>
                      {errors.availabilityDate && (
                        <div className="flex items-center gap-1 text-sm text-red-600">
                          <AlertCircle className="h-4 w-4" />
                          {errors.availabilityDate}
                        </div>
                      )}
                      {!permissions.canEditAvailabilityDate && (
                        <p className="text-xs text-yellow-600">
                          Availability date cannot be changed while unit has an active lease
                        </p>
                      )}
                    </div>

                    {/* Expiration Date */}
                    <div className="space-y-2">
                      <Label htmlFor="expirationDate" className="text-sm font-medium">
                        Listing Expires (Optional)
                      </Label>
                      <div className="relative">
                        <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400" />
                        <Input
                          id="expirationDate"
                          type="date"
                          value={formData.expirationDate}
                          onChange={(e) => handleInputChange('expirationDate', e.target.value)}
                          className={`pl-10 ${errors.expirationDate ? 'border-red-500' : ''}`}
                          disabled={isSubmitting}
                        />
                      </div>
                      {errors.expirationDate && (
                        <div className="flex items-center gap-1 text-sm text-red-600">
                          <AlertCircle className="h-4 w-4" />
                          {errors.expirationDate}
                        </div>
                      )}
                      <p className="text-xs text-slate-500">
                        Leave empty for no expiration
                      </p>
                    </div>
                  </div>

                  <Separator />

                  {/* Form Actions */}
                  <div className="flex flex-col sm:flex-row gap-3 pt-4">
                    <Button
                      type="submit"
                      disabled={isSubmitting}
                      className="flex-1 sm:flex-none"
                    >
                      {isSubmitting ? (
                        <>
                          <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2" />
                          Saving Changes...
                        </>
                      ) : (
                        <>
                          <CheckCircle className="h-4 w-4 mr-2" />
                          Save Changes
                        </>
                      )}
                    </Button>
                    <Button
                      type="button"
                      variant="outline"
                      onClick={onClose}
                      disabled={isSubmitting}
                      className="flex-1 sm:flex-none"
                    >
                      Cancel
                    </Button>
                    <Button
                      type="button"
                      variant="ghost"
                      onClick={() => window.open(`/marketplace?listing=${listingId}`, '_blank')}
                      disabled={isSubmitting}
                      className="flex-1 sm:flex-none"
                    >
                      <Eye className="h-4 w-4 mr-2" />
                      View on Marketplace
                    </Button>
                  </div>
                </form>
              </CardContent>
            </Card>

            {/* Error Display */}
            {error && (
              <Card className="border-red-200 bg-red-50">
                <CardContent className="p-4">
                  <div className="flex items-center gap-2">
                    <XCircle className="h-5 w-5 text-red-600" />
                    <p className="text-red-700">{error}</p>
                  </div>
                </CardContent>
              </Card>
            )}

            {/* Current Values */}
            <Card className="border-slate-200">
              <CardHeader>
                <CardTitle className="text-sm font-medium text-slate-600">
                  Current Values
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                  <div>
                    <span className="text-slate-600">Title:</span>
                    <p className="font-medium text-slate-900">{formData.title || 'Not set'}</p>
                  </div>
                  <div>
                    <span className="text-slate-600">Price:</span>
                    <p className="font-medium text-slate-900">{formatCurrency(formData.price)}</p>
                  </div>
                  <div>
                    <span className="text-slate-600">Available From:</span>
                    <p className="font-medium text-slate-900">{formatDate(formData.availabilityDate)}</p>
                  </div>
                  <div>
                    <span className="text-slate-600">Expires:</span>
                    <p className="font-medium text-slate-900">
                      {formData.expirationDate ? formatDate(formData.expirationDate) : 'No expiration'}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        )}
      </DialogContent>
    </Dialog>
  )
}

// Named export for compatibility
export { EditListingModal }

// UI component for displaying lease-related listing changes and notifications
'use client';

import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Separator } from '@/components/ui/separator';
import { 
  Clock, 
  CheckCircle, 
  AlertTriangle, 
  Home, 
  Calendar,
  Bell,
  ExternalLink
} from 'lucide-react';
import { api } from '@/lib/api-client';

interface LeaseStatusChange {
  id: string;
  leaseId: string;
  unitNumber: string;
  propertyName: string;
  previousStatus: string;
  newStatus: string;
  timestamp: Date;
  listingAction: 'REMOVED' | 'PROMPT_SENT' | 'NOTIFICATION_SENT' | 'NO_ACTION';
  reason: string;
}

interface LeaseIntegrationPanelProps {
  propertyId?: string;
  unitId?: string;
  className?: string;
}

export function LeaseIntegrationPanel({ 
  propertyId, 
  unitId, 
  className 
}: LeaseIntegrationPanelProps) {
  const [statusChanges, setStatusChanges] = useState<LeaseStatusChange[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    fetchLeaseStatusChanges();
  }, [propertyId, unitId]);

  const fetchLeaseStatusChanges = async () => {
    try {
      setLoading(true);
      setError(null);
      
      const params = new URLSearchParams();
      if (propertyId) params.append('propertyId', propertyId);
      if (unitId) params.append('unitId', unitId);

      const result = await api.get<{ success: boolean; changes: LeaseStatusChange[]; total: number }>(
        `/api/lease/status-changes?${params}`
      );

      if (result.error) {
        // Handle API client errors (including 401 redirects)
        if (result.status === 401) {
          // The api client already handled redirect, but we can set error message
          setError('Session expired. Please log in again.');
          return;
        }
        throw new Error(result.error);
      }

      if (!result.data?.success) {
        throw new Error('Failed to fetch lease status changes');
      }

      setStatusChanges(result.data.changes || []);
    } catch (err) {
      // Only set error if it's not a 401 (which already redirected)
      if (err instanceof Error && !err.message.includes('Session expired')) {
        setError(err.message);
      }
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadgeVariant = (status: string) => {
    switch (status) {
      case 'ACTIVE':
        return 'default';
      case 'EXPIRED':
      case 'TERMINATED':
        return 'destructive';
      case 'SIGNED':
        return 'secondary';
      default:
        return 'outline';
    }
  };

  const getActionIcon = (action: string) => {
    switch (action) {
      case 'REMOVED':
        return <CheckCircle className="h-4 w-4 text-green-600" />;
      case 'PROMPT_SENT':
        return <Bell className="h-4 w-4 text-blue-600" />;
      case 'NOTIFICATION_SENT':
        return <Bell className="h-4 w-4 text-yellow-600" />;
      default:
        return <Clock className="h-4 w-4 text-gray-400" />;
    }
  };

  const getActionDescription = (action: string, status: string) => {
    switch (action) {
      case 'REMOVED':
        return 'Listing automatically removed from marketplace';
      case 'PROMPT_SENT':
        return 'Listing decision prompt sent to property manager';
      case 'NOTIFICATION_SENT':
        return status === 'SIGNED' 
          ? 'Notification sent about upcoming listing removal'
          : 'Notification sent about listing change';
      default:
        return 'No listing action required';
    }
  };

  const formatTimestamp = (timestamp: Date) => {
    return new Date(timestamp).toLocaleString();
  };

  if (loading) {
    return (
      <Card className={className}>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Home className="h-5 w-5" />
            Lease Integration Activity
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-center py-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-gray-900"></div>
          </div>
        </CardContent>
      </Card>
    );
  }

  if (error) {
    return (
      <Card className={className}>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Home className="h-5 w-5" />
            Lease Integration Activity
          </CardTitle>
        </CardHeader>
        <CardContent>
          <Alert>
            <AlertTriangle className="h-4 w-4" />
            <AlertDescription>
              Error loading lease integration activity: {error}
            </AlertDescription>
          </Alert>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Home className="h-5 w-5" />
          Lease Integration Activity
        </CardTitle>
        <p className="text-sm text-muted-foreground">
          Recent lease status changes and their impact on marketplace listings
        </p>
      </CardHeader>
      <CardContent>
        {statusChanges.length === 0 ? (
          <div className="text-center py-8">
            <Clock className="h-12 w-12 text-gray-400 mx-auto mb-4" />
            <p className="text-muted-foreground">No recent lease activity</p>
          </div>
        ) : (
          <div className="space-y-4">
            {statusChanges.map((change) => (
              <div key={change.id} className="border rounded-lg p-4">
                <div className="flex items-start justify-between mb-3">
                  <div className="flex items-center gap-3">
                    <div className="flex items-center gap-2">
                      <Badge variant="outline">
                        Unit {change.unitNumber}
                      </Badge>
                      <span className="text-sm text-muted-foreground">
                        {change.propertyName}
                      </span>
                    </div>
                  </div>
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Calendar className="h-4 w-4" />
                    {formatTimestamp(change.timestamp)}
                  </div>
                </div>

                <div className="flex items-center gap-4 mb-3">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-medium">Status:</span>
                    <Badge variant={getStatusBadgeVariant(change.previousStatus)}>
                      {change.previousStatus}
                    </Badge>
                    <span className="text-muted-foreground">→</span>
                    <Badge variant={getStatusBadgeVariant(change.newStatus)}>
                      {change.newStatus}
                    </Badge>
                  </div>
                </div>

                <div className="flex items-start gap-3">
                  {getActionIcon(change.listingAction)}
                  <div className="flex-1">
                    <p className="text-sm font-medium">
                      {getActionDescription(change.listingAction, change.newStatus)}
                    </p>
                    {change.reason && (
                      <p className="text-sm text-muted-foreground mt-1">
                        {change.reason}
                      </p>
                    )}
                  </div>
                </div>

                {change.listingAction === 'PROMPT_SENT' && (
                  <div className="mt-3 pt-3 border-t">
                    <Alert>
                      <Bell className="h-4 w-4" />
                      <AlertDescription>
                        A listing decision is required for this unit. Check your email or visit the unit management page to make your decision.
                      </AlertDescription>
                    </Alert>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        <Separator className="my-4" />

        <div className="flex items-center justify-between">
          <Button
            variant="outline"
            size="sm"
            onClick={fetchLeaseStatusChanges}
            disabled={loading}
          >
            Refresh Activity
          </Button>
          
          {(propertyId || unitId) && (
            <Button
              variant="ghost"
              size="sm"
              className="flex items-center gap-2"
              onClick={() => {
                const url = unitId 
                  ? `/property-manager/units/${unitId}`
                  : `/property-manager/view-property/${propertyId}`;
                window.open(url, '_blank');
              }}
            >
              <ExternalLink className="h-4 w-4" />
              View Details
            </Button>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

export default LeaseIntegrationPanel;

'use client'

import React, { useState, useEffect } from 'react'
import { 
  History, 
  Filter, 
  Download, 
  Search, 
  Calendar, 
  User, 
  Activity, 
  ChevronDown,
  ChevronUp,
  FileText,
  Clock,
  AlertCircle,
  CheckCircle,
  XCircle,
  Pause,
  Play,
  Eye,
  EyeOff
} from 'lucide-react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Input } from '@/components/ui/input'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from '@/components/ui/dropdown-menu'
import { Skeleton } from '@/components/ui/skeleton'
import { ListingAuditEntry, ListingAction, ListingStatus } from '@/lib/listing-types'
import { auditService, AuditFilter } from '@/lib/audit-service'

interface ListingHistoryPanelProps {
  unitId?: string
  listingId?: string
  userId?: string
  className?: string
  showFilters?: boolean
  showExport?: boolean
  maxHeight?: string
}

interface FilterState {
  search: string
  action?: ListingAction
  status?: ListingStatus
  dateFrom?: string
  dateTo?: string
  userId?: string
}

export default function ListingHistoryPanel({
  unitId,
  listingId,
  userId,
  className = '',
  showFilters = true,
  showExport = true,
  maxHeight = '600px'
}: ListingHistoryPanelProps) {
  const [auditEntries, setAuditEntries] = useState<ListingAuditEntry[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [expandedEntries, setExpandedEntries] = useState<Set<string>>(new Set())
  const [filters, setFilters] = useState<FilterState>({
    search: ''
  })
  const [hasMore, setHasMore] = useState(false)
  const [offset, setOffset] = useState(0)
  const [isExporting, setIsExporting] = useState(false)

  const ITEMS_PER_PAGE = 20

  // Load audit entries
  const loadAuditEntries = async (reset = false) => {
    try {
      setIsLoading(true)
      setError(null)

      const auditFilter: AuditFilter = {
        unitId,
        listingId,
        userId: filters.userId || userId,
        action: filters.action,
        status: filters.status,
        dateFrom: filters.dateFrom ? new Date(filters.dateFrom) : undefined,
        dateTo: filters.dateTo ? new Date(filters.dateTo) : undefined,
        limit: ITEMS_PER_PAGE,
        offset: reset ? 0 : offset
      }

      const result = await auditService.getAuditTrail(auditFilter)
      
      if (reset) {
        setAuditEntries(result.entries)
        setOffset(ITEMS_PER_PAGE)
      } else {
        setAuditEntries(prev => [...prev, ...result.entries])
        setOffset(prev => prev + ITEMS_PER_PAGE)
      }
      
      setHasMore(result.hasMore)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to load audit history')
    } finally {
      setIsLoading(false)
    }
  }

  // Initial load and filter changes
  useEffect(() => {
    loadAuditEntries(true)
  }, [unitId, listingId, userId, filters])

  // Filter handlers
  const handleFilterChange = (key: keyof FilterState, value: string | undefined) => {
    setFilters(prev => ({
      ...prev,
      [key]: value || undefined
    }))
    setOffset(0)
  }

  const clearFilters = () => {
    setFilters({ search: '' })
    setOffset(0)
  }

  // Export functionality
  const handleExport = async (format: 'json' | 'csv') => {
    try {
      setIsExporting(true)
      
      const auditFilter: AuditFilter = {
        unitId,
        listingId,
        userId: filters.userId || userId,
        action: filters.action,
        status: filters.status,
        dateFrom: filters.dateFrom ? new Date(filters.dateFrom) : undefined,
        dateTo: filters.dateTo ? new Date(filters.dateTo) : undefined
      }

      const exportData = await auditService.exportAuditData(auditFilter, {
        format,
        includeMetadata: true
      })

      // Create and download file
      const blob = new Blob([exportData], { 
        type: format === 'csv' ? 'text/csv' : 'application/json' 
      })
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `listing-audit-${new Date().toISOString().split('T')[0]}.${format}`
      document.body.appendChild(a)
      a.click()
      document.body.removeChild(a)
      URL.revokeObjectURL(url)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to export data')
    } finally {
      setIsExporting(false)
    }
  }

  // Entry expansion
  const toggleEntryExpansion = (entryId: string) => {
    setExpandedEntries(prev => {
      const newSet = new Set(prev)
      if (newSet.has(entryId)) {
        newSet.delete(entryId)
      } else {
        newSet.add(entryId)
      }
      return newSet
    })
  }

  // Get action configuration
  const getActionConfig = (action: ListingAction) => {
    switch (action) {
      case ListingAction.CREATE:
        return {
          label: 'Created',
          color: 'bg-green-100 text-green-800 border-green-200',
          icon: CheckCircle
        }
      case ListingAction.REMOVE:
        return {
          label: 'Removed',
          color: 'bg-red-100 text-red-800 border-red-200',
          icon: XCircle
        }
      case ListingAction.SUSPEND:
        return {
          label: 'Suspended',
          color: 'bg-yellow-100 text-yellow-800 border-yellow-200',
          icon: Pause
        }
      case ListingAction.ACTIVATE:
        return {
          label: 'Activated',
          color: 'bg-blue-100 text-blue-800 border-blue-200',
          icon: Play
        }
      case ListingAction.UPDATE:
        return {
          label: 'Updated',
          color: 'bg-purple-100 text-purple-800 border-purple-200',
          icon: FileText
        }
      case ListingAction.EXPIRE:
        return {
          label: 'Expired',
          color: 'bg-gray-100 text-gray-800 border-gray-200',
          icon: Clock
        }
      default:
        return {
          label: 'Unknown',
          color: 'bg-gray-100 text-gray-800 border-gray-200',
          icon: AlertCircle
        }
    }
  }

  // Get status configuration
  const getStatusConfig = (status: ListingStatus) => {
    switch (status) {
      case ListingStatus.ACTIVE:
        return { label: 'Active', icon: Eye, color: 'text-green-600' }
      case ListingStatus.PRIVATE:
        return { label: 'Private', icon: EyeOff, color: 'text-gray-600' }
      case ListingStatus.SUSPENDED:
        return { label: 'Suspended', icon: Pause, color: 'text-yellow-600' }
      case ListingStatus.PENDING:
        return { label: 'Pending', icon: Clock, color: 'text-blue-600' }
      case ListingStatus.EXPIRED:
        return { label: 'Expired', icon: XCircle, color: 'text-red-600' }
      default:
        return { label: 'Unknown', icon: AlertCircle, color: 'text-gray-600' }
    }
  }

  // Format date and time
  const formatDateTime = (date: Date) => {
    return new Intl.DateTimeFormat('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: 'numeric',
      minute: '2-digit',
      hour12: true
    }).format(new Date(date))
  }

  // Format relative time
  const formatRelativeTime = (date: Date) => {
    const now = new Date()
    const diff = now.getTime() - new Date(date).getTime()
    const minutes = Math.floor(diff / 60000)
    const hours = Math.floor(minutes / 60)
    const days = Math.floor(hours / 24)

    if (minutes < 1) return 'Just now'
    if (minutes < 60) return `${minutes}m ago`
    if (hours < 24) return `${hours}h ago`
    if (days < 7) return `${days}d ago`
    return formatDateTime(date)
  }

  // Filter audit entries based on search
  const filteredEntries = auditEntries.filter(entry => {
    if (!filters.search) return true
    
    const searchLower = filters.search.toLowerCase()
    return (
      entry.reason?.toLowerCase().includes(searchLower) ||
      entry.action.toLowerCase().includes(searchLower) ||
      entry.newStatus.toLowerCase().includes(searchLower) ||
      entry.userId.toLowerCase().includes(searchLower)
    )
  })

  return (
    <Card className={`${className}`}>
      <CardHeader>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <History className="h-5 w-5 text-gray-600" />
            <CardTitle>Listing History</CardTitle>
            {filteredEntries.length > 0 && (
              <Badge variant="secondary">{filteredEntries.length} entries</Badge>
            )}
          </div>
          
          <div className="flex items-center gap-2">
            {showExport && (
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button 
                    variant="outline" 
                    size="sm" 
                    disabled={isExporting || filteredEntries.length === 0}
                  >
                    <Download className="h-4 w-4 mr-2" />
                    Export
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end">
                  <DropdownMenuItem onClick={() => handleExport('csv')}>
                    Export as CSV
                  </DropdownMenuItem>
                  <DropdownMenuItem onClick={() => handleExport('json')}>
                    Export as JSON
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            )}
          </div>
        </div>
      </CardHeader>

      <CardContent className="space-y-4">
        {/* Filters */}
        {showFilters && (
          <div className="space-y-3 p-4 bg-gray-50 rounded-lg">
            <div className="flex items-center gap-2">
              <Filter className="h-4 w-4 text-gray-500" />
              <span className="text-sm font-medium">Filters</span>
              {(filters.action || filters.status || filters.dateFrom || filters.dateTo || filters.userId) && (
                <Button variant="ghost" size="sm" onClick={clearFilters}>
                  Clear all
                </Button>
              )}
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
                <Input
                  placeholder="Search entries..."
                  value={filters.search}
                  onChange={(e) => handleFilterChange('search', e.target.value)}
                  className="pl-10"
                />
              </div>
              
              <Select
                value={filters.action ?? 'all'}
                onValueChange={(value) => handleFilterChange('action', value === 'all' ? undefined : value)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Filter by action" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All actions</SelectItem>
                  {Object.values(ListingAction).map(action => (
                    <SelectItem key={action} value={action}>
                      {getActionConfig(action).label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              
              <Select
                value={filters.status ?? 'all'}
                onValueChange={(value) => handleFilterChange('status', value === 'all' ? undefined : value)}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Filter by status" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All statuses</SelectItem>
                  {Object.values(ListingStatus).map(status => (
                    <SelectItem key={status} value={status}>
                      {getStatusConfig(status).label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <label className="text-xs text-gray-500 mb-1 block">From Date</label>
                <Input
                  type="date"
                  value={filters.dateFrom || ''}
                  onChange={(e) => handleFilterChange('dateFrom', e.target.value)}
                />
              </div>
              <div>
                <label className="text-xs text-gray-500 mb-1 block">To Date</label>
                <Input
                  type="date"
                  value={filters.dateTo || ''}
                  onChange={(e) => handleFilterChange('dateTo', e.target.value)}
                />
              </div>
            </div>
          </div>
        )}

        {/* Error Display */}
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4">
            <div className="flex items-center gap-2">
              <AlertCircle className="h-4 w-4 text-red-600" />
              <p className="text-sm text-red-700">{error}</p>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setError(null)}
              className="mt-2"
            >
              Dismiss
            </Button>
          </div>
        )}

        {/* Audit Entries */}
        <div 
          className="space-y-3 overflow-y-auto"
          style={{ maxHeight }}
        >
          {isLoading && auditEntries.length === 0 ? (
            // Loading skeletons
            Array.from({ length: 5 }).map((_, index) => (
              <div key={index} className="border rounded-lg p-4">
                <div className="flex items-start gap-3">
                  <Skeleton className="h-8 w-8 rounded-full" />
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-1/3" />
                    <Skeleton className="h-3 w-2/3" />
                    <Skeleton className="h-3 w-1/2" />
                  </div>
                </div>
              </div>
            ))
          ) : filteredEntries.length === 0 ? (
            <div className="text-center py-8">
              <History className="h-12 w-12 text-gray-300 mx-auto mb-4" />
              <p className="text-gray-500">No audit entries found</p>
              {(filters.search || filters.action || filters.status || filters.dateFrom || filters.dateTo) && (
                <Button variant="ghost" onClick={clearFilters} className="mt-2">
                  Clear filters to see all entries
                </Button>
              )}
            </div>
          ) : (
            filteredEntries.map((entry) => {
              const actionConfig = getActionConfig(entry.action)
              const statusConfig = getStatusConfig(entry.newStatus)
              const ActionIcon = actionConfig.icon
              const StatusIcon = statusConfig.icon
              const isExpanded = expandedEntries.has(entry.id)

              return (
                <div key={entry.id} className="border rounded-lg p-4 hover:bg-gray-50 transition-colors">
                  <div className="flex items-start gap-3">
                    <div className={`p-2 rounded-full ${actionConfig.color.replace('text-', 'bg-').replace('border-', '')}`}>
                      <ActionIcon className="h-4 w-4" />
                    </div>
                    
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <Badge className={`${actionConfig.color} border text-xs`}>
                          {actionConfig.label}
                        </Badge>
                        <div className="flex items-center gap-1 text-xs text-gray-500">
                          <StatusIcon className={`h-3 w-3 ${statusConfig.color}`} />
                          <span>{statusConfig.label}</span>
                        </div>
                        <span className="text-xs text-gray-400">•</span>
                        <span className="text-xs text-gray-500">{formatRelativeTime(entry.timestamp)}</span>
                      </div>
                      
                      <p className="text-sm text-gray-900 mb-1">
                        {entry.reason || `Listing ${entry.action.toLowerCase()}`}
                      </p>
                      
                      <div className="flex items-center gap-4 text-xs text-gray-500">
                        <div className="flex items-center gap-1">
                          <User className="h-3 w-3" />
                          <span>{entry.userId}</span>
                        </div>
                        <div className="flex items-center gap-1">
                          <Clock className="h-3 w-3" />
                          <span>{formatDateTime(entry.timestamp)}</span>
                        </div>
                      </div>

                      {/* Status Transition */}
                      {entry.previousStatus && entry.previousStatus !== entry.newStatus && (
                        <div className="mt-2 text-xs text-gray-600">
                          <span>Status changed from </span>
                          <span className="font-medium">{getStatusConfig(entry.previousStatus).label}</span>
                          <span> to </span>
                          <span className="font-medium">{statusConfig.label}</span>
                        </div>
                      )}

                      {/* Expandable Metadata */}
                      {entry.metadata && (
                        <div className="mt-2">
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => toggleEntryExpansion(entry.id)}
                            className="h-6 px-2 text-xs"
                          >
                            {isExpanded ? (
                              <>
                                <ChevronUp className="h-3 w-3 mr-1" />
                                Hide details
                              </>
                            ) : (
                              <>
                                <ChevronDown className="h-3 w-3 mr-1" />
                                Show details
                              </>
                            )}
                          </Button>
                          
                          {isExpanded && (
                            <div className="mt-2 p-3 bg-gray-100 rounded text-xs">
                              <pre className="whitespace-pre-wrap text-gray-700">
                                {JSON.stringify(entry.metadata, null, 2)}
                              </pre>
                            </div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              )
            })
          )}

          {/* Load More Button */}
          {hasMore && !isLoading && (
            <div className="text-center pt-4">
              <Button
                variant="outline"
                onClick={() => loadAuditEntries(false)}
                disabled={isLoading}
              >
                {isLoading ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-current mr-2" />
                    Loading...
                  </>
                ) : (
                  'Load More'
                )}
              </Button>
            </div>
          )}

          {/* Loading More Indicator */}
          {isLoading && auditEntries.length > 0 && (
            <div className="text-center py-4">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600 mx-auto" />
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  )
}
