export { ListingHistoryPanel }

"use client";

import React, { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from '@/components/ui/alert-dialog';
import { Wrench, Play, Square, Calendar, AlertTriangle, CheckCircle } from 'lucide-react';
import { toast } from 'sonner';

interface MaintenanceModeStatus {
  isInMaintenance: boolean;
  maintenanceRequestId?: string;
  canRestore: boolean;
  estimatedEndDate?: string;
}

interface MaintenanceModeUnit {
  unitId: string;
  unitNumber: string;
  propertyName: string;
  maintenanceRequestId?: string;
  startDate: string;
  estimatedEndDate?: string;
  reason: string;
}

interface MaintenanceModePanelProps {
  unitId?: string;
  organizationId?: string;
  onStatusChange?: () => void;
}

export function MaintenanceModePanel({ unitId, organizationId, onStatusChange }: MaintenanceModePanelProps) {
  const [status, setStatus] = useState<MaintenanceModeStatus | null>(null);
  const [units, setUnits] = useState<MaintenanceModeUnit[]>([]);
  const [loading, setLoading] = useState(false);
  const [showStartDialog, setShowStartDialog] = useState(false);
  const [showEndDialog, setShowEndDialog] = useState(false);
  const [reason, setReason] = useState('');
  const [estimatedEndDate, setEstimatedEndDate] = useState('');

  // Load maintenance status
  useEffect(() => {
    loadMaintenanceStatus();
  }, [unitId, organizationId]);

  const loadMaintenanceStatus = async () => {
    try {
      setLoading(true);
      
      if (unitId) {
        // Load status for specific unit
        const response = await fetch(`/api/maintenance/listing-integration?unitId=${unitId}`);
        if (response.ok) {
          const data = await response.json();
          setStatus(data);
        }
      } else if (organizationId) {
        // Load all units in maintenance mode for organization
        const response = await fetch(`/api/maintenance/listing-integration?organizationId=${organizationId}`);
        if (response.ok) {
          const data = await response.json();
          setUnits(data.units || []);
        }
      }
    } catch (error) {
      console.error('Error loading maintenance status:', error);
      toast.error('Failed to load maintenance status');
    } finally {
      setLoading(false);
    }
  };

  const startMaintenanceMode = async () => {
    if (!unitId || !reason.trim()) {
      toast.error('Unit ID and reason are required');
      return;
    }

    try {
      setLoading(true);
      
      const response = await fetch('/api/maintenance/listing-integration', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          action: 'start',
          unitId,
          reason: reason.trim(),
          estimatedEndDate: estimatedEndDate || undefined,
        }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        toast.success('Maintenance mode started successfully');
        setShowStartDialog(false);
        setReason('');
        setEstimatedEndDate('');
        await loadMaintenanceStatus();
        onStatusChange?.();
      } else {
        toast.error(data.error || 'Failed to start maintenance mode');
      }
    } catch (error) {
      console.error('Error starting maintenance mode:', error);
      toast.error('Failed to start maintenance mode');
    } finally {
      setLoading(false);
    }
  };

  const endMaintenanceMode = async (targetUnitId?: string) => {
    const targetUnit = targetUnitId || unitId;
    if (!targetUnit) {
      toast.error('Unit ID is required');
      return;
    }

    try {
      setLoading(true);
      
      const response = await fetch('/api/maintenance/listing-integration', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          action: 'end',
          unitId: targetUnit,
          reason: reason.trim() || 'Maintenance completed',
        }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        toast.success('Maintenance mode ended successfully');
        setShowEndDialog(false);
        setReason('');
        await loadMaintenanceStatus();
        onStatusChange?.();
      } else {
        toast.error(data.error || 'Failed to end maintenance mode');
      }
    } catch (error) {
      console.error('Error ending maintenance mode:', error);
      toast.error('Failed to end maintenance mode');
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  // Single unit view
  if (unitId && status !== null) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Wrench className="h-5 w-5" />
            Maintenance Mode
          </CardTitle>
          <CardDescription>
            Manage unit availability during maintenance periods
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="text-sm font-medium">Status:</span>
              <Badge variant={status.isInMaintenance ? "destructive" : "secondary"}>
                {status.isInMaintenance ? (
                  <>
                    <AlertTriangle className="h-3 w-3 mr-1" />
                    In Maintenance
                  </>
                ) : (
                  <>
                    <CheckCircle className="h-3 w-3 mr-1" />
                    Available
                  </>
                )}
              </Badge>
            </div>
            
            <div className="flex gap-2">
              {!status.isInMaintenance ? (
                <AlertDialog open={showStartDialog} onOpenChange={setShowStartDialog}>
                  <AlertDialogTrigger asChild>
                    <Button variant="outline" size="sm">
                      <Play className="h-4 w-4 mr-1" />
                      Start Maintenance
                    </Button>
                  </AlertDialogTrigger>
                  <AlertDialogContent>
                    <AlertDialogHeader>
                      <AlertDialogTitle>Start Maintenance Mode</AlertDialogTitle>
                      <AlertDialogDescription>
                        This will temporarily remove the unit from marketplace listings.
                      </AlertDialogDescription>
                    </AlertDialogHeader>
                    <div className="space-y-4">
                      <div>
                        <Label htmlFor="reason">Reason for Maintenance</Label>
                        <Textarea
                          id="reason"
                          placeholder="Describe the maintenance work being performed..."
                          value={reason}
                          onChange={(e) => setReason(e.target.value)}
                          className="mt-1"
                        />
                      </div>
                      <div>
                        <Label htmlFor="endDate">Estimated End Date (Optional)</Label>
                        <Input
                          id="endDate"
                          type="datetime-local"
                          value={estimatedEndDate}
                          onChange={(e) => setEstimatedEndDate(e.target.value)}
                          className="mt-1"
                        />
                      </div>
                    </div>
                    <AlertDialogFooter>
                      <AlertDialogCancel>Cancel</AlertDialogCancel>
                      <AlertDialogAction
                        onClick={startMaintenanceMode}
                        disabled={!reason.trim() || loading}
                      >
                        {loading ? 'Starting...' : 'Start Maintenance'}
                      </AlertDialogAction>
                    </AlertDialogFooter>
                  </AlertDialogContent>
                </AlertDialog>
              ) : (
                status.canRestore && (
                  <AlertDialog open={showEndDialog} onOpenChange={setShowEndDialog}>
                    <AlertDialogTrigger asChild>
                      <Button variant="outline" size="sm">
                        <Square className="h-4 w-4 mr-1" />
                        End Maintenance
                      </Button>
                    </AlertDialogTrigger>
                    <AlertDialogContent>
                      <AlertDialogHeader>
                        <AlertDialogTitle>End Maintenance Mode</AlertDialogTitle>
                        <AlertDialogDescription>
                          This will restore the unit to marketplace listings.
                        </AlertDialogDescription>
                      </AlertDialogHeader>
                      <div className="space-y-4">
                        <div>
                          <Label htmlFor="endReason">Completion Notes (Optional)</Label>
                          <Textarea
                            id="endReason"
                            placeholder="Add any notes about the completed maintenance..."
                            value={reason}
                            onChange={(e) => setReason(e.target.value)}
                            className="mt-1"
                          />
                        </div>
                      </div>
                      <AlertDialogFooter>
                        <AlertDialogCancel>Cancel</AlertDialogCancel>
                        <AlertDialogAction
                          onClick={() => endMaintenanceMode()}
                          disabled={loading}
                        >
                          {loading ? 'Ending...' : 'End Maintenance'}
                        </AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>
                )
              )}
            </div>
          </div>

          {status.isInMaintenance && status.estimatedEndDate && (
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <Calendar className="h-4 w-4" />
              <span>Estimated completion: {formatDate(status.estimatedEndDate)}</span>
            </div>
          )}
        </CardContent>
      </Card>
    );
  }

  // Organization overview
  if (organizationId) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Wrench className="h-5 w-5" />
            Units in Maintenance Mode
          </CardTitle>
          <CardDescription>
            Overview of all units currently under maintenance
          </CardDescription>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="text-center py-4">Loading...</div>
          ) : units.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              <CheckCircle className="h-12 w-12 mx-auto mb-2 opacity-50" />
              <p>No units currently in maintenance mode</p>
            </div>
          ) : (
            <div className="space-y-3">
              {units.map((unit) => (
                <div
                  key={unit.unitId}
                  className="flex items-center justify-between p-3 border rounded-lg"
                >
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                      <span className="font-medium">{unit.unitNumber}</span>
                      <Badge variant="outline">{unit.propertyName}</Badge>
                    </div>
                    <p className="text-sm text-muted-foreground">{unit.reason}</p>
                    <div className="flex items-center gap-4 text-xs text-muted-foreground">
                      <span>Started: {formatDate(unit.startDate)}</span>
                      {unit.estimatedEndDate && (
                        <span>Est. End: {formatDate(unit.estimatedEndDate)}</span>
                      )}
                    </div>
                  </div>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => endMaintenanceMode(unit.unitId)}
                    disabled={loading}
                  >
                    <Square className="h-4 w-4 mr-1" />
                    End Maintenance
                  </Button>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    );
  }

  return null;
}

// Property Deactivation Panel Component
// Provides UI for property deactivation and recovery operations

'use client';

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { 
  AlertTriangle, 
  CheckCircle, 
  XCircle, 
  RefreshCw, 
  Users, 
  Home, 
  FileText,
  Clock
} from 'lucide-react';

interface PropertyDeactivationPanelProps {
  propertyId: string;
  propertyName: string;
  isDeactivated?: boolean;
  unitsCount?: number;
  activeListingsCount?: number;
  onDeactivationComplete?: (result: any) => void;
  onRecoveryComplete?: (result: any) => void;
}

interface DeactivationResult {
  success: boolean;
  unitsAffected: number;
  listingsRemoved: number;
  applicationsAffected: number;
  notificationsSent: number;
  canRecover: boolean;
  error?: string;
}

interface RecoveryInfo {
  canRecover: boolean;
  unitsAffected?: number;
  listingsToRestore?: number;
  applicationsAffected?: number;
  deactivationDate?: string;
}

export default function PropertyDeactivationPanel({
  propertyId,
  propertyName,
  isDeactivated = false,
  unitsCount = 0,
  activeListingsCount = 0,
  onDeactivationComplete,
  onRecoveryComplete
}: PropertyDeactivationPanelProps) {
  const [isLoading, setIsLoading] = useState(false);
  const [reason, setReason] = useState('');
  const [notifyPropertyManagers, setNotifyPropertyManagers] = useState(true);
  const [notifyTenants, setNotifyTenants] = useState(true);
  const [gracePeriodHours, setGracePeriodHours] = useState(0);
  const [result, setResult] = useState<DeactivationResult | null>(null);
  const [recoveryInfo, setRecoveryInfo] = useState<RecoveryInfo | null>(null);
  const [showConfirmation, setShowConfirmation] = useState(false);

  // Load recovery info if property is deactivated
  React.useEffect(() => {
    if (isDeactivated) {
      loadRecoveryInfo();
    }
  }, [isDeactivated, propertyId]);

  const loadRecoveryInfo = async () => {
    try {
      const response = await fetch(`/api/properties/${propertyId}/recover`);
      if (response.ok) {
        const data = await response.json();
        setRecoveryInfo(data);
      }
    } catch (error) {
      console.error('Error loading recovery info:', error);
    }
  };

  const handleDeactivate = async () => {
    if (!reason.trim()) {
      alert('Please provide a reason for deactivation');
      return;
    }

    setIsLoading(true);
    try {
      const response = await fetch(`/api/properties/${propertyId}/deactivate`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          reason: reason.trim(),
          notifyPropertyManagers,
          notifyTenants,
          gracePeriodHours
        }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        const deactivationResult: DeactivationResult = {
          success: true,
          unitsAffected: data.data.unitsAffected,
          listingsRemoved: data.data.listingsRemoved,
          applicationsAffected: data.data.applicationsAffected,
          notificationsSent: data.data.notificationsSent,
          canRecover: data.data.canRecover
        };
        
        setResult(deactivationResult);
        setShowConfirmation(false);
        onDeactivationComplete?.(deactivationResult);
      } else {
        setResult({
          success: false,
          unitsAffected: 0,
          listingsRemoved: 0,
          applicationsAffected: 0,
          notificationsSent: 0,
          canRecover: false,
          error: data.message || 'Deactivation failed'
        });
      }
    } catch (error) {
      setResult({
        success: false,
        unitsAffected: 0,
        listingsRemoved: 0,
        applicationsAffected: 0,
        notificationsSent: 0,
        canRecover: false,
        error: 'Network error occurred'
      });
    } finally {
      setIsLoading(false);
    }
  };

  const handleRecover = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(`/api/properties/${propertyId}/recover`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          reason: 'Property recovered from accidental deactivation'
        }),
      });

      const data = await response.json();

      if (response.ok && data.success) {
        const recoveryResult = {
          success: true,
          unitsRestored: data.data.unitsRestored,
          listingsRestored: data.data.listingsRestored,
          notificationsSent: data.data.notificationsSent
        };
        
        setResult(null);
        setRecoveryInfo(null);
        onRecoveryComplete?.(recoveryResult);
      } else {
        alert(data.message || 'Recovery failed');
      }
    } catch (error) {
      alert('Network error occurred during recovery');
    } finally {
      setIsLoading(false);
    }
  };

  if (isDeactivated) {
    return (
      <Card className="border-orange-200 bg-orange-50">
        <CardHeader>
          <CardTitle className="flex items-center gap-2 text-orange-800">
            <AlertTriangle className="h-5 w-5" />
            Property Deactivated
          </CardTitle>
          <CardDescription>
            This property has been deactivated and all listings have been removed from the marketplace.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {recoveryInfo && recoveryInfo.canRecover && (
            <>
              <div className="grid grid-cols-2 gap-4 text-sm">
                <div className="flex items-center gap-2">
                  <Home className="h-4 w-4 text-gray-500" />
                  <span>Units Affected: {recoveryInfo.unitsAffected}</span>
                </div>
                <div className="flex items-center gap-2">
                  <FileText className="h-4 w-4 text-gray-500" />
                  <span>Listings to Restore: {recoveryInfo.listingsToRestore}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Users className="h-4 w-4 text-gray-500" />
                  <span>Applications Affected: {recoveryInfo.applicationsAffected}</span>
                </div>
                {recoveryInfo.deactivationDate && (
                  <div className="flex items-center gap-2">
                    <Clock className="h-4 w-4 text-gray-500" />
                    <span>Deactivated: {new Date(recoveryInfo.deactivationDate).toLocaleDateString()}</span>
                  </div>
                )}
              </div>
              
              <Separator />
              
              <div className="flex gap-2">
                <Button 
                  onClick={handleRecover}
                  disabled={isLoading}
                  className="bg-green-600 hover:bg-green-700"
                >
                  {isLoading ? (
                    <>
                      <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                      Recovering...
                    </>
                  ) : (
                    <>
                      <RefreshCw className="h-4 w-4 mr-2" />
                      Recover Property
                    </>
                  )}
                </Button>
              </div>
            </>
          )}
          
          {recoveryInfo && !recoveryInfo.canRecover && (
            <Alert>
              <AlertTriangle className="h-4 w-4" />
              <AlertDescription>
                Recovery is not available for this property. Recovery data may have expired or been cleared.
              </AlertDescription>
            </Alert>
          )}
        </CardContent>
      </Card>
    );
  }

  return (
    <Card className="border-red-200">
      <CardHeader>
        <CardTitle className="flex items-center gap-2 text-red-800">
          <AlertTriangle className="h-5 w-5" />
          Property Deactivation
        </CardTitle>
        <CardDescription>
          Deactivate this property and remove all associated listings from the marketplace.
          This action affects all units and active applications.
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Current Property Stats */}
        <div className="grid grid-cols-2 gap-4 p-4 bg-gray-50 rounded-lg">
          <div className="text-center">
            <div className="text-2xl font-bold text-gray-900">{unitsCount}</div>
            <div className="text-sm text-gray-600">Total Units</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-blue-600">{activeListingsCount}</div>
            <div className="text-sm text-gray-600">Active Listings</div>
          </div>
        </div>

        {/* Deactivation Form */}
        {!showConfirmation && !result && (
          <div className="space-y-4">
            <div>
              <Label htmlFor="reason">Reason for Deactivation *</Label>
              <Textarea
                id="reason"
                placeholder="Explain why this property is being deactivated..."
                value={reason}
                onChange={(e) => setReason(e.target.value)}
                className="mt-1"
                rows={3}
              />
            </div>

            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <Label htmlFor="notify-managers">Notify Property Managers</Label>
                <Switch
                  id="notify-managers"
                  checked={notifyPropertyManagers}
                  onCheckedChange={setNotifyPropertyManagers}
                />
              </div>
              
              <div className="flex items-center justify-between">
                <Label htmlFor="notify-tenants">Notify Affected Tenants</Label>
                <Switch
                  id="notify-tenants"
                  checked={notifyTenants}
                  onCheckedChange={setNotifyTenants}
                />
              </div>
              
              <div>
                <Label htmlFor="grace-period">Grace Period (hours)</Label>
                <Input
                  id="grace-period"
                  type="number"
                  min="0"
                  max="168"
                  value={gracePeriodHours}
                  onChange={(e) => setGracePeriodHours(parseInt(e.target.value) || 0)}
                  className="mt-1"
                />
                <p className="text-xs text-gray-500 mt-1">
                  Optional delay before deactivation takes effect (0-168 hours)
                </p>
              </div>
            </div>

            <Button 
              onClick={() => setShowConfirmation(true)}
              disabled={!reason.trim()}
              variant="destructive"
              className="w-full"
            >
              <AlertTriangle className="h-4 w-4 mr-2" />
              Deactivate Property
            </Button>
          </div>
        )}

        {/* Confirmation Dialog */}
        {showConfirmation && !result && (
          <div className="space-y-4 p-4 border-2 border-red-200 rounded-lg bg-red-50">
            <div className="flex items-center gap-2 text-red-800 font-semibold">
              <AlertTriangle className="h-5 w-5" />
              Confirm Property Deactivation
            </div>
            
            <div className="text-sm text-red-700">
              <p className="font-medium mb-2">This action will:</p>
              <ul className="list-disc list-inside space-y-1">
                <li>Remove all {activeListingsCount} active listings from the marketplace</li>
                <li>Disable tenant applications for all {unitsCount} units</li>
                <li>Cancel any pending applications</li>
                <li>Send notifications to affected parties</li>
              </ul>
            </div>

            <div className="bg-white p-3 rounded border">
              <p className="text-sm"><strong>Reason:</strong> {reason}</p>
            </div>

            <div className="flex gap-2">
              <Button 
                onClick={handleDeactivate}
                disabled={isLoading}
                variant="destructive"
                className="flex-1"
              >
                {isLoading ? (
                  <>
                    <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                    Deactivating...
                  </>
                ) : (
                  'Confirm Deactivation'
                )}
              </Button>
              <Button 
                onClick={() => setShowConfirmation(false)}
                variant="outline"
                disabled={isLoading}
              >
                Cancel
              </Button>
            </div>
          </div>
        )}

        {/* Results Display */}
        {result && (
          <div className={`p-4 rounded-lg border-2 ${
            result.success 
              ? 'border-green-200 bg-green-50' 
              : 'border-red-200 bg-red-50'
          }`}>
            <div className={`flex items-center gap-2 font-semibold mb-3 ${
              result.success ? 'text-green-800' : 'text-red-800'
            }`}>
              {result.success ? (
                <CheckCircle className="h-5 w-5" />
              ) : (
                <XCircle className="h-5 w-5" />
              )}
              {result.success ? 'Property Deactivated Successfully' : 'Deactivation Failed'}
            </div>

            {result.success ? (
              <div className="space-y-2 text-sm text-green-700">
                <div className="grid grid-cols-2 gap-4">
                  <div>Units Affected: <Badge variant="secondary">{result.unitsAffected}</Badge></div>
                  <div>Listings Removed: <Badge variant="secondary">{result.listingsRemoved}</Badge></div>
                  <div>Applications Affected: <Badge variant="secondary">{result.applicationsAffected}</Badge></div>
                  <div>Notifications Sent: <Badge variant="secondary">{result.notificationsSent}</Badge></div>
                </div>
                
                {result.canRecover && (
                  <Alert className="mt-3">
                    <CheckCircle className="h-4 w-4" />
                    <AlertDescription>
                      Recovery data has been saved. You can restore this property if the deactivation was accidental.
                    </AlertDescription>
                  </Alert>
                )}
              </div>
            ) : (
              <div className="text-sm text-red-700">
                <p>{result.error}</p>
              </div>
            )}
          </div>
        )}
      </CardContent>
    </Card>
  );
}
// Named export for compatibility
export { PropertyDeactivationPanel }

"use client";

import React, { useState, useEffect } from "react";
import { Wrench } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import type { ReactElement } from "react";
import CreateRequestForm from "./CreateRequestForm";
import { useAuth } from "@/context/AuthContext";
import { toast } from "sonner";
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";

type Request = {
  id: string;
  title: string;
  description: string;
  propertyId?: string;
  unitId?: string;
  priority: string;
  status: string;
  category?: string;
  requestedBy?: { user?: { firstName?: string; lastName?: string } };
  createdAt?: string;
  property?: { address?: string | null; name?: string | null; city?: string | null };
  unit?: { unitNumber: string; unitName?: string | null };
  vendor?: { user?: { firstName?: string; lastName?: string }; companyName?: string | null };
  cost?: string;
};

function handleExcel(data: any, filename = "maintenance_requests.xlsx", username: string) {
  const worksheet = XLSX.utils.json_to_sheet(data);
  worksheet["!cols"] = [
    { wch: 20 }, { wch: 50 }, { wch: 20 }, { wch: 20 }, { wch: 10 },
    { wch: 10 }, { wch: 10 }, { wch: 15 }, { wch: 12 }, { wch: 25 },
  ];
  const range = XLSX.utils.decode_range(worksheet["!ref"] || "");
  const headerRowIndex = 0;
  for (let C = range.s.c; C <= range.e.c; ++C) {
    const cell_address = XLSX.utils.encode_cell({ r: headerRowIndex, c: C });
    const cell = worksheet[cell_address];
    if (cell) cell.s = { font: { bold: true } };
  }
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Data");
  const excelBuffer = XLSX.write(workbook, { bookType: "xlsx", type: "array" });
  const blob = new Blob([excelBuffer], { type: "application/octet-stream" });
  saveAs(blob, `${username}_${filename}`);
}

function handleCSV(data: any, filename = "maintenance_requests.csv", username: string) {
  const headers = Object.keys(data[0] || {});
  const rows = data.map((row: any) =>
    headers.map((header) => {
      const value = row[header] ?? "";
      return typeof value === "string" ? `"${value.replace(/"/g, '""')}"` : value;
    }).join(",")
  );
  const csvString = [headers.join(","), ...rows].join("\n");
  const blob = new Blob([csvString], { type: "text/csv;charset=utf-8;" });
  saveAs(blob, `${username}_${filename}`);
}

// Helper to get property display name
function getPropertyDisplayName(property: any): string {
  return property?.apartmentComplexDetail?.buildingName || property?.houseDetail?.houseName || property?.name || property?.address || property?.city || property?.id || '-';
}

export default function MaintenanceRequestsClient(): ReactElement {
  const { user } = useAuth();
  const router = useRouter();
  const loggedInUser = `${user?.firstName ?? ""}_${user?.lastName ?? ""}`;
  const organizationId = user?.organization?.id;
  const [requests, setRequests] = useState<Request[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");
  const [propertyFilter, setPropertyFilter] = useState<string>("all");
  const [exportFormat, setExportFormat] = useState("");
  const [selectedRequest, setSelectedRequest] = useState<Request | null>(null);

  
    async function fetchRequests() {
      if (!organizationId) { setLoading(false); return; }
      try {
        const res = await fetch(`/api/maintenance?organizationId=${organizationId}`);
        if (!res.ok) console.error("Failed to fetch requests");
        const data = await res.json();
        setRequests(data);
      } catch (error) { console.error("Error fetching maintenance requests:", error); }
      finally { setLoading(false); }
    }
    
    useEffect(() => {
  fetchRequests();
}, [organizationId]);

  function flattenRequestsForExcel(data: Request[]) {
    const capFirst = (s?: string | null) => s && s.length > 0 ? s.charAt(0) + s.slice(1) : "";
    return data.map((r) => ({
      TITLE: capFirst(r.title),
      DESCRIPTION: capFirst(r.description),
      PROPERTY_NAME: capFirst(r.property?.name),
      ADDRESS: capFirst(r.property?.city),
      UNIT: r.unit?.unitName ?? r.unit?.unitNumber ?? "",
      PRIORITY: r.priority ?? "",
      STATUS: r.status ?? "",
      REQUESTED_BY: `${capFirst(r.requestedBy?.user?.firstName)} ${capFirst(r.requestedBy?.user?.lastName)}`.trim(),
      CATEGORY: capFirst(r.category),
      CreatedAt: r.createdAt ? new Date(r.createdAt).toLocaleDateString() : "",
    }));
  }

  // Get unique property names for dropdown
  const propertyNames = Array.from(new Set(requests.map(r => getPropertyDisplayName(r.property)).filter(Boolean)));

  const filteredRequests = requests.filter((r) => {
    // Filter by property name if selected
    if (propertyFilter !== "all" && getPropertyDisplayName(r.property) !== propertyFilter) return false;
    const search = searchTerm.trim().toLowerCase();
    if (search) {
      const prop = `${r.property?.address ?? ""} ${r.property?.city ?? ""}`.toLowerCase();
      if (!prop.includes(search) && !(r.title ?? "").toLowerCase().includes(search)) return false;
    }
    return true;
  });

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px] bg-white">
        <svg className="animate-spin h-10 w-10 text-emerald-500" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v4a4 4 0 00-4 4H4z" />
        </svg>
      </div>
    );
  }
  return (
    <div className="min-h-[400px] p-6 bg-white text-gray-900">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-6 gap-4 sm:gap-0">
        <div>
          <h1 className="text-2xl font-bold">Maintenance Requests</h1>
          <p className="text-gray-600 text-sm">Track property issues, repairs and service needs</p>
        </div>
        <div className="flex flex-row flex-wrap gap-2 items-center">
          <button
            onClick={() => setShowForm(true)}
            className="inline-flex items-center gap-2 px-4 py-2 rounded bg-emerald-600 hover:bg-emerald-700 text-white shadow"
          >
            Make Request
          </button>
          <Link href="/property-manager/maintenance/vendors" className="inline-flex items-center gap-2 px-4 py-2 rounded bg-blue-600 hover:bg-blue-700 text-white shadow">
            Assign Vendor
          </Link>
          {/* <a
            href="/property-manager/maintenance/vendors/add"
            className="inline-flex items-center gap-2 px-4 py-2 rounded bg-gray-600 hover:bg-gray-700 text-white shadow"
          >
            Add Vendor
          </a> */}
        </div>
      </div>

      {showForm && (
        <div className="fixed inset-0 bg-gray-900/30 flex items-center justify-center z-50 p-4">
          <div className="bg-white border border-gray-200 rounded-lg w-full max-w-lg shadow-xl p-6 max-h-[90vh] overflow-y-auto">
            <div className="mb-6 flex justify-between items-center">
              <h3 className="text-2xl font-bold text-gray-900">Create Maintenance Request</h3>
              <button
                onClick={() => setShowForm(false)}
                className="text-gray-500 hover:text-gray-900 text-xl font-bold"
                aria-label="Close"
              >
                ×
              </button>
            </div>
            <CreateRequestForm organizationId={organizationId}
              onSuccess={() => {
                fetchRequests();
                setShowForm(false);
              }}
            />
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
        <div className="bg-white border border-gray-200 rounded-xl p-4 shadow-sm">
          <p className="text-gray-600 text-sm mb-1">Requests Assigned</p>
          <p className="text-3xl font-bold">{requests.length}</p>
        </div>
        <div className="bg-white border border-gray-200 rounded-xl p-4 shadow-sm">
          <p className="text-gray-600 text-sm mb-1">Open Requests</p>
          <p className="text-3xl font-bold text-yellow-600">
            {requests.filter((r) => (r.status ?? "").toLowerCase().includes("open")).length}
          </p>
        </div>
        <div className="bg-white border border-gray-200 rounded-xl p-4 shadow-sm">
          <p className="text-gray-600 text-sm mb-1">Requests Completed</p>
          <p className="text-3xl font-bold text-emerald-600">
            {requests.filter((r) => !(r.status ?? "").toLowerCase().includes("open")).length}
          </p>
        </div>
      </div>

      <div className="bg-gray-50 border border-gray-200 rounded-xl p-4 mb-6">
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <input
              type="text"
              placeholder="Search by description..."
              className="w-full bg-white border border-gray-300 text-gray-900 placeholder-gray-400 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-400 focus:border-transparent"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          {/* Property filter dropdown */}
          <div>
            <select
              className="bg-white border border-gray-300 text-gray-900 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-400 focus:border-transparent min-w-40"
              value={propertyFilter ?? "all"}
              onChange={e => setPropertyFilter(e.target.value)}
            >
              <option value="all">All Properties</option>
              {propertyNames.map(name => (
                <option key={name} value={name ?? ''}>{name}</option>
              ))}
            </select>
          </div>

          {organizationId && (
            <div className="flex gap-2">
              <select
                className="bg-white border border-gray-300 text-gray-900 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-400 focus:border-transparent min-w-40"
                value={exportFormat}
                onChange={(e) => {
                  const value = e.target.value;
                  setExportFormat(value);
                  if (value === "Excel") {
                    toast.success("Your Excel file is downloading...");
                    handleExcel(flattenRequestsForExcel(requests), "maintenance_requests.xlsx", loggedInUser);
                    setExportFormat("Export");
                  }
                  if (value === "CSV") {
                    toast.success("Your CSV file is downloading...");
                    handleCSV(flattenRequestsForExcel(requests), "maintenance_requests.csv", loggedInUser);
                    setExportFormat("Export");
                  }
                }}
              >
                <option value="Export">Export</option>
                <option value="Excel">Excel sheet</option>
                <option value="CSV">CSV</option>
              </select>
            </div>
          )}
        </div>
      </div>

      <div className="bg-white border border-gray-200 rounded-xl overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-100">
              <tr>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Title</th>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Description</th>
                {/* <th className="text-left p-2 text-gray-700 font-semibold text-sm">Property</th>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Address</th> */}
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Priority</th>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Status</th>
                {/* <th className="text-left p-2 text-gray-700 font-semibold text-sm">Requested</th> */}
                {/* <th className="text-left p-2 text-gray-700 font-semibold text-sm">Category</th> */}
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Cost</th>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Assign to</th>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Unit</th>
                <th className="text-left p-2 text-gray-700 font-semibold text-sm">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredRequests.map((r) => (
                <tr key={r.id} className="border-t border-gray-200 hover:bg-gray-50 transition-colors">
                  <td className="p-2 text-gray-900">{r.title}</td>
                  <td className="p-2 text-gray-900">
                    {r.description.length > 15 ? `${r.description.slice(0, 15)}...` : r.description}
                  </td>
                  {/* <td className="p-2 text-gray-900">{r.property?.name}</td>
                  <td className="p-2 text-gray-900">{r.property?.city}</td> */}
                  <td className="p-2">
                    <span
                      className={`px-3 py-1 rounded-full text-xs font-semibold
                        ${r.priority === "LOW" ? "bg-gray-200 text-gray-800"
                          : r.priority === "NORMAL" ? "bg-green-100 text-green-800"
                          : r.priority === "HIGH" ? "bg-green-500 text-white"
                          : r.priority === "URGENT" ? "bg-red-500 text-white"
                          : "bg-orange-400 text-white"}`}
                    >
                      {r.priority ? r.priority.charAt(0) + r.priority.slice(1).toLowerCase() : ""}
                    </span>
                  </td>
                  <td className="p-2">
                    <span
                      className={`px-3 py-1 rounded-full text-xs font-semibold ${
                        (r.status ?? "").toLowerCase().includes("open")
                          ? "bg-yellow-100 text-yellow-700"
                          : "bg-emerald-100 text-emerald-700"
                      }`}
                    >
                      {r.status}
                    </span>
                  </td>
                  {/* <td className="p-2 text-gray-900">
                    {r.requestedBy?.user?.firstName ?? "Unknown"} {r.requestedBy?.user?.lastName?.charAt(0) ?? ""}
                  </td> */}
                  {/* <td className="p-2 text-gray-900">{r.category?.toLowerCase() ?? "standard"}</td> */}
                  <td className="p-2 text-gray-900">{r.cost ?? "-"}</td>
                  <td className="p-2 text-gray-900">
                    {r.vendor ? (
                      r.vendor.companyName
                        ? r.vendor.companyName
                        : `${r.vendor.user?.firstName ?? ""} ${r.vendor.user?.lastName ? r.vendor.user.lastName.charAt(0) + "." : ""}`.trim()
                    ) : (
                      "-"
                    )}
                  </td>
                  <td className="p-2 text-gray-900">
                    {r.unit?.unitName ? r.unit.unitName : r.unit?.unitNumber ?? "-"}
                  </td>
                  <td className="p-2 text-gray-900"> 
                    <button 
                      onClick={() => setSelectedRequest(r)}
                      className="inline-flex items-center gap-1 px-3 py-1 rounded text-xs bg-green-100 hover:bg-green-200 text-green-700 font-medium transition-colors"
                    >
                      View Details
                    </button>
                  </td>
                      {selectedRequest && (
                      <div className="fixed inset-0 bg-black/5 flex items-center justify-center z-50 p-4">

                          <div className="bg-white border border-gray-200 rounded-lg w-full max-w-lg shadow-xl p-6 max-h-[90vh] overflow-y-auto">
                            <div className="mb-6 flex justify-between items-center">
                              <h3 className="text-2xl font-bold text-gray-900">{`Maintenance Details for ${getPropertyDisplayName(selectedRequest.property) ?? '-'} unit ${selectedRequest.unit?.unitName ?? selectedRequest.unit?.unitNumber ?? '-'}`}</h3>
                              <button
                                onClick={() => setSelectedRequest(null)}
                                className="text-gray-500 hover:text-gray-900 text-xl font-bold"
                                aria-label="Close"
                              >
                                ×
                              </button>
                            </div>
                            <div className="space-y-3">
                              <div><strong>Property:</strong> {getPropertyDisplayName(selectedRequest.property) ?? '-'} ({selectedRequest.property?.address ?? ''} {selectedRequest.property?.city ?? ''})</div>
                              <div><strong>Title:</strong> {selectedRequest.title}</div>
                              <div><strong>Description:</strong> {selectedRequest.description}</div>
                              <div><strong>Priority:</strong> {selectedRequest.priority}</div>
                              <div><strong>Status:</strong> {selectedRequest.status}</div>
                              <div><strong>Category:</strong> {selectedRequest.category ?? '-'}</div>
                              <div><strong>Cost:</strong> {selectedRequest.cost ?? '-'}</div>
                              <div><strong>Created At:</strong> {selectedRequest.createdAt ? new Date(selectedRequest.createdAt).toLocaleString() : '-'}</div>
                              <div><strong>Unit:</strong> {selectedRequest.unit?.unitName ?? selectedRequest.unit?.unitNumber ?? '-'}</div>
                              <div><strong>Requested By:</strong> {selectedRequest.requestedBy?.user ? `${selectedRequest.requestedBy.user.firstName ?? ''} ${selectedRequest.requestedBy.user.lastName ?? ''}` : '-'}</div>
                              <div><strong>Assigned Vendor:</strong> {selectedRequest.vendor?.companyName ? selectedRequest.vendor.companyName : `${selectedRequest.vendor?.user?.firstName ?? ''} ${selectedRequest.vendor?.user?.lastName ?? ''}`}</div>
                            </div>
                          </div>
                        </div>
                      )}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { Loader2, Plus } from "lucide-react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import { Lease } from "../type";

export default function CreateInvoiceModal() {
    const [isOpen, setIsOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [leases, setLeases] = useState<Lease[]>([]);

    // Form State
    const [leaseId, setLeaseId] = useState("");
    const [type, setType] = useState("RENT");
    const [amount, setAmount] = useState("");
    const [dueDate, setDueDate] = useState(new Date().toISOString().split('T')[0]);

    // Fetch Leases on Open
    useEffect(() => {
        if (isOpen) {
            fetch("/api/tenants")
                .then(res => res.json())
                .then(data => {
                    if (data.data) setLeases(data.data);
                    else if (Array.isArray(data)) setLeases(data);
                })
                .catch(err => console.error("Failed to load tenants", err));
        }
    }, [isOpen]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!leaseId || !amount) {
            toast.error("Please select a tenant and amount");
            return;
        }

        setLoading(true);
        try {
            const res = await fetch("/api/invoices/manual", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    leaseId, // API now expects leaseId
                    type,
                    amount: parseFloat(amount),
                    dueDate
                })
            });

            if (!res.ok) throw new Error("Failed to create invoice");

            toast.success("Invoice Created & Posted to GL!");
            setIsOpen(false);
            setTimeout(() => {
                window.location.reload(); // Refresh the list after showing toast
            }, 3000);
        } catch (error) {
            toast.error("Error creating invoice");
        } finally {
            setLoading(false);
        }
    };

    if (!isOpen) {
        return (
            <Button onClick={() => setIsOpen(true)} className="bg-blue-600 hover:bg-blue-700 text-white font-semibold transition-all duration-200">
                <Plus className="w-4 h-4 mr-2" /> Create Invoice
            </Button>
        );
    }

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
            <div className="bg-white rounded-xl p-8 w-full max-w-md shadow-2xl animate-in fade-in zoom-in duration-200">
                <h2 className="text-2xl font-bold mb-6 text-slate-800">Create Manual Invoice</h2>

                <form onSubmit={handleSubmit} className="space-y-5">

                    {/* Tenant Select */}
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-2">Select Tenant (Lease)</label>
                        <select
                            className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-slate-50 cursor-pointer"
                            value={leaseId}
                            onChange={(e) => setLeaseId(e.target.value)}
                            required
                        >
                            <option value="">-- Choose Tenant --</option>
                            {leases.map((lease) => (
                                <option key={lease.id} value={lease.id}>
                                    {lease.tenant?.firstName} {lease.tenant?.lastName} ({lease.unit?.unitNumber || 'No Unit'})
                                </option>
                            ))}
                        </select>
                    </div>

                    {/* Type */}
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-2">Invoice Type</label>
                        <select
                            className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-slate-50 cursor-pointer"
                            value={type}
                            onChange={(e) => setType(e.target.value)}
                        >
                            <option value="RENT">Rent</option>
                            <option value="UTILITY">Utility</option>
                        </select>
                    </div>

                    {/* Amount */}
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-2">Amount ($)</label>
                        <input
                            type="number"
                            step="0.01"
                            className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-slate-50"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                            placeholder="0.00"
                            required
                        />
                    </div>

                    {/* Date */}
                    <div>
                        <label className="block text-sm font-semibold text-slate-700 mb-2">Due Date</label>
                        <input
                            type="date"
                            className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none bg-slate-50 cursor-pointer"
                            value={dueDate}
                            onChange={(e) => setDueDate(e.target.value)}
                            required
                        />
                    </div>

                    {/* Actions */}
                    <div className="flex justify-end gap-3 mt-8">
                        <Button
                            variant="ghost"
                            type="button"
                            onClick={() => setIsOpen(false)}
                            className="text-slate-600 hover:bg-slate-100"
                        >
                            Cancel
                        </Button>
                        <Button
                            type="submit"
                            disabled={loading}
                            className="bg-blue-600 hover:bg-blue-700 text-white px-6 font-semibold shadow-md shadow-blue-200"
                        >
                            {loading ? <Loader2 className="animate-spin mr-2" /> : null}
                            {loading ? "Generating..." : "Generate Invoice"}
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { useRouter } from "next/navigation";
import { Loader2, FileText, AlertCircle, Clock } from "lucide-react";
import DraftReviewModal from "./DraftReviewModal";

interface InvoiceQueueItem {
  id: string;
  totalAmount: number;
  dueDate: Date;
  status: "DRAFT" | "PENDING" | "PAID" | "OVERDUE" | "CANCELLED";
  postingStatus: string;
  Lease?: {
    unit?: { unitNumber: string };
    tenant?: { firstName: string; lastName: string; email: string } | null;
  };
}

export default function InvoiceQueueCard() {
  const [invoices, setInvoices] = useState<InvoiceQueueItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedInvoice, setSelectedInvoice] = useState<InvoiceQueueItem | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const router = useRouter();

  // 1. Wrap the fetch logic in useCallback so it can be reused safely
  const fetchInvoices = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      
      const res = await fetch("/api/invoices?status=DRAFT,PENDING,OVERDUE"); 
      
      // IMPROVEMENT: Capture the actual error status and message from the server
      if (!res.ok) {
        const errorText = await res.text();
        throw new Error(`Server Error (${res.status}): ${errorText || "Failed to load"}`);
      }
      
      const data = await res.json();
      
      let invoiceList: InvoiceQueueItem[] =[];
      
      // Handle both grouped and flat response formats
      if (data.invoices && Array.isArray(data.invoices)) {
        // New format with separate invoices array
        invoiceList = data.invoices;
      } else if (Array.isArray(data)) {
        // Old format - grouped response
        if (data[0]?.id) {
          invoiceList = data;
        } else {
          data.forEach((group: any) => {
            if (group.invoices && Array.isArray(group.invoices)) {
              invoiceList =[...invoiceList, ...group.invoices];
            }
          });
        }
      }
      
      const sorted = invoiceList
          .filter((inv) =>["DRAFT", "PENDING", "OVERDUE"].includes(inv.status))
          .sort((a, b) => {
            if (a.status === "OVERDUE" && b.status !== "OVERDUE") return -1;
            if (b.status === "OVERDUE" && a.status !== "OVERDUE") return 1;
            return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
          })
          .slice(0, 5);

      setInvoices(sorted);
    } catch (error) {
      console.error("Invoice Fetch Error:", error);
      setError(error instanceof Error ? error.message : "Failed to load invoices");
    } finally {
      setLoading(false);
    }
  },[]);

  // 2. Reuse the callback for the initial load
  useEffect(() => {
    fetchInvoices();
  }, [fetchInvoices]);

  // 3. Reuse the callback for refreshing after a post
  const refreshList = useCallback(() => {
    fetchInvoices();
  }, [fetchInvoices]);

  const getStatusBadge = (invoice: InvoiceQueueItem) => {
    const due = new Date(invoice.dueDate);
    const now = new Date();
    due.setHours(23, 59, 59, 999);
    const diffTime = due.getTime() - now.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    if (invoice.status === "DRAFT") {
      return (
        <span className="text-xs font-medium px-2 py-0.5 rounded bg-gray-100 text-gray-600 flex items-center gap-1">
          <FileText size={12} /> Draft
        </span>
      );
    }

    if (invoice.status === "OVERDUE" || diffDays < 0) {
      return (
        <span className="text-xs font-medium px-2 py-0.5 rounded bg-red-50 text-red-600 flex items-center gap-1">
          <AlertCircle size={12} /> Overdue {Math.abs(diffDays)}d
        </span>
      );
    }

    if (diffDays === 0) {
      return <span className="text-xs font-medium text-orange-600">Due Today</span>;
    }

    if (diffDays <= 3) {
      return <span className="text-xs font-medium text-amber-600">Due in {diffDays} days</span>;
    }

    return <span className="text-xs text-gray-500">Due in {diffDays} days</span>;
  };

  if (loading) {
    return (
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full flex items-center justify-center">
        <Loader2 className="animate-spin text-gray-300" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full flex items-center justify-center">
        <div className="text-center text-red-500">
          <AlertCircle className="w-8 h-8 mx-auto mb-2" />
          {/* This will now output the actual Server Error status (e.g. 404 or 500) */}
          <p className="text-sm px-4">{error}</p>
          <button 
            onClick={refreshList}
            className="text-xs text-blue-500 hover:underline mt-2"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 h-full flex flex-col">
      <div className="flex justify-between items-center mb-4">
        <h3 className="font-semibold text-gray-900">Invoice Queue</h3>
        <button 
            onClick={() => router.push('/property-manager/finance/invoices')}
            className="text-xs text-blue-600 hover:text-blue-700 font-medium"
        >
            View All
        </button>
      </div>

      <div className="flex-1 overflow-y-auto space-y-4">
        {invoices.length === 0 ? (
          <p className="text-sm text-gray-400 text-center py-4">All caught up! No open invoices.</p>
        ) : (
          invoices.map((inv) => (
            <div 
              key={inv.id} 
              className="flex items-center justify-between group cursor-pointer hover:bg-gray-50 p-2 rounded-lg -mx-2 transition-colors"
              onClick={() => {
                setSelectedInvoice(inv);
                setIsModalOpen(true);
              }}
            >
              <div className="flex flex-col">
                <span className="text-sm font-medium text-gray-900">
                  {inv.Lease?.tenant ? `${inv.Lease.tenant.firstName} ${inv.Lease.tenant.lastName}` : "Unknown Tenant"}
                </span>
                {getStatusBadge(inv)}
              </div>

              <div className="text-right">
                <div className="text-xs text-gray-500 mb-0.5">
                  Unit {inv.Lease?.unit?.unitNumber || "N/A"}
                </div>
                <div className="font-bold text-gray-900">
                  ${Number(inv.totalAmount).toLocaleString(undefined, { minimumFractionDigits: 2 })}
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      <DraftReviewModal 
        isOpen={isModalOpen} 
        invoice={selectedInvoice} 
        onClose={() => setIsModalOpen(false)}
        onSuccess={refreshList}
      />
    </div>
  );
}

import React, { useEffect, useState } from "react";
import { CardContent } from "@/components/ui/card";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from "recharts";
import RentUtilitiesChart from "./RentUtilitiesChart";
import DashboardChartTooltip, { DASHBOARD_TOOLTIP_WRAPPER_STYLE } from "./DashboardChartTooltip";

// Utility: generate color palette
const COLORS = [
	"#4F46E5", "#60A5FA", "#F59E42", "#10B981", "#EF4444", "#A78BFA", "#F472B6", "#FBBF24", "#34D399", "#6366F1"
];

interface OccupancyLineChartProps {
	selectedProperty: string;
	myproperties: Array<{ id: string; name?: string }>;
}

const OccupancyLineChart: React.FC<OccupancyLineChartProps> = ({ selectedProperty, myproperties }) => {
	const [chartData, setChartData] = useState<any[]>([]);
	const [loading, setLoading] = useState(true);


	useEffect(() => {
		async function fetchOccupancyHistory() {
			setLoading(true);
			try {
				if (selectedProperty === "all") {
					const propertyIds = myproperties.map(p => p.id);
					const res = await fetch(`/api/occupancy-history?propertyIds=${propertyIds.join(",")}`);
					const data = await res.json();
					// Group by month/year, each propertyId as a separate line
					const grouped: { [key: string]: any } = {};
					data.forEach((row: any) => {
						const key = `${row.year}-${row.month}`;
						if (!grouped[key]) {
							grouped[key] = {
								month: new Date(row.year, row.month - 1).toLocaleString('default', { month: 'short' }),
								year: row.year,
							};
						}
						// Always use propertyId as key
						grouped[key][row.propertyId] = Number(row.occupancyRate);
					});
					const sorted = Object.values(grouped).sort((a: any, b: any) => {
						if (a.year !== b.year) return a.year - b.year;
						return new Date(`${a.year}-${a.month}-01`).getMonth() - new Date(`${b.year}-${b.month}-01`).getMonth();
					});
					setChartData(sorted);
					// Debug log
					console.log("[OccupancyLineChart] chartData:", sorted);
				} else {
					const res = await fetch(`/api/occupancy-history?propertyId=${selectedProperty}`);
					const data = await res.json();
					const formatted = data.map((row: any) => ({
						month: new Date(row.year, row.month - 1).toLocaleString('default', { month: 'short' }),
						year: row.year,
						occupancyRate: Number(row.occupancyRate),
					}));
					setChartData(formatted);
					console.log("[OccupancyLineChart] chartData (single):", formatted);
				}
			} catch (err) {
				setChartData([]);
			} finally {
				setLoading(false);
			}
		}
		fetchOccupancyHistory();
	}, [selectedProperty, myproperties]);

	// Helper to get display name for a property
	function getPropertyDisplayName(property: { name?: string; apartmentComplexDetail?: { buildingName?: string } | null; houseDetail?: { houseName?: string } | null }): string {
		return property?.apartmentComplexDetail?.buildingName || property?.houseDetail?.houseName || property?.name || '';
	}

	// Get property IDs for lines
	const propertyIds = selectedProperty === "all"
		? myproperties.map(p => p.id)
		: [];
	console.log("[OccupancyLineChart] propertyIds:", propertyIds);

	// Ensure myproperties passed to RentUtilitiesChart always has name as string
	const safeMyProperties = myproperties.map(p => ({
		...p,
		name: p.name ?? ''
	}));

	return (
		<div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mt-8 min-h-[350px]">
			<CardContent className="p-0 flex flex-col min-h-[300px] h-full w-full relative">
				<div className="mb-4">
					<h3 className="text-lg font-semibold text-gray-900">Occupancy Rate</h3>
				</div>
				<div className="flex-1 w-full overflow-x-auto custom-scrollbar pb-2">
					<div style={{ minWidth: "100%", width: Math.max(600, chartData.length * 60), height: "100%" }}>
						<ResponsiveContainer width="100%" height="100%">
							<LineChart
								data={chartData}
								margin={{ left: 10, right: 10, top: 10, bottom: 10 }}
							>
								<CartesianGrid strokeDasharray="3 3" vertical={false} />
								<XAxis
									dataKey="month"
									axisLine={false}
									tickLine={false}
									interval={0}
									minTickGap={0}
									padding={{ left: 10, right: 10 }}
								/>
								<YAxis domain={[0, 100]} tickFormatter={tick => `${tick}%`} />
								<Tooltip
									content={
										<DashboardChartTooltip
											valueFormatter={(value) => {
												if (typeof value === "number") return `${value.toFixed(1)}%`;
												return `${value}%`;
											}}
										/>
									}
									wrapperStyle={DASHBOARD_TOOLTIP_WRAPPER_STYLE}
								/>
								<Legend formatter={(value) => {
									const prop = myproperties.find(p => p.id === value);
									return prop ? getPropertyDisplayName(prop) : value;
								}} />
								{selectedProperty === "all"
									? myproperties.map((property, idx) => (
										<Line
											key={property.id}
											type="monotone"
											dataKey={property.id}
											name={getPropertyDisplayName(property)}
											stroke={COLORS[idx % COLORS.length] || "#000"}
											strokeWidth={3}
											dot={false}
										/>
									))
									: (
										<Line
											type="monotone"
											dataKey="occupancyRate"
											stroke="#4F46E5"
											strokeWidth={3}
											dot={false}
										/>
									)}
							</LineChart>
						</ResponsiveContainer>
					</div>
				</div>
			</CardContent>
			<div className="h-full min-h-[300px] w-full relative">
				<RentUtilitiesChart selectedProperty={selectedProperty} myproperties={safeMyProperties} />
			</div>
		</div>
	);
};

export default OccupancyLineChart;

import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import React, { useEffect, useState, useMemo } from 'react';
import DashboardChartTooltip, { DASHBOARD_TOOLTIP_WRAPPER_STYLE } from "./DashboardChartTooltip";

interface Property {
  id: string;
  name: string;
}

interface RentUtilitiesChartProps {
  myproperties: Property[];
  selectedProperty: string;
}

export default function RentUtilitiesChart({ myproperties, selectedProperty }: RentUtilitiesChartProps) {
  const [data, setData] = useState<any[]>([]);
  const [selectedMonth, setSelectedMonth] = useState<string>('all');

  // Generate last 12 months for dropdown
  const months = useMemo(() => {
    const result = [];
    const now = new Date();
    for (let i = 0; i < 12; i++) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      result.push({
        value: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`,
        label: d.toLocaleString('default', { month: 'short', year: 'numeric' })
      });
    }
    return result.sort((a, b) => a.value.localeCompare(b.value));
  }, []);

  useEffect(() => {
    async function fetchData() {
      let url = '';
      if (selectedProperty === 'all') {
        const ids = myproperties.map(p => p.id).join(',');
        url = `/api/properties/utilities?propertyIds=${ids}`;
      } else {
        url = `/api/properties/utilities?propertyId=${selectedProperty}`;
      }
      if (selectedMonth !== 'all') {
        url += (url.includes('?') ? '&' : '?') + `month=${selectedMonth}`;
      }
      try {
        const res = await fetch(url);
        if (!res.ok) throw new Error('Failed to fetch');
        const apiData = await res.json();
        setData(apiData.map((item: any) => ({
          name: item.propertyName,
          rentCollected: item.rentCollected,
          utilitiesPaid: item.utilitiesPaid,
        })));
      } catch (e) {
        setData([]);
      }
    }
    if (myproperties.length > 0) fetchData();
  }, [myproperties, selectedProperty, selectedMonth]);

  return (
    <div className="w-full h-full min-h-[300px] p-4 bg-white rounded-2xl shadow-md flex flex-col">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl font-semibold">Rent & Utilities Overview</h2>
        <div>
          <select
            className="border border-gray-300 rounded px-2 py-1 text-sm"
            value={selectedMonth}
            onChange={e => setSelectedMonth(e.target.value)}
          >
            <option value="all">All Months</option>
            {months.map(m => (
              <option key={m.value} value={m.value}>{m.label}</option>
            ))}
          </select>
        </div>
      </div>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="name" />
          <YAxis />
          <Tooltip
            content={
              <DashboardChartTooltip
                valueFormatter={(value) => {
                  if (typeof value === "number") return `$${value.toLocaleString()}`;
                  return `$${value}`;
                }}
              />
            }
            wrapperStyle={DASHBOARD_TOOLTIP_WRAPPER_STYLE}
          />
          <Legend />
          <Bar dataKey="rentCollected" name="Rent Collected" />
          <Bar dataKey="utilitiesPaid" name="Utilities Paid" />
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
}

"use client";

import React, { useEffect, useState, useMemo } from "react";
import { 
	CheckCircle, Clock, AlertCircle, Wrench, 
	TrendingUp, TrendingDown, DollarSign, 
	FileText, Plus, Search, Building2
} from "lucide-react";
import Link from "next/link";
import { Skeleton } from "@/components/ui/skeleton";
import RevenueChart from "./RevenueChart";
import { FinancialSummaryCard } from "./financial-summary-card";
import { PendingLeasesCard } from "./pending-leases-card";
import OccupancyLineChart from "./OccupancyLineChart";
import InvoiceQueueCard from "./InvoiceQueueCard";
import { cn } from "@/lib/utils";
import { toast } from "sonner";

// --- Alert Chip Component ---
function AlertChip({ icon: Icon, color, text }: { icon: any; color: string; text: string }) {
	return (
		<div className={cn("flex items-center gap-2 px-3 py-2 rounded-md border text-sm font-medium", color)}>
			<Icon className="w-4 h-4" />
			<span>{text}</span>
		</div>
	);
}

// --- KPI Card with Trend ---
function KpiCard({ title, value, trend, trendUp, icon: Icon }: { title: string; value: string; trend: string; trendUp: boolean; icon?: any }) {
	return (
		<div className="bg-white p-5 rounded-xl border border-slate-100 shadow-sm">
			<div className="flex justify-between items-start mb-2">
				<p className="text-sm font-medium text-slate-500">{title}</p>
			</div>
			<div className="flex items-baseline gap-2">
				<h3 className="text-2xl font-bold text-slate-900">{value}</h3>
			</div>
			<div className={cn("flex items-center gap-1 mt-2 text-xs font-semibold", trendUp ? "text-emerald-600" : "text-rose-600")}>
				{trendUp ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
				{trend}
			</div>
		</div>
	);
}

// --- Queue Card Component ---
function QueueCard({ title, items, type }: { title: string; items: any[]; type: string }) {
	return (
		<div className="bg-white rounded-xl border border-slate-100 shadow-sm overflow-hidden flex flex-col h-[320px]">
			<div className="px-5 py-4 border-b border-slate-50 flex justify-between items-center">
				<h4 className="text-sm font-bold text-slate-800 uppercase tracking-tight">{title}</h4>
			</div>
			<div className="flex-1 overflow-y-auto">
				{items.length === 0 ? (
					<div className="flex items-center justify-center h-full text-slate-400 text-sm">
						No items found
					</div>
				) : (
					items.map((item: any, i: number) => (
						<div key={i} className="px-5 py-3 border-b border-slate-50 last:border-0 hover:bg-slate-50 transition-colors cursor-pointer flex justify-between items-center">
							<div className="space-y-0.5">
								<p className="text-sm font-bold text-slate-900">{item.name}</p>
								<p className="text-[11px] text-slate-400">{item.subtext}</p>
							</div>
							<div className="text-right space-y-0.5">
								<p className="text-xs font-bold text-slate-700">{item.value}</p>
								{item.badge && (
									<span className={cn("text-[9px] px-1.5 py-0.5 rounded font-bold uppercase", item.badgeColor)}>
										{item.badge}
									</span>
								)}
							</div>
						</div>
					))
				)}
			</div>
		</div>
	);
}

// --- Main Dashboard Page ---

export default function Dashboard() {
	const [data, setData] = useState<any>(null);
	const [loading, setLoading] = useState(true);
	const [selectedProperty, setSelectedProperty] = useState("all");
	const [selectedTimeRange, setSelectedTimeRange] = useState("6m");

	// Check if this is a zero-data state (no properties yet)
	const isZeroDataState = !data || data.kpis?.totalUnits === 0;

	// Build maintenance items from API data using useMemo - BEFORE the loading check
	const maintenanceItems = useMemo(() => {
		const mbp = data?.breakdowns?.maintenanceByPriority;
		if (!mbp) return [];

		const { urgent, high, normal } = mbp;
		const items: { name: string; subtext: string; value: string; badge: string; badgeColor: string }[] = [];

		if (urgent > 0) {
			items.push({
				name: `${urgent} Urgent Request${urgent > 1 ? 's' : ''}`,
				subtext: "Requires immediate attention",
				value: "Action Required",
				badge: "Urgent",
				badgeColor: "bg-red-600 text-white"
			});
		}

		if (high > 0) {
			items.push({
				name: `${high} High Priority Request${high > 1 ? 's' : ''}`,
				subtext: "Requires attention soon",
				value: "Action Required",
				badge: "High",
				badgeColor: "bg-rose-600 text-white"
			});
		}

		if (normal > 0) {
			items.push({
				name: `${normal} Standard Request${normal > 1 ? 's' : ''}`,
				subtext: "Scheduled maintenance",
				value: "Pending",
				badge: "Normal",
				badgeColor: "bg-emerald-500 text-white"
			});
		}

		return items.length > 0 ? items : [{ name: "No active requests", subtext: "All clear", value: "Clear", badge: "OK", badgeColor: "bg-slate-100 text-slate-500" }];
	}, [data]);

	useEffect(() => {
		const fetchData = async (propId: string, timeRange: string) => {
			try {
				setLoading(true);
				let url = "/api/dashboard/analytics";
				const params = new URLSearchParams();
				if (propId && propId !== "all") params.append("propertyId", propId);
				if (timeRange) params.append("timeRange", timeRange);

				if (Array.from(params).length > 0) {
					url += `?${params.toString()}`;
				}

				const res = await fetch(url);
				if (res.ok) {
					const json = await res.json();
					setData(json);
				}
			} catch (err) {
				console.error(err);
				toast.error("Could not update live stats.");
			} finally {
				setLoading(false);
			}
		};
		fetchData(selectedProperty, selectedTimeRange);
	}, [selectedProperty, selectedTimeRange]);

	if (loading) {
		return (
			<div className="p-6 space-y-6">
				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
					{[...Array(4)].map((_, i) => <Skeleton key={i} className="h-28 w-full rounded-xl" />)}
				</div>
				<div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
					{[...Array(3)].map((_, i) => <Skeleton key={i} className="h-64 w-full rounded-xl" />)}
				</div>
			</div>
		);
	}

	// Default values for zero-data state
	const kpis = data?.kpis || {
		occupancyRate: 0,
		occupancyTrend: "0",
		totalUnits: 0,
		revenue: 0,
		noi: 0,
		arrears: 0,
		vacancyLoss: 0,
		collectedThisMonth: 0,
		revenueTrend: "0",
		activeMaintenance: 0,
		maintenanceSla: 0,
		expiringLeases: 0,
		operatingExpenseRatio: 0,
		averageMaintenanceResponseTime: 0,
		averageTimeToFillVacancy: 0,
		debtServiceCoverageRatio: "N/A"
	};

	const breakdowns = data?.breakdowns || {
		leaseExpirations: { days30: 0, days60: 0, details: [] },
		openInvoices: { count: 0, amount: 0 },
		maintenanceByPriority: { high: 0, normal: 0 }
	};

	// Determine status alerts based on data
	const portfolioHealth = kpis.occupancyRate >= 90 ? "Strong" : kpis.occupancyRate >= 70 ? "Stable" : "Attention";
	const leasesExpiringCount = breakdowns?.leaseExpirations?.days60 || 0;
	const overdueInvoicesCount = breakdowns?.openInvoices?.count || 0;
	const highPriorityMaintenance = (breakdowns?.maintenanceByPriority?.urgent || 0) + (breakdowns?.maintenanceByPriority?.high || 0);

	// Format currency
	const formatCurrency = (amount: number) => {
		if (amount >= 1000000) return `${(amount / 1000000).toFixed(1)}M`;
		if (amount >= 1000) return `${(amount / 1000).toFixed(0)}K`;
		return `${amount}`;
	};

	// Build queue data from API - FIXED: Access nested tenant and unit objects
	const invoiceItems = (breakdowns?.openInvoices?.details || []).slice(0, 5).map((inv: any) => ({
		name: inv.Lease?.tenant?.firstName && inv.Lease?.tenant?.lastName 
			? `${inv.Lease.tenant.firstName} ${inv.Lease.tenant.lastName}` 
			: "Unknown Tenant",
		subtext: inv.dueDate ? `Due ${new Date(inv.dueDate).toLocaleDateString()}` : "Due date unknown",
		value: formatCurrency(inv.totalAmount || 0),
		badge: inv.Lease?.unit?.unitNumber || "Unit",
		badgeColor: inv.status === "OVERDUE" ? "bg-rose-100 text-rose-600" : "bg-slate-100 text-slate-600"
	}));

	const leaseItems = (breakdowns?.leaseExpirations?.details || []).slice(0, 5).map((lease: any) => ({
		name: lease.tenant?.firstName && lease.tenant?.lastName 
			? `${lease.tenant.firstName} ${lease.tenant.lastName}` 
			: "Unknown Tenant",
		subtext: lease.unit?.unitNumber ? `Unit ${lease.unit.unitNumber}` : "Unit unknown",
		value: lease.endDate ? new Date(lease.endDate).toLocaleDateString() : "N/A"
	}));

	return (
		<div className="p-6 bg-slate-50/40 min-h-screen space-y-6">
			
			{/* 1. Header & Global Actions */}
			<div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
				<div>
					<h1 className="text-2xl font-bold text-slate-900 tracking-tight">Command Center</h1>
					<p className="text-sm text-slate-500 mt-1">
						{isZeroDataState ? "Add properties to start tracking your portfolio" : "Portfolio overview and pending actions"}
					</p>
				</div>
				<div className="flex items-center gap-3">
					{/* Search */}
					<div className="relative">
						<Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-slate-400" />
						<input 
							type="text" 
							placeholder="Search..." 
							className="pl-9 pr-4 py-2 text-sm border border-slate-300 rounded-lg focus:ring-blue-500 focus:border-blue-500 outline-none"
						/>
					</div>
					{/* Add Property Button */}
					<Link href="/property-manager/add-property">
						<button className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2.5 rounded-lg text-sm font-medium transition-colors shadow-sm">
							<Plus className="w-4 h-4" />
							Add Property
						</button>
					</Link>
				</div>
			</div>

			{/* 2. Alert Ribbon - Compact top-level status */}
			<div className="flex flex-wrap gap-3">
				<AlertChip 
					icon={CheckCircle} 
					color={portfolioHealth === "Strong" ? "bg-emerald-50 border-emerald-100 text-emerald-700" : portfolioHealth === "Stable" ? "bg-blue-50 border-blue-100 text-blue-700" : "bg-rose-50 border-rose-100 text-rose-700"} 
					text={`Portfolio Health: ${portfolioHealth}`} 
				/>
				<AlertChip 
					icon={Clock} 
					color="bg-blue-50 border-blue-100 text-blue-700" 
					text={`${leasesExpiringCount} leases expiring in 60 days`} 
				/>
				<AlertChip 
					icon={AlertCircle} 
					color={overdueInvoicesCount > 0 ? "bg-rose-50 border-rose-100 text-rose-700" : "bg-emerald-50 border-emerald-100 text-emerald-700"} 
					text={overdueInvoicesCount > 0 ? `${overdueInvoicesCount} overdue invoice` : "No overdue invoices"} 
				/>
				<AlertChip 
					icon={Wrench} 
					color={highPriorityMaintenance > 0 ? "bg-orange-50 border-orange-100 text-orange-700" : "bg-emerald-50 border-emerald-100 text-emerald-700"} 
					text={highPriorityMaintenance > 0 ? `${highPriorityMaintenance} high-priority work order` : "Maintenance OK"} 
				/>
			</div>

			{/* 3. KPI Cards Row (4 Columns) */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
				<KpiCard 
					title="Occupancy Rate" 
					value={isZeroDataState ? "0%" : `${kpis.occupancyRate}%`} 
					trend={isZeroDataState ? "0% vs last month" : `${parseFloat(kpis.occupancyTrend) >= 0 ? "+" : ""}${kpis.occupancyTrend}% vs last month`}
					trendUp={parseFloat(kpis.occupancyTrend || "0") >= 0}
				/>
				<KpiCard 
					title="Open Invoices" 
					value={isZeroDataState ? "0" : `${breakdowns?.openInvoices?.count || 0}`} 
					trend="12.4% past 30 days"
					trendUp={false}
				/>
				<KpiCard 
					title="Collected This Month" 
					value={isZeroDataState ? "$0" : formatCurrency(kpis.collectedThisMonth || 0)} 
					trend={isZeroDataState ? "0% MTD" : `${parseFloat(kpis.revenueTrend) >= 0 ? "+" : ""}${Math.abs(parseFloat(kpis.revenueTrend))}% MTD cash received`}
					trendUp={parseFloat(kpis.revenueTrend || "0") >= 0}
				/>
				<KpiCard 
					title="Open Requests" 
					value={isZeroDataState ? "0" : `${kpis.activeMaintenance}`} 
					trend="4.5% maintenance queue"
					trendUp={false}
				/>
			</div>

			{/* 4. Trends Section (2 Columns on Large) */}
			<div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
				{/* Occupancy Trend */}
				<div className="bg-white p-5 rounded-xl border border-slate-100 shadow-sm flex flex-col lg:col-span-2 min-h-[380px]">
					<div className="flex justify-between mb-4">
						<h4 className="text-sm font-semibold text-slate-800">Occupancy Trend</h4>
						<span className="text-[10px] text-slate-400 uppercase tracking-wider">Last 7 months</span>
					</div>
					<div className="flex-1 bg-slate-50/50 rounded-lg flex items-stretch border-2 border-dashed border-slate-100">
						{isZeroDataState ? (
							<div className="w-full h-full flex items-center justify-center">
								<p className="text-xs text-slate-400">Add properties to see trends</p>
							</div>
						) : (
							<div className="w-full h-full">
								<OccupancyLineChart selectedProperty={selectedProperty} myproperties={data?.properties || []} />
							</div>
						)}
					</div>
					<p className="mt-4 text-xs text-slate-500">Current occupancy <span className="font-bold text-slate-900">{kpis.occupancyRate}%</span></p>
				</div>

