// components/lease/AmendmentManager.tsx
"use client";

import { useState, useEffect } from "react";
import {
  FileEdit,
  Plus,
  CheckCircle,
  XCircle,
  Clock,
  Eye,
  Trash2,
  AlertTriangle,
  ArrowRight,
  History,
} from "lucide-react";

interface Amendment {
  id: string;
  amendmentType: string;
  effectiveDate: string;
  description: string;
  changes: any;
  previousValues: any;
  status: string;
  createdAt: string;
  createdBy: string;
  approvedBy?: string;
  approvedAt?: string;
  executedBy?: string;
  executedAt?: string;
}

interface AmendmentManagerProps {
  leaseId: string;
}

export default function AmendmentManager({ leaseId }: AmendmentManagerProps) {
  const [amendments, setAmendments] = useState<Amendment[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [selectedAmendment, setSelectedAmendment] = useState<Amendment | null>(null);

  const [amendmentForm, setAmendmentForm] = useState({
    amendmentType: "RENT_CHANGE",
    effectiveDate: "",
    description: "",
    changes: {} as any,
    requiresSignature: true,
  });

  useEffect(() => {
    fetchAmendments();
  }, [leaseId]);

 async function fetchAmendments() {
  try {
    const res = await fetch(`/api/lease/${leaseId}/ammendment`);
    if (!res.ok) {
      const err = await res.json().catch(() => ({ error: "Unknown error" }));
      throw new Error(err.error);
    }
    const data = await res.json();
    setAmendments(data);
  } catch (error) {
    console.error("Failed to fetch amendments:", error);
    setAmendments([]);
  } finally {
    setLoading(false);
  }
}


  async function createAmendment() {
    try {
      const res = await fetch(`/api/lease/${leaseId}/ammendment`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(amendmentForm),
      });

      const data = await res.json();

      if (res.ok) {
        alert("Amendment created successfully");
        setAmendments([data, ...amendments]);
        setShowCreateForm(false);
        resetForm();
      } else {
        alert(data.error || "Failed to create ammendment");
      }
    } catch (error) {
      console.error("Create amendment error:", error);
      alert("An error occurred");
    }
  }

  async function updateAmendmentStatus(
    amendmentId: string,
    action: "APPROVE" | "REJECT" | "EXECUTE"
  ) {
    const confirmMessages = {
      APPROVE: "Are you sure you want to approve this amendment?",
      REJECT: "Are you sure you want to reject this amendment?",
      EXECUTE: "This will apply the changes to the lease. Continue?",
    };

    if (!confirm(confirmMessages[action])) return;

    try {
      const res = await fetch(
        `/api/lease/${leaseId}/ammendment/${amendmentId}`,
        {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ action }),
        }
      );

      const data = await res.json();

      if (res.ok) {
        alert(`Amendment ${action.toLowerCase()}d successfully`);
        fetchAmendments();
      } else {
        alert(data.error || `Failed to ${action.toLowerCase()} amendment`);
      }
    } catch (error) {
      console.error("Update amendment error:", error);
      alert("An error occurred");
    }
  }

  async function deleteAmendment(amendmentId: string) {
    if (!confirm("Are you sure you want to delete this amendment?")) return;

    try {
      const res = await fetch(
        `/api/lease/${leaseId}/ammendment/${amendmentId}`,
        {
          method: "DELETE",
        }
      );

      if (res.ok) {
        alert("Amendment deleted");
        setAmendments(amendments.filter((a) => a.id !== amendmentId));
      } else {
        alert("Failed to delete amendment");
      }
    } catch (error) {
      console.error("Delete error:", error);
      alert("An error occurred");
    }
  }

  function resetForm() {
    setAmendmentForm({
      amendmentType: "RENT_CHANGE",
      effectiveDate: "",
      description: "",
      changes: {},
      requiresSignature: true,
    });
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case "PENDING":
        return "bg-yellow-100 text-yellow-800 border-yellow-300";
      case "APPROVED":
        return "bg-blue-100 text-blue-800 border-blue-300";
      case "EXECUTED":
        return "bg-green-100 text-green-800 border-green-300";
      case "REJECTED":
        return "bg-red-100 text-red-800 border-red-300";
      default:
        return "bg-gray-100 text-gray-800 border-gray-300";
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case "PENDING":
        return <Clock className="w-4 h-4" />;
      case "APPROVED":
        return <CheckCircle className="w-4 h-4" />;
      case "EXECUTED":
        return <CheckCircle className="w-4 h-4" />;
      case "REJECTED":
        return <XCircle className="w-4 h-4" />;
      default:
        return null;
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow p-6">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-semibold flex items-center gap-2">
          <FileEdit className="w-6 h-6 text-blue-600" />
          Lease Amendments
        </h2>
        <button
          onClick={() => setShowCreateForm(!showCreateForm)}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2"
        >
          <Plus className="w-4 h-4" />
          New Amendment
        </button>
      </div>

      {/* Create Amendment Form */}
      {showCreateForm && (
        <div className="mb-6 p-5 border-2 border-blue-200 rounded-lg bg-blue-50">
          <h3 className="font-semibold mb-4 text-lg">Create New Amendment</h3>

          <div className="space-y-4">
            {/* Amendment Type */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Amendment Type
              </label>
              <select
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={amendmentForm.amendmentType}
                onChange={(e) => {
                  setAmendmentForm({
                    ...amendmentForm,
                    amendmentType: e.target.value,
                    changes: {}, // Reset changes when type changes
                  });
                }}
              >
                <option value="RENT_CHANGE">Rent Change</option>
                <option value="TERM_EXTENSION">Term Extension</option>
                <option value="UTILITY_CHANGE">Utility Responsibility Change</option>
                <option value="RESPONSIBILITY_CHANGE">Responsibility Change</option>
                <option value="TENANT_CHANGE">Tenant Change</option>
                <option value="DEPOSIT_CHANGE">Deposit Change</option>
                <option value="FEE_STRUCTURE_CHANGE">Fee Structure Change</option>
                <option value="OTHER">Other</option>
              </select>
            </div>

            {/* Effective Date */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Effective Date
              </label>
              <input
                type="date"
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={amendmentForm.effectiveDate}
                onChange={(e) =>
                  setAmendmentForm({
                    ...amendmentForm,
                    effectiveDate: e.target.value,
                  })
                }
              />
            </div>

            {/* Description */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Description
              </label>
              <textarea
                rows={3}
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                placeholder="Describe the amendment..."
                value={amendmentForm.description}
                onChange={(e) =>
                  setAmendmentForm({
                    ...amendmentForm,
                    description: e.target.value,
                  })
                }
              />
            </div>

            {/* Dynamic fields based on amendment type */}
            <AmendmentFields
              amendmentType={amendmentForm.amendmentType}
              changes={amendmentForm.changes}
              onChange={(changes) =>
                setAmendmentForm({ ...amendmentForm, changes })
              }
            />

            {/* Requires Signature */}
            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id="requiresSignature"
                checked={amendmentForm.requiresSignature}
                onChange={(e) =>
                  setAmendmentForm({
                    ...amendmentForm,
                    requiresSignature: e.target.checked,
                  })
                }
              />
              <label htmlFor="requiresSignature" className="text-sm text-gray-700">
                Requires new signatures from both parties
              </label>
            </div>

            {amendmentForm.requiresSignature && (
              <div className="bg-yellow-50 border border-yellow-200 rounded p-3 flex items-start gap-2">
                <AlertTriangle className="w-5 h-5 text-yellow-600 flex-shrink-0 mt-0.5" />
                <p className="text-sm text-yellow-800">
                  This amendment will reset all signatures. Both landlord and tenant
                  will need to re-sign the lease.
                </p>
              </div>
            )}

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              <button
                onClick={createAmendment}
                disabled={
                  !amendmentForm.effectiveDate ||
                  !amendmentForm.description ||
                  Object.keys(amendmentForm.changes).length === 0
                }
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed"
              >
                Create Amendment
              </button>
              <button
                onClick={() => {
                  setShowCreateForm(false);
                  resetForm();
                }}
                className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Amendments List */}
      {amendments.length === 0 ? (
        <div className="text-center py-12">
          <FileEdit className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <p className="text-gray-500">No amendments yet</p>
        </div>
      ) : (
        <div className="space-y-4">
          {amendments.map((amendment) => (
            <div
              key={amendment.id}
              className="border border-gray-200 rounded-lg p-5 hover:bg-gray-50 transition-colors"
            >
              <div className="flex items-start justify-between mb-3">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h3 className="font-semibold text-lg text-gray-900">
                      {amendment.amendmentType.replace(/_/g, " ")}
                    </h3>
                    <span
                      className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-semibold border ${getStatusColor(
                        amendment.status
                      )}`}
                    >
                      {getStatusIcon(amendment.status)}
                      {amendment.status}
                    </span>
                  </div>
                  <p className="text-sm text-gray-600 mb-2">
                    {amendment.description}
                  </p>
                  <div className="flex items-center gap-4 text-xs text-gray-500">
                    <span>
                      Effective: {new Date(amendment.effectiveDate).toLocaleDateString()}
                    </span>
                    <span>
                      Created: {new Date(amendment.createdAt).toLocaleDateString()}
                    </span>
                  </div>
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 ml-4">
                  <button
                    onClick={() => setSelectedAmendment(amendment)}
                    className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                    title="View Details"
                  >
                    <Eye className="w-4 h-4" />
                  </button>

                  {amendment.status === "PENDING" && (
                    <>
                      <button
                        onClick={() =>
                          updateAmendmentStatus(amendment.id, "APPROVE")
                        }
                        className="p-2 text-green-500 hover:bg-green-50 rounded-lg"
                        title="Approve"
                      >
                        <CheckCircle className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() =>
                          updateAmendmentStatus(amendment.id, "REJECT")
                        }
                        className="p-2 text-red-600 hover:bg-red-50 rounded-lg"
                        title="Reject"
                      >
                        <XCircle className="w-4 h-4" />
                      </button>
                      <button
                        onClick={() => deleteAmendment(amendment.id)}
                        className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg"
                        title="Delete"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </>
                  )}

                  {amendment.status === "APPROVED" && (
                    <button
                      onClick={() =>
                        updateAmendmentStatus(amendment.id, "EXECUTE")
                      }
                      className="px-3 py-1 bg-green-500 text-white rounded-lg hover:bg-green-600 text-sm font-medium flex items-center gap-1"
                    >
                      <ArrowRight className="w-3 h-3" />
                      Execute
                    </button>
                  )}
                </div>
              </div>

              {/* Changes Preview */}
              {amendment.changes && Object.keys(amendment.changes).length > 0 && (
                <div className="mt-3 pt-3 border-t border-gray-200">
                  <p className="text-xs font-medium text-gray-500 mb-2">Changes:</p>
                  <div className="grid grid-cols-2 gap-2 text-sm">
                    {Object.entries(amendment.changes).map(([key, value]) => (
                      <div key={key} className="flex items-center gap-2">
                        <span className="text-gray-600">{key}:</span>
                        <span className="font-medium">{String(value)}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Amendment Detail Modal */}
      {selectedAmendment && (
        <AmendmentDetailModal
          amendment={selectedAmendment}
          onClose={() => setSelectedAmendment(null)}
        />
      )}
    </div>
  );
}

// Dynamic Amendment Fields Component
function AmendmentFields({
  amendmentType,
  changes,
  onChange,
}: {
  amendmentType: string;
  changes: any;
  onChange: (changes: any) => void;
}) {
  const updateChange = (key: string, value: any) => {
    onChange({ ...changes, [key]: value });
  };

  switch (amendmentType) {
    case "RENT_CHANGE":
      return (
        <div className="space-y-3">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              New Rent Amount
            </label>
            <input
              type="number"
              step="0.01"
              className="w-full border border-gray-300 rounded-lg px-4 py-2"
              value={changes.rentAmount || ""}
              onChange={(e) =>
                updateChange("rentAmount", parseFloat(e.target.value))
              }
            />
          </div>
        </div>
      );

    case "TERM_EXTENSION":
      return (
        <div className="space-y-3">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              New End Date
            </label>
            <input
              type="date"
              className="w-full border border-gray-300 rounded-lg px-4 py-2"
              value={changes.endDate || ""}
              onChange={(e) => updateChange("endDate", e.target.value)}
            />
          </div>
        </div>
      );

    case "UTILITY_CHANGE":
      return (
        <div className="space-y-2">
          {[
            ["tenantPaysElectric", "Electricity"],
            ["tenantPaysWater", "Water"],
            ["tenantPaysTrash", "Trash"],
            ["tenantPaysInternet", "Internet"],
          ].map(([key, label]) => (
            <label key={key} className="flex items-center gap-2">
              <input
                type="checkbox"
                checked={changes[key] || false}
                onChange={(e) => updateChange(key, e.target.checked)}
              />
              <span className="text-sm">Tenant Pays {label}</span>
            </label>
          ))}
        </div>
      );

    case "DEPOSIT_CHANGE":
      return (
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            New Security Deposit
          </label>
          <input
            type="number"
            step="0.01"
            className="w-full border border-gray-300 rounded-lg px-4 py-2"
            value={changes.securityDeposit || ""}
            onChange={(e) =>
              updateChange("securityDeposit", parseFloat(e.target.value))
            }
          />
        </div>
      );

    default:
      return (
        <div className="bg-gray-50 border border-gray-200 rounded p-3">
          <p className="text-sm text-gray-600">
            Enter changes as JSON or specify them in the description above
          </p>
        </div>
      );
  }
}

// Amendment Detail Modal
function AmendmentDetailModal({
  amendment,
  onClose,
}: {
  amendment: Amendment;
  onClose: () => void;
}) {
  return (
    <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
        <div className="p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-2xl font-bold">Amendment Details</h2>
            <button
              onClick={onClose}
              className="p-2 hover:bg-gray-100 rounded-lg"
            >
              ✕
            </button>
          </div>

          <div className="space-y-4">
            <div>
              <p className="text-sm text-gray-500">Type</p>
              <p className="font-semibold">
                {amendment.amendmentType.replace(/_/g, " ")}
              </p>
            </div>

            <div>
              <p className="text-sm text-gray-500">Description</p>
              <p className="font-semibold">{amendment.description}</p>
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-sm text-gray-500">Effective Date</p>
                <p className="font-semibold">
                  {new Date(amendment.effectiveDate).toLocaleDateString()}
                </p>
              </div>
              <div>
                <p className="text-sm text-gray-500">Status</p>
                <p className="font-semibold">{amendment.status}</p>
              </div>
            </div>

            {amendment.previousValues &&
              Object.keys(amendment.previousValues).length > 0 && (
                <div>
                  <p className="text-sm text-gray-500 mb-2 flex items-center gap-2">
                    <History className="w-4 h-4" />
                    Previous Values
                  </p>
                  <div className="bg-gray-50 rounded p-3 space-y-1">
                    {Object.entries(amendment.previousValues).map(([key, value]) => (
                      <div key={key} className="flex justify-between text-sm">
                        <span className="text-gray-600">{key}:</span>
                        <span className="font-medium">{String(value)}</span>
                      </div>
                    ))}
                  </div>
                </div>
              )}

            {amendment.changes && Object.keys(amendment.changes).length > 0 && (
              <div>
                <p className="text-sm text-gray-500 mb-2">New Values</p>
                <div className="bg-blue-50 rounded p-3 space-y-1">
                  {Object.entries(amendment.changes).map(([key, value]) => (
                    <div key={key} className="flex justify-between text-sm">
                      <span className="text-gray-600">{key}:</span>
                      <span className="font-medium text-blue-600">
                        {String(value)}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="pt-4 border-t">
              <button
                onClick={onClose}
                className="w-full px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

// components/lease/DocumentManager.tsx
"use client";

import { useState, useEffect } from "react";
import {
  FileText,
  Upload,
  Download,
  Eye,
  Trash2,
  CheckCircle,
  Clock,
  AlertCircle,
} from "lucide-react";

interface LeaseDocument {
  id: string;
  documentType: string;
  fileName: string;
  fileUrl: string;
  fileSize: number;
  version: number;
  uploadedAt: string;
  isSigned: boolean;
  signedAt: string | null;
  description: string;
}

interface DocumentManagerProps {
  leaseId: string;
}

export default function DocumentManager({ leaseId }: DocumentManagerProps) {
  const [documents, setDocuments] = useState<LeaseDocument[]>([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [showUploadForm, setShowUploadForm] = useState(false);

  const [uploadForm, setUploadForm] = useState({
    file: null as File | null,
    documentType: "LEASE_AGREEMENT",
    description: "",
  });

  useEffect(() => {
    fetchDocuments();
  }, [leaseId]);

  async function fetchDocuments() {
    try {
      const res = await fetch(`/api/lease/${leaseId}/documents`);
      const data = await res.json();
      if (res.ok) {
        setDocuments(data);
      }
    } catch (error) {
      console.error("Failed to fetch documents:", error);
    } finally {
      setLoading(false);
    }
  }

  async function handleUpload() {
    if (!uploadForm.file) {
      alert("Please select a file");
      return;
    }

    setUploading(true);
    try {
      const formData = new FormData();
      formData.append("file", uploadForm.file);
      formData.append("documentType", uploadForm.documentType);
      formData.append("description", uploadForm.description);

      const res = await fetch(`/api/lease/${leaseId}/document`, {
        method: "POST",
        body: formData,
      });

      const data = await res.json();

      if (res.ok) {
        alert("Document uploaded successfully");
        setDocuments([...documents, data]);
        setShowUploadForm(false);
        setUploadForm({
          file: null,
          documentType: "LEASE_AGREEMENT",
          description: "",
        });
      } else {
        alert(data.error || "Upload failed");
      }
    } catch (error) {
      console.error("Upload error:", error);
      alert("An error occurred");
    } finally {
      setUploading(false);
    }
  }

  async function handleDelete(docId: string) {
    if (!confirm("Are you sure you want to delete this document?")) return;

    try {
      const res = await fetch(`/api/lease/${leaseId}/document/${docId}`, {
        method: "DELETE",
      });

      if (res.ok) {
        setDocuments(documents.filter((d) => d.id !== docId));
        alert("Document deleted");
      } else {
        alert("Failed to delete document");
      }
    } catch (error) {
      console.error("Delete error:", error);
      alert("An error occurred");
    }
  }

  const getDocumentTypeColor = (type: string) => {
    switch (type) {
      case "LEASE_AGREEMENT":
        return "bg-blue-100 text-blue-800";
      case "ADDENDUM":
        return "bg-purple-100 text-purple-800";
      case "AMENDMENT":
        return "bg-orange-100 text-orange-800";
      case "RENEWAL_NOTICE":
        return "bg-green-100 text-green-800";
      default:
        return "bg-gray-100 text-gray-800";
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return bytes + " B";
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + " KB";
    return (bytes / (1024 * 1024)).toFixed(1) + " MB";
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-8">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow p-6">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-semibold flex items-center gap-2">
          <FileText className="w-6 h-6 text-blue-600" />
          Documents
        </h2>
        <button
          onClick={() => setShowUploadForm(!showUploadForm)}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center gap-2"
        >
          <Upload className="w-4 h-4" />
          Upload
        </button>
      </div>

      {/* Upload Form */}
      {showUploadForm && (
        <div className="mb-6 p-4 border border-gray-200 rounded-lg bg-gray-50">
          <h3 className="font-semibold mb-3">Upload New Document</h3>

          <div className="space-y-3">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Document Type
              </label>
              <select
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                value={uploadForm.documentType}
                onChange={(e) =>
                  setUploadForm({ ...uploadForm, documentType: e.target.value })
                }
              >
                <option value="LEASE_AGREEMENT">Lease Agreement</option>
                <option value="ADDENDUM">Addendum</option>
                <option value="AMENDMENT">Amendment</option>
                <option value="RENEWAL_NOTICE">Renewal Notice</option>
                <option value="TERMINATION_NOTICE">Termination Notice</option>
                <option value="INSPECTION_REPORT">Inspection Report</option>
                <option value="PROOF_OF_INSURANCE">Proof of Insurance</option>
                <option value="OTHER">Other</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                File
              </label>
              <input
                type="file"
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                onChange={(e) =>
                  setUploadForm({
                    ...uploadForm,
                    file: e.target.files?.[0] || null,
                  })
                }
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Description (optional)
              </label>
              <input
                type="text"
                className="w-full border border-gray-300 rounded-lg px-4 py-2"
                placeholder="Brief description..."
                value={uploadForm.description}
                onChange={(e) =>
                  setUploadForm({ ...uploadForm, description: e.target.value })
                }
              />
            </div>

            <div className="flex gap-2">
              <button
                onClick={handleUpload}
                disabled={uploading || !uploadForm.file}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 ${
                  uploading || !uploadForm.file
                    ? "bg-gray-400 cursor-not-allowed"
                    : "bg-blue-600 hover:bg-blue-700"
                } text-white`}
              >
                <Upload className="w-4 h-4" />
                {uploading ? "Uploading..." : "Upload"}
              </button>
              <button
                onClick={() => setShowUploadForm(false)}
                className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Documents List */}
      {documents.length === 0 ? (
        <div className="text-center py-8">
          <FileText className="w-16 h-16 text-gray-300 mx-auto mb-4" />
          <p className="text-gray-500">No documents uploaded yet</p>
        </div>
      ) : (
        <div className="space-y-3">
          {documents.map((doc) => (
            <div
              key={doc.id}
              className="border border-gray-200 rounded-lg p-4 hover:bg-gray-50 transition-colors"
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <FileText className="w-5 h-5 text-gray-400" />
                    <div>
                      <p className="font-semibold text-gray-900">{doc.fileName}</p>
                      <div className="flex items-center gap-2 mt-1">
                        <span
                          className={`text-xs px-2 py-1 rounded-full font-medium ${getDocumentTypeColor(
                            doc.documentType
                          )}`}
                        >
                          {doc.documentType.replace("_", " ")}
                        </span>
                        <span className="text-xs text-gray-500">
                          v{doc.version}
                        </span>
                        <span className="text-xs text-gray-500">
                          {formatFileSize(doc.fileSize)}
                        </span>
                      </div>
                    </div>
                  </div>

                  {doc.description && (
                    <p className="text-sm text-gray-600 mb-2">{doc.description}</p>
                  )}

                  <div className="flex items-center gap-3 text-xs text-gray-500">
                    <span className="flex items-center gap-1">
                      <Clock className="w-3 h-3" />
                      {new Date(doc.uploadedAt).toLocaleDateString()}
                    </span>
                    {doc.isSigned ? (
                      <span className="flex items-center gap-1 text-green-500">
                        <CheckCircle className="w-3 h-3" />
                        Signed {doc.signedAt && `on ${new Date(doc.signedAt).toLocaleDateString()}`}
                      </span>
                    ) : (
                      <span className="flex items-center gap-1 text-gray-400">
                        <AlertCircle className="w-3 h-3" />
                        Unsigned
                      </span>
                    )}
                  </div>
                </div>

                {/* Actions */}
                <div className="flex items-center gap-2 ml-4">
                  <a
                    href={doc.fileUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                    title="View"
                  >
                    <Eye className="w-4 h-4" />
                  </a>
                  <a
                    href={doc.fileUrl}
                    download
                    className="p-2 text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                    title="Download"
                  >
                    <Download className="w-4 h-4" />
                  </a>
                  <button
                    onClick={() => handleDelete(doc.id)}
                    className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition-colors"
                    title="Delete"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Document Stats */}
      <div className="mt-6 pt-4 border-t border-gray-200">
        <div className="grid grid-cols-3 gap-4 text-center">
          <div>
            <p className="text-2xl font-bold text-gray-900">
              {documents.length}
            </p>
            <p className="text-xs text-gray-500">Total Documents</p>
          </div>
          <div>
            <p className="text-2xl font-bold text-green-500">
              {documents.filter((d) => d.isSigned).length}
            </p>
            <p className="text-xs text-gray-500">Signed</p>
          </div>
          <div>
            <p className="text-2xl font-bold text-gray-400">
              {documents.filter((d) => !d.isSigned).length}
            </p>
            <p className="text-xs text-gray-500">Unsigned</p>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface Invite {
  leaseId: string;
  id: string;
  token: string; 
  email: string;
  firstName?: string;
  lastName?: string;
  phone?: string;
  accepted: boolean;
  createdAt: string;
  
}

interface Lease {
  id: string;
  tenantId?: string | null;
  applicationId?: string | null;
  propertyId: string;
  unitId: string;
  startDate: string;
  endDate: string;
  rentAmount: number;
  leaseStatus: string;
  tenant?: {
    email?: string;
    firstName?: string;
    lastName?: string;
    phone?: string;
  } | null;
  application?: {
    id: string;
    fullName?: string;
    email?: string;
    phone?: string;
  } | null;
  property?: {
    id: string;
    address: string;
    city?: string;
  } | null;
  unit?: {
    id: string;
    unitNumber: string;
    unitName?: string;
  } | null;
}

export default function InvitesPage() {
  const [invites, setInvites] = useState<Invite[]>([]);
  const [filteredInvites, setFilteredInvites] = useState<Invite[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<"ALL" | "ACCEPTED" | "PENDING">("ALL");
  const [isOpen, setIsOpen] = useState(false);
  const [copiedToken, setCopiedToken] = useState<string | null>(null);

  // Form state
  const [email, setEmail] = useState("");
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [phone, setPhone] = useState("");
  const [selectedLeaseId, setSelectedLeaseId] = useState<string | null>(null);
  const [leases, setLeases] = useState<Lease[]>([]);
  const [loading, setLoading] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Fetch invites and leases
  useEffect(() => {
    const fetchData = async () => {
      setInitialLoading(true);
      setError(null);
      
      try {
        // Fetch invites
        const invitesRes = await fetch("/api/auth/invites/tenant");
        if (!invitesRes.ok) throw new Error("Failed to fetch invites");
        const invitesData = await invitesRes.json();
        setInvites(invitesData.invites || []);
        setFilteredInvites(invitesData.invites || []);

        // Fetch leases
        const leasesRes = await fetch("/api/lease");
        if (!leasesRes.ok) {
          const errorData = await leasesRes.json();
          throw new Error(errorData.error || "Failed to fetch leases");
        }
        const leasesData = await leasesRes.json();
        console.log("Leases API Response:", leasesData);
        
        // API returns array directly, not wrapped in {leases: [...]}
        const leasesArray = Array.isArray(leasesData) ? leasesData : (leasesData.leases || []);
        console.log("Leases Array:", leasesArray);
        console.log("First lease application:", leasesArray[0]?.application);
        
        setLeases(leasesArray);
      } catch (err) {
        console.error(err);
        setError(err instanceof Error ? err.message : "Failed to load data");
      } finally {
        setInitialLoading(false);
      }
    };

    fetchData();
  }, []);

  // Filter invites by search and status
  useEffect(() => {
    let filtered = invites;

    if (filterStatus !== "ALL") {
      filtered = filtered.filter(inv =>
        filterStatus === "ACCEPTED" ? inv.accepted : !inv.accepted
      );
    }

    if (searchTerm.trim() !== "") {
      filtered = filtered.filter(
        inv =>
          inv.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
          (inv.firstName?.toLowerCase().includes(searchTerm.toLowerCase()) ?? false) ||
          (inv.lastName?.toLowerCase().includes(searchTerm.toLowerCase()) ?? false)
      );
    }

    setFilteredInvites(filtered);
  }, [searchTerm, filterStatus, invites]);

  // Prefill form when lease is selected
  useEffect(() => {
    console.log("Selected Lease ID changed:", selectedLeaseId);
    
    if (selectedLeaseId) {
      const lease = leases.find(l => l.id === selectedLeaseId);
      console.log("Found lease:", lease);
      console.log("Lease application:", lease?.application);
      
      if (lease?.application) {
        // Split fullName into firstName and lastName
        const fullName = lease.application.fullName || "";
        const nameParts = fullName.trim().split(/\s+/);
        const fName = nameParts[0] || "";
        const lName = nameParts.slice(1).join(" ") || "";
        
        console.log("Prefilling with:", {
          email: lease.application.email,
          firstName: fName,
          lastName: lName,
          phone: lease.application.phone
        });
        
        setEmail(lease.application.email || "");
        setFirstName(fName);
        setLastName(lName);
        setPhone(lease.application.phone || "");
      } else {
        console.log("No application data found on lease");
        setEmail("");
        setFirstName("");
        setLastName("");
        setPhone("");
      }
    } else {
      console.log("No lease selected, clearing form");
      setEmail("");
      setFirstName("");
      setLastName("");
      setPhone("");
    }
  }, [selectedLeaseId, leases]);

  const validateForm = () => {
    if (!selectedLeaseId) {
      setError("Please select a lease");
      return false;
    }
    if (!email.trim()) {
      setError("Email is required");
      return false;
    }
    if (!firstName.trim()) {
      setError("First name is required");
      return false;
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      setError("Please enter a valid email address");
      return false;
    }
    return true;
  };

  const handleInvite = async () => {
    setError(null);
    setSuccessMessage(null);

    if (!validateForm()) {
      return;
    }

    setLoading(true);
    try {
      const res = await fetch("/api/auth/invites/tenant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ 
          email: email.trim(), 
          firstName: firstName.trim(), 
          lastName: lastName.trim(), 
          phone: phone.trim(), 
          leaseId: selectedLeaseId 
        }),
      });

      const data = await res.json();
      
      if (!res.ok) {
        throw new Error(data.error || "Failed to send invite");
      }

      setInvites(prev => [data.tenant, ...prev]);
      setSuccessMessage("Invite sent successfully!");
      setTimeout(() => setSuccessMessage(null), 3000);
      setIsOpen(false);
      resetForm();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to send invite");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setSelectedLeaseId(null);
    setEmail("");
    setFirstName("");
    setLastName("");
    setPhone("");
    setError(null);
  };

  const copyInviteLink = async (token: string, email: string, leaseId: string) => {
  const baseUrl = window.location.origin;

  const inviteLink = `${baseUrl}/invite/tenant/accept?email=${encodeURIComponent(
    email
  )}&token=${token}&leaseId=${leaseId}`;

      try {
        await navigator.clipboard.writeText(inviteLink);
        setCopiedToken(token);
        setTimeout(() => setCopiedToken(null), 2000);
      } catch (err) {
        console.error("Failed to copy link");
        setError("Failed to copy link to clipboard");
      }
    };


  if (initialLoading) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-[#0f172a] via-[#0a1628] to-[#0f172a] flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-[#30D5C8] mx-auto mb-4"></div>
          <p className="text-gray-400">Loading invites...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#0f172a] via-[#0a1628] to-[#0f172a] p-6">
      <div className="max-w-7xl mx-auto">
        {successMessage && (
          <div className="mb-4 bg-green-500/20 border border-green-500 text-green-400 p-4 rounded-lg flex items-center gap-2">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
            </svg>
            {successMessage}
          </div>
        )}

        {error && (
          <div className="mb-4 bg-red-500/20 border border-red-500 text-red-400 p-4 rounded-lg flex items-center justify-between gap-2">
            <div className="flex items-center gap-2">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              {error}
            </div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-red-300">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        )}

        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4 mb-8">
          <div>
            <h1 className="text-3xl font-bold text-white mb-2">Tenant Invites</h1>
            <p className="text-gray-400 text-sm">Manage and track your tenant invitations</p>
          </div>
          <button
            onClick={() => {
              setIsOpen(true);
              setError(null);
            }}
            className="bg-[#30D5C8] text-[#0f172a] px-6 py-3 rounded-lg font-semibold hover:bg-[#28bfb4] transition-all duration-200 shadow-lg hover:shadow-[#30D5C8]/20 flex items-center justify-center gap-2"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            New Invite
          </button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-6">
          <div className="bg-[#15386a]/30 backdrop-blur-sm border border-[#15386a] rounded-xl p-4">
            <p className="text-gray-400 text-sm mb-1">Total Invites</p>
            <p className="text-3xl font-bold text-white">{invites.length}</p>
          </div>
          <div className="bg-[#15386a]/30 backdrop-blur-sm border border-[#15386a] rounded-xl p-4">
            <p className="text-gray-400 text-sm mb-1">Pending</p>
            <p className="text-3xl font-bold text-yellow-400">{invites.filter(i => !i.accepted).length}</p>
          </div>
          <div className="bg-[#15386a]/30 backdrop-blur-sm border border-[#15386a] rounded-xl p-4">
            <p className="text-gray-400 text-sm mb-1">Accepted</p>
            <p className="text-3xl font-bold text-[#30D5C8]">{invites.filter(i => i.accepted).length}</p>
          </div>
        </div>

        <div className="bg-[#15386a]/30 backdrop-blur-sm border border-[#15386a] rounded-xl p-4 mb-6">
          <div className="flex flex-col sm:flex-row gap-4">
            <div className="flex-1">
              <input
                type="text"
                placeholder="Search by name or email..."
                className="w-full bg-[#0a1628] border border-[#15386a] text-white placeholder-gray-500 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8] focus:border-transparent"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
              />
            </div>
            <select
              className="bg-[#0a1628] border border-[#15386a] text-white p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8] focus:border-transparent min-w-[160px]"
              value={filterStatus}
              onChange={e => setFilterStatus(e.target.value as "ALL" | "ACCEPTED" | "PENDING")}
            >
              <option value="ALL">All Statuses</option>
              <option value="PENDING">Pending</option>
              <option value="ACCEPTED">Accepted</option>
            </select>
          </div>
        </div>

        <div className="bg-[#15386a]/30 backdrop-blur-sm border border-[#15386a] rounded-xl overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-[#15386a]/50">
                <tr>
                  <th className="text-left p-4 text-gray-300 font-semibold text-sm">Email</th>
                  <th className="text-left p-4 text-gray-300 font-semibold text-sm">Name</th>
                  <th className="text-left p-4 text-gray-300 font-semibold text-sm">Phone</th>
                  <th className="text-left p-4 text-gray-300 font-semibold text-sm">Status</th>
                  <th className="text-left p-4 text-gray-300 font-semibold text-sm">Created At</th>
                  <th className="text-left p-4 text-gray-300 font-semibold text-sm">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredInvites.map((inv) => (
                  <tr key={inv.id} className="border-t border-[#15386a]/50 hover:bg-[#15386a]/20 transition-colors">
                    <td className="p-4 text-gray-200">{inv.email}</td>
                    <td className="p-4 text-gray-200">{inv.firstName || inv.lastName ? `${inv.firstName ?? ""} ${inv.lastName ?? ""}`.trim() : "-"}</td>
                    <td className="p-4 text-gray-200">{inv.phone ?? "-"}</td>
                    <td className="p-4">
                      <span className={`px-3 py-1 rounded-full text-xs font-semibold ${inv.accepted ? "bg-[#30D5C8]/20 text-[#30D5C8]" : "bg-yellow-500/20 text-yellow-400"}`}>
                        {inv.accepted ? "Accepted" : "Pending"}
                      </span>
                    </td>
                    <td className="p-4 text-gray-400 text-sm">{new Date(inv.createdAt).toLocaleDateString('en-US', { year:'numeric', month:'short', day:'numeric', hour:'2-digit', minute:'2-digit' })}</td>
                    <td className="p-4">
                      {!inv.accepted && (
                        <button
                          onClick={() => copyInviteLink(inv.token, inv.email, inv.leaseId)}
                          className="flex items-center gap-2 bg-[#15386a] hover:bg-[#15386a]/80 text-[#30D5C8] px-3 py-2 rounded-lg transition-colors text-sm font-medium"
                          title="Copy invite link"
                        >
                          {copiedToken === inv.token ? (
                            <>
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                              </svg>
                              Copied!
                            </>
                          ) : (
                            <>
                              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                              </svg>
                              Copy Link
                            </>
                          )}
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
                {filteredInvites.length === 0 && (
                  <tr>
                    <td colSpan={6} className="text-center p-12">
                      <div className="flex flex-col items-center gap-2">
                        <svg className="w-12 h-12 text-gray-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 13V6a2 2 0 00-2-2H6a2 2 0 00-2 2v7m16 0v5a2 2 0 01-2 2H6a2 2 0 01-2-2v-5m16 0h-2.586a1 1 0 00-.707.293l-2.414 2.414a1 1 0 01-.707.293h-3.172a1 1 0 01-.707-.293l-2.414-2.414A1 1 0 006.586 13H4" />
                        </svg>
                        <p className="text-gray-400 text-lg">No invites found</p>
                        <p className="text-gray-500 text-sm">Try adjusting your filters or create a new invite</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <AlertDialog open={isOpen} onOpenChange={(open) => {
        setIsOpen(open);
        if (!open) resetForm();
      }}>
        <AlertDialogContent className="bg-[#0a1628] border-[#15386a] max-w-md">
          <AlertDialogHeader>
            <AlertDialogTitle className="text-2xl font-bold text-white mb-2">Invite New Tenant</AlertDialogTitle>
            <AlertDialogDescription className="text-gray-400">Send an invitation to a new tenant</AlertDialogDescription>
          </AlertDialogHeader>

          <div className="space-y-4 py-4">
            <div>
              <label className="block text-gray-300 text-sm font-medium mb-2">Select Lease *</label>
              <select
                value={selectedLeaseId || ""}
                onChange={(e) => setSelectedLeaseId(e.target.value || null)}
                className="w-full bg-[#15386a]/30 border border-[#15386a] text-white p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8]"
                disabled={loading}
              >
                <option value="">-- Select a lease ({leases.length} available) --</option>
                {leases.map(lease => {
                  const unitNum = lease.unit?.unitNumber || "N/A";
                  const unitName = lease.unit?.unitName || "";
                  const city = lease.property?.city || "";
                  const address = lease.property?.address || "No Address";
                  const fullAddress = city && address !== city ? `${address}, ${city}` : address;
                  const displayName = unitName ? `${unitNum} (${unitName})` : unitNum;
                  
                  return (
                    <option key={lease.id} value={lease.id}>
                      Unit {displayName} - {fullAddress}
                    </option>
                  );
                })}
              </select>
              {leases.length === 0 && (
                <p className="text-yellow-400 text-xs mt-2">No leases available. Please create a lease first.</p>
              )}
            </div>

            <div>
              <label className="block text-gray-300 text-sm font-medium mb-2">Email Address *</label>
              <input 
                type="email" 
                placeholder="tenant@example.com" 
                value={email} 
                onChange={e => setEmail(e.target.value)} 
                className="w-full bg-[#15386a]/30 border border-[#15386a] text-white placeholder-gray-500 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8]"
                disabled={loading}
              />
            </div>

            <div>
              <label className="block text-gray-300 text-sm font-medium mb-2">First Name *</label>
              <input 
                type="text" 
                placeholder="John" 
                value={firstName} 
                onChange={e => setFirstName(e.target.value)} 
                className="w-full bg-[#15386a]/30 border border-[#15386a] text-white placeholder-gray-500 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8]"
                disabled={loading}
              />
            </div>

            <div>
              <label className="block text-gray-300 text-sm font-medium mb-2">Last Name</label>
              <input 
                type="text" 
                placeholder="Doe" 
                value={lastName} 
                onChange={e => setLastName(e.target.value)} 
                className="w-full bg-[#15386a]/30 border border-[#15386a] text-white placeholder-gray-500 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8]"
                disabled={loading}
              />
            </div>

            <div>
              <label className="block text-gray-300 text-sm font-medium mb-2">Phone Number</label>
              <input 
                type="text" 
                placeholder="+1 (555) 000-0000" 
                value={phone} 
                onChange={e => setPhone(e.target.value)} 
                className="w-full bg-[#15386a]/30 border border-[#15386a] text-white placeholder-gray-500 p-3 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#30D5C8]"
                disabled={loading}
              />
            </div>
          </div>

          <AlertDialogFooter className="gap-3">
            <AlertDialogCancel 
              className="bg-[#15386a]/50 text-gray-300 hover:bg-[#15386a] border-none"
              disabled={loading}
            >
              Cancel
            </AlertDialogCancel>
            <AlertDialogAction 
              onClick={handleInvite} 
              disabled={loading} 
              className="bg-[#30D5C8] text-[#0f172a] hover:bg-[#28bfb4]"
            >
              {loading ? "Sending..." : "Send Invite"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
  User, Home, FileText, Mail, DollarSign, Calendar,
  Phone, Search, Eye, Download, Check, X,
  AlertCircle, Plus, ExternalLink, TrendingUp,
  Clock, CheckCircle, AlertTriangle, Edit,
  RefreshCw // Added for resend icon
} from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
} from "@/components/ui/dropdown-menu";
import { TenantApplication } from "../../type";

// Types
interface Tenant {
  id: string;
  firstName?: string | null;
  lastName?: string | null;
  email: string;
  phone?: string | null;
}

interface Property {
  id: string;
  name: string;
  city?: string;
  address?: string;
}

interface Unit {
  id: string;
  unitNumber: string;
  unitName?: string;
  rentAmount?: number;
}

interface FinancialSummary {
  totalInvoiced: number;
  totalPaid: number;
  balance: number;
  lastPaymentDate?: string;
}

interface Payment {
  id: string;
  amount: number;
  isReversed: boolean;
  // Add other payment properties as needed
}

interface Invoice {
  id: string;
  amount: number;
  payment?: Payment[];
  // Add other invoice properties as needed
}

interface Lease {
  invoice?: Invoice[];
  id: string;
  tenant?: Tenant;
  property?: Property;
  unit?: Unit;
  startDate: string;
  endDate: string;
  rentAmount: number;
  securityDeposit?: number | null;
  leaseStatus: string;
  financialSummary?: FinancialSummary;
  application?: {
    id: string;
    fullName?: string;
    email?: string;
    phone?: string;
  } | null;
}

interface Application {
  id: string;
  fullName: string;
  email: string;
  phone: string;
  status: string;
  property?: Property;
  unit?: Unit;
  moveInDate: string;
  createdAt: string;
  employerName?: string;
  jobTitle?: string;
  monthlyIncome?: number;
  address?: string;
  dob?: string;
}

interface Invite {
  id: string;
  email: string;
  firstName?: string;
  lastName?: string;
  phone?: string;
  accepted: boolean;
  createdAt: string;
  leaseId: string;
  token: string;
}

export default function EnhancedTenantDashboard() {
  const [activeTab, setActiveTab] = useState<"tenants" | "applications" | "invites">("tenants");
  const [tenants, setTenants] = useState<Tenant[]>([]);

  // Data states
  const [leases, setLeases] = useState<Lease[]>([]);
  const [applications, setApplications] = useState<Application[]>([]);
  const [invites, setInvites] = useState<Invite[]>([]);

  // UI states
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("ALL");
  const [copiedToken, setCopiedToken] = useState<string | null>(null);
  const [resendingInviteId, setResendingInviteId] = useState<string | null>(null);
  const [selectedApplication, setSelectedApplication] = useState<Application | null>(null);
  const [showDetailModal, setShowDetailModal] = useState(false);
  const [showInviteModal, setShowInviteModal] = useState(false);

  // Invite form state
  const [inviteEmail, setInviteEmail] = useState("");
  const [inviteFirstName, setInviteFirstName] = useState("");
  const [inviteLastName, setInviteLastName] = useState("");
  const [invitePhone, setInvitePhone] = useState("");
  const [selectedLeaseId, setSelectedLeaseId] = useState<string | null>(null);
  const [inviteSending, setInviteSending] = useState(false);
  const [inviteError, setInviteError] = useState<string | null>(null);
  const [inviteSuccess, setInviteSuccess] = useState<string | null>(null);
  const [showModal, setShowModal] = useState(false);
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [selectedTenant, setSelectedTenant] = useState<Tenant | null>(null);
  const [formData, setFormData] = useState({
    firstName: selectedTenant?.firstName || "",
    lastName: selectedTenant?.lastName || "",
    email: selectedTenant?.email || "",
    phone: selectedTenant?.phone || "",
  });

  const [isSaving, setIsSaving] = useState(false);

  // Fetch all data
  useEffect(() => {
    async function fetchAllData() {
      setLoading(true);
      try {
        const [leasesRes, appsRes, invitesRes] = await Promise.all([
          fetch("/api/lease"),
          fetch("/api/tenant-application"),
          fetch("/api/auth/invites/tenant")
        ]);

        const [leasesData, appsData, invitesData] = await Promise.all([
          leasesRes.json(),
          appsRes.json(),
          invitesRes.json()
        ]);

        setLeases(Array.isArray(leasesData) ? leasesData : []);
        setApplications(Array.isArray(appsData) ? appsData : []);
        setInvites(invitesData.invites || []);
      } catch (error) {
        console.error("Error fetching data:", error);
      } finally {
        setLoading(false);
      }
    }

    fetchAllData();
  }, []);

  // Prefill form when lease is selected for invite
  useEffect(() => {
    if (selectedLeaseId) {
      const lease = leases.find(l => l.id === selectedLeaseId);

      if (lease?.application) {
        const fullName = lease.application.fullName || "";
        const nameParts = fullName.trim().split(/\s+/);
        const fName = nameParts[0] || "";
        const lName = nameParts.slice(1).join(" ") || "";

        setInviteEmail(lease.application.email || "");
        setInviteFirstName(fName);
        setInviteLastName(lName);
        setInvitePhone(lease.application.phone || "");
      } else {
        setInviteEmail("");
        setInviteFirstName("");
        setInviteLastName("");
        setInvitePhone("");
      }
    } else {
      setInviteEmail("");
      setInviteFirstName("");
      setInviteLastName("");
      setInvitePhone("");
    }
  }, [selectedLeaseId, leases]);

  // Full name helper
  const getTenantName = (tenant?: Tenant) => {
    if (!tenant) return "Unnamed Tenant";
    const full = [tenant.firstName, tenant.lastName].filter(Boolean).join(" ");
    return full || tenant.email || "Unnamed Tenant";
  };
  // Filter functions
  const filteredLeases = leases.filter((lease) => {
    const name = getTenantName(lease.tenant).toLowerCase();
    const email = lease.tenant?.email?.toLowerCase() || "";
    const property = lease.property?.name?.toLowerCase() || "";
    const unit = lease.unit?.unitNumber?.toLowerCase() || "";

    const matchesSearch =
      name.includes(searchTerm.toLowerCase()) ||
      email.includes(searchTerm.toLowerCase()) ||
      property.includes(searchTerm.toLowerCase()) ||
      unit.includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === "ALL" || lease.leaseStatus === statusFilter;
    return matchesSearch && matchesStatus;
  });

  const filteredApplications = applications.filter((app) => {
    const matchesSearch =
      app.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      app.email.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus = statusFilter === "ALL" || app.status === statusFilter;
    return matchesSearch && matchesStatus;
  });



  // Handle input changes
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };


  const openEditModal = (tenant?: Tenant) => {
    if (!tenant) return;

    setSelectedTenant(tenant);

    setFormData({
      firstName: tenant.firstName || "",
      lastName: tenant.lastName || "",
      email: tenant.email || "",
      phone: tenant.phone || "",
    });

    setIsEditModalOpen(true);
  };



  // Submit edited tenant details
  const handleSave = async () => {
    if (!selectedTenant) return;

    setIsSaving(true);
    try {
      const res = await fetch(`/api/tenants/${selectedTenant.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (!res.ok) throw new Error("Failed to update tenant");

      setIsEditModalOpen(false);
    } catch (err) {
      console.error(err);
      alert("Failed to update tenant");
    } finally {
      setIsSaving(false);
    }
  };


  // Handle Approve
  async function handleApprove(appId: string) {
    try {
      const res = await fetch(`/api/tenant-application/${appId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status: "APPROVED" }),
      });

      if (res.ok) {
        setApplications((prev) =>
          prev.map((app) => (app.id === appId ? { ...app, status: "Approved" } : app))
        );
        setShowModal(false);
        alert("Application approved! You can now proceed to lease signing.");
      }
    } catch (err) {
      console.error("Error approving application:", err);
      alert("Failed to approve application");
    }
  }

  // Handle Reject
  async function handleReject(appId: string) {
    try {
      const res = await fetch(`/api/tenant-application/${appId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status: "REJECTED" }),
      });

      if (res.ok) {
        setApplications((prev) =>
          prev.map((app) => (app.id === appId ? { ...app, status: "Rejected" } : app))
        );
        setShowModal(false);
      }
    } catch (err) {
      console.error("Error rejecting application:", err);
      alert("Failed to reject application");
    }
  }


  function proceedToLease(app: TenantApplication) {
    // Navigate to lease signing page with application data
    const userId = app.id || app.id;
    window.location.href = `/property-manager/content/lease/create?applicationId=${app.id}&tenantId=${userId}`;
  }


  const filteredInvites = invites.filter((invite) => {
    const matchesSearch =
      invite.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
      invite.firstName?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesStatus =
      statusFilter === "ALL" ||
      (statusFilter === "ACCEPTED" && invite.accepted) ||
      (statusFilter === "PENDING" && !invite.accepted);
    return matchesSearch && matchesStatus;
  });

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric'
    });
  };

  const getStatusColor = (status: string) => {
    switch (status.toUpperCase()) {
      case "SIGNED":
      case "APPROVED":
      case "PAID":
        return "bg-green-100 text-green-700 border-navy-200";
      case "PENDING":
        return "bg-amber-100 text-amber-700 border-amber-200";
      case "DRAFT":
      case "REJECTED":
        return "bg-slate-100 text-slate-700 border-slate-200";
      case "OVERDUE":
        return "bg-red-100 text-red-700 border-red-200";
      default:
        return "bg-gray-100 text-gray-700 border-gray-200";
    }
  };

  const copyInviteLink = async (token: string, email: string, leaseId: string) => {
    const baseUrl = window.location.origin;
    const inviteLink = `${baseUrl}/invite/tenant/accept?email=${encodeURIComponent(email)}&token=${token}&leaseId=${leaseId}`;

    try {
      await navigator.clipboard.writeText(inviteLink);
      setCopiedToken(token);
      setTimeout(() => setCopiedToken(null), 2000);
    } catch (err) {
      console.error("Failed to copy link");
    }
  };

  // Resend invite function
  const handleResendInvite = async (inviteId: string) => {
    setResendingInviteId(inviteId);
    try {
      const res = await fetch(`/api/auth/invites/tenant/${inviteId}/resend`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || "Failed to resend invite");
      }

      alert("Invite resent successfully!");
    } catch (err) {
      console.error("Error resending invite:", err);
      alert(err instanceof Error ? err.message : "Failed to resend invite");
    } finally {
      setResendingInviteId(null);
    }
  };

  const validateInviteForm = () => {
    if (!selectedLeaseId) {
      setInviteError("Please select a lease");
      return false;
    }
    if (!inviteEmail.trim()) {
      setInviteError("Email is required");
      return false;
    }
    if (!inviteFirstName.trim()) {
      setInviteError("First name is required");
      return false;
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(inviteEmail)) {
      setInviteError("Please enter a valid email address");
      return false;
    }
    return true;
  };

  const handleSendInvite = async () => {
    setInviteError(null);
    setInviteSuccess(null);

    if (!validateInviteForm()) {
      return;
    }

    setInviteSending(true);
    try {
      const res = await fetch("/api/auth/invites/tenant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: inviteEmail.trim(),
          firstName: inviteFirstName.trim(),
          lastName: inviteLastName.trim(),
          phone: invitePhone.trim(),
          leaseId: selectedLeaseId
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || "Failed to send invite");
      }

      setInvites(prev => [data.tenant, ...prev]);
      setInviteSuccess("Invite sent successfully!");
      setTimeout(() => {
        setInviteSuccess(null);
        setShowInviteModal(false);
        resetInviteForm();
      }, 2000);
    } catch (err) {
      setInviteError(err instanceof Error ? err.message : "Failed to send invite");
    } finally {
      setInviteSending(false);
    }
  };

  const resetInviteForm = () => {
    setSelectedLeaseId(null);
    setInviteEmail("");
    setInviteFirstName("");
    setInviteLastName("");
    setInvitePhone("");
    setInviteError(null);
  };

  const exportToCSV = () => {
    let data: (string | number)[][] = [];
    let headers: string[] = [];
    let filename = "";

    if (activeTab === "tenants") {
      headers = ["Tenant Name", "Email", "Phone", "Property", "Unit", "Rent Amount", "Start Date", "End Date", "Status", "Balance"];
      data = filteredLeases.map(lease => [
        getTenantName(lease.tenant),
        lease.tenant?.email || "N/A",
        lease.tenant?.phone || "N/A",
        lease.property?.name || lease.property?.city || "N/A",
        lease.unit?.unitNumber || "N/A",
        lease.rentAmount || "N/A",
        formatDate(lease.startDate),
        formatDate(lease.endDate),
        lease.leaseStatus,
        lease.financialSummary?.balance || "N/A"
      ]);
      filename = "tenants";
    } else if (activeTab === "applications") {
      headers = ["Full Name", "Email", "Phone", "Property", "Unit", "Move-in Date", "Status", "Monthly Income", "Submitted"];
      data = filteredApplications.map(app => [
        app.fullName,
        app.email,
        app.phone,
        app.property?.name || app.property?.city || "N/A",
        app.unit?.unitNumber || "N/A",
        formatDate(app.moveInDate),
        app.status,
        app.monthlyIncome || "N/A",
        formatDate(app.createdAt)
      ]);
      filename = "applications";
    } else {
      headers = ["Email", "Name", "Phone", "Status", "Created At"];
      data = filteredInvites.map(invite => [
        invite.email,
        `${invite.firstName || ""} ${invite.lastName || ""}`.trim() || "N/A",
        invite.phone || "N/A",
        invite.accepted ? "Accepted" : "Pending",
        formatDate(invite.createdAt)
      ]);
      filename = "invites";
    }

    const csvContent = [
      headers.join(","),
      ...data.map((row: (string | number)[]) => row.map((cell: string | number) => `"${cell}"`).join(","))
    ].join("\n");

    const blob = new Blob([csvContent], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${filename}-${new Date().toISOString().split("T")[0]}.csv`;
    a.click();
    window.URL.revokeObjectURL(url);
  };

  // Statistics
  const stats = leases.reduce(
    (acc, lease) => {
      acc.totalTenants = leases.length;
      if (lease.leaseStatus === "SIGNED") acc.activeLeases++;

      // Sum invoiced across all invoices
      const totalInvoiced = lease.invoice?.reduce((sum: number, inv: Invoice) => sum + (inv.amount || 0), 0) || 0;

      // Sum paid ignoring reversed payments
      const totalPaid = lease.invoice?.reduce((sum: number, inv: Invoice) => {
        const paid = inv.payment?.filter(p => !p.isReversed).reduce((pSum: number, p: Payment) => pSum + (p.amount || 0), 0) || 0;
        return sum + paid;
      }, 0) || 0;

      const balance = totalInvoiced - totalPaid;

      acc.totalRevenue += totalInvoiced;
      acc.totalPaid += totalPaid;
      acc.totalBalance += balance;

      return acc;
    },
    {
      totalTenants: 0,
      activeLeases: 0,
      totalRevenue: 0,
      totalPaid: 0,
      totalBalance: 0,
      pendingApplications: applications.filter(a => a.status.toLowerCase() === "pending").length,
      pendingInvites: invites.filter(i => !i.accepted).length,
    }
  );



  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-slate-50 to-slate-100">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-4 border-slate-200 border-t-blue-600 mx-auto mb-4"></div>
          <p className="text-slate-600 text-lg font-medium">Loading dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 p-6">
      <div className="max-w-7xl mx-auto space-y-6">
        {/* Header */}
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
          <div className="flex justify-between items-start">
            <div>
              <h1 className="text-3xl font-bold text-slate-900">Tenant Management</h1>
              <p className="text-slate-600 mt-1">Manage tenants, applications, invitations & payments</p>
            </div>
            <button
              onClick={() => setShowInviteModal(true)}
              className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
            >
              <Plus className="w-4 h-4" />
              New Invite
            </button>
          </div>
        </div>

        {/* Statistics Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5">
            <div className="flex items-center gap-3">
              <div className="bg-blue-100 p-3 rounded-lg">
                <User className="w-6 h-6 text-blue-600" />
              </div>
              <div>
                <p className="text-sm text-slate-600">Total Tenants</p>
                <p className="text-2xl font-bold text-slate-900">{stats.totalTenants}</p>
                <p className="text-xs text-slate-500">{stats.activeLeases} active</p>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5">
            <div className="flex items-center gap-3">
              <div className="bg-green-100 p-3 rounded-lg">
                <DollarSign className="w-6 h-6 text-green-500" />
              </div>
              <div>
                <p className="text-sm text-slate-600">Revenue</p>
                <p className="text-2xl font-bold text-green-500">$ {(stats.totalRevenue / 1000).toFixed(0)}k</p>
                <p className="text-xs text-slate-500">Paid: $ {(stats.totalPaid / 1000).toFixed(0)}k</p>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5">
            <div className="flex items-center gap-3">
              <div className="bg-amber-100 p-3 rounded-lg">
                <AlertCircle className="w-6 h-6 text-amber-600" />
              </div>
              <div>
                <p className="text-sm text-slate-600">Pending Items</p>
                <p className="text-2xl font-bold text-amber-600">{stats.pendingApplications + stats.pendingInvites}</p>
                <p className="text-xs text-slate-500">Applications & Invites</p>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5">
            <div className="flex items-center gap-3">
              <div className="bg-red-100 p-3 rounded-lg">
                <TrendingUp className="w-6 h-6 text-red-600" />
              </div>
              <div>
                <p className="text-sm text-slate-600">Outstanding Balance</p>
                <p className="text-2xl font-bold text-red-600">$ {(stats.totalBalance / 1000).toFixed(0)}k</p>
                <p className="text-xs text-slate-500">Total pending</p>
              </div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-2">
          <div className="flex gap-2">
            <button
              onClick={() => {
                setActiveTab("tenants");
                setSearchTerm("");
                setStatusFilter("ALL");
              }}
              className={`flex-1 px-4 py-3 rounded-lg font-medium transition-colors ${activeTab === "tenants"
                ? "bg-blue-600 text-white"
                : "text-slate-600 hover:bg-slate-100"
                }`}
            >
              Active Tenants ({stats.totalTenants})
            </button>
            <button
              onClick={() => {
                setActiveTab("applications");
                setSearchTerm("");
                setStatusFilter("ALL");
              }}
              className={`flex-1 px-4 py-3 rounded-lg font-medium transition-colors ${activeTab === "applications"
                ? "bg-blue-600 text-white"
                : "text-slate-600 hover:bg-slate-100"
                }`}
            >
              Applications ({applications.length})
            </button>
            <button
              onClick={() => {
                setActiveTab("invites");
                setSearchTerm("");
                setStatusFilter("ALL");
              }}
              className={`flex-1 px-4 py-3 rounded-lg font-medium transition-colors ${activeTab === "invites"
                ? "bg-blue-600 text-white"
                : "text-slate-600 hover:bg-slate-100"
                }`}
            >
              Invites ({invites.length})
            </button>
          </div>
        </div>

        {/* Search, Filters, and Export */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-4">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1 relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="text"
                placeholder="Search by name or email..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
              />
            </div>
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="px-4 py-2.5 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none bg-white"
            >
              <option value="ALL">All Status</option>
              {activeTab === "tenants" && (
                <>
                  <option value="SIGNED">Active</option>
                  <option value="PENDING">Pending</option>
                  <option value="DRAFT">Draft</option>
                </>
              )}
              {activeTab === "applications" && (
                <>
                  <option value="PENDING">Pending</option>
                  <option value="APPROVED">Approved</option>
                  <option value="REJECTED">Rejected</option>
                </>
              )}
              {activeTab === "invites" && (
                <>
                  <option value="PENDING">Pending</option>
                  <option value="ACCEPTED">Accepted</option>
                </>
              )}
            </select>
            <button
              onClick={exportToCSV}
              className="flex items-center gap-2 bg-green-500 text-white px-4 py-2.5 rounded-lg hover:bg-green-600 transition-colors"
            >
              <Download className="w-4 h-4" />
              Export CSV
            </button>
          </div>
        </div>

        {/* Content Area - Tables */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          {/* Active Tenants Table */}
          {activeTab === "tenants" && (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Tenant</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Property & Unit</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Monthly Rent</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredLeases.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="px-6 py-12 text-center">
                        <FileText className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                        <p className="text-slate-600">No tenants found</p>
                      </td>
                    </tr>
                  ) : (
                    filteredLeases.map((lease) => (
                      <tr key={lease.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="bg-blue-100 p-2 rounded-lg">
                              <User className="w-5 h-5 text-blue-600" />
                            </div>
                            <div>
                              <p className="font-semibold text-slate-900">
                                {getTenantName(lease.tenant)}
                              </p>                              <p className="text-sm text-slate-500">{lease.tenant?.email}</p>
                              {lease.tenant?.phone && (
                                <p className="text-sm text-slate-500">{lease.tenant?.phone}</p>
                              )}
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <p className="font-medium text-slate-900">{lease.property?.name || lease.property?.city}</p>
                          <p className="text-sm text-slate-500">Unit {lease.unit?.unitNumber}</p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="font-semibold text-slate-900">$ {lease.rentAmount?.toLocaleString()}</p>
                          <p className="text-xs text-slate-500">/month</p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="space-y-1 text-sm">
                            {(() => {
                              // Calculate adjusted totals considering reversed payments
                              const totalInvoiced = lease.invoice?.reduce((sum: number, inv: Invoice) => sum + (inv.amount || 0), 0) || 0;
                              const totalPaid = lease.invoice?.reduce((sum: number, inv: Invoice) => {
                                const paid = inv.payment?.filter(p => !p.isReversed).reduce((pSum: number, p: Payment) => pSum + (p.amount || 0), 0) || 0;
                                return sum + paid;
                              }, 0) || 0;
                              const balance = totalInvoiced - totalPaid;

                              return (
                                <>
                                  <div className="flex justify-between">
                                    <span className="text-slate-600">Invoiced:</span>
                                    <span className="font-semibold text-slate-900">
                                      $ {totalInvoiced.toLocaleString()}
                                    </span>
                                  </div>

                                  <div className="flex justify-between">
                                    <span className="text-slate-600">Paid:</span>
                                    <span className="font-semibold text-green-500">
                                      $ {totalPaid.toLocaleString()}
                                    </span>
                                  </div>

                                  <div className="flex justify-between">
                                    <span className="text-slate-600">Balance:</span>
                                    <span className={`font-semibold ${balance > 0 ? "text-red-600" : "text-green-500"}`}>
                                      $ {balance.toLocaleString()}
                                    </span>
                                  </div>
                                </>
                              );
                            })()}
                          </div>
                        </td>


                        <td className="px-6 py-4">
                          <span className={`inline-flex px-3 py-1 rounded-full text-xs font-semibold border ${getStatusColor(lease.leaseStatus)}`}>
                            {lease.leaseStatus}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <button className="inline-flex justify-center w-full rounded-lg bg-gray-200 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500">
                                Actions
                              </button>
                            </DropdownMenuTrigger>

                            <DropdownMenuContent align="end" className="w-48 bg-white shadow-lg rounded-md border border-slate-200">
                              <DropdownMenuItem
                                onClick={() => window.location.href = `/property-manager/content/lease/${lease.id}`}
                                className="flex items-center gap-2"
                              >
                                <Eye className="w-4 h-4" /> View Lease
                              </DropdownMenuItem>

                              <DropdownMenuItem
                                onClick={() => window.location.href = `/property-manager/content/tenants/${lease.tenant?.id}`}
                                className="flex items-center gap-2"
                              >
                                <DollarSign className="w-4 h-4" /> Finance
                              </DropdownMenuItem>

                              <DropdownMenuItem
                                onClick={() => lease.tenant && openEditModal(lease.tenant)}
                                className="flex items-center gap-2"
                              >
                                <Edit className="w-4 h-4" /> Edit Tenant
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>

                        </td>

                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          )}

          {/* Applications Table */}
          {activeTab === "applications" && (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Applicant</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Property & Unit</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Employment</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Move-in Date</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredApplications.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="px-6 py-12 text-center">
                        <FileText className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                        <p className="text-slate-600">No applications found</p>
                      </td>
                    </tr>
                  ) : (
                    filteredApplications.map((app) => (
                      <tr key={app.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="bg-amber-100 p-2 rounded-lg">
                              <FileText className="w-5 h-5 text-amber-600" />
                            </div>
                            <div>
                              <p className="font-semibold text-slate-900">{app.fullName}</p>
                              <p className="text-sm text-slate-500">{app.email}</p>
                              <p className="text-sm text-slate-500">{app.phone}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <p className="font-medium text-slate-900">{app.property?.name || app.property?.city}</p>
                          <p className="text-sm text-slate-500">Unit {app.unit?.unitNumber}</p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="space-y-1">
                            <p className="text-sm font-medium text-slate-900">{app.jobTitle || "N/A"}</p>
                            <p className="text-xs text-slate-500">{app.employerName || "N/A"}</p>
                            <p className="text-xs text-slate-600">$ {(app.monthlyIncome || 0).toLocaleString()}</p>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-700">{formatDate(app.moveInDate)}</p>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`inline-flex px-3 py-1 rounded-full text-xs font-semibold border ${getStatusColor(app.status)}`}>
                            {app.status}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <button
                            onClick={() => {
                              setSelectedApplication(app);
                              setShowDetailModal(true);
                            }}
                            className="flex items-center gap-2 bg-blue-600 text-white px-3 py-1.5 rounded-lg hover:bg-blue-700 transition-colors text-sm"
                          >
                            <Eye className="w-4 h-4" />
                            Review
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          )}

          {/* Invites Table */}
          {activeTab === "invites" && (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-slate-50 border-b border-slate-200">
                  <tr>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Email</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Name</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Phone</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Status</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Created</th>
                    <th className="px-6 py-4 text-left text-xs font-semibold text-slate-600 uppercase tracking-wider">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {filteredInvites.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="px-6 py-12 text-center">
                        <Mail className="w-12 h-12 text-slate-300 mx-auto mb-3" />
                        <p className="text-slate-600">No invites found</p>
                      </td>
                    </tr>
                  ) : (
                    filteredInvites.map((invite) => (
                      <tr key={invite.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <div className="bg-purple-100 p-2 rounded-lg">
                              <Mail className="w-5 h-5 text-purple-600" />
                            </div>
                            <p className="font-medium text-slate-900">{invite.email}</p>
                          </div>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-700">
                            {invite.firstName || invite.lastName
                              ? `${invite.firstName || ""} ${invite.lastName || ""}`.trim()
                              : "N/A"}
                          </p>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-700">{invite.phone || "N/A"}</p>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`inline-flex px-3 py-1 rounded-full text-xs font-semibold border ${invite.accepted ? getStatusColor("APPROVED") : getStatusColor("PENDING")}`}>
                            {invite.accepted ? "Accepted" : "Pending"}
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <p className="text-sm text-slate-500">{formatDate(invite.createdAt)}</p>
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex gap-2">
                            {!invite.accepted && (
                              <>
                                <button
                                  disabled={!invite?.leaseId}
                                  onClick={() =>
                                    copyInviteLink(
                                      invite.token,
                                      invite.email,
                                      invite.leaseId // safe now
                                    )
                                  }
                                  className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm transition-colors
                                  ${!invite?.leaseId
                                      ? "bg-gray-400 cursor-not-allowed"
                                      : "bg-blue-600 text-white hover:bg-blue-700"}
                                `}
                                >
                                  {copiedToken === invite.token ? (
                                    <>
                                      <Check className="w-4 h-4" />
                                      Copied!
                                    </>
                                  ) : (
                                    <>
                                      <ExternalLink className="w-4 h-4" />
                                      Copy Link
                                    </>
                                  )}
                                </button>
                                <button
                                  onClick={() => handleResendInvite(invite.id)}
                                  disabled={resendingInviteId === invite.id || !invite?.leaseId}
                                  className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm transition-colors
                                  ${!invite?.leaseId || resendingInviteId === invite.id
                                      ? "bg-gray-400 cursor-not-allowed"
                                      : "bg-amber-600 text-white hover:bg-amber-700"}
                                `}
                                >
                                  <RefreshCw className={`w-4 h-4 ${resendingInviteId === invite.id ? "animate-spin" : ""}`} />
                                  {resendingInviteId === invite.id ? "Sending..." : "Resend"}
                                </button>
                              </>
                            )}
                          </div>
                        </td>

                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {/* Edit Tenant Modal */}
        {isEditModalOpen && selectedTenant && (
          <div className="fixed inset-0 bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white p-8 rounded-xl w-full max-w-md shadow-2xl border border-gray-200">

              {/* Header */}
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Edit Tenant</h2>
                <button
                  onClick={() => setIsEditModalOpen(false)}
                  className="text-gray-400 hover:text-gray-600 text-2xl"
                  disabled={isSaving}
                >
                  ✕
                </button>
              </div>

              {/* Form */}
              <div className="space-y-4">
                {/* First Name */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">
                    First Name
                  </label>
                  <input
                    type="text"
                    name="firstName"
                    placeholder="Enter first name"
                    value={formData.firstName}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all hover:border-gray-400"
                    disabled={isSaving}
                  />
                </div>

                {/* Last Name */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">
                    Last Name
                  </label>
                  <input
                    type="text"
                    name="lastName"
                    placeholder="Enter last name"
                    value={formData.lastName}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all hover:border-gray-400"
                    disabled={isSaving}
                  />
                </div>

                {/* Email */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">
                    Email
                  </label>
                  <input
                    type="email"
                    name="email"
                    placeholder="Enter email"
                    value={formData.email}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all hover:border-gray-400"
                    disabled={isSaving}
                  />
                </div>

                {/* Phone */}
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">
                    Phone
                  </label>
                  <input
                    type="text"
                    name="phone"
                    placeholder="Enter phone number"
                    value={formData.phone}
                    onChange={handleChange}
                    className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all hover:border-gray-400"
                    disabled={isSaving}
                  />
                </div>
              </div>

              {/* Actions */}
              <div className="flex justify-end gap-3 mt-8 pt-6 border-t border-gray-200">
                <button
                  onClick={() => setIsEditModalOpen(false)}
                  className="px-5 py-2.5 bg-gray-100 text-gray-700 font-medium rounded-lg hover:bg-gray-200 transition-colors disabled:opacity-50"
                  disabled={isSaving}
                >
                  Cancel
                </button>
                <button
                  onClick={handleSave}
                  className="px-5 py-2.5 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 flex items-center gap-2"
                  disabled={isSaving}
                >
                  {isSaving ? "Saving..." : "Save Changes"}
                </button>
              </div>
            </div>
          </div>
        )}


        {/* Invite Modal */}
        {showInviteModal && (
          <div className="fixed inset-0  bg-opacity-50 flex items-start justify-center z-50 p-4 overflow-auto ">
            <div className="bg-white rounded-lg shadow-lg rounded-2xl max-w-md w-full">
              {/* Modal Header */}
              <div className="border-b bg-blue-700 border-slate-200 p-6">
                <h2 className="text-2xl font-bold text-slate-100">Invite New Tenant</h2>
                <p className="text-slate-100 mt-1">Send an invitation to a new tenant</p>
              </div>

              {/* Error Message */}
              {inviteError && (
                <div className="mx-6 mt-6 bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg flex items-start gap-3">
                  <AlertCircle className="w-5 h-5 flex-shrink-0 mt-0.5" />
                  <div className="flex-1">
                    <p className="font-medium text-sm">{inviteError}</p>
                  </div>
                  <button
                    onClick={() => setInviteError(null)}
                    className="text-red-500 hover:text-red-700 flex-shrink-0"
                  >
                    <X className="w-4 h-4" />
                  </button>
                </div>
              )}

              {/* Success Message */}
              {inviteSuccess && (
                <div className="mx-6 mt-6 bg-green-50 border border-navy-200 text-green-700 p-4 rounded-lg flex items-start gap-3">
                  <CheckCircle className="w-5 h-5 flex-shrink-0 mt-0.5" />
                  <p className="font-medium text-sm">{inviteSuccess}</p>
                </div>
              )}

              {/* Form Content */}
              <div className="p-6 space-y-4">
                <div>
                  <label htmlFor="lease-select" className="block text-sm font-medium text-slate-900 mb-2">Select Lease *</label>
                  <select
                    id="lease-select"
                    value={selectedLeaseId || ""}
                    onChange={(e) => setSelectedLeaseId(e.target.value || null)}
                    className="w-full border border-slate-300 px-4 py-2.5 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none bg-white text-slate-900"
                    disabled={inviteSending}
                  >
                    <option value="">-- Select a lease ({leases.length} available) --</option>
                    {leases.map(lease => {
                      const unitNum = lease.unit?.unitNumber || "N/A";
                      const unitName = lease.unit?.unitName || "";
                      const city = lease.property?.city || "";
                      const address = lease.property?.address || "No Address";
                      const fullAddress = city && address !== city ? `${address}, ${city}` : address;
                      const displayName = unitName ? `${unitNum} (${unitName})` : unitNum;

                      return (
                        <option key={lease.id} value={lease.id}>
                          Unit {displayName} - {fullAddress}
                        </option>
                      );
                    })}
                  </select>
                  {leases.length === 0 && (
                    <p className="text-amber-600 text-xs mt-2">No leases available. Please create a lease first.</p>
                  )}
                </div>

                <div>
                  <label htmlFor="invite-email" className="block text-sm font-medium text-slate-900 mb-2">Email Address *</label>
                  <input
                    id="invite-email"
                    type="email"
                    placeholder="tenant@example.com"
                    value={inviteEmail}
                    onChange={(e) => setInviteEmail(e.target.value)}
                    className="w-full border border-slate-300 px-4 py-2.5 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none text-slate-900"
                    disabled={inviteSending}
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-900 mb-2">First Name *</label>
                  <input
                    type="text"
                    placeholder="John"
                    value={inviteFirstName}
                    onChange={(e) => setInviteFirstName(e.target.value)}
                    className="w-full border border-slate-300 px-4 py-2.5 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none text-slate-900"
                    disabled={inviteSending}
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-900 mb-2">Last Name</label>
                  <input
                    type="text"
                    placeholder="Doe"
                    value={inviteLastName}
                    onChange={(e) => setInviteLastName(e.target.value)}
                    className="w-full border border-slate-300 px-4 py-2.5 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none text-slate-900"
                    disabled={inviteSending}
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-slate-900 mb-2">Phone Number</label>
                  <input
                    type="text"
                    placeholder="+254 7XX XXX XXX"
                    value={invitePhone}
                    onChange={(e) => setInvitePhone(e.target.value)}
                    className="w-full border border-slate-300 px-4 py-2.5 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none text-slate-900"
                    disabled={inviteSending}
                  />
                </div>
              </div>

              {/* Modal Footer */}
              <div className="border-t border-slate-200 p-6 bg-slate-50 flex gap-3 justify-end">
                <button
                  onClick={() => {
                    setShowInviteModal(false);
                    resetInviteForm();
                  }}
                  className="px-6 py-2 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-100 transition-colors font-medium"
                  disabled={inviteSending}
                >
                  Cancel
                </button>
                <button
                  onClick={handleSendInvite}
                  disabled={inviteSending}
                  className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {inviteSending ? "Sending..." : "Send Invite"}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Application Detail Modal */}
        {showDetailModal && selectedApplication && (
          <div className="fixed inset-0  bg-opacity-50 flex items-center justify-center p-4 z-50">
            <div className="bg-white rounded-2xl max-w-3xl w-full max-h-[90vh] overflow-y-auto">
              {/* Modal Header */}
              <div className="sticky top-0 bg-white border-b border-slate-200 p-6 flex justify-between items-start">
                <div>
                  <h2 className="text-2xl font-bold text-slate-900">Application Details</h2>
                  <p className="text-slate-600 mt-1">Complete review of tenant application</p>
                </div>
                <button
                  onClick={() => setShowDetailModal(false)}
                  className="text-slate-400 hover:text-slate-600"
                >
                  <X className="w-6 h-6" />
                </button>
              </div>

              <div className="p-6 space-y-6">
                {/* Status Banner */}
                <div className={`p-4 rounded-lg border flex items-center justify-between ${selectedApplication.status === "APPROVED" || selectedApplication.status === "Approved"
                  ? "bg-green-50 border-navy-200"
                  : selectedApplication.status === "REJECTED" || selectedApplication.status === "Rejected"
                    ? "bg-red-50 border-red-200"
                    : "bg-amber-50 border-amber-200"
                  }`}>
                  <div>
                    <p className="text-sm font-medium text-slate-600">Current Status</p>
                    <p className={`text-lg font-bold ${selectedApplication.status === "APPROVED" || selectedApplication.status === "Approved"
                      ? "text-green-700"
                      : selectedApplication.status === "REJECTED" || selectedApplication.status === "Rejected"
                        ? "text-red-700"
                        : "text-amber-700"
                      }`}>
                      {selectedApplication.status}
                    </p>
                  </div>
                  <span className={`inline-flex px-4 py-2 rounded-lg text-sm font-semibold border ${getStatusColor(selectedApplication.status)}`}>
                    {selectedApplication.status}
                  </span>
                </div>

                {/* Personal Information */}
                <div>
                  <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
                    <User className="w-5 h-5 text-blue-600" />
                    Personal Information
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Full Name</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.fullName}</p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Date of Birth</p>
                      <p className="text-slate-900 font-semibold mt-1">
                        {selectedApplication.dob ? formatDate(selectedApplication.dob) : "N/A"}
                      </p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Email</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.email}</p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Phone</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.phone}</p>
                    </div>
                    <div className="col-span-2 bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Current Address</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.address || "N/A"}</p>
                    </div>
                  </div>
                </div>

                {/* Property & Unit Information */}
                <div>
                  <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
                    <Home className="w-5 h-5 text-emerald-600" />
                    Property & Unit Details
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Property</p>
                      <p className="text-slate-900 font-semibold mt-1">
                        {selectedApplication.property?.name || selectedApplication.property?.city || "N/A"}
                      </p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Unit Number</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.unit?.unitNumber || "N/A"}</p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Monthly Rent</p>
                      <p className="text-slate-900 font-semibold mt-1">
                        $ {(selectedApplication.unit?.rentAmount || 0).toLocaleString()}
                      </p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Desired Move-in Date</p>
                      <p className="text-slate-900 font-semibold mt-1">{formatDate(selectedApplication.moveInDate)}</p>
                    </div>
                  </div>
                </div>

                {/* Employment Information */}
                <div>
                  <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center gap-2">
                    <DollarSign className="w-5 h-5 text-green-500" />
                    Employment & Financial Information
                  </h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Employer Name</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.employerName || "N/A"}</p>
                    </div>
                    <div className="bg-slate-50 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Job Title</p>
                      <p className="text-slate-900 font-semibold mt-1">{selectedApplication.jobTitle || "N/A"}</p>
                    </div>
                    <div className="col-span-2 bg-green-50 border border-navy-200 p-4 rounded-lg">
                      <p className="text-sm text-slate-600 font-medium">Monthly Income</p>
                      <p className="text-green-700 font-bold text-xl mt-1">
                        $ {(selectedApplication.monthlyIncome || 0).toLocaleString()}
                      </p>
                      <p className="text-xs text-slate-600 mt-2">
                        Rent-to-Income Ratio: {selectedApplication.unit?.rentAmount && selectedApplication.monthlyIncome
                          ? ((selectedApplication.unit.rentAmount / selectedApplication.monthlyIncome) * 100).toFixed(1)
                          : "N/A"}%
                      </p>
                    </div>
                  </div>
                </div>

                {/* Submission Info */}
                <div className="bg-blue-50 border border-blue-200 p-4 rounded-lg">
                  <p className="text-sm text-slate-600 font-medium">Application Submitted</p>
                  <p className="text-slate-900 font-semibold mt-1">{formatDate(selectedApplication.createdAt)}</p>
                </div>
              </div>

              {/* Modal Footer */}
              <div className="border-t border-slate-200 p-6 bg-slate-50 flex gap-3 justify-end">
                <button
                  onClick={() => setShowDetailModal(false)}
                  className="px-6 py-2 border border-slate-300 text-slate-700 rounded-lg hover:bg-slate-100 transition-colors font-medium"
                >
                  Close
                </button>
                <div className="p-6 border-t border-gray-200 bg-gray-50 flex gap-3 justify-end">

                  {(selectedApplication.status === "Pending" || selectedApplication.status === "PENDING") && (
                    <>
                      <button
                        onClick={() => handleReject(selectedApplication.id)}
                        className="flex items-center gap-2 px-6 py-2.5 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
                      >
                        <X className="h-4 w-4" />
                        Reject
                      </button>
                      <button
                        onClick={() => handleApprove(selectedApplication.id)}
                        className="flex items-center gap-2 px-6 py-2.5 bg-green-500 text-white rounded-lg hover:bg-green-600 transition-colors"
                      >
                        <Check className="h-4 w-4" />
                        Approve
                      </button>
                    </>
                  )}
                  {(selectedApplication.status === "Approved" || selectedApplication.status === "APPROVED") && (
                    <button
                      onClick={() => proceedToLease(selectedApplication as unknown as TenantApplication)}
                      className="flex items-center gap-2 px-6 py-2.5 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors"
                    >
                      <FileText className="h-4 w-4" />
                      Proceed to Lease Signing
                    </button>

                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useForm } from "react-hook-form";
import { useRouter } from "next/navigation";
import toast from "react-hot-toast";
import { useState, useEffect } from "react";
import { updateUnitDetails } from "@/lib/units";
import { ListingDecisionModal } from "@/components/Dashboard/listing/ListingDecisionModal";
import { ListingStatus, UnitWithListingStatus } from "@/lib/listing-types";

export interface ApplianceInput {
  name: string;
}

export interface UnitFormData {
  bedrooms: number;
  bathrooms: number;
  floorNumber?: number | null;
  rentAmount?: number | null;
  unitName?: string;
  currency?: string;
  isOccupied?: boolean;
  appliances?: ApplianceInput[];
}

export default function EditUnitForm({
  propertyId,
  unitNumber,
  existingUnit,
}: {
  propertyId: string;
  unitNumber: string;
  existingUnit: UnitFormData | null;
}) {
  const router = useRouter();
  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
    watch,
  } = useForm<UnitFormData>({
    defaultValues: {
      bedrooms: existingUnit?.bedrooms || 0,
      bathrooms: existingUnit?.bathrooms || 0,
      floorNumber: existingUnit?.floorNumber || null,
      rentAmount: existingUnit?.rentAmount || null,
      unitName: existingUnit?.unitName || "",
      currency: existingUnit?.currency || "USD",

      isOccupied: existingUnit?.isOccupied || false,
      // appliances will be handled separately
    },
  });

  const [loading, setLoading] = useState(false);
  const [applianceInput, setApplianceInput] = useState("");
  const [showListingDecision, setShowListingDecision] = useState(false);
  const [createdUnitId, setCreatedUnitId] = useState<string | null>(null);

  // Initialize appliance input from existing data
  useEffect(() => {
    if (existingUnit?.appliances && existingUnit.appliances.length > 0) {
      const applianceNames = existingUnit.appliances
        .map((appliance) => appliance.name)
        .join(", ");
      setApplianceInput(applianceNames);
    }
  }, [existingUnit]);

  const onSubmit = async (data: UnitFormData) => {
    setLoading(true);

    try {
      // Convert appliance string input into structured array for backend
      const appliancesArray: ApplianceInput[] = applianceInput
        .split(",")
        .map((name) => name.trim())
        .filter(Boolean)
        .map((name) => ({ name }));

      const formattedData = {
        ...data,
        bedrooms: Number(data.bedrooms),
        bathrooms: Number(data.bathrooms),
        floorNumber: data.floorNumber ? Number(data.floorNumber) : null,
        rentAmount: data.rentAmount ? Number(data.rentAmount) : null,
        appliances: appliancesArray,
      };

      const result = await updateUnitDetails(propertyId, unitNumber, formattedData);

      if (result.success) {
        // Check if this was a new unit creation
        if (result.isNewUnit && result.unit?.id) {
          setCreatedUnitId(result.unit.id);
          setShowListingDecision(true);
          toast.success("Unit created successfully! Choose listing preference.");
        } else {
          toast.success("Unit details saved successfully!");
          setTimeout(() => router.back(), 1000);
        }
      } else {
        toast.error(result.message || "Failed to save unit details.");
      }
    } catch (error: any) {
      toast.error("An error occurred while saving unit details.");
      console.error("Form submission error:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleListingDecision = async (unitId: string, decision: 'list' | 'private') => {
    if (!createdUnitId) return;
    if (!unitId) {
      toast.error("Unit ID is missing. Please try again.");
      return;
    }
    
    try {
      if (decision === 'list') {
        const response = await fetch("/api/listings", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            unitId,
            action: "CREATE",
            listingData: {
              title: watch('unitName') || `Unit ${unitNumber}`,
              description: watch('unitName') || `Unit ${unitNumber}`,
              price: watch('rentAmount') || 0
            }
          })
        });

        if (response.ok) {
          toast.success("Unit listed on marketplace successfully!");
        } else {
          const payload = await response.json().catch(() => ({}));
          toast.error(payload.error || "Failed to list unit on marketplace");
        }
      } else {
        toast.success("Unit kept private as requested.");
      }
      
      setShowListingDecision(false);
      setTimeout(() => router.back(), 1000);
    } catch (error) {
      console.error('Error handling listing decision:', error);
      toast.error("Error processing listing decision");
      setShowListingDecision(false);
      setTimeout(() => router.back(), 1000);
    }
  };

  const getListingDecisionUnit = (): UnitWithListingStatus => ({
    id: createdUnitId || '',
    unitNumber,
    propertyId,
    rentAmount: watch('rentAmount') || undefined,
    bedrooms: watch('bedrooms') || undefined,
    bathrooms: watch('bathrooms') || undefined,
    listing: {
      id: '',
      status: ListingStatus.PRIVATE,
      createdAt: new Date(),
      updatedAt: new Date(),
      title: watch('unitName') || `Unit ${unitNumber}`,
      description: watch('unitName') || `Unit ${unitNumber}`,
      price: watch('rentAmount') || 0
    }
  });

  return (
    <>
      <div className="max-w-2xl mx-auto bg-white/90 backdrop-blur-xl border border-gray-200 shadow-2xl rounded-3xl p-8 transition-all duration-300">
      <div className="text-center mb-8">
        <div className="w-16 h-16 bg-gradient-to-r from-blue-500 to-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg">
          <span className="text-white font-bold text-lg">#{unitNumber}</span>
        </div>
        <h1 className="text-3xl font-bold bg-gradient-to-r from-blue-600 to-indigo-600 bg-clip-text text-transparent mb-2">
          Edit Unit Details
        </h1>
        <p className="text-gray-600 text-sm">
          Update the information for this rental unit
        </p>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {/* Unit Name */}
          <div className="md:col-span-2">
            <label className="block text-gray-700 mb-2 font-semibold text-sm uppercase tracking-wide">
              Unit Name
            </label>
            <input
              type="text"
              {...register("unitName")}
              placeholder="e.g. Apartment A1"
              className="w-full px-4 py-3 rounded-xl border placeholder:text-gray-400 border-gray-300 bg-white focus:ring-2 focus:ring-blue-500 shadow-sm"
            />
          </div>

          {/* Bedrooms */}
          <div>
            <label className="block text-gray-700 mb-2 font-semibold text-sm uppercase tracking-wide">
              Bedrooms *
            </label>
            <input
              type="number"
              min="0"
              {...register("bedrooms", {
                required: "Number of bedrooms is required",
                min: { value: 0, message: "Bedrooms cannot be negative" }
              })}
              placeholder="e.g. 2"
              className="w-full px-4 py-3 rounded-xl border placeholder:text-gray-400 border-gray-300 focus:ring-2 focus:ring-blue-500"
            />
            {errors.bedrooms && (
              <p className="text-red-500 text-xs mt-1">{errors.bedrooms.message}</p>
            )}
          </div>

          {/* Bathrooms */}
          <div>
            <label className="block text-gray-700 mb-2 font-semibold text-sm uppercase tracking-wide">
              Bathrooms *
            </label>
            <input
              type="number"
              min="0"
              step="1"
              {...register("bathrooms", {
                required: "Number of bathrooms is required",
                min: { value: 0, message: "Bathrooms cannot be negative" }
              })}
              placeholder="e.g. 1.5"
              className="w-full px-4 py-3 rounded-xl border placeholder:text-gray-400 border-gray-300 focus:ring-2 focus:ring-blue-500"
            />
            {errors.bathrooms && (
              <p className="text-red-500 text-xs mt-1">{errors.bathrooms.message}</p>
            )}
          </div>

          {/* Floor Number */}
          <div>
            <label className="block text-gray-700 mb-2 font-semibold text-sm uppercase tracking-wide">
              Floor Number
            </label>
            <input
              type="number"
              min="0"
              {...register("floorNumber")}
              placeholder="e.g. 3"
              className="w-full px-4 py-3 rounded-xl border placeholder:text-gray-400 border-gray-300 focus:ring-2 focus:ring-blue-500"
            />
          </div>

          {/* Rent Amount */}
          <div>
            <label className="block text-gray-700 mb-2 font-semibold text-sm uppercase tracking-wide">
              Rent Amount
            </label>
            <div className="flex gap-2">
              <select
                {...register("currency")}
                className="w-1/3 px-4 py-3 rounded-xl border border-gray-300 focus:ring-2 focus:ring-blue-500"
                defaultValue="USD"
              >
                <option value="USD">USD</option>
                <option value="USD">USD</option>
                <option value="EUR">EUR</option>
                <option value="GBP">GBP</option>
              </select>


              <input
                type="number"
                min="0"
                step="0.01"
                {...register("rentAmount", { valueAsNumber: true })}
                placeholder="e.g. 25000"
                className="w-2/3 px-4 py-3 rounded-xl border placeholder:text-gray-400 border-gray-300 focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          {/* Appliances */}
          <div className="md:col-span-2">
            <label className="block text-gray-700 mb-2 font-semibold text-sm uppercase tracking-wide">
              Appliances
            </label>
            <input
              type="text"
              value={applianceInput}
              onChange={(e) => setApplianceInput(e.target.value)}
              placeholder="e.g. Fridge, Microwave, Washing Machine"
              className="w-full px-4 py-3 rounded-xl border placeholder:text-gray-400 border-gray-300 bg-white focus:ring-2 focus:ring-blue-500 shadow-sm"
            />
            <p className="text-xs text-gray-500 mt-1">
              Separate multiple appliances with commas (,)
            </p>
          </div>



        </div>

        {/* Occupied */}
        <div className="flex items-center gap-3 mt-4">
          <input
            type="checkbox"
            {...register("isOccupied")}
            className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
          />
          <span className="text-gray-700 font-medium">Currently Occupied</span>
        </div>

        {/* Buttons */}
        <div className="flex gap-4 pt-6">
          <button
            type="button"
            onClick={() => router.back()}
            disabled={loading}
            className="flex-1 py-3 px-6 rounded-xl border border-gray-300 text-gray-700 bg-white hover:bg-gray-50 disabled:opacity-50 transition-colors"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={loading}
            className={`flex-1 py-3 px-6 rounded-xl text-white font-semibold shadow-md transition-all ${loading
              ? "bg-gray-400 cursor-not-allowed"
              : "bg-gradient-to-r from-blue-600 to-indigo-600 hover:scale-[1.02] hover:shadow-lg"
              }`}
          >
            {loading ? (
              <span className="flex items-center justify-center">
                <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                </svg>
                Saving...
              </span>
            ) : (
              "Save Changes"
            )}
          </button>
        </div>
      </form>
    </div>

    {/* Listing Decision Modal */}
    {showListingDecision && createdUnitId && (
      <ListingDecisionModal
        isOpen={showListingDecision}
        unit={getListingDecisionUnit()}
        onDecision={handleListingDecision}
        onClose={() => {
          setShowListingDecision(false);
        }}
      />
    )}
    </>
  );
}

"use client";

import { Building, Bed, Bath, DollarSign, Users, Home, Utensils } from "lucide-react";
import Link from "next/link";

interface Unit {
  unitNumber: string;
  unitName?: string;
  floorNumber?: number;
  bedrooms?: number;
  bathrooms?: number;
  rentAmount?: number;
  appliances?: any[];
  isOccupied: boolean;
}

interface UnitsTableProps {
  propertyId: string;
  units: Unit[];
  inModal?: boolean; // optional, if rendered inside a modal
}

export default function UnitsTable({ propertyId, units, inModal = false }: UnitsTableProps) {
  const occupiedUnits = units.filter(unit => unit.isOccupied).length;
  const totalRooms = units.reduce((total, unit) => total + (unit.bedrooms || 0), 0);
  const totalBathrooms = units.reduce((total, unit) => total + (unit.bathrooms || 0), 0);

  if (units.length === 0) {
    return (
      <div className="min-h-[200px] flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-2">
            <Home className="w-6 h-6 text-gray-400" />
          </div>
          <h3 className="text-lg font-semibold text-gray-800 mb-1">No Units Found</h3>
          <p className="text-gray-600 text-sm">
            This property doesn't have any units yet.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className={inModal ? "max-h-[70vh] overflow-y-auto" : ""}>
      <table className="w-full border-collapse">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-4 py-2 text-left text-sm font-semibold text-gray-900">Unit Details</th>
            <th className="px-4 py-2 text-left text-sm font-semibold text-gray-900">Specifications</th>
            <th className="px-4 py-2 text-left text-sm font-semibold text-gray-900">Rent</th>
            <th className="px-4 py-2 text-left text-sm font-semibold text-gray-900">Appliances</th>
            <th className="px-4 py-2 text-left text-sm font-semibold text-gray-900">Status</th>
            <th className="px-4 py-2 text-left text-sm font-semibold text-gray-900">Actions</th>
          </tr>
        </thead>
        <tbody>
          {units.map(unit => {
            const applianceCount = unit.appliances?.length || 0;
            const hasDetails = unit.unitName || unit.bedrooms || unit.bathrooms || unit.floorNumber || unit.rentAmount;

            return (
              <tr key={unit.unitNumber} className="hover:bg-gray-50 transition-colors">
                <td className="px-4 py-2">
                  <div className="flex items-center gap-2">
                    <div className="w-8 h-8 bg-blue-100 flex items-center justify-center rounded-lg">
                      <Home className="w-4 h-4 text-blue-600" />
                    </div>
                    <div>
                      <div className="font-medium text-gray-900">Unit {unit.unitNumber}</div>
                      {unit.unitName && <div className="text-sm text-gray-500">{unit.unitName}</div>}
                      {unit.floorNumber && (
                        <div className="flex items-center gap-1 text-xs text-gray-500 mt-1">
                          <Building className="w-3 h-3" /> Floor {unit.floorNumber}
                        </div>
                      )}
                    </div>
                  </div>
                </td>
                <td className="px-4 py-2 flex gap-3">
                  <div className="flex items-center gap-1">
                    <Bed className="w-4 h-4 text-gray-400" />
                    {unit.bedrooms || 0}
                  </div>
                  <div className="flex items-center gap-1">
                    <Bath className="w-4 h-4 text-gray-400" />
                    {unit.bathrooms || 0}
                  </div>
                </td>
                <td className="px-4 py-2">
                  {unit.rentAmount ? `USD ${unit.rentAmount.toLocaleString()}` : "Not set"}
                </td>
                <td className="px-4 py-2">{applianceCount || "None"}</td>
                <td className="px-4 py-2">
                  <span className={`${unit.isOccupied ? "text-green-500" : "text-gray-500"}`}>
                    {unit.isOccupied ? "Occupied" : "Vacant"}
                  </span>
                </td>
                <td className="px-4 py-2 flex flex-col gap-1">
                  <Link
                    href={`/property-manager/view-own-property/${propertyId}/units/${unit.unitNumber}/edit`}
                    className={`px-2 py-1 text-sm rounded-lg text-white ${
                      hasDetails ? "bg-yellow-500 hover:bg-yellow-600" : "bg-blue-600 hover:bg-blue-700"
                    }`}
                  >
                    {hasDetails ? "Edit Details" : "Add Details"}
                  </Link>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>

      {/* Footer summary if not in modal */}
      {!inModal && (
        <div className="mt-4 grid grid-cols-4 gap-4 text-sm text-gray-700">
          <div>Total Units: {units.length}</div>
          <div>Occupied Units: {occupiedUnits}</div>
          <div>Total Rooms: {totalRooms}</div>
          <div>Total Bathrooms: {totalBathrooms}</div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { toast } from "sonner";
import { Copy, CheckCircle2, Clock, Trash2, Send, X } from "lucide-react";

interface Invite {
  id: string;
  token: string;
  email: string;
  accepted: boolean;
  createdAt: string;
  expiresAt: string;
}

export default function VendorInviteForm() {
  const router = useRouter();
  const [invites, setInvites] = useState<Invite[]>([]);
  const [filteredInvites, setFilteredInvites] = useState<Invite[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState<"ALL" | "ACCEPTED" | "PENDING">("ALL");
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [copiedToken, setCopiedToken] = useState<string | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState<string | null>(null);

  // Form state
  const [email, setEmail] = useState("");
  const [firstName, setFirstName] = useState("");
  const [lastName, setLastName] = useState("");
  const [phone, setPhone] = useState("");
  const [companyName, setCompanyName] = useState("");
  const [serviceType, setServiceType] = useState("");

  const [loading, setLoading] = useState(false);
  const [initialLoading, setInitialLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  useEffect(() => {
    const fetchInvites = async () => {
      setInitialLoading(true);
      setError(null);

      try {
        const res = await fetch("/api/auth/invites/vendor");
        if (!res.ok) throw new Error("Failed to fetch vendor invites");
        const data = await res.json();
        setInvites(data.invites || []);
        setFilteredInvites(data.invites || []);
      } catch (err) {
        console.error("Error fetching vendor invites:", err);
        setError(err instanceof Error ? err.message : "Failed to load invites");
      } finally {
        setInitialLoading(false);
      }
    };

    fetchInvites();
  }, []);

  useEffect(() => {
    let filtered = invites;

    if (filterStatus !== "ALL") {
      filtered = filtered.filter((inv) =>
        filterStatus === "ACCEPTED" ? inv.accepted : !inv.accepted
      );
    }

    if (searchTerm.trim() !== "") {
      filtered = filtered.filter((inv) =>
        inv.email.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    setFilteredInvites(filtered);
  }, [searchTerm, filterStatus, invites]);

  const validateForm = () => {
    if (!email.trim()) {
      setError("Email is required");
      return false;
    }
    if (!firstName.trim()) {
      setError("First name is required");
      return false;
    }
    if (!companyName.trim()) {
      setError("Company name is required");
      return false;
    }
    if (!serviceType.trim()) {
      setError("Service type is required");
      return false;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      setError("Invalid email format");
      return false;
    }

    return true;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMessage(null);

    if (!validateForm()) return;

    setLoading(true);

    try {
      const res = await fetch("/api/auth/invites/vendor", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          email: email.toLowerCase(),
          firstName,
          lastName,
          phone,
          companyName,
          serviceType,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || "Failed to send invite");
      }

      toast.success("Vendor invite sent successfully!");
      setSuccessMessage("Invite sent successfully!");

      setEmail("");
      setFirstName("");
      setLastName("");
      setPhone("");
      setCompanyName("");
      setServiceType("");
      setIsModalOpen(false);

      const invitesRes = await fetch("/api/auth/invites/vendor");
      if (invitesRes.ok) {
        const invitesData = await invitesRes.json();
        setInvites(invitesData.invites || []);
      }
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : "Something went wrong";
      setError(errorMsg);
      toast.error(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (inviteLink: string, token: string) => {
    navigator.clipboard.writeText(inviteLink);
    setCopiedToken(token);
    toast.success("Invite link copied to clipboard!");
    setTimeout(() => setCopiedToken(null), 2000);
  };

  const handleDeleteInvite = async (inviteId: string) => {
    try {
      const res = await fetch(`/api/auth/invites/vendor/${inviteId}`, {
        method: "DELETE",
      });

      if (!res.ok) throw new Error("Failed to delete invite");

      toast.success("Invite deleted successfully");
      setInvites(invites.filter((inv) => inv.id !== inviteId));
      setShowDeleteConfirm(null);
    } catch (err) {
      toast.error(err instanceof Error ? err.message : "Failed to delete invite");
    }
  };

  const baseUrl = process.env.NEXT_PUBLIC_BASE_URL;
  if (!baseUrl) {
    throw new Error("Environment variable NEXT_PUBLIC_BASE_URL is not set.");
  }
  const generateInviteLink = (token: string, inviteEmail: string) => {
    return `${baseUrl}/inviteor?email=${encodeURIComponent(inviteEmail)}&token=${token}`;
  };

  return (
    <div className="space-y-6 bg-white">
      <button
        onClick={() => router.back()}
        className="inline-flex items-center gap-2 mb-4 text-gray-500 hover:text-gray-900 transition-colors"
      >
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" className="w-5 h-5">
          <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
        </svg>
        Back
      </button>
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-black">Vendor Management</h2>
          <p className="text-black text-sm mt-1">Invite and manage service vendors</p>
        </div>
        <button
          onClick={() => setIsModalOpen(true)}
          className="inline-flex items-center gap-2 px-4 py-2 rounded bg-emerald-600 hover:bg-emerald-700 text-white shadow transition-colors"
        >
          <Send size={18} />
          Send Vendor Invite
        </button>
      </div>

      {error && (
        <div className="bg-red-100 border border-red-300 text-red-700 px-4 py-3 rounded-lg">
          {error}
        </div>
      )}
      {successMessage && (
        <div className="bg-emerald-100 border border-emerald-300 text-emerald-700 px-4 py-3 rounded-lg">
          {successMessage}
        </div>
      )}

      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-start sm:items-center justify-center z-50 p-4">
          <div className="bg-white border border-gray-200 rounded-lg w-full max-w-lg shadow-xl max-h-[90vh] overflow-y-auto">
            <div className="flex items-center justify-between p-6 border-b border-gray-200">
              <div>
                <h3 className="text-xl font-bold text-gray-900">Send Vendor Invite</h3>
                <p className="text-gray-600 text-sm mt-1">Fill in the vendor details and send them an invitation to sign up.</p>
              </div>
              <button
                onClick={() => setIsModalOpen(false)}
                className="text-gray-500 hover:text-gray-900 transition-colors"
              >
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Email <span className="text-red-500">*</span>
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="vendor@example.com"
                  className="w-full bg-gray-50 border border-gray-300 text-gray-900 placeholder-gray-400 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  First Name <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={firstName}
                  onChange={(e) => setFirstName(e.target.value)}
                  placeholder="John"
                  className="w-full bg-gray-50 border border-gray-300 text-gray-900 placeholder-gray-400 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Last Name
                </label>
                <input
                  type="text"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  placeholder="Doe"
                  className="w-full bg-gray-50 border border-gray-300 text-gray-900 placeholder-gray-400 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Phone
                </label>
                <input
                  type="tel"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  placeholder="+1 (555) 000-0000"
                  className="w-full bg-gray-50 border border-gray-300 text-gray-900 placeholder-gray-400 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Company Name <span className="text-red-500">*</span>
                </label>
                <input
                  type="text"
                  value={companyName}
                  onChange={(e) => setCompanyName(e.target.value)}
                  placeholder="ABC Services Inc"
                  className="w-full bg-gray-50 border border-gray-300 text-gray-900 placeholder-gray-400 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Service Type <span className="text-red-500">*</span>
                </label>
                <select
                  value={serviceType}
                  onChange={(e) => setServiceType(e.target.value)}
                  className="w-full bg-gray-50 border border-gray-300 text-gray-900 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
                  required
                >
                  <option value="">Select a service type</option>
                  <option value="Plumbing">Plumbing</option>
                  <option value="Electrical">Electrical</option>
                  <option value="Cleaning">Cleaning</option>
                  <option value="Maintenance">Maintenance</option>
                  <option value="HVAC">HVAC</option>
                  <option value="Landscaping">Landscaping</option>
                  <option value="Painting">Painting</option>
                  <option value="Carpentry">Carpentry</option>
                  <option value="Other">Other</option>
                </select>
              </div>

              <div className="flex items-center gap-3 pt-4">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 px-4 py-2 rounded bg-gray-200 hover:bg-gray-300 text-gray-900 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  disabled={loading}
                  className="flex-1 px-4 py-2 rounded bg-emerald-600 hover:bg-emerald-700 text-white transition-colors disabled:opacity-50"
                >
                  {loading ? "Sending..." : "Send Invite"}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className="bg-gray-50 border border-gray-200 rounded-xl p-4">
          <p className="text-gray-600 text-sm mb-1">Total Invites</p>
          <p className="text-3xl font-bold text-gray-900">{invites.length}</p>
        </div>
        <div className="bg-gray-50 border border-gray-200 rounded-xl p-4">
          <p className="text-gray-600 text-sm mb-1">Pending Invites</p>
          <p className="text-3xl font-bold text-yellow-600">
            {invites.filter((i) => !i.accepted).length}
          </p>
        </div>
      </div>

      <div className="bg-gray-50 border border-gray-200 rounded-xl p-4 space-y-4">
        <div className="flex flex-col sm:flex-row gap-4">
          <input
            type="text"
            placeholder="Search by email..."
            className="flex-1 bg-white border border-gray-300 text-gray-900 placeholder-gray-400 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <select
            className="bg-white border border-gray-300 text-gray-900 px-3 py-2 rounded-lg focus:outline-none focus:ring-2 focus:ring-emerald-300 focus:border-transparent min-w-40"
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value as "ALL" | "ACCEPTED" | "PENDING")}
          >
            <option value="ALL">All Invites</option>
            <option value="PENDING">Pending</option>
            <option value="ACCEPTED">Accepted</option>
          </select>
        </div>
      </div>

      {initialLoading ? (
        <div className="flex justify-center items-center py-12">
          <div className="text-gray-600">Loading invites...</div>
        </div>
      ) : (
        <div className="bg-white border border-gray-200 rounded-xl overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-100">
                <tr>
                  <th className="text-left p-3 text-gray-700 font-semibold text-sm">Email</th>
                  <th className="text-left p-3 text-gray-700 font-semibold text-sm">Status</th>
                  <th className="text-left p-3 text-gray-700 font-semibold text-sm">Created</th>
                  <th className="text-left p-3 text-gray-700 font-semibold text-sm">Expires</th>
                  <th className="text-left p-3 text-gray-700 font-semibold text-sm">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredInvites.length > 0 ? (
                  filteredInvites.map((invite) => {
                    const inviteLink = generateInviteLink(invite.token, invite.email);
                    const isExpired = new Date(invite.expiresAt) < new Date();
                    const isAccepted = invite.accepted;

                    return (
                      <tr
                        key={invite.id}
                        className="border-t border-gray-200 hover:bg-gray-50 transition-colors"
                      >
                        <td className="p-3 text-gray-900">{invite.email}</td>
                        <td className="p-3">
                          {isAccepted ? (
                            <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-semibold bg-emerald-100 text-emerald-700">
                              <CheckCircle2 size={14} />
                              Accepted
                            </span>
                          ) : isExpired ? (
                            <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-semibold bg-red-100 text-red-700">
                              <Clock size={14} />
                              Expired
                            </span>
                          ) : (
                            <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-semibold bg-yellow-100 text-yellow-700">
                              <Clock size={14} />
                              Pending
                            </span>
                          )}
                        </td>
                        <td className="p-3 text-gray-900 text-sm">
                          {new Date(invite.createdAt).toLocaleDateString()}
                        </td>
                        <td className="p-3 text-gray-900 text-sm">
                          {new Date(invite.expiresAt).toLocaleDateString()}
                        </td>
                        <td className="p-3">
                          <button 
                            onClick={() => router.push(`/property-manager/vendors/${invite.id}`)}
                            className="inline-flex items-center gap-1 px-3 py-1 rounded text-xs bg-green-100 hover:bg-green-200 text-green-700 font-medium transition-colors"
                          >
                            View Details
                          </button>
                          <div className="flex items-center gap-2 flex-wrap mt-2">
                            {!isAccepted && !isExpired && (
                              <button
                                onClick={() => copyToClipboard(inviteLink, invite.token)}
                                className="inline-flex items-center gap-1 px-3 py-1 rounded text-xs bg-emerald-100 hover:bg-emerald-200 text-emerald-700 transition-colors"
                              >
                                {copiedToken === invite.token ? (
                                  <>
                                    <CheckCircle2 size={14} />
                                    Copied
                                  </>
                                ) : (
                                  <>
                                    <Copy size={14} />
                                    Copy Link
                                  </>
                                )}
                              </button>
                            )}

                            {showDeleteConfirm === invite.id && (
                              <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                                <div className="bg-white border border-gray-200 rounded-lg p-6 max-w-sm shadow-xl">
                                  <h4 className="text-gray-900 font-bold mb-2">Delete Invite?</h4>
                                  <p className="text-gray-600 text-sm mb-4">This action cannot be undone. The vendor will not receive this invite.</p>
                                  <div className="flex gap-3">
                                    <button
                                      onClick={() => setShowDeleteConfirm(null)}
                                      className="flex-1 px-3 py-2 rounded bg-gray-200 hover:bg-gray-300 text-gray-900 text-sm transition-colors"
                                    >
                                      Cancel
                                    </button>
                                    <button
                                      onClick={() => handleDeleteInvite(invite.id)}
                                      className="flex-1 px-3 py-2 rounded bg-red-600 hover:bg-red-700 text-white text-sm transition-colors"
                                    >
                                      Delete
                                    </button>
                                  </div>
                                </div>
                              </div>
                            )}

                            {/* <button
                              onClick={() => setShowDeleteConfirm(invite.id)}
                              className="inline-flex items-center gap-1 px-3 py-1 rounded text-xs bg-red-100 hover:bg-red-200 text-red-700 transition-colors"
                            >
                              <Trash2 size={14} />
                            </button> */}
                          </div>
                        </td>
                      </tr>
                    );
                  })
                ) : (
                  <tr>
                    <td colSpan={5} className="text-center p-12">
                      <div className="flex flex-col items-center gap-2">
                        <svg
                          className="w-12 h-12 text-gray-400"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
                            d="M12 4.354a4 4 0 110 5.292M15 9H9m6 0a9 9 0 11-18 0 9 9 0 0118 0z"
                          />
                        </svg>
                        <p className="text-gray-600 text-lg">No vendor invites yet</p>
                        <p className="text-gray-500 text-sm">
                          Send your first vendor invite to get started
                        </p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { CreditCard, Smartphone, Building2, Wallet } from "lucide-react";
import { toast } from "react-hot-toast";

interface PaymentModalProps {
  isOpen: boolean;
  onClose: () => void;
  invoiceId?: string;
  amount: number;
  currency?: string;
  onPaymentSuccess?: () => void;
}

type PaymentMethod = "mpesa" | "card" | "paystack" | "stripe" | "plaid";

export function PaymentModal({
  isOpen,
  onClose,
  invoiceId,
  amount,
  currency = "KES",
  onPaymentSuccess,
}: PaymentModalProps) {
  const router = useRouter();
  const [selectedMethod, setSelectedMethod] = useState<PaymentMethod>("mpesa");
  const [phoneNumber, setPhoneNumber] = useState("");
  const [isProcessing, setIsProcessing] = useState(false);
  const [cardDetails, setCardDetails] = useState({
    number: "",
    expiry: "",
    cvc: "",
    name: "",
  });

  const paymentMethods = [
    {
      id: "mpesa" as PaymentMethod,
      label: "M-Pesa",
      description: "Pay via M-Pesa STK Push",
      icon: Smartphone,
      color: "bg-green-100 text-green-700 border-green-300",
      iconColor: "text-green-600",
    },
    {
      id: "paystack" as PaymentMethod,
      label: "Paystack",
      description: "Card payments (Nigeria/Ghana)",
      icon: CreditCard,
      color: "bg-purple-100 text-purple-700 border-purple-300",
      iconColor: "text-purple-600",
    },
    {
      id: "stripe" as PaymentMethod,
      label: "Stripe",
      description: "International cards",
      icon: Building2,
      color: "bg-blue-100 text-blue-700 border-blue-300",
      iconColor: "text-blue-600",
    },
    {
      id: "plaid" as PaymentMethod,
      label: "Plaid",
      description: "US Bank transfers",
      icon: Wallet,
      color: "bg-orange-100 text-orange-700 border-orange-300",
      iconColor: "text-orange-600",
    },
  ];

  const handlePayment = async () => {
    if (!invoiceId) {
      toast.error("No invoice selected for payment");
      return;
    }

    setIsProcessing(true);
    try {
      // Call payment initialization API
      const response = await fetch("/api/payments/initialize", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          invoiceId,
          paymentMethod: selectedMethod,
          ...(selectedMethod === "mpesa" && { phoneNumber }),
          ...(selectedMethod === "card" && { cardDetails }),
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        if (response.status === 401) {
          const returnUrl =
            typeof window !== "undefined"
              ? `${window.location.pathname}${window.location.search}`
              : "/";
          toast.error("Please sign in to continue with payment.");
          router.push(`/login?next=${encodeURIComponent(returnUrl)}`);
          return;
        }
        throw new Error(data.error || "Payment initialization failed");
      }

      // Handle M-Pesa STK Push flow
      if (selectedMethod === "mpesa" && data.gateway === "MPESA_DIRECT") {
        toast.success(
          `M-Pesa STK Push sent to ${phoneNumber}. Please check your phone to complete payment.`,
          { duration: 5000 }
        );
        
        // Show payment status monitoring
        monitorPaymentStatus(data.transactionId);
      } else {
        toast.success("Payment initialized successfully!");
        if (onPaymentSuccess) onPaymentSuccess();
        onClose();
      }
    } catch (error) {
      console.error("Payment error:", error);
      toast.error(error instanceof Error ? error.message : "Payment failed");
    } finally {
      setIsProcessing(false);
    }
  };

  const monitorPaymentStatus = async (transactionId: string) => {
    // In a real implementation, you would poll the payment status API
    // or use WebSocket to get real-time updates
    toast.loading("Waiting for payment confirmation...", { id: "payment-status" });
    
    // Simulate waiting for callback
    setTimeout(() => {
      toast.dismiss("payment-status");
      toast.success("Payment confirmed!", { duration: 3000 });
      if (onPaymentSuccess) onPaymentSuccess();
      onClose();
    }, 10000);
  };

  const formatAmount = () => {
    return new Intl.NumberFormat("en-KE", {
      style: "currency",
      currency: currency,
    }).format(amount);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onClose}>
      <DialogContent className="w-[min(100vw-1.5rem,720px)] max-h-[85vh] overflow-y-auto rounded-2xl border-slate-200/70 bg-white p-0 shadow-2xl dark:border-slate-800 dark:bg-slate-950">
        <div className="border-b border-slate-200/70 bg-gradient-to-r from-slate-50 via-white to-slate-50 px-6 py-5 dark:border-slate-800 dark:from-slate-950 dark:via-slate-950 dark:to-slate-950">
          <DialogHeader>
            <DialogTitle className="text-xl font-bold text-slate-900 dark:text-slate-100">
              Make Payment
            </DialogTitle>
            <DialogDescription className="text-slate-600 dark:text-slate-300">
              Pay your invoice using your preferred payment method
            </DialogDescription>
          </DialogHeader>

          {/* Mobile-only quick summary */}
          <div className="mt-4 flex items-center justify-between rounded-lg border border-blue-200/70 bg-blue-50 px-3 py-2 text-blue-900 sm:hidden">
            <div className="flex flex-col">
              <span className="text-[11px] uppercase tracking-wide text-blue-700">
                Amount
              </span>
              <span className="text-base font-semibold">{formatAmount()}</span>
            </div>
            <div className="h-8 w-px bg-blue-200/80" />
            <div className="flex flex-col text-right">
              <span className="text-[11px] uppercase tracking-wide text-blue-700">
                Invoice
              </span>
              <span className="text-sm font-semibold">
                #{invoiceId ? invoiceId.slice(0, 8) : "—"}
              </span>
            </div>
          </div>
        </div>

        <div className="space-y-6 px-6 py-5">
          {/* Amount Display */}
          <div className="rounded-xl border border-blue-200 bg-gradient-to-r from-blue-50 to-blue-100 p-4">
            <div className="flex justify-between items-center">
              <span className="text-sm font-medium text-blue-800">Amount to Pay</span>
              <span className="text-2xl font-bold text-blue-900">{formatAmount()}</span>
            </div>
            {invoiceId && (
              <p className="text-xs text-blue-700 mt-2">
                Invoice: #{invoiceId.slice(0, 8)}
              </p>
            )}
          </div>

          {/* Payment Method Selection */}
          <div className="space-y-4">
            <Label className="text-base font-semibold">Select Payment Method</Label>
            <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
              {paymentMethods.map((method) => {
                const Icon = method.icon;
                const isSelected = selectedMethod === method.id;
                return (
                  <div key={method.id} className="relative">
                    <input
                      type="radio"
                      id={method.id}
                      name="paymentMethod"
                      value={method.id}
                      checked={isSelected}
                      onChange={(e) => setSelectedMethod(e.target.value as PaymentMethod)}
                      className="sr-only peer"
                    />
                    <Label
                      htmlFor={method.id}
                      className={`group flex flex-col items-center justify-center rounded-xl border-2 p-4 text-center transition-all duration-200 hover:-translate-y-0.5 hover:shadow-md active:scale-[0.99] ${method.color} ${isSelected ? "border-2 ring-2 ring-blue-500 ring-offset-2" : ""}`}
                    >
                      <Icon className={`mb-2 h-8 w-8 transition-transform duration-200 group-hover:scale-110 ${method.iconColor}`} />
                      <span className="text-sm font-medium transition-colors duration-200 group-hover:text-slate-900">
                        {method.label}
                      </span>
                      <span className="mt-1 text-xs opacity-80">
                        {method.description}
                      </span>
                      <span className={`mt-2 h-1 w-10 rounded-full bg-current/30 transition-all duration-200 ${isSelected ? "w-16 bg-current/60" : "group-hover:w-12"}`} />
                    </Label>
                  </div>
                );
              })}
            </div>
          </div>

          {/* M-Pesa Phone Number Input */}
          {selectedMethod === "mpesa" && (
            <div className="space-y-3 rounded-xl border border-blue-200 bg-blue-50/70 p-4">
              <Label htmlFor="phone" className="text-sm font-medium text-blue-900">
                Enter M-Pesa Phone Number
              </Label>
              <div className="flex items-center gap-2">
                <span className="rounded-l-lg border border-blue-200 bg-white px-3 py-2 text-blue-700">
                  +254
                </span>
                <Input
                  id="phone"
                  type="tel"
                  placeholder="7XXXXXXXX"
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value.replace(/\D/g, ""))}
                  className="flex-1 rounded-l-none border-blue-200 bg-white focus-visible:ring-blue-500"
                />
              </div>
              <p className="text-xs text-blue-700/80">
                Enter your Safaricom number to receive STK Push prompt
              </p>
            </div>
          )}

          {/* Card Details Input (for demo) */}
          {selectedMethod === "card" && (
            <div className="space-y-4 rounded-lg border border-gray-200 p-4">
              <Label className="text-sm font-medium">Card Details</Label>
              <div className="space-y-3">
                <Input
                  placeholder="Card Number"
                  value={cardDetails.number}
                  onChange={(e) =>
                    setCardDetails({ ...cardDetails, number: e.target.value })
                  }
                />
                <div className="grid grid-cols-2 gap-3">
                  <Input
                    placeholder="MM/YY"
                    value={cardDetails.expiry}
                    onChange={(e) =>
                      setCardDetails({ ...cardDetails, expiry: e.target.value })
                    }
                  />
                  <Input
                    placeholder="CVC"
                    value={cardDetails.cvc}
                    onChange={(e) =>
                      setCardDetails({ ...cardDetails, cvc: e.target.value })
                    }
                  />
                </div>
                <Input
                  placeholder="Cardholder Name"
                  value={cardDetails.name}
                  onChange={(e) =>
                    setCardDetails({ ...cardDetails, name: e.target.value })
                  }
                />
              </div>
              <p className="text-xs text-gray-500">
                Note: This is a demo. Real card payments would use secure tokenization.
              </p>
            </div>
          )}

          {/* Payment Method Notes */}
          <div className="rounded-lg border border-gray-200 bg-gray-50 p-4">
            <h4 className="mb-2 text-sm font-medium text-gray-700">
              About {paymentMethods.find(m => m.id === selectedMethod)?.label}:
            </h4>
            {selectedMethod === "mpesa" && (
              <ul className="list-disc space-y-1 pl-4 text-xs text-gray-600">
                <li>You will receive an STK Push prompt on your phone</li>
                <li>Enter your M-Pesa PIN to complete payment</li>
                <li>Transaction fee: KSh 0 (waived for rent payments)</li>
              </ul>
            )}
            {selectedMethod === "paystack" && (
              <ul className="list-disc space-y-1 pl-4 text-xs text-gray-600">
                <li>Redirect to Paystack for secure payment</li>
                <li>Supports cards, bank transfers, and mobile money</li>
                <li>Available for Nigeria and Ghana residents</li>
              </ul>
            )}
            {selectedMethod === "stripe" && (
              <ul className="list-disc space-y-1 pl-4 text-xs text-gray-600">
                <li>Secure international card payments</li>
                <li>Supports Visa, Mastercard, American Express</li>
                <li>3D Secure authentication required</li>
              </ul>
            )}
            {selectedMethod === "plaid" && (
              <ul className="list-disc space-y-1 pl-4 text-xs text-gray-600">
                <li>Connect directly to your US bank account</li>
                <li>No card details needed</li>
                <li>ACH transfers with 2-3 business day settlement</li>
              </ul>
            )}
          </div>
        </div>

        <DialogFooter className="flex flex-col gap-3 border-t border-slate-200/70 px-6 py-5 sm:flex-row dark:border-slate-800">
          <Button
            type="button"
            variant="outline"
            onClick={onClose}
            disabled={isProcessing}
            className="sm:flex-1"
          >
            Cancel
          </Button>
          <Button
            type="button"
            onClick={handlePayment}
            disabled={isProcessing || (selectedMethod === "mpesa" && !phoneNumber)}
            className="sm:flex-1 bg-blue-600 hover:bg-blue-700"
          >
            {isProcessing ? (
              <>
                <span className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></span>
                Processing...
              </>
            ) : (
              `Pay ${formatAmount()}`
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { toast } from "react-hot-toast";

interface Receipt {
  id: string;
  receiptNo: string;
  issuedOn: string;
  paymentId: string;
  invoiceId: string;
}

interface Payment {
  id: string;
  amount: number;
  method: string;
  reference?: string;
  paidOn?: string;
  receipt?: Receipt[];
}

interface Lease {
  id: string;
}

interface Invoice {
  id: string;
  leaseId: string;
  amount: number;
  dueDate: string;
  status: "PENDING" | "PAID" | "OVERDUE";
  Lease: Lease;
  payment: Payment[];
}

interface TenantInvoicesProps {
  tenantId: string;
}

export default function TenantInvoices({ tenantId }: TenantInvoicesProps) {
  const [invoices, setInvoices] = useState<Invoice[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchInvoices();
  }, []);

  async function fetchInvoices() {
    setLoading(true);
    try {
      const res = await fetch(`/api/invoice/tenant/${tenantId}`);
      const data = await res.json();
      setInvoices(data);
    } catch (error) {
      console.error(error);
      toast.error("Failed to fetch invoices");
    } finally {
      setLoading(false);
    }
  }

  async function payInvoice(invoiceId: string) {
    try {
      const amountToPay = invoices.find(inv => inv.id === invoiceId)?.amount || 0;
      const res = await fetch(`/api/invoice/${invoiceId}/payments`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ amount: amountToPay, method: "Mpesa" }),
      });

      const data = await res.json();
      if (res.ok) {
        toast.success("Payment successful");
        fetchInvoices();
      } else {
        toast.error(data.error || "Payment failed");
      }
    } catch (error) {
      console.error(error);
      toast.error("Payment failed");
    }
  }

  async function viewReceipt(paymentId: string) {
    try {
      const res = await fetch(`/api/receipt/${paymentId}`);
      if (!res.ok) throw new Error("Receipt not found");
      const receipt: Receipt = await res.json();

      // Open PDF or show receipt details
      // Here we simply alert the receipt number, you can integrate PDF download later
      alert(`Receipt No: ${receipt.receiptNo}\nIssued On: ${new Date(receipt.issuedOn).toLocaleDateString()}`);
    } catch (error) {
      console.error(error);
      toast.error("Failed to fetch receipt");
    }
  }

  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">My Invoices</h1>
      {loading ? (
        <p>Loading invoices...</p>
      ) : invoices.length === 0 ? (
        <p>No invoices found.</p>
      ) : (
        <table className="w-full border-collapse border">
          <thead>
            <tr className="bg-gray-200">
              <th className="border px-4 py-2">Invoice No</th>
              <th className="border px-4 py-2">Amount (USD)</th>
              <th className="border px-4 py-2">Due Date</th>
              <th className="border px-4 py-2">Status</th>
              <th className="border px-4 py-2">Action</th>
            </tr>
          </thead>
          <tbody>
            {invoices.map((inv, idx) => (
              <tr key={inv.id} className={idx % 2 === 0 ? "bg-gray-50" : ""}>
                <td className="border px-4 py-2">{inv.id.slice(0, 8)}</td>
                <td className="border px-4 py-2">{inv.amount.toFixed(2)}</td>
                <td className="border px-4 py-2">{new Date(inv.dueDate).toLocaleDateString()}</td>
                <td className="border px-4 py-2">{inv.status}</td>
                <td className="border px-4 py-2 flex gap-2">
                  {inv.status === "PENDING" && (
                    <Button onClick={() => payInvoice(inv.id)}>Pay Now</Button>
                  )}
                  {inv.status === "PAID" &&
                    inv.payment?.map(pmt =>
                      pmt.receipt?.map(rcpt => (
                        <Button key={rcpt.id} onClick={() => viewReceipt(pmt.id)}>
                          View Receipt
                        </Button>
                      ))
                    ) || []}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

