    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setFile(e.target.files[0]);
        }
    };

    const updateParticipant = (index: number, field: keyof Participant, value: string) => {
        const newParts = [...participants];
        newParts[index] = { ...newParts[index], [field]: value };
        setParticipants(newParts);
    };

    const removeParticipant = (index: number) => {
        setParticipants(participants.filter((_, i) => i !== index));
    };

    const addParticipant = () => {
        setParticipants([...participants, { email: "", fullName: "", role: "WITNESS" }]);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!file || !title) {
            toast.error("Please provide a title and a file.");
            return;
        }

        setLoading(true);
        const formData = new FormData();
        formData.append("file", file);
        formData.append("title", title);
        formData.append("participants", JSON.stringify(participants));

        try {
            const res = await fetch("/api/dss/documents", {
                method: "POST",
                body: formData,
            });

            const data = await res.json();

            if (!res.ok) throw new Error(data.error);

            toast.success("Document created & hashed successfully!");
            // Redirect to the "Signing Room" or List (We will build this next)
            // router.push(`/property-manager/dss/${data.data.id}`);

        } catch (error: any) {
            console.error(error);
            toast.error(error.message || "Upload failed");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-2xl mx-auto p-6 bg-white rounded-xl shadow-md border border-gray-200">
            <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                <Upload className="w-5 h-5 text-blue-600" />
                Upload New Contract
            </h2>

            <form onSubmit={handleSubmit} className="space-y-6">
                {/* Title */}
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Document Title</label>
                    <input
                        type="text"
                        className="w-full p-2 border rounded-md"
                        placeholder="e.g. Lease Agreement - Unit 101"
                        value={title}
                        onChange={(e) => setTitle(e.target.value)}
                        required
                    />
                </div>

                {/* File Drop Area (Simple) */}
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Upload PDF</label>
                    <input
                        type="file"
                        accept="application/pdf"
                        onChange={handleFileChange}
                        className="w-full p-2 border border-dashed border-gray-300 rounded-md bg-gray-50"
                        required
                    />
                </div>

                {/* Participants List */}
                <div>
                    <div className="flex justify-between items-center mb-2">
                        <label className="block text-sm font-medium text-gray-700">Signers (Ordered)</label>
                        <button type="button" onClick={addParticipant} className="text-sm text-blue-600 hover:underline flex items-center gap-1">
                            <Plus size={14} /> Add Signer
                        </button>
                    </div>

                    <div className="space-y-3">
                        {participants.map((p, index) => (
                            <div key={index} className="flex gap-2 items-start p-3 bg-gray-50 rounded-md border">
                                <span className="mt-2 text-xs font-bold text-gray-400 w-4">{index + 1}.</span>

                                <div className="grid grid-cols-1 md:grid-cols-3 gap-2 flex-1">
                                    <input
                                        placeholder="Full Name"
                                        className="p-2 text-sm border rounded"
                                        value={p.fullName}
                                        onChange={(e) => updateParticipant(index, "fullName", e.target.value)}
                                        required
                                    />
                                    <input
                                        type="email"
                                        placeholder="Email"
                                        className="p-2 text-sm border rounded"
                                        value={p.email}
                                        onChange={(e) => updateParticipant(index, "email", e.target.value)}
                                        required
                                    />
                                    <select
                                        className="p-2 text-sm border rounded bg-white"
                                        value={p.role}
                                        onChange={(e) => updateParticipant(index, "role", e.target.value)}
                                    >
                                        <option value="TENANT">Tenant</option>
                                        <option value="LANDLORD">Landlord</option>
                                        <option value="WITNESS">Witness</option>
                                    </select>
                                </div>

                                <button
                                    type="button"
                                    onClick={() => removeParticipant(index)}
                                    className="mt-2 text-red-400 hover:text-red-600"
                                >
                                    <Trash size={16} />
                                </button>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Submit */}
                <button
                    type="submit"
                    disabled={loading}
                    className="w-full bg-blue-600 text-white py-2.5 rounded-lg font-semibold hover:bg-blue-700 disabled:opacity-50 flex justify-center items-center gap-2"
                >
                    {loading ? <Loader2 className="animate-spin" /> : "Create & Hash Document"}
                </button>
            </form>
        </div>
    );
}

"use client";
import { useState, useEffect, useCallback } from "react";
import { usePlaidLink, PlaidLinkOnSuccess, PlaidLinkOnExit } from "react-plaid-link";

interface ConnectBankProps {
    userId: string;
    onConnected: () => void;
}

export default function ConnectBank({ userId, onConnected }: ConnectBankProps) {
    const [token, setToken] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);

    // 1. Fetch Link Token on Mount
    useEffect(() => {
        async function createLinkToken() {
            try {
                const res = await fetch("/api/plaid/create-link-token", { method: "POST" });
                const data = await res.json();
                if (data.link_token) {
                    setToken(data.link_token);
                } else {
                    console.error("Failed to get link token", data);
                }
            } catch (e) {
                console.error("Error creating link token", e);
            }
        }
        createLinkToken();
    }, []);

    // 2. Handle Success (User selected bank)
    const onSuccess = useCallback<PlaidLinkOnSuccess>(async (publicToken, metadata) => {
        setLoading(true);
        try {
            // metadata contains account_id
            // We typically want the first account for simplicity in this MVP, 
            // or we could let the user select if we support multiple. 
            // Plaid Link usually lets user select one account if we configure it so.
            // metadata.accounts is an array.
            const accountId = metadata.accounts[0]?.id;

            if (!accountId) {
                throw new Error("No account selected");
            }

            await fetch("/api/plaid/exchange-token", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ publicToken, accountId, userId }),
            });

            onConnected(); // Refresh UI to show "Bank Connected"
        } catch (error) {
            console.error("Exchange token failed", error);
        } finally {
            setLoading(false);
        }
    }, [userId, onConnected]);

    const onExit = useCallback<PlaidLinkOnExit>((error, metadata) => {
        if (error) {
            console.error("Plaid Link exited with error", error);
        }
    }, []);

    const config: Parameters<typeof usePlaidLink>[0] = {
        token,
        onSuccess,
        onExit,
    };

    const { open, ready } = usePlaidLink(config);

    return (
        <div className="mt-4">
            <button
                onClick={() => open()}
                disabled={!ready || loading}
                className="bg-green-600 hover:bg-green-700 text-white font-semibold py-2 px-4 rounded shadow-md transition-colors"
            >
                {loading ? "Connecting..." : "Connect Bank Account (ACH)"}
            </button>
        </div>
    );
}

'use client';
import React, { useEffect, useRef } from 'react';
import 'leaflet/dist/leaflet.css';

interface PropertyMapProps {
  initialLat: number;
  initialLng: number;
  onMarkerPositionChange: (lat: number, lng: number) => void;
  height?: string;
  zoom?: number;
  isDraggable?: boolean;
}

const PropertyMap: React.FC<PropertyMapProps> = ({
  initialLat,
  initialLng,
  onMarkerPositionChange,
  height = '400px',
  zoom = 15,
  isDraggable = true,
}) => {
  const mapRef = useRef<HTMLDivElement | null>(null);
  const mapInstanceRef = useRef<any>(null);
  const markerRef = useRef<any>(null);

  // Initialize map once
  useEffect(() => {
    if (!mapRef.current || mapInstanceRef.current) return;

    import('leaflet').then((L) => {
      // marker icons
      delete (L.Icon.Default.prototype as any)._getIconUrl;
      L.Icon.Default.mergeOptions({
        iconRetinaUrl:
          'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
        iconUrl:
          'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
        shadowUrl:
          'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
      });

      const map = L.map(mapRef.current!).setView(
        [initialLat, initialLng],
        zoom
      );

      L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© OpenStreetMap contributors',
        maxZoom: 19,
      }).addTo(map);

      const marker = L.marker([initialLat, initialLng], {
        draggable: isDraggable,
      }).addTo(map);

      if (isDraggable) {
        marker.on('dragend', () => {
          const { lat, lng } = marker.getLatLng();
          onMarkerPositionChange(lat, lng);
        });
      }

      mapInstanceRef.current = map;
      markerRef.current = marker;

      // Fix map sizing issues
      setTimeout(() => {
        map.invalidateSize();
      }, 200);
    });

    return () => {
      mapInstanceRef.current?.remove();
      mapInstanceRef.current = null;
      markerRef.current = null;
    };
  }, []);

  // Update marker + map when coordinates change
  useEffect(() => {
    if (!mapInstanceRef.current || !markerRef.current) return;

    import('leaflet').then((L) => {
      const latLng = L.latLng(initialLat, initialLng);
      markerRef.current.setLatLng(latLng);
      mapInstanceRef.current.setView(latLng, zoom);
    });
  }, [initialLat, initialLng, zoom]);

  return (
    <div className="rounded-lg overflow-hidden shadow-md">
      <div
        ref={mapRef}
        style={{ width: '100%', height }}
        className="z-0"
      />
    </div>
  );
};

export default PropertyMap;

"use client";
import React, { useCallback, useEffect, useRef, useState } from "react";
import { AnimatePresence, motion, LayoutGroup } from "framer-motion";
import { cn } from "@/lib/utils";

export const FlipWords = ({
  words,
  duration = 3000,
  className,
}: {
  words: string[];
  duration?: number;
  className?: string;
}) => {
  const [currentWord, setCurrentWord] = useState(words[0]);
  const [isAnimating, setIsAnimating] = useState<boolean>(false);

  const startAnimation = useCallback(() => {
    const word = words[words.indexOf(currentWord) + 1] || words[0];
    setCurrentWord(word);
    setIsAnimating(true);
  }, [currentWord, words]);

  useEffect(() => {
    if (!isAnimating)
      setTimeout(() => {
        startAnimation();
      }, duration);
  }, [isAnimating, duration, startAnimation]);

  return (
    <AnimatePresence
      onExitComplete={() => {
        setIsAnimating(false);
      }}
    >
      <motion.div
        initial={{
          opacity: 0,
          y: 10,
        }}
        animate={{
          opacity: 1,
          y: 0,
        }}
        transition={{
          type: "spring",
          stiffness: 100,
          damping: 10,
        }}
        exit={{
          opacity: 0,
          y: -40,
          x: 40,
          filter: "blur(8px)",
          scale: 2,
          position: "absolute",
        }}
        className={cn(
          "z-10 inline-block relative text-left text-[#0089bf neutral-900  px-2",
          className
        )}
        key={currentWord}
      >
        {/* edit suggested by Sajal: https://x.com/DewanganSajal */}
        {currentWord.split(" ").map((word, wordIndex) => (
          <motion.span
            key={word + wordIndex}
            initial={{ opacity: 0, y: 10, filter: "blur(8px)" }}
            animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
            transition={{
              delay: wordIndex * 0.3,
              duration: 0.3,
            }}
            className="inline-block whitespace-nowrap"
          >
            {word.split("").map((letter, letterIndex) => (
              <motion.span
                key={word + letterIndex}
                initial={{ opacity: 0, y: 10, filter: "blur(8px)" }}
                animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
                transition={{
                  delay: wordIndex * 0.3 + letterIndex * 0.05,
                  duration: 0.2,
                }}
                className="inline-block"
              >
                {letter}
              </motion.span>
            ))}
            <span className="inline-block">&nbsp;</span>
          </motion.span>
        ))}
      </motion.div>
    </AnimatePresence>
  );
};

"use client";

import { cn } from "@/lib/utils";
import { motion, stagger, useAnimate, useInView } from "motion/react";
import { useEffect } from "react";

export const TypewriterEffect = ({
  words,
  className,
  cursorClassName,
}: {
  words: {
    text: string;
    className?: string;
  }[];
  className?: string;
  cursorClassName?: string;
}) => {
  // split text inside of words into array of characters
  const wordsArray = words.map((word) => {
    return {
      ...word,
      text: word.text.split(""),
    };
  });

  const [scope, animate] = useAnimate();
  const isInView = useInView(scope);
  useEffect(() => {
    if (isInView) {
      animate(
        "span",
        {
          display: "inline-block",
          opacity: 1,
          width: "fit-content",
        },
        {
          duration: 0.3,
          delay: stagger(0.1),
          ease: "easeInOut",
        }
      );
    }
  }, [isInView]);

  const renderWords = () => {
    return (
      <motion.div ref={scope} className="inline">
        {wordsArray.map((word, idx) => {
          return (
            <div key={`word-${idx}`} className="inline-block">
              {word.text.map((char, index) => (
                <motion.span
                  initial={{}}
                  key={`char-${index}`}
                  className={cn(
                    `text-white opacity-0 hidden`,
                    word.className
                  )}
                >
                  {char}
                </motion.span>
              ))}
              &nbsp;
            </div>
          );
        })}
      </motion.div>
    );
  };
  return (
    <div
      className={cn(
        "text-base sm:text-xl md:text-3xl lg:text-5xl font-bold text-center",
        className
      )}
    >
      {renderWords()}
      <motion.span
        initial={{
          opacity: 0,
        }}
        animate={{
          opacity: 1,
        }}
        transition={{
          duration: 0.8,
          repeat: Infinity,
          repeatType: "reverse",
        }}
        className={cn(
          "inline-block rounded-sm w-[4px] h-4 md:h-6 lg:h-10 bg-blue-500",
          cursorClassName
        )}
      ></motion.span>
    </div>
  );
};

