'use client'
import { useState } from "react";
import { Logo } from "@/components/Logo";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { useRouter, useSearchParams } from "next/navigation";
import { ArrowRight, Eye, EyeOff, Mail, Lock } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/context/AuthContext";
import { useEffect } from "react";

const LoginPageContent = () => {
  const { login } = useAuth();
  const router = useRouter();
  const searchParams = useSearchParams();
  const [formData, setFormData] = useState({
    email: "",
    password: ""
  });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [showPassword, setShowPassword] = useState(false);

  // ✅ Handle Verification Toasts
  useEffect(() => {
    const verified = searchParams.get('verified');
    const errorParam = searchParams.get('error');

    if (verified === 'true') {
      toast.success("Email verified successfully! Please log in.", {
        duration: 6000,
        className: 'bg-navy-50 text-green-800 border-navy-200'
      });
      // Clean URL
      router.replace('/login');
    }

    if (errorParam) {
      let msg = "Authentication error";
      if (errorParam === 'invalid_token') msg = "Verification link is invalid or expired.";
      if (errorParam === 'missing_token') msg = "Invalid verification link.";

      toast.error(msg, {
        duration: 6000,
      });
      setError(msg);
      router.replace('/login');
    }
  }, [searchParams, router]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    if (error) setError("");
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    if (!formData.email || !formData.password) {
      setError("Please fill in all fields");
      return;
    }

    setIsLoading(true);

    try {
      const response = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(formData),
      });

      if (response.ok) {
        const data = await response.json();


        // AuthContext.login expects the full token bundle (access/refresh/expiresAt)
        login(data.user, data.tokens);

        toast.success("Login successful! Redirecting...");

        // Redirect based on user role
        switch (data.user.role) {
          case "SYSTEM_ADMIN":
            router.push("/admin");
            break;
          case "PROPERTY_MANAGER":
            router.push("/property-manager");
            break;
          case "TENANT":
            router.push("/tenant");
            break;
          case "VENDOR":
            router.push("/vendor");
            break;
          default:
            router.push("/");
        }

      } else {
        const err = await response.json();
        let errorMsg = err.error || 'Invalid credentials';

        if (response.status === 404) {
          errorMsg = 'User does not exist. Please create an account to continue.';
        } else if (response.status === 401) {
          // credential mismatch
          errorMsg = 'Invalid email or password.';
        }

        setError(errorMsg);
        toast.error(errorMsg, { duration: 4000 });
      }
    } catch (error) {
      const errorMsg = "Network error. Please try again.";
      setError(errorMsg);
      toast.error(errorMsg, { duration: 4000 });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full p-8 lg:p-10">
      <Logo className="w-28 h-28" />

      <div className="text-center mb-8">
        <p className="text-neutral-500 text-sm lg:text-base">
          Sign in to manage your properties and access your dashboard
        </p>
      </div>

      {/* Login Form */}
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Email */}
        <div className="relative">
          <div className="absolute left-3 top-1/2 transform -translate-y-1/2 text-neutral-400">
            <Mail className="w-5 h-5" />
          </div>
          <Input
            type="email"
            name="email"
            placeholder="Email Address *"
            value={formData.email}
            onChange={handleInputChange}
            required
            className="h-12 pl-11 pr-4 text-base bg-white border-neutral-200 text-neutral-900 placeholder:text-neutral-400 focus:bg-white focus:border-[#003b73] focus:ring-2 focus:ring-[#003b73]/20 transition-all"
          />
        </div>

        {/* Password */}
        <div className="relative">
          <div className="absolute left-3 top-1/2 transform -translate-y-1/2 text-neutral-400">
            <Lock className="w-5 h-5" />
          </div>
          <Input
            type={showPassword ? "text" : "password"}
            name="password"
            placeholder="Password *"
            value={formData.password}
            onChange={handleInputChange}
            required
            className="h-12 pl-11 pr-12 text-base bg-white border-neutral-200 text-neutral-900 placeholder:text-neutral-400 focus:bg-white focus:border-[#003b73] focus:ring-2 focus:ring-[#003b73]/20 transition-all"
          />
          <button
            type="button"
            onClick={() => setShowPassword(!showPassword)}
            className="absolute right-3 top-1/2 transform -translate-y-1/2 text-neutral-400 hover:text-neutral-600 transition-colors"
          >
            {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
          </button>
        </div>

        {/* Forgot Password */}
        <div className="text-right">
          <a
            href="/forgot-password"
            className="text-sm text-neutral-500 hover:text-[#003b73] font-medium hover:underline"
          >
            Forgot your password?
          </a>
        </div>

        {/* Error Message */}
        {error && (
          <div className="p-3 bg-red-50 border border-red-200 rounded-lg">
            <p className="text-red-600 text-sm text-center">{error}</p>
          </div>
        )}

        <Button
          type="submit"
          disabled={isLoading}
          className="w-full h-12 bg-[#003b73] hover:bg-[#002b5b] text-white text-base font-semibold transition-all duration-300"
        >
          {isLoading ? (
            <div className="flex items-center justify-center">
              <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2" />
              Signing In...
            </div>
          ) : (
            <>
              Sign In
              <ArrowRight className="w-4 h-4 ml-2" />
            </>
          )}
        </Button>
      </form>

      {/* Sign Up Link */}
      <div className="text-center mt-8 pt-6 border-t border-neutral-100">
        <p className="text-neutral-500">
          Don't have an account?{" "}
          <a
            href="/signup"
            className="text-neutral-600 hover:text-[#003b73] font-semibold underline underline-offset-2 transition-colors"
          >
            Sign up here
          </a>
        </p>
      </div>
    </div>
  );
};

export default LoginPageContent;

import { NavbarClient } from "./NavbarClient";
import { prisma } from "@/lib/db";

interface NavbarItem {
  id: number;
  name: string;
  href: string;
  order: number;
  isVisible: boolean;
  isAvailable: boolean;
}

let navbarCache: { expiresAt: number; data: NavbarItem[] } | null = null
const NAVBAR_CACHE_TTL = 30 * 1000 // 30 seconds

async function getNavbarItems(): Promise<NavbarItem[]> {
  const now = Date.now()
  if (navbarCache && navbarCache.expiresAt > now) {
    return navbarCache.data
  }

  try {

    const raw = await prisma.navbarItem.findMany({
      where: {
        isVisible: true,
        isAvailable: true,
        parentId: null,
      },
      include: {
        children: {
          where: { isVisible: true, isAvailable: true },
          orderBy: { order: 'asc' },
        },
      },
      orderBy: { order: 'asc' },
    });

    const items: NavbarItem[] = raw.map((i: any) => ({
      id: i.id,
      name: i.name === "Service" ? "Services" : i.name,
      href: i.href,
      order: i.order,
      isVisible: i.isVisible,
      isAvailable: i.isAvailable,
    }));

    // Attach children if present 
    const itemsWithChildren = raw.map((i: any) => ({
      id: i.id,
      name: i.name === "Service" ? "Services" : i.name,
      href: i.href,
      order: i.order,
      isVisible: i.isVisible,
      isAvailable: i.isAvailable,
      children: i.children?.map((c: any) => ({
        id: c.id,
        name: c.name === "Service" ? "Services" : c.name,
        href: c.href,
        order: c.order,
        isVisible: c.isVisible,
        isAvailable: c.isAvailable,
        parentId: c.parentId,
      })) || [],
    })) as unknown as NavbarItem[];

    // Cache result
    navbarCache = { expiresAt: now + NAVBAR_CACHE_TTL, data: itemsWithChildren };
    return itemsWithChildren;
  } catch (error) {
    console.error("Error fetching navbar items:", error);
    return [];
  }
}

export default async function Navbar() {
  const navLinks = await getNavbarItems();

  return <NavbarClient navLinks={navLinks} />;
}

"use client";

import { useState, useEffect } from "react";
import { Button } from "../ui/button";
import { Bell, ChevronDown } from "lucide-react";
import Image from "next/image";
import Logo from "@/assets/rf_logo.jpeg";
import Link from "next/link";
import { useAuth } from "@/context/AuthContext";
import { useRouter, usePathname } from "next/navigation";
import { MobileMenu } from "./ MobileMenu";

interface NavbarItem {
  id: number;
  name: string;
  href: string;
  order: number;
  isVisible: boolean;
  isAvailable: boolean;
  parentId?: number | null;
  children?: NavbarItem[];
}

interface NavbarClientProps {
  navLinks: NavbarItem[];
}

export const NavbarClient = ({ navLinks }: NavbarClientProps) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [openSubmenu, setOpenSubmenu] = useState<number | null>(null);

  const { user, logout } = useAuth();
  const router = useRouter();
  const pathname = usePathname();

  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const handleLogout = async () => {
    await logout();
    router.push("/login");
  };

  const getDashboardPath = () => {
    if (!user) return "/login";
    const roleDashboards = {
      SYSTEM_ADMIN: "/admin",
      PROPERTY_MANAGER: "/property-manager",
      TENANT: "/tenant",
      VENDOR: "/vendor",
    };
    return roleDashboards[user.role as keyof typeof roleDashboards] || "/dashboard";
  };

  const getUserInitials = () => {
    if (!user) return "U";
    return `${user.firstName?.[0] || ""}${user.lastName?.[0] || ""}`.toUpperCase();
  };

  const formatRoleName = (role: string) =>
    role.replace("_", " ").replace(/\b\w/g, (l) => l.toUpperCase());

  // Remove Privacy Policy from the top navbar (retain link in footer)
  const filteredNavLinks = navLinks.filter((n) => n.name !== "Privacy Policy");

  // Base text color should always be dark because the landing page hero is light
  const textColor = "text-slate-700";
  const hoverColor = "hover:text-[#003b73]";

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${isScrolled
        ? "bg-white shadow-md py-2"
        : "bg-white py-4 border-b border-slate-100"
        }`}
    >
      <div className="site-container">
        <div className="flex items-center justify-between h-20 sm:h-24 transition-all duration-500">
          {/* Logo */}
          <Link href="/" className="flex items-center group cursor-pointer">
            <div className="relative w-20 h-20 sm:w-24 sm:h-24 transition-all duration-500 group-hover:scale-105">
              <Image
                src={Logo}
                alt="RentFlow360"
                fill
                className="object-contain mix-blend-multiply"
                priority
              />
            </div>
          </Link>

          {/* Navigation Links */}
          <div className="hidden md:flex items-center gap-1">
            {filteredNavLinks.map((link) => (
              <div
                key={link.id}
                className="relative group px-1"
                onMouseEnter={() => link.children?.length && setOpenSubmenu(link.id)}
                onMouseLeave={() => setOpenSubmenu(null)}
              >
                {link.children && link.children.length > 0 ? (
                  <>
                    <button
                      className={`font-medium text-[15px] px-3 py-2 transition-all duration-300 flex items-center gap-1 group relative
                        ${pathname.startsWith(link.href) && link.href !== "/"
                          ? "text-[#003b73]"
                          : `${textColor} ${hoverColor}`
                        }
                        ${openSubmenu === link.id ? "text-[#003b73]" : ""}
                      `}
                    >
                      {link.name}
                      <ChevronDown className={`h-4 w-4 transition-transform duration-200 ${openSubmenu === link.id ? 'rotate-180' : ''}`} />

                      {/* Submenu Trigger Underline */}
                      <span className={`absolute bottom-0 left-1 right-1 h-0.5 bg-[#003b73] transition-all duration-300 
                        ${(pathname.startsWith(link.href) && link.href !== "/") || openSubmenu === link.id ? "w-[calc(100%-8px)]" : "w-0 group-hover:w-[calc(100%-8px)]"}
                      `} />
                    </button>

                    {/* Submenu Dropdown */}
                    <div
                      className={`absolute top-full left-0 mt-2 w-56 bg-white rounded-xl shadow-lg border border-slate-100 py-2 transition-all duration-200 transform origin-top-left ${openSubmenu === link.id
                        ? "opacity-100 visible translate-y-0 scale-100"
                        : "opacity-0 invisible -translate-y-2 scale-95"
                        }`}
                    >
                      {link.children.map((child) => (
                        <Link
                          key={child.id}
                          href={child.href}
                          className="block px-4 py-2.5 text-sm font-medium text-slate-600 hover:bg-[#003b73] hover:text-white transition-colors"
                        >
                          {child.name}
                        </Link>
                      ))}
                    </div>
                  </>
                ) : (
                  <Link
                    href={link.href}
                    className={`relative font-medium text-[15px] px-4 py-2 transition-all duration-300 block group
                      ${pathname === link.href
                        ? "text-[#003b73]"
                        : `${textColor} hover:text-[#003b73]`
                      }
                    `}
                  >
                    {link.name}
                    <span className={`absolute bottom-0 left-4 right-4 h-0.5 bg-[#003b73] transition-all duration-300
                      ${pathname === link.href ? "w-[calc(100%-32px)]" : "w-0 group-hover:w-[calc(100%-32px)]"}
                    `} />
                  </Link>
                )}
              </div>
            ))}
          </div>

          {/* User Actions */}
          <div className="hidden md:flex items-center space-x-4">
            {
              <>
                <Link href="/login">
                  <Button
                    variant="outline"
                    className={`font-semibold text-[15px] px-5 h-10 rounded-full border-[#003b73] text-[#003b73] hover:bg-[#f0f7ff] hover:text-[#002b5b] transition-all duration-300`}
                  >
                    Login
                  </Button>
                </Link>

                <Link href="/signup">
                  <Button
                    className="h-10 px-6 rounded-full text-[15px] font-bold text-white bg-[#003b73] hover:bg-[#002b5b] shadow-sm hover:shadow-md transition-all duration-300"
                  >
                    Sign up
                  </Button>
                </Link>
              </>
            }
          </div>

          {/* Mobile Menu */}
          <MobileMenu
            scrollProgress={isScrolled ? 1 : 0}
            navLinks={filteredNavLinks}
          />
        </div>
      </div>
    </nav>
  );
};

// src/components/website/PropertyManager/RegisterPropertyForm.tsx
'use client'
import React, { useState } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import { postProperty, PropertyPayload } from "@/lib/property-manager";
import { usePropertyForm } from "@/hooks/usePropertyForm";
import { useGeocoding } from "@/hooks/useGeocoding";
import { toast } from "sonner";
import { Loader2 } from "lucide-react";
import { LocationForm } from "@/components/website/PropertyManager/sub-propertyFroms/LocationForm";
import { HouseDetailForm } from "@/components/website/PropertyManager/sub-propertyFroms/HouseDetailForm";
import { ApartmentDetailForm } from "@/components/website/PropertyManager/sub-propertyFroms/ApartmentDetailForm";
import { CondoDetailForm } from "@/components/website/PropertyManager/sub-propertyFroms/CondoDetailForm";
import { LandDetailForm } from "@/components/website/PropertyManager/sub-propertyFroms/landDetailForm";
import { TownhouseDetailForm } from "@/components/website/PropertyManager/sub-propertyFroms/TownhouseDetailForm";
import { ContactDetailsForm } from "@/components/website/PropertyManager/sub-propertyFroms/ContactDetailsForm";
import PropertyCreationSuccessModal from "./PropertyCreationSuccessModal";
import { Property } from "@/app/data/PropertyData";

interface PropertyFormProps {
  onSuccess?: () => void;
}

export default function PropertyForm({ onSuccess }: PropertyFormProps) {
  const router = useRouter();
  const { user } = useAuth();
  const { form, propertyTypes, appliances } = usePropertyForm();
  const { register, handleSubmit, watch, reset, setValue } = form;
  const [loading, setLoading] = useState(false);
  const [uploadingImages, setUploadingImages] = useState(false);
  const [uploadProgress, setUploadProgress] = useState("");
  const [showSuccessModal, setShowSuccessModal] = useState(false);
  const [createdPropertyId, setCreatedPropertyId] = useState<string | null>(null);
  const [successfulImageCount, setSuccessfulImageCount] = useState(0);

  const selectedPropertyTypeId = watch("propertyTypeId");
  const selectedPropertyTypeName = propertyTypes.find(
    (type) => type.id === selectedPropertyTypeId
  )?.name?.toLowerCase();

  const [country, city, zipCode, address] = watch(["country", "city", "zipCode", "address"]);

  const {
    coordinates: mapCoordinates,
    loading: mapLoading,
    showMap,
    setCoordinates: setMapCoordinates,
    setShowMap,
  } = useGeocoding({ country, city, zipCode, address }, setValue);

  const handleMarkerPositionChange = (lat: number, lng: number) => {
    setValue("latitude", lat);
    setValue("longitude", lng);
  };

  const onSubmit = async (data: Property) => {
    if (!user) {
      toast.error("Unauthorized", {
        description: "You must be logged in to create a property."
      });
      return;
    }

    if (!mapCoordinates) {
      toast.error("Location Missing", {
        description: "Please pin the property location on the map before submitting."
      });
      return;
    }

    setLoading(true);
    setUploadProgress("Creating property...");

    const payload: PropertyPayload = {
      manager: {
        id: user.id,
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        orgUserId: user.organizationUserId!,
        organizationId: user.organization!.id,
      },
      organizationId: user.organization!.id,
      name: data.name,
      propertyTypeId: selectedPropertyTypeId!,
      locationId: data.locationId!,
      city: data.city,
      address: data.address,
      country: data.country,
      zipCode: data.zipCode,
      latitude: data.latitude,
      longitude: data.longitude,
      amenities: data.amenities,
      isFurnished: data.isFurnished,
      availabilityStatus: data.availabilityStatus,
      contactPhone: data.contactPhone,
      contactEmail: data.contactEmail,
      propertyDetails:
        selectedPropertyTypeName === "apartment"
          ? data.apartmentComplexDetail
          : selectedPropertyTypeName === "house"
            ? data.houseDetail
            : undefined,
      applianceIds: data.applianceIds || [],
    };

    try {
      // Create property
      const result = await postProperty(payload);
      console.log("Property creation result:", result);
      const propertyId = result.property.id;

      console.log("Property created with ID:", propertyId);
      toast.success("Property created successfully!");
      setCreatedPropertyId(propertyId);

      let imageCount = 0;
      
      // Upload images if any
      if (data.images && data.images.length > 0) {
        setUploadingImages(true);
        setUploadProgress(`Uploading ${data.images.length} images to Cloudinary...`);

        const formData = new FormData();
        formData.append("propertyId", propertyId);

        Array.from(data.images).forEach((file, index) => {
          formData.append("images", file);
          formData.append("orders", index.toString());
        });

        const imageUploadRes = await fetch("/api/property-post/upload-image", {
          method: "POST",
          body: formData,
        });

        if (!imageUploadRes.ok) {
          const errorData = await imageUploadRes.json();
          throw new Error(errorData.error || "Image upload failed");
        }

        const uploadResult = await imageUploadRes.json();
        console.log("Images uploaded and saved:", uploadResult);
        
        imageCount = uploadResult.images.length;
        setSuccessfulImageCount(imageCount);

        toast.success(
          `All done! ${imageCount} images uploaded to Cloudinary and saved to database.`
        );
        setUploadingImages(false);
      }

      // Reset form
      reset();
      setMapCoordinates(null);
      setShowMap(false);
      setUploadProgress("");

      // Show success modal
      setShowSuccessModal(true);

      if (onSuccess) {
        onSuccess();
      }
    } catch (error: unknown) {
      console.error("Error creating property:", error);
      const errorMessage = error instanceof Error ? error.message : "Failed to create property.";
      toast.error(errorMessage);
      setUploadProgress("");
    } finally {
      setLoading(false);
      setUploadingImages(false);
    }
  };

  // Navigation handlers
  const handleViewPropertyAnalytics = (propertyId: string) => {
    // Use property detail page (simpler route that exists)
    router.push(`/property-manager`);
    setShowSuccessModal(false);
    // TODO: In future, use property detail page when Next.js type issues are resolved
    // router.push(`/property-manager/view-own-property/${propertyId}`);
  };

  const handleReturnToDashboard = () => {
    router.push('/property-manager');
    setShowSuccessModal(false);
  };

  const handleAddAnotherProperty = () => {
    // Modal will close, form is already reset
    setShowSuccessModal(false);
    // Optional: Scroll to top of form
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleCloseModal = () => {
    setShowSuccessModal(false);
    // Default action: return to dashboard if user closes modal
    router.push('/property-manager');
  };

  return (
    <div className="bg-gradient-to-b from-gray-50 to-gray-200">

      <main className="max-w-4xl mx-auto px-6 sm:px-8 py-8">
        <div className="bg-white">
          <div className="flex items-center gap-2 mb-8">
            <h2 className="text-3xl font-bold text-gray-800">Property Details</h2>
          </div>

          <form onSubmit={handleSubmit(onSubmit)} className="space-y-8">
            <LocationForm
              register={register}
              watch={watch}
              propertyTypes={propertyTypes}
              mapLoading={mapLoading}
              mapCoordinates={mapCoordinates}
              showMap={showMap}
              onMarkerPositionChange={handleMarkerPositionChange}
            />

            {selectedPropertyTypeName === "house" && (
              <HouseDetailForm register={register} />
            )}

            {selectedPropertyTypeName === "apartment" && (
              <ApartmentDetailForm register={register} />
            )}
            
            {(selectedPropertyTypeName === "condominium (condo)" || 
              selectedPropertyTypeName === "condo" || 
              selectedPropertyTypeName === "condominium") && (
              <CondoDetailForm register={register} />
            )}
 
            {selectedPropertyTypeName === "land" && (
              <LandDetailForm register={register} />
            )}

            {selectedPropertyTypeName === "townhouse" && (
              <TownhouseDetailForm register={register} />
            )}

            <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100">
              <div className="flex items-center gap-3 mb-4">
                <div className="p-2 rounded-lg">
                  <svg className="w-5 h-5 text-gray-600" fill="currentColor" viewBox="0 0 20 20">
                    <path fillRule="evenodd" d="M11.49 3.17c-.38-1.56-2.6-1.56-2.98 0a1.532 1.532 0 01-2.286.948c-1.372-.836-2.942.734-2.106 2.106.54.886.061 2.042-.947 2.287-1.561.379-1.561 2.6 0 2.978a1.532 1.532 0 01.947 2.287c-.836 1.372.734 2.942 2.106 2.106a1.532 1.532 0 012.287.947c.379 1.561 2.6 1.561 2.978 0a1.533 1.533 0 012.287-.947c1.372.836 2.942-.734 2.106-2.106a1.533 1.533 0 01.947-2.287c1.561-.379 1.561-2.6 0-2.978a1.532 1.532 0 01-.947-2.287c.836-1.372-.734-2.942-2.106-2.106a1.532 1.532 0 01-2.287-.947zM10 13a3 3 0 100-6 3 3 0 000 6z" clipRule="evenodd" />
                  </svg>
                </div>
                <h2 className="text-lg font-bold text-gray-500">Additional Options</h2>
              </div>

              <label className="flex items-center gap-3 p-3 rounded-lg cursor-pointer group">
                <input
                  type="checkbox"
                  {...register("isFurnished")}
                  className="h-5 w-5 accent-blue-200 rounded cursor-pointer"
                />
                <span className="text-sm font-medium text-gray-700 group-hover:text-blue-700 transition-colors">
                  Property is Furnished
                </span>
              </label>
            </div>

            <ContactDetailsForm register={register} />

            <div className="bg-gray-50 rounded-2xl p-6 border border-gray-100">
              <h2 className="text-lg font-bold text-gray-800 mb-4">Property Images</h2>
              <input
                type="file"
                accept="image/*"
                multiple
                {...register("images")}
                className="block w-full text-sm text-gray-600 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 hover:file:cursor-pointer"
              />
              <p className="text-xs text-gray-500 mt-2">
                Upload multiple images (JPG, PNG). Images will be optimized automatically.
              </p>
            </div>

            <button
              type="submit"
              disabled={loading || uploadingImages}
              className={`w-full py-3 px-4 rounded-lg text-white font-medium transition-all ${loading || uploadingImages
                ? "bg-blue-400 cursor-wait"
                : "bg-blue-600 hover:bg-blue-700 shadow-lg hover:shadow-xl"
                }`}
            >
              {loading || uploadingImages ? (
                <span className="flex items-center justify-center gap-2">
                  <Loader2 className="animate-spin" size={20} />
                  {uploadingImages ? "Uploading Images..." : "Registering..."}
                </span>
              ) : (
                "Register Property"
              )}
            </button>
          </form>
        </div>
      </main>

      {/* Success Modal */}
      <PropertyCreationSuccessModal
        isOpen={showSuccessModal}
        onClose={handleCloseModal}
        propertyId={createdPropertyId}
        imageCount={successfulImageCount}
        onViewPropertyAnalytics={handleViewPropertyAnalytics}
        onReturnToDashboard={handleReturnToDashboard}
        onAddAnotherProperty={handleAddAnotherProperty}
      />
    </div>
  );
}

"use client";
import { useEffect, useState } from "react";
import { useForm } from "react-hook-form";
import { Property } from "@/app/data/PropertyData";
import { PropertyType } from "@/app/data/PropertTypeData";
import { Appliance } from "@/app/data/ApplianceData";
import { fetchPropertyTypes } from "@/lib/property-type";
import { fetchAppliances } from "@/lib/appliance";
import { updateProperty, PropertyPayload } from "@/lib/property-manager";
import { HomeIcon } from "lucide-react";
import toast, { Toaster } from "react-hot-toast";
import { useAuth } from "@/context/AuthContext";

interface EditPropertyFormProps {
  initialData: any; 
  onSuccess?: () => void;
}

interface ApiProperty {
  id: string;
  name: string;
  city: string;
  address: string;
  type: string; 
  isFurnished: boolean;
  availabilityStatus: string;
  details: any; 
  manager: any;
  organization: any;
  createdAt: string;
}

export default function EditPropertyForm({ initialData, onSuccess }: EditPropertyFormProps) {
  const { register, handleSubmit, reset, watch } = useForm<any>({
    defaultValues: initialData,
  });

  const { user } = useAuth();
  const [propertyTypes, setPropertyTypes] = useState<PropertyType[]>([]);
  const [appliances, setAppliances] = useState<Appliance[]>([]);
  const [loading, setLoading] = useState(false);
  
  const propertyTypeName = initialData.type?.toLowerCase() || "";
  
  useEffect(() => {
    console.log("Initial data in EditPropertyForm:", initialData);
  }, [initialData]);

  useEffect(() => {
    const getData = async () => {
      try {
        const [types, apps] = await Promise.all([fetchPropertyTypes(), fetchAppliances()]);
        setPropertyTypes(types);
        setAppliances(apps);
      } catch (error) {
        console.error(error);
        toast.error("Failed to load property types or appliances.");
      }
    };
    getData();

    // Reset form with data from API response
    reset({
      // Basic info
      city: initialData.city || "",
      address: initialData.address || "",
      isFurnished: initialData.isFurnished || false,
      availabilityStatus: initialData.availabilityStatus || "available",
      amenities: initialData.amenities || "",
      
      // Property type info
      type: initialData.type || "",
      propertyTypeId: initialData.propertyTypeId || "",
      
      // Details - map from API response to form structure
      houseDetail: initialData.type?.toLowerCase() === "house" ? {
        houseName: initialData.details?.houseName || "",
        numberOfFloors: initialData.details?.numberOfFloors || 0,
        bedrooms: initialData.details?.bedrooms || 0,
        bathrooms: initialData.details?.bathrooms || 0,
        size: initialData.details?.size || 0,
        totalUnits: initialData.details?.totalUnits || 0,
      } : {},
      
      apartmentComplexDetail: initialData.type?.toLowerCase() === "apartment" ? {
        buildingName: initialData.details?.buildingName || "",
        totalFloors: initialData.details?.totalFloors || 0,
        totalUnits: initialData.details?.totalUnits || 0,
      } : {},
    });
  }, [initialData, reset]);

  const onSubmit = async (data: any) => {
    if (!user) return toast.error("You must be logged in to edit a property.");

    setLoading(true);

    try {
      // property details based on type
      let propertyDetails = {};
      
      if (propertyTypeName === "apartment") {
        propertyDetails = {
          buildingName: data.apartmentComplexDetail?.buildingName || "",
          totalFloors: data.apartmentComplexDetail?.totalFloors || 0,
          totalUnits: data.apartmentComplexDetail?.totalUnits || 0,
        };
      } else if (propertyTypeName === "house") {
        propertyDetails = {
          houseName: data.houseDetail?.houseName || "",
          numberOfFloors: data.houseDetail?.numberOfFloors || 0,
          bedrooms: data.houseDetail?.bedrooms || 0,
          bathrooms: data.houseDetail?.bathrooms || 0,
          size: data.houseDetail?.size || 0,
          totalUnits: data.houseDetail?.totalUnits || 0,
        };
      }

      let propertyTypeId = data.propertyTypeId;
      
      // find it from property types
      if (!propertyTypeId && propertyTypes.length > 0) {
        const foundType = propertyTypes.find(
          (type) => type.name.toLowerCase() === propertyTypeName
        );
        if (foundType) {
          propertyTypeId = foundType.id;
        }
      }

      const payload = {
        id: initialData.id, // Property ID for the update
        city: data.city,
        address: data.address,
        locationId: initialData.locationId, 
        amenities: data.amenities,
        isFurnished: data.isFurnished,
        availabilityStatus: data.availabilityStatus,
        propertyDetails: propertyDetails,
        propertyTypeId: propertyTypeId,
      };

      await updateProperty(initialData.id, payload);
      toast.success("Property updated successfully!");
      if (onSuccess) onSuccess();
    } catch (error: any) {
      console.error("Error updating property:", error);
      toast.error(error.message || "Failed to update property.");
    } finally {
      setLoading(false);
    }
  };

  // Get display name for property type
  const getPropertyTypeDisplayName = () => {
    if (initialData.type) {
      return initialData.type.charAt(0).toUpperCase() + initialData.type.slice(1);
    }
    return "Property";
  };

  return (
    <div className="bg-gray-50 p-6 rounded-2xl shadow-xl">
      <Toaster position="top-center" />
      <div className="flex items-center gap-3 mb-8">
        <div className="p-3 bg-blue-600 text-white rounded-full shadow-lg">
          <HomeIcon className="w-6 h-6" />
        </div>
        <h2 className="text-3xl font-bold text-gray-800">Edit {getPropertyTypeDisplayName()}</h2>
      </div>

      <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
        {/* Property Type Display (Read-only) */}
        <div className="bg-white p-4 rounded-xl border border-gray-200">
          <label className="block text-sm font-semibold text-gray-700 mb-2">
            Property Type
          </label>
          <div className="flex items-center gap-3">
            <span className="inline-flex items-center px-3 py-1 rounded-full text-sm font-medium bg-blue-100 text-blue-800 capitalize">
              {propertyTypeName || "Unknown"}
            </span>
            <span className="text-sm text-gray-500">
              (Property type cannot be changed)
            </span>
          </div>
        </div>

        {/* Basic Information */}
        <div className="bg-white p-6 rounded-xl border border-gray-200">
          <h3 className="text-lg font-semibold text-gray-800 mb-4">Basic Information</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            
            <div className="flex flex-row md:col-span-2 gap-12">
            <div className="flex flex-col md:col-span-2">
              <label htmlFor="city" className="text-sm font-semibold text-gray-700 mb-1">
                City *
              </label>
              <input
                id="city"
                {...register("city", { required: "City is required" })}
                placeholder="Enter city"
