"use client";

import { useState } from "react";
import Image from "next/image";
import { Search, MapPin, Grid, X } from "lucide-react";
import ApplyModal from "./ApplyModal";

export interface MarketplaceItem {
  id: string;
  title: string;
  description?: string;
  price: number;
  image: string;


  unitId?: string | null;
  propertyId?: string | null;
  unit?: {
    id: string;
    unitNumber?: string;
    property?: {
      id: string;
      name?: string;
    };
  } | null;
  property?: {
    id: string;
    name?: string;
  } | null;
}

interface MarketplaceClientPageProps {
  listings: MarketplaceItem[];
}

export function MarketplaceClientPage({ listings: initialListings }: MarketplaceClientPageProps) {
  const [listings] = useState(initialListings);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterCategory, setFilterCategory] = useState("all");
  const [filterLocation, setFilterLocation] = useState("all");
  const [selectedListing, setSelectedListing] = useState<MarketplaceItem | null>(null);
  const [showModal, setShowModal] = useState(false);




  const handleApply = async (listing: MarketplaceItem) => {
    const unitId = listing.unitId ?? listing.unit?.id;
    const propertyId = listing.propertyId ?? listing.unit?.property?.id ?? listing.property?.id;

    if (!unitId || !propertyId) {
      alert("This listing doesn't have an associated unit or property. Please contact support.");
      return;
    }

    // Check application eligibility before opening modal
    try {
      const response = await fetch(`/api/units/by-id/${unitId}/application-eligibility`);
      if (!response.ok) {
        alert("Unable to check unit availability. Please try again later.");
        return;
      }
      const eligibility = await response.json();

      if (!eligibility.isEligible) {
        alert(eligibility.reason || "This unit is not currently available for applications.");
        return;
      }

      setSelectedListing({
        ...listing,
        unitId,
        propertyId,
        unit: listing.unit || { id: unitId, property: { id: propertyId, name: listing.property?.name || "" } },
        property: listing.property || { id: propertyId, name: listing.unit?.property?.name || "" },
      });

      setShowModal(true);
    } catch (error) {
      console.error('Error checking application eligibility:', error);
      alert("Unable to check unit availability. Please try again later.");
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setSelectedListing(null);
  };

  // ✅ FIXED: Just close the modal, the ApplyModal already handles submission
  const handleSubmit = (data: any) => {
    console.log("Application submitted successfully:", data);
    handleCloseModal();
  };

  return (
    <div className="max-w-7xl mx-auto px-6 py-16">
      {/* Search + Filters */}
      <div className="bg-white/90 backdrop-blur-md shadow-lg rounded-2xl p-6 mb-12 border border-gray-100">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
          {/* Search */}
          <div className="relative w-full md:w-1/3">
            <Search className="absolute left-3 top-2.5 text-gray-400" size={20} />
            <input
              type="text"
              placeholder="Search listings..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-10 pr-10 py-2.5 border border-gray-200 rounded-xl text-gray-700 focus:outline-none focus:ring-2 focus:ring-[#003b73] focus:border-transparent transition-all"
            />
            {searchTerm && (
              <button
                onClick={() => setSearchTerm("")}
                className="absolute right-3 top-2.5 text-gray-400 hover:text-gray-600"
              >
                <X size={20} />
              </button>
            )}
          </div>




        </div>
      </div>

      {/* Listings */}
      {listings.length > 0 ? (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-8">
          {listings.map((item) => (
            <div
              key={item.id}
              className="bg-white rounded-2xl shadow-lg overflow-hidden hover:shadow-xl hover:-translate-y-1 transition-all duration-300"
            >
              <Image src={item.image} alt={item.title} width={400} height={300} className="object-cover w-full h-60" />
              <div className="p-5 space-y-2">
                <h3 className="font-semibold text-xl text-gray-900">{item.title}</h3>
                <p className="text-gray-600 text-sm line-clamp-3">{item.description}</p>
                <div className="flex items-center justify-between mt-4">
                  <span className="text-[#003b73] font-semibold">USD {item.price.toLocaleString()}</span>
                </div>
                <div className="mt-5">
                  <button
                    onClick={() => handleApply(item)}
                    className="w-full bg-[#003b73] hover:bg-[#002b5b] text-white py-2.5 rounded-xl font-semibold transition-all duration-200"
                  >
                    Apply for Property
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <p className="text-center text-gray-500 mt-16">No listings found.</p>
      )}

      {/* Application Modal */}
      {showModal && selectedListing && (
        <ApplyModal open={true} onClose={handleCloseModal} onSubmit={handleSubmit} listing={selectedListing} />
      )}
    </div>
  );
}

"use client";

import React, { useState, useCallback } from "react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Upload, X, Image as ImageIcon, MapPin, Tag, DollarSign } from "lucide-react";
import { useDropzone } from "react-dropzone";

export default function ListingForm() {
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    price: "",
    location: "",
    category: "property",
    contactEmail: "",
    contactPhone: "",
  });

  const [images, setImages] = useState<File[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>
  ) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value,
    }));
  };

  const onDrop = useCallback((acceptedFiles: File[]) => {
    setImages(prev => [...prev, ...acceptedFiles.slice(0, 6)]); // Limit to 6 images
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: {
      'image/*': ['.jpeg', '.jpg', '.png', '.webp']
    },
    maxFiles: 6,
    maxSize: 5 * 1024 * 1024, // 5MB
  });

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    try {
      // Simulate API call
      await new Promise(resolve => setTimeout(resolve, 2000));
      console.log("Listing submitted:", formData);
      console.log("Images:", images);

      // Reset form
      setFormData({
        title: "",
        description: "",
        price: "",
        location: "",
        category: "property",
        contactEmail: "",
        contactPhone: "",
      });
      setImages([]);

      alert("Listing published successfully!");
    } catch (error) {
      console.error("Error submitting listing:", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const previewUrls = images.map(file => URL.createObjectURL(file));

  return (
    <section className="min-h-screen bg-gradient-to-br from-slate-50 to-blue-50 flex items-center justify-center py-12 px-4">
      <Card className="w-full max-w-2xl bg-white/80 backdrop-blur-sm border border-slate-200 rounded-3xl shadow-2xl shadow-blue-500/5">
        <CardHeader className="text-center pb-4">
          <div className="w-16 h-16 bg-gradient-to-r from-blue-500 to-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg">
            <Tag className="w-8 h-8 text-white" />
          </div>
          <CardTitle className="text-3xl font-bold bg-gradient-to-r from-slate-800 to-blue-600 bg-clip-text text-transparent">
            Create New Listing
          </CardTitle>
          <p className="text-slate-600 text-lg font-medium mt-2">
            Share your property or item with potential buyers
          </p>
        </CardHeader>

        <CardContent>
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Title */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-slate-700">
                Listing Title *
              </label>
              <Input
                type="text"
                name="title"
                value={formData.title}
                onChange={handleChange}
                placeholder="Modern 2-Bedroom Apartment with Mountain View"
                className="w-full bg-white text-slate-900 placeholder-slate-400 border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 rounded-xl transition-all duration-200 px-4 py-3"
                required
              />
            </div>

            {/* Description */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-slate-700">
                Description *
              </label>
              <textarea
                id="description"
                name="description"
                value={formData.description}
                onChange={handleChange}
                placeholder="Describe your property or item in detail. Include key features, condition, and any special notes..."
                className="w-full bg-white text-slate-900 placeholder-slate-400 border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 rounded-xl transition-all duration-200 px-4 py-3 resize-vertical min-h-[120px]"
                rows={4}
                required
              />
            </div>

            {/* Price & Location */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className=" text-sm font-semibold text-slate-700 flex items-center gap-2">
                  Price (USD) *
                </label>
                <Input
                  type="number"
                  name="price"
                  value={formData.price}
                  onChange={handleChange}
                  placeholder="85,000"
                  className="w-full bg-white text-slate-900 placeholder-slate-400 border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 rounded-xl transition-all duration-200 px-4 py-3"
                  min="0"
                  required
                />
              </div>

              <div className="space-y-2">
                <label className=" text-sm font-semibold text-slate-700 flex items-center gap-2">
                  <MapPin className="w-4 h-4" />
                  Location *
                </label>
                <Input
                  type="text"
                  name="location"
                  value={formData.location}
                  onChange={handleChange}
                  placeholder="Westlands, Nairobi"
                  className="w-full bg-white text-slate-900 placeholder-slate-400 border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 rounded-xl transition-all duration-200 px-4 py-3"
                  required
                />
              </div>
            </div>

            {/* Contact Information */}


            {/* Category */}
            <div className="space-y-2">
              <label className="block text-sm font-semibold text-slate-700">
                Category *
              </label>
              <select
                id="category"
                name="category"
                value={formData.category}
                onChange={handleChange}
                className="w-full bg-white text-slate-900 border border-slate-300 focus:border-blue-500 focus:ring-2 focus:ring-blue-200 rounded-xl transition-all duration-200 px-4 py-3 appearance-none cursor-pointer"
                title="Select a category for your listing"
              >
                <option value="property">Property</option>
                <option value="furniture"> Furniture</option>
                <option value="appliance">Appliance</option>
                <option value="decor"> Home Décor</option>
                <option value="service"> Service</option>
                <option value="vehicle"> Vehicle</option>
                <option value="electronics"> Electronics</option>
              </select>
            </div>

            {/* Image Upload */}
            <div className="space-y-4">
              <label className=" text-sm font-semibold text-slate-700 flex items-center gap-2">
                <ImageIcon className="w-4 h-4" />
                Images {images.length > 0 && `(${images.length}/6)`}
              </label>

              <div
                {...getRootProps()}
                className={`relative border-2 border-dashed rounded-2xl p-8 text-center transition-all duration-300 cursor-pointer ${isDragActive
                  ? "border-blue-500 bg-blue-50/50"
                  : "border-slate-300 bg-slate-50/50 hover:border-blue-400 hover:bg-blue-50/30"
                  }`}
              >
                <input {...getInputProps()} />
                <div className="space-y-3">
                  <Upload className={`w-12 h-12 mx-auto transition-colors ${isDragActive ? "text-blue-500" : "text-slate-400"
                    }`} />
                  <div className="space-y-1">
                    <p className="text-slate-700 font-medium">
                      {isDragActive ? "Drop images here" : "Drag & drop images here"}
                    </p>
                    <p className="text-slate-500 text-sm">
                      or click to browse (max 6 images, 5MB each)
                    </p>
                  </div>
                </div>
              </div>

              {/* Image Previews */}
              {previewUrls.length > 0 && (
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
                  {previewUrls.map((src, index) => (
                    <div key={index} className="relative group">
                      <img
                        src={src}
                        alt={`Preview ${index + 1}`}
                        className="w-full h-32 object-cover rounded-xl border-2 border-slate-200 group-hover:border-slate-300 transition-all duration-200 shadow-sm"
                      />
                      <button
                        type="button"
                        onClick={() => removeImage(index)}
                        aria-label={`Remove image ${index + 1}`}
                        title="Remove image"
                        className="absolute -top-2 -right-2 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-200 hover:bg-red-600 shadow-lg"
                      >
                        <X className="w-3 h-3" />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Submit Button */}
            <Button
              type="submit"
              disabled={isSubmitting}
              className="w-full bg-gradient-to-r from-blue-600 to-blue-500 hover:from-blue-700 hover:to-blue-600 text-white py-4 rounded-xl font-semibold text-lg transition-all duration-300 shadow-lg shadow-blue-500/25 hover:shadow-xl hover:shadow-blue-500/35 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
            >
              {isSubmitting ? (
                <div className="flex items-center gap-2">
                  <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                  Publishing...
                </div>
              ) : (
                "Publish Listing"
              )}
            </Button>
          </form>
        </CardContent>
      </Card>
    </section>
  );
}

"use client";

import Image from "next/image";
import { useState } from "react";
import { MapPin, Clock, Phone } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { MarketplaceItem } from "@/app/data/marketplaceData";

interface ListingDetailsPageProps {
  listing: MarketplaceItem;
}

export default function MyListing({ listing }: ListingDetailsPageProps) {
  const [editableListing, setEditableListing] = useState(listing);
  const [activeTab, setActiveTab] = useState<"view" | "edit" | "inquiries">("view");

  const handleChange = (field: keyof MarketplaceItem, value: string | number) => {
    setEditableListing((prev) => ({ ...prev, [field]: value }));
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    alert("Listing updated successfully!");
  };

  return (
    <section className="max-w-6xl mx-auto p-6 md:p-10">
      <article className="bg-white rounded-2xl shadow-md border border-gray-100 overflow-hidden">
        {/* Image */}
        <div className="relative w-full h-[250px] md:h-[350px] overflow-hidden">
          <Image
            src={editableListing.image}
            alt={editableListing.title}
            fill
            className="object-cover"
          />
        </div>

        {/* Tabs */}
        <div className="mt-8 border-b border-gray-200 flex divide-x divide-gray-300 rounded-t-xl overflow-hidden">
          {["view", "edit", "inquiries"].map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab as "view" | "edit" | "inquiries")}
              className={`flex-1 py-3 text-sm font-semibold transition-colors
        ${activeTab === tab
                  ? "text-blue-600 border-b-2 border-blue-600 bg-gray-50"
                  : "text-gray-500 hover:text-gray-700"
                }`}
            >
              {tab === "view"
                ? "Overview"
                : tab === "edit"
                  ? "Edit Listing"
                  : "Inquiries"}
            </button>
          ))}
        </div>


        {/* Content Area */}
        <div className="p-6 md:p-10">
          <AnimatePresence mode="wait">
            {activeTab === "view" && (
              <motion.div
                key="view"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.25 }}
                className="space-y-6"
              >
                {/* Title & Price */}
                <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
                  <h1 className="text-2xl md:text-3xl font-bold text-gray-900">
                    {editableListing.title}
                  </h1>
                  <p className="text-blue-600 font-semibold text-lg">
                    $ {editableListing.price.toLocaleString()}
                  </p>
                </div>

                {/* Meta Info */}
                <div className="flex flex-wrap items-center gap-4 text-sm text-gray-600">
                  <span className="flex items-center gap-1">
                    <MapPin className="w-4 h-4 text-blue-500" />
                    {editableListing.location}
                  </span>
                  <span className="flex items-center gap-1">
                    <Clock className="w-4 h-4 text-blue-500" />
                    Posted {editableListing.dateposted}
                  </span>
                </div>

                {/* Description */}
                <div>
                  <h2 className="text-base font-semibold text-blue-600 mb-2">
                    Description
                  </h2>
                  <p className="text-gray-700 leading-relaxed">
                    {editableListing.description}
                  </p>
                </div>


                <p className="text-sm text-gray-500 mt-4">
                  <strong>You Posted as:</strong> {editableListing.postedBy}
                </p>
              </motion.div>
            )}

            {activeTab === "edit" && (
              <motion.form
                key="edit"
                onSubmit={handleSave}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.25 }}
                className="space-y-6"
              >
                {/* Editable Fields */}
                <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
                  <input
                    type="text"
                    value={editableListing.title}
                    onChange={(e) => handleChange("title", e.target.value)}
                    className="text-2xl md:text-3xl font-bold text-gray-900 border-b border-gray-300 focus:outline-none focus:border-blue-500"
                    style={{ width: `${editableListing.title.length + 2}ch` }}

                  />
                  <input
                    type="number"
                    value={editableListing.price}
                    onChange={(e) => handleChange("price", Number(e.target.value))}
                    className="text-blue-600 font-semibold text-lg bg-transparent border-b border-gray-300 focus:outline-none focus:border-blue-500"
                  />
                </div>

                <input
                  type="text"
                  value={editableListing.location}
                  onChange={(e) => handleChange("location", e.target.value)}
                  className="w-full border-b border-gray-300 focus:outline-none focus:border-blue-500 py-2"
                />

                <textarea
                  value={editableListing.description}
                  onChange={(e) => handleChange("description", e.target.value)}
                  rows={5}
                  className="w-full text-gray-900 border border-gray-300 rounded-xl p-3 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 resize-none"
                />



                <button
                  type="submit"
                  className="w-full bg-blue-600 text-white py-3 rounded-xl font-semibold hover:bg-blue-700 transition-colors"
