// src/hooks/useGeocoding.ts
import { useState, useEffect } from "react";
import toast from "react-hot-toast";

interface GeocodingParams {
  country?: string;
  city?: string;
  zipCode?: string;
  address?: string;
}

interface Coordinates {
  lat: number;
  lng: number;
}

export function useGeocoding(params: GeocodingParams, setValue: any) {
  const [coordinates, setCoordinates] = useState<Coordinates | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMap, setShowMap] = useState(false);

  useEffect(() => {
    const { country, city, zipCode, address } = params;

    if (!country?.trim() || !city?.trim() || !zipCode?.trim() || !address?.trim()) {
      setCoordinates(null);
      setShowMap(false);
      return;
    }

    const geocodeAddress = async () => {
      setLoading(true);
      setShowMap(false);

      try {
        const searchParams = new URLSearchParams({
          country: country.trim(),
          city: city.trim(),
          street: address.trim(),
          zipcode: zipCode.trim(),
        });

        const response = await fetch(`/api/geocode?${searchParams.toString()}`);
        const data = await response.json();

        if (!response.ok) {
          throw new Error(data.error || "Geocoding failed");
        }

        setCoordinates({ lat: data.lat, lng: data.lng });
        setValue("latitude", data.lat);
        setValue("longitude", data.lng);
        setShowMap(true);
        toast.success("Location found! You can adjust the marker on the map.");
      } catch (error: any) {
        toast.error(error.message || "Could not find location. Please check the address.");
        setCoordinates(null);
        setShowMap(false);
      } finally {
        setLoading(false);
      }
    };

    const timeoutId = setTimeout(geocodeAddress, 800);
    return () => clearTimeout(timeoutId);
  }, [params.country, params.city, params.zipCode, params.address, setValue]);

  return {
    coordinates,
    loading,
    showMap,
    setCoordinates,
    setShowMap,
  };
}

"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { useAuth } from "@/context/AuthContext";

export interface MaintenanceRequest {
  id: string;
  title: string;
  description: string;
  status: string;
  priority: string;
  category?: string;
  createdAt: string;
  updatedAt?: string;
  completedDate?: string;
  property?: {
    name: string;
    address: string;
  };
  unit?: {
    unitNumber: string;
    unitName?: string;
  };
  requestedBy?: {
    user: {
      firstName: string;
      lastName: string;
      email: string;
    };
  };
}

type UseMaintenanceRequestsState = {
  requests: MaintenanceRequest[];
  loading: boolean;
  error: string | null;
  count: number;
  refetch: () => Promise<void>;
  createRequest: (data: CreateMaintenanceRequestData) => Promise<{ success: boolean; error?: string }>;
};

export interface CreateMaintenanceRequestData {
  title: string;
  description: string;
  priority: "LOW" | "NORMAL" | "HIGH" | "URGENT";
  category?: "EMERGENCY" | "URGENT" | "ROUTINE" | "STANDARD";
}

export function useMaintenanceRequests(propertyId?: string, unitId?: string): UseMaintenanceRequestsState {
  const [requests, setRequests] = useState<MaintenanceRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const { user } = useAuth();

  const refetch = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);

      // Get tenant's maintenance requests
      const res = await fetch("/api/maintenance/tenant", {
        method: "GET",
        headers: { "Content-Type": "application/json" },
        cache: "no-store",
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data?.error || "Failed to fetch maintenance requests");
      }

      setRequests(Array.isArray(data.requests) ? data.requests : []);
    } catch (err) {
      setRequests([]);
      setError(err instanceof Error ? err.message : "Unknown error");
      console.error("Error fetching maintenance requests:", err);
    } finally {
      setLoading(false);
    }
  }, []);

  const createRequest = useCallback(async (data: CreateMaintenanceRequestData) => {
    try {
      setLoading(true);
      
      // Get user's organization and active lease info
      // This would be enhanced with actual user context in a real implementation
      const res = await fetch("/api/maintenance/tenant", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...data,
          // These would come from user's active lease context
          propertyId,
          unitId,
        }),
      });

      const responseData = await res.json();

      if (!res.ok) {
        throw new Error(responseData?.error || "Failed to create maintenance request");
      }

      // Refresh the requests list
      await refetch();
      return { success: true };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : "Failed to create maintenance request";
      setError(errorMessage);
      console.error("Error creating maintenance request:", err);
      return { success: false, error: errorMessage };
    } finally {
      setLoading(false);
    }
  }, [propertyId, unitId, refetch]);

  useEffect(() => {
    refetch();
  }, [refetch]);

  const count = useMemo(() => requests.length, [requests]);

  return {
    requests,
    loading,
    error,
    count,
    refetch,
    createRequest,
  };
}

