/**
 * SSN Encryption Utility Module
 * 
 * Provides AES-256-GCM encryption/decryption for sensitive PII data (SSN).
 * This is critical for GDPR compliance and data security.
 */

import crypto from 'crypto';

/**
 * Configuration constants for SSN encryption
 */
const ENCRYPTION_ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 16; // 16 bytes for GCM
const AUTH_TAG_LENGTH = 16; // 16 bytes for GCM authentication tag
const KEY_ENCODING: BufferEncoding = 'base64';
const STRING_ENCODING: BufferEncoding = 'utf8';

/**
 * SSN Encryption Error Class
 */
export class EncryptionError extends Error {
  constructor(
    message: string,
    public readonly operation: 'encrypt' | 'decrypt' | 'key_validation',
    public readonly cause?: Error
  ) {
    super(message);
    this.name = 'EncryptionError';
  }
}

/**
 * Validates that the encryption key is present and properly formatted
 */
function validateEncryptionKey(): Buffer {
  const key = process.env.SSN_ENCRYPTION_KEY;
  
  if (!key) {
    throw new EncryptionError(
      'SSN_ENCRYPTION_KEY environment variable is not set',
      'key_validation'
    );
  }

  try {
    // Key should be a base64 encoded 32-byte (256-bit) key
    const keyBuffer = Buffer.from(key, KEY_ENCODING);
    
    if (keyBuffer.length !== 32) {
      throw new EncryptionError(
        `SSN_ENCRYPTION_KEY must be 32 bytes (256 bits) after base64 decoding. Got ${keyBuffer.length} bytes.`,
        'key_validation'
      );
    }
    
    return keyBuffer;
  } catch (error) {
    if (error instanceof EncryptionError) {
      throw error;
    }
    throw new EncryptionError(
      'SSN_ENCRYPTION_KEY is not valid base64',
      'key_validation',
      error as Error
    );
  }
}

/**
 * Encrypts plaintext SSN data using AES-256-GCM
 * 
 * @param plaintext - The plaintext SSN to encrypt
 * @returns Encrypted string in format: `${iv}:${ciphertext}:${authTag}`
 * @throws {EncryptionError} If encryption fails
 */
export function encryptSSN(plaintext: string): string {
  try {
    if (!plaintext || typeof plaintext !== 'string') {
      throw new Error('Plaintext must be a non-empty string');
    }

    const key = validateEncryptionKey();
    const iv = crypto.randomBytes(IV_LENGTH);
    
    const cipher = crypto.createCipheriv(ENCRYPTION_ALGORITHM, key, iv);
    
    // Encrypt the plaintext
    let ciphertext = cipher.update(plaintext, STRING_ENCODING, 'hex');
    ciphertext += cipher.final('hex');
    
    // Get the authentication tag
    const authTag = cipher.getAuthTag();
    
    // Format: iv:ciphertext:authTag (all hex encoded)
    return `${iv.toString('hex')}:${ciphertext}:${authTag.toString('hex')}`;
  } catch (error) {
    if (error instanceof EncryptionError) {
      throw error;
    }
    throw new EncryptionError(
      `Failed to encrypt SSN: ${error instanceof Error ? error.message : 'Unknown error'}`,
      'encrypt',
      error as Error
    );
  }
}

/**
 * Decrypts encrypted SSN data using AES-256-GCM
 * 
 * @param encryptedString - The encrypted string in format: `${iv}:${ciphertext}:${authTag}`
 * @returns Decrypted plaintext SSN
 * @throws {EncryptionError} If decryption fails
 */
export function decryptSSN(encryptedString: string): string {
  try {
    if (!encryptedString || typeof encryptedString !== 'string') {
      throw new Error('Encrypted string must be a non-empty string');
    }

    // Parse the encrypted string format
    const parts = encryptedString.split(':');
    if (parts.length !== 3) {
      throw new Error('Invalid encrypted string format. Expected iv:ciphertext:authTag');
    }

    const [ivHex, ciphertext, authTagHex] = parts;
    
    const key = validateEncryptionKey();
    const iv = Buffer.from(ivHex, 'hex');
    const authTag = Buffer.from(authTagHex, 'hex');
    
    if (iv.length !== IV_LENGTH) {
      throw new Error(`Invalid IV length: expected ${IV_LENGTH} bytes, got ${iv.length}`);
    }
    
    if (authTag.length !== AUTH_TAG_LENGTH) {
      throw new Error(`Invalid auth tag length: expected ${AUTH_TAG_LENGTH} bytes, got ${authTag.length}`);
    }

    const decipher = crypto.createDecipheriv(ENCRYPTION_ALGORITHM, key, iv);
    decipher.setAuthTag(authTag);
    
    // Decrypt the ciphertext
    let plaintext = decipher.update(ciphertext, 'hex', STRING_ENCODING);
    plaintext += decipher.final(STRING_ENCODING);
    
    return plaintext;
  } catch (error) {
    if (error instanceof EncryptionError) {
      throw error;
    }
    throw new EncryptionError(
      `Failed to decrypt SSN: ${error instanceof Error ? error.message : 'Unknown error'}`,
      'decrypt',
      error as Error
    );
  }
}

/**
 * Validates if a string is a properly encrypted SSN
 * 
 * @param encryptedString - The string to validate
 * @returns True if the string appears to be a valid encrypted SSN
 */
export function isEncryptedSSN(encryptedString: string): boolean {
  if (!encryptedString || typeof encryptedString !== 'string') {
    return false;
  }

  try {
    // Check the format: iv:ciphertext:authTag
    const parts = encryptedString.split(':');
    if (parts.length !== 3) {
      return false;
    }

    const [ivHex, ciphertext, authTagHex] = parts;
    
    // Check that all parts are valid hex
    if (!/^[0-9a-fA-F]+$/.test(ivHex) || 
        !/^[0-9a-fA-F]+$/.test(ciphertext) || 
        !/^[0-9a-fA-F]+$/.test(authTagHex)) {
      return false;
    }
    
    // Check IV length (optional, but good for format validation)
    const iv = Buffer.from(ivHex, 'hex');
    if (iv.length !== IV_LENGTH) {
      return false;
    }
    
    return true;
  } catch {
    return false;
  }
}

/**
 * Rotates encryption keys by re-encrypting data with a new key
 * 
 * @param oldKey - The old encryption key (base64)
 * @param newKey - The new encryption key (base64)
 * @param encryptedData - The data encrypted with the old key
 * @returns Data re-encrypted with the new key
 * @throws {EncryptionError} If key rotation fails
 */
export function rotateEncryptionKey(
  oldKey: string,
  newKey: string,
  encryptedData: string
): string {
  try {
    // Temporarily set the old key to decrypt
    const originalKey = process.env.SSN_ENCRYPTION_KEY;
    process.env.SSN_ENCRYPTION_KEY = oldKey;
    
    try {
      // Decrypt with old key
      const decrypted = decryptSSN(encryptedData);
      
      // Set new key and re-encrypt
      process.env.SSN_ENCRYPTION_KEY = newKey;
      const reencrypted = encryptSSN(decrypted);
      
      // Restore original key
      process.env.SSN_ENCRYPTION_KEY = originalKey;
      
      return reencrypted;
    } catch (error) {
      // Always restore original key on error
      process.env.SSN_ENCRYPTION_KEY = originalKey;
      throw error;
    }
  } catch (error) {
    if (error instanceof EncryptionError) {
      throw error;
    }
    throw new EncryptionError(
      `Failed to rotate encryption key: ${error instanceof Error ? error.message : 'Unknown error'}`,
      'decrypt',
      error as Error
    );
  }
}

/**
 * Middleware function to automatically encrypt SSN fields in objects
 * 
 * @param data - Object containing SSN fields
 * @param ssnFieldNames - Array of field names that should be encrypted (default: ['ssn'])
 * @returns Object with SSN fields encrypted
 */
export function encryptSSNFields<T extends Record<string, unknown>>(
  data: T,
  ssnFieldNames: string[] = ['ssn']
): T {
  const result: Record<string, unknown> = { ...data };
  
  for (const fieldName of ssnFieldNames) {
    if (fieldName in result && result[fieldName]) {
      const value = result[fieldName];
      
      // Only encrypt if it's a string and not already encrypted
      if (typeof value === 'string' && value.trim() && !isEncryptedSSN(value)) {
        result[fieldName] = encryptSSN(value);
      }
    }
  }
  
  return result as T;
}

/**
 * Middleware function to automatically decrypt SSN fields in objects
 * 
 * @param data - Object containing encrypted SSN fields
 * @param ssnFieldNames - Array of field names that should be decrypted (default: ['ssnEncrypted'])
 * @returns Object with SSN fields decrypted
 */
export function decryptSSNFields<T extends Record<string, unknown>>(
  data: T,
  ssnFieldNames: string[] = ['ssnEncrypted']
): T {
  const result: Record<string, unknown> = { ...data };
  
  for (const fieldName of ssnFieldNames) {
    if (fieldName in result && result[fieldName]) {
      const value = result[fieldName];
      
      // Only decrypt if it's a string and appears to be encrypted
      if (typeof value === 'string' && value.trim() && isEncryptedSSN(value)) {
        try {
          result[fieldName] = decryptSSN(value);
        } catch (error) {
          // If decryption fails, leave it encrypted and log warning
          console.warn(`Failed to decrypt field ${fieldName}:`, error);
        }
      }
    }
  }
  
  return result as T;
}

/**
 * Validates SSN format (basic US SSN format validation)
 * Note: This is for format validation only, not encryption
 * 
 * @param ssn - The SSN to validate
 * @returns True if the SSN format appears valid
 */
export function isValidSSNFormat(ssn: string): boolean {
  // Basic US SSN format validation (XXX-XX-XXXX)
  const ssnRegex = /^(?!000|666|9\d\d)\d{3}-(?!00)\d{2}-(?!0000)\d{4}$/;
  return ssnRegex.test(ssn);
}

export default {
  encryptSSN,
  decryptSSN,
  isEncryptedSSN,
  rotateEncryptionKey,
  encryptSSNFields,
  decryptSSNFields,
  isValidSSNFormat,
  EncryptionError,
};

import { prisma } from "@/lib/db";
import { Decimal } from "@prisma/client/runtime/library";
import { CHART_OF_ACCOUNTS } from "./types";
import { journalService } from "./journal-service";
import { MaintenanceRequestStatus } from "@prisma/client";

export const maintenanceService = {
    /**
     * Finalize a maintenance request and post to GL.
     * DR: Maintenance Expense (5100), CR: Accounts Payable (2200)
     * If tenantChargeable: DR: AR (1100), CR: Maintenance Recovery (4300) + Tenant Invoice
     */
    async postMaintenanceBill(requestId: string) {
        return await prisma.$transaction(async (tx) => {
            // 1. Fetch request with relations
            const request = await tx.maintenanceRequest.findUnique({
                where: { id: requestId },
                include: {
                    property: { include: { organization: true } },
                    unit: {
                        include: {
                            leases: {
                                where: { leaseStatus: 'ACTIVE' },
                                take: 1
                            }
                        }
                    }
                }
            });

            if (!request) throw new Error("Maintenance request not found");
            if (request.status !== MaintenanceRequestStatus.COMPLETED) {
                throw new Error("Only completed requests can be billed");
            }
            if (!request.cost || Number(request.cost) <= 0) {
                throw new Error("Maintenance cost must be greater than zero to post");
            }
            if (request.journalEntryId) throw new Error("Request already posted to ledger");

            const orgId = request.organizationId;
            const cost = request.cost;

            // 2. Post Vendor Expense to GL
            // DR: Maintenance Expense (5100)
            // CR: Accounts Payable (2200)
            const expenseGLEntry = await journalService.post(
                {
                    organizationId: orgId,
                    date: new Date(),
                    description: `Maintenance Cost: ${request.title} - ${request.property.name}`,
                    reference: request.id,
                    lines: [
                        {
                            accountCode: CHART_OF_ACCOUNTS.MAINTENANCE_EXPENSE,
                            debit: cost,
                            credit: 0,
                            propertyId: request.propertyId,
                            unitId: request.unitId || undefined
                        },
                        {
                            accountCode: CHART_OF_ACCOUNTS.ACCOUNTS_PAYABLE,
                            debit: 0,
                            credit: cost,
                            propertyId: request.propertyId,
                            unitId: request.unitId || undefined
                        }
                    ]
                },
                tx
            );

            let invoiceId: string | undefined;

            // 3. Handle Tenant Chargeback if applicable
            if (request.isTenantChargeable) {
                const activeLease = request.unit?.leases[0];
                if (!activeLease) {
                    throw new Error("No active lease found for tenant chargeback");
                }

                // Create Invoice
                const invoice = await tx.invoice.create({
                    data: {
                        leaseId: activeLease.id,
                        type: 'MAINTENANCE',
                        totalAmount: Number(cost),
                        balance: Number(cost),
                        amountPaid: 0,
                        status: 'PENDING',
                        dueDate: new Date(Date.now() + 15 * 24 * 60 * 60 * 1000), // 15 days
                        maintenanceRequest: {
                            connect: { id: request.id }
                        },
                        InvoiceItem: {
                            create: {
                                description: `Maintenance Chargeback: ${request.title}`,
                                amount: Number(cost)
                            }
                        }
                    }
                });

                invoiceId = invoice.id;

                // Post Recovery to GL
                // DR: Accounts Receivable (1100)
                // CR: Maintenance Income (4300)
                const recoveryGLEntry = await journalService.post(
                    {
                        organizationId: orgId,
                        date: new Date(),
                        description: `Maintenance Chargeback: ${request.title} - Unit ${request.unit?.unitNumber}`,
                        reference: invoice.id,
                        lines: [
                            {
                                accountCode: CHART_OF_ACCOUNTS.ACCOUNTS_RECEIVABLE,
                                debit: cost,
                                credit: 0,
                                propertyId: request.propertyId,
                                unitId: request.unitId || undefined,
                                leaseId: activeLease.id,
                                tenantId: activeLease.tenantId || undefined
                            },
                            {
                                accountCode: CHART_OF_ACCOUNTS.MAINTENANCE_INCOME,
                                debit: 0,
                                credit: cost,
                                propertyId: request.propertyId,
                                unitId: request.unitId || undefined,
                                leaseId: activeLease.id
                            }
                        ]
                    },
                    tx
                );

                // Link invoice to its GL entry
                await tx.invoice.update({
                    where: { id: invoice.id },
                    data: { journalEntryId: recoveryGLEntry.id }
                });
            }

            // 4. Update request with financial links
            const updatedRequest = await tx.maintenanceRequest.update({
                where: { id: request.id },
                data: {
                    journalEntryId: expenseGLEntry.id,
                    invoiceId: invoiceId
                }
            });

            return {
                request: updatedRequest,
                expenseGLEntry,
                invoiceId
            };
        }, { timeout: 30000 });
    }
};

// src/lib/lease-listing-integration.ts
import { prisma } from "@/lib/db";
import { ListingService } from "@/lib/listing-service";
import { ListingAction, ListingStatus } from "@/lib/listing-types";
import { auditService } from "@/lib/audit-service";
import { leaseNotificationService } from "@/lib/lease-notification-service";
import type { Prisma } from "@prisma/client";

type LeaseStatus = 'DRAFT' | 'SIGNED' | 'ACTIVE' | 'EXPIRED' | 'TERMINATED' | 'PENDING_APPROVAL';

type UnitWithDecisionLeases = Prisma.UnitGetPayload<{
    include: {
        property: {
            include: {
                manager: {
                    include: {
                        user: true;
                    };
                };
            };
        };
        leases: {
            where: {
                leaseStatus: { in: ['EXPIRED', 'TERMINATED'] };
            };
            orderBy: {
                updatedAt: 'desc';
            };
            take: 1;
        };
    };
}>;

export class LeaseListingIntegration {
    private listingService: ListingService;

    constructor() {
        this.listingService = new ListingService();
    }

    /**
     * Handle lease activation - automatically remove unit from marketplace
     */
    async handleLeaseActivation(leaseId: string, userId?: string): Promise<void> {
        try {
            const lease = await prisma.lease.findUnique({
                where: { id: leaseId },
                include: {
                    unit: {
                        include: {
                            listing: {
                                include: {
                                    status: true
                                }
                            }
                        }
                    },
                    property: {
                        include: {
                            manager: {
                                include: {
                                    user: true
                                }
                            }
                        }
                    }
                }
            });

            if (!lease || !lease.unit) {
                console.warn(`Lease ${leaseId} or associated unit not found`);
                return;
            }

            // If unit has an active listing, remove it
            if (lease.unit.listing && lease.unit.listing.status?.name === ListingStatus.ACTIVE) {
                const removeResult = await this.listingService.removeListing(
                    lease.unit.id,
                    userId || 'system',
                    'Automatic removal due to lease activation'
                );

                if (removeResult.success) {
                    // Send notification to property manager
                    const managerEmail = lease.property.manager?.user?.email;
                    if (managerEmail) {
                        await leaseNotificationService.sendLeaseActivationNotification(
                            managerEmail,
                            lease.unit.unitNumber,
                            lease.property.name || 'Property',
                            leaseId
                        );
                    }

                    // Create audit entry for the automatic removal
                    await auditService.createAuditEntry({
                        unitId: lease.unit.id,
                        listingId: lease.unit.listing.id,
                        action: ListingAction.REMOVE,
                        previousStatus: ListingStatus.ACTIVE,
                        newStatus: ListingStatus.PRIVATE,
                        userId: userId || 'system',
                        reason: 'Automatic removal due to lease activation',
                        metadata: { leaseId, trigger: 'lease_activation' }
                    });

                    console.log(`Removed listing for unit ${lease.unit.unitNumber} due to lease activation`);
                } else {
                    console.error(`Failed to remove listing for unit ${lease.unit.unitNumber}:`, removeResult.message);
                }
            }

            // Mark unit as occupied
            await prisma.unit.update({
                where: { id: lease.unit.id },
                data: { isOccupied: true }
            });

        } catch (error) {
            console.error(`Error handling lease activation for lease ${leaseId}:`, error);
            throw error;
        }
    }

    /**
     * Handle lease expiration - prompt property manager for listing decision
     */
    async handleLeaseExpiration(leaseId: string, userId?: string): Promise<void> {
        try {
            const lease = await prisma.lease.findUnique({
                where: { id: leaseId },
                include: {
                    unit: true,
                    property: {
                        include: {
                            manager: {
                                include: {
                                    user: true
                                }
                            }
                        }
                    }
                }
            });

            if (!lease || !lease.unit) {
                console.warn(`Lease ${leaseId} or associated unit not found`);
                return;
            }

            // Mark unit as not occupied
            await prisma.unit.update({
                where: { id: lease.unit.id },
                data: { isOccupied: false }
            });

            // Create audit entry for lease expiration
            await auditService.createAuditEntry({
                unitId: lease.unit.id,
                action: ListingAction.UPDATE,
                previousStatus: ListingStatus.PRIVATE,
                newStatus: ListingStatus.PRIVATE,
                userId: userId || 'system',
                reason: 'Unit available due to lease expiration',
                metadata: { leaseId, trigger: 'lease_expiration' }
            });

            // Send listing decision prompt to property manager
            const managerEmail = lease.property.manager?.user?.email;
            if (managerEmail) {
                await leaseNotificationService.sendLeaseExpirationNotification(
                    managerEmail,
                    lease.unit.unitNumber,
                    lease.property.name || 'Property',
                    lease.unit.id,
                    leaseId
                );
            }

            console.log(`Processed lease expiration for unit ${lease.unit.unitNumber}`);

        } catch (error) {
            console.error(`Error handling lease expiration for lease ${leaseId}:`, error);
            throw error;
        }
    }

    /**
     * Handle lease termination (early termination)
     */
    async handleLeaseTermination(leaseId: string, userId?: string): Promise<void> {
        try {
            const lease = await prisma.lease.findUnique({
                where: { id: leaseId },
                include: {
                    unit: true,
                    property: {
                        include: {
                            manager: {
                                include: {
                                    user: true
                                }
                            }
                        }
                    }
                }
            });

            if (!lease || !lease.unit) {
                console.warn(`Lease ${leaseId} or associated unit not found`);
                return;
            }

            // Mark unit as not occupied
            await prisma.unit.update({
                where: { id: lease.unit.id },
                data: { isOccupied: false }
            });

            // Create audit entry for lease termination
            await auditService.createAuditEntry({
                unitId: lease.unit.id,
                action: ListingAction.UPDATE,
                previousStatus: ListingStatus.PRIVATE,
                newStatus: ListingStatus.PRIVATE,
                userId: userId || 'system',
                reason: 'Unit available due to lease termination',
                metadata: { leaseId, trigger: 'lease_termination' }
            });

            // Send listing decision prompt to property manager
            const managerEmail = lease.property.manager?.user?.email;
            if (managerEmail) {
                await leaseNotificationService.sendLeaseTerminationNotification(
                    managerEmail,
                    lease.unit.unitNumber,
                    lease.property.name || 'Property',
                    lease.unit.id,
                    leaseId
                );
            }

            console.log(`Processed lease termination for unit ${lease.unit.unitNumber}`);

        } catch (error) {
            console.error(`Error handling lease termination for lease ${leaseId}:`, error);
            throw error;
        }
    }

    /**
     * Handle any lease status change - main entry point for lease lifecycle management
     */
    async handleLeaseStatusChange(
        leaseId: string, 
        newStatus: LeaseStatus, 
        previousStatus: LeaseStatus | null,
        userId?: string
    ): Promise<void> {
        try {
            console.log(`Processing lease status change: ${leaseId} from ${previousStatus} to ${newStatus}`);

            switch (newStatus) {
                case 'ACTIVE':
                    // When lease becomes active, remove unit from marketplace
                    await this.handleLeaseActivation(leaseId, userId);
                    break;

                case 'EXPIRED':
                    // When lease expires, prompt for listing decision
                    await this.handleLeaseExpiration(leaseId, userId);
                    break;

                case 'TERMINATED':
                    // When lease is terminated, prompt for listing decision
                    await this.handleLeaseTermination(leaseId, userId);
                    break;

                case 'SIGNED':
                    // When lease is signed but not yet active, prepare for activation
                    await this.prepareForLeaseActivation(leaseId, userId);
                    break;

                default:
                    // For other statuses (DRAFT, PENDING_APPROVAL, etc.), no action needed
                    console.log(`No listing action required for lease status: ${newStatus}`);
                    break;
            }

        } catch (error) {
            console.error(`Error handling lease status change for lease ${leaseId}:`, error);
            throw error;
        }
    }

    /**
     * Prepare for lease activation (when lease is signed but not yet active)
     */
    private async prepareForLeaseActivation(leaseId: string, userId?: string): Promise<void> {
        try {
            const lease = await prisma.lease.findUnique({
                where: { id: leaseId },
                include: {
                    unit: {
                        include: {
                            listing: {
                                include: {
                                    status: true
                                }
                            }
                        }
                    },
                    property: {
                        include: {
                            manager: {
                                include: {
                                    user: true
                                }
                            }
                        }
                    }
                }
            });

            if (!lease || !lease.unit) {
                console.warn(`Lease ${leaseId} or associated unit not found`);
                return;
            }

            // If unit has an active listing, send notification that it will be removed when lease activates
            if (lease.unit.listing) {
                const managerEmail = lease.property.manager?.user?.email;
                if (managerEmail) {
                    await leaseNotificationService.sendLeaseSignedNotification(
                        managerEmail,
                        lease.unit.unitNumber,
                        lease.property.name || 'Property',
                        lease.startDate,
                        leaseId
                    );
                }
            }

            console.log(`Prepared for lease activation for unit ${lease.unit.unitNumber}`);

        } catch (error) {
            console.error(`Error preparing for lease activation for lease ${leaseId}:`, error);
            throw error;
        }
    }

    /**
     * Check for units that need listing decisions after lease changes
     * This can be called periodically or triggered by lease status changes
     */
    async processUnitsNeedingListingDecisions(): Promise<void> {
        try {
            // Find units that are not occupied, have no active listing, and had a recent lease change
            const unitsNeedingDecision = await prisma.unit.findMany({
                where: {
                    isOccupied: false,
                    listing: null,
                    leases: {
                        some: {
                            leaseStatus: { in: ['EXPIRED', 'TERMINATED'] },
                            updatedAt: {
                                gte: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000) // Within last 7 days
                            }
                        }
                    }
                },
                include: {
                    property: {
                        include: {
                            manager: {
                                include: {
                                    user: true
                                }
                            }
                        }
                    },
                    leases: {
                        where: {
                            leaseStatus: { in: ['EXPIRED', 'TERMINATED'] }
                        },
                        orderBy: {
                            updatedAt: 'desc'
                        },
                        take: 1
                    }
                }
            });

            // Batch process notifications
            interface LeaseDecisionNotification {
                type: 'expiration' | 'termination';
                managerEmail: string;
                unitNumber: string;
                propertyName: string;
                unitId: string;
                leaseId: string;
            }

            type UnitWithManagerEmail = (typeof unitsNeedingDecision)[number] & {
                property: {
                    manager: {
                        user: {
                            email: string;
                        };
                    };
                };
            };

            const notifications: LeaseDecisionNotification[] = unitsNeedingDecision
                .filter((unit): unit is UnitWithManagerEmail =>
                    Boolean(unit.property.manager?.user?.email)
                )
                .map((unit) => ({
                    type: unit.leases[0]!.leaseStatus === 'EXPIRED' ? 'expiration' : 'termination',
                    managerEmail: unit.property.manager.user.email,
                    unitNumber: unit.unitNumber,
                    propertyName: unit.property.name || 'Property',
                    unitId: unit.id,
                    leaseId: unit.leases[0]!.id
                }));

            if (notifications.length > 0) {
                await leaseNotificationService.sendBatchNotifications(notifications);
            }

            console.log(`Processed ${unitsNeedingDecision.length} units needing listing decisions`);

        } catch (error) {
            console.error('Error processing units needing listing decisions:', error);
            throw error;
        }
    }
}

